--

DROP TABLE IF EXISTS `rag_query_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rag_query_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `conversation_id` int DEFAULT NULL,
  `user_message_id` int DEFAULT NULL,
  `assistant_message_id` int DEFAULT NULL,
  `query` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `answer` longtext COLLATE utf8mb4_unicode_ci,
  `source_file_filter` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `retrieved_chunks_json` json DEFAULT NULL,
  `top_k` int NOT NULL,
  `latency_ms` int DEFAULT NULL,
  `success` tinyint(1) NOT NULL,
  `error_message` text COLLATE utf8mb4_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `user_message_id` (`user_message_id`),
  KEY `assistant_message_id` (`assistant_message_id`),
  KEY `ix_rag_query_logs_conversation_id` (`conversation_id`),
  KEY `ix_rag_query_logs_user_id` (`user_id`),
  CONSTRAINT `rag_query_logs_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `rag_query_logs_ibfk_2` FOREIGN KEY (`conversation_id`) REFERENCES `conversations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `rag_query_logs_ibfk_3` FOREIGN KEY (`user_message_id`) REFERENCES `messages` (`id`) ON DELETE SET NULL,
  CONSTRAINT `rag_query_logs_ibfk_4` FOREIGN KEY (`assistant_message_id`) REFERENCES `messages` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
