INSERT INTO `rag_query_logs` VALUES (1,1,NULL,NULL,NULL,'你是？','根据当前用户手册资料，未检索到相关内容，无法确定答案。','cleaned_2.pdf','[]',5,2064,1,NULL,'2026-06-18 16:13:01'),(2,1,NULL,NULL,NULL,'我的车的电池报废了，怎么办？','根据当前用户手册资料，未检索到相关内容，无法确定答案。','cleaned_2.pdf','[]',5,750,1,NULL,'2026-06-18 16:14:27'),(3,1,NULL,NULL,NULL,'将废旧动力电池怎么处理？','根据当前用户手册资料，未检索到相关内容，无法确定答案。','cleaned_2.pdf','[]',5,491,1,NULL,'2026-06-18 16:14:40'),(4,1,NULL,NULL,NULL,'废旧动力电池怎么处理？','根据当前用户手册资料，未检索到相关内容，无法确定答案。','cleaned_2.pdf','[]',5,2091,1,NULL,'2026-06-18 16:15:37'),(5,1,NULL,NULL,NULL,'废旧动力电池怎么处理？','根据用户手册资料，当新能源汽车达到报废要求时，请按以下标准流程处理废旧动力电池：\n\n1. **残值评估**：将车辆送至比亚迪回收服务网点，进行动力电池残值评估。\n2. **专业拆卸**：将评估后的车辆送至报废汽车回收拆解企业，由机构拆卸动力电池。\n3. **回收移交**：将拆卸下的废旧动力电池移交至回收服务网点，网点将进行回购。\n\n⚠️ **安全与合规提醒**：\n- 新能源汽车所有人有责任和义务将废旧动力电池移交至指定回收网点。**非专业人员严禁私自打开、拆卸或拆解电池包**。私自转移、拆解导致的环境污染或安全事故，需由单位或个人承担相应责任。\n- 若电池在使用中出现故障或仪表异常指示，请勿自行处理，建议及时前往比亚迪汽车授权服务店检查。为保障行车及设备安全，具体请以车辆实际提示和官方售后指引为准。','xia.pdf','[{\"score\": 0.7227011, \"content\": \"动力电池回收\\n\\n当新能源汽车达到报废要求时，建议您按以下流程操作：\\n\\n- 1. 将车辆送至比亚迪回收服务网点，比亚迪将对动力电池进行残值评估。\\n- 2. 将评估后的车辆送至报废汽车回收拆解企业拆卸动力电池。\\n- 3. 将汽车回收拆卸机构拆卸的废旧动力电池移交至回收服务网点，回收服务网点将对动力电池进行回购。\", \"chunk_id\": \"xia_p26_c102\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"动力电池回收\", \"page_number_end\": \"167\", \"page_number_start\": \"167\"}, {\"score\": 0.7067028, \"content\": \"警告\\n\\n■ 新能源汽车所有人有责任和义务将废旧动力电池移交回收服务网点。私自将废旧动力电池移交给其他单位或个人，私自拆卸、拆解动力电池，由此导致环境污染或安全事故的，应承担相应责任。\", \"chunk_id\": \"xia_p26_c103\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"167\", \"page_number_start\": \"167\"}, {\"score\": 0.6268246, \"content\": \"警告\\n\\n非专业人员请勿打开动力电池包。私自拆卸、拆解电池导致的环境污染或安全事故，单位或个人将承担相应责任。\", \"chunk_id\": \"xia_p26_c099\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"167\", \"page_number_start\": \"167\"}, {\"score\": 0.5938476, \"content\": \"注意\\n\\n■ 动力电池出现故障时，建议您联系比亚迪汽车授权服务店。\", \"chunk_id\": \"xia_p26_c100\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"167\", \"page_number_start\": \"167\"}, {\"score\": 0.57751036, \"content\": \"用车建议\\n\\n为了延长动力电池使用寿命，有以下建议：\\n\\n- 车辆长时间存放前，建议充满电后放电至 40%~60%，电量不宜太高或太低，车辆存放时请关好车门、窗。\\n- 车辆长时间存放时，建议每3个月满充和满放电一次，再充电至40%~60%存放。\\n- 车辆使用时，若仪表 SOC 指示条进入红色警戒格时，电池电量已不足，请及时充电避免长时间低电量使用。\\n- 车辆使用时，建议每 1~2 周可以使用车载充电设备为车辆满充电一次。\\n- 气温较高时，应避免车辆长期满电存放，建议车辆充满电后放电至95%以下。\\n- 温度很低或很高时，建议车辆不要长时间室外停放。\\n- 使用车辆时，应尽量避免反复急加速和急减速。\\n\\n- 使用车辆时，应尽量避免长时间连续使用，长时间工作可能会导致电池温度过高，影响车辆性能。\\n- 使用车辆时，若仪表出现故障指示，建议及时前往比亚迪汽车授权服务店检查。\\n- 电池温度较高时，车辆性能会有一定限制，请将车辆静置待电池温度下降后再使用。\", \"chunk_id\": \"xia_p30_c118\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"用车建议\", \"page_number_end\": \"172\", \"page_number_start\": \"171\"}]',5,11338,1,NULL,'2026-06-18 16:16:36'),(6,1,NULL,NULL,NULL,'这车充电有多快啊？','根据当前用户手册资料，无法确定具体的充电速度或固定充电时间。手册中未提供明确的充电功率或满充时长参数，但您可通过以下方式了解与操作：\n\n1. **如何查看充电时间**：组合仪表会实时显示“预计剩余充满电时间”。受当前电量、环境温度、充电设施功率等因素影响，该时间存在合理偏差，请以仪表显示为准。\n2. **影响充电快慢的因素**：\n   - 温度：低温或高温时，电池热管理系统会启动加热/冷却，导致充电时间延长。北方建议在有供暖室内充电，南方建议在阴凉通风处充电。\n   - 用电设备：充电时使用空调会降低充电功率。\n   - 充电设备：推荐使用220V 10A专用交流线路；若使用公共快充桩，建议直流充电至80%~90%即可（时间允许可充满）。\n3. **基础操作提示**：请将车辆停放在通风处，车头半米内请勿遮挡；充电连接线严禁盘放，以免影响散热。\n\n⚠️ **安全与售后提醒**：充电时建议人员不要停留在车辆内。车辆实际充电速度与状态请以组合仪表盘提示为准，如需确认具体充电参数或设置，建议联系官方售后服务中心。','xia.pdf','[{\"score\": 0.650614, \"content\": \"温馨提示\\n\\n如整车电量低，可使用原地发电功能，建议您参考充电说明章节。\", \"chunk_id\": \"xia_p53_c199\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"194\", \"page_number_start\": \"194\"}, {\"score\": 0.6249294, \"content\": \"充电中注意事项\\n\\n- ■ 充电时建议人员不要停留在车辆内。\\n- 充电时空调可正常使用，但会降低充电功率。\\n- ■ 建议将车辆停放在通风处，车头半米内请勿遮挡。\\n- 当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n- 电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n- 充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n- 在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\\n\\n- 充电时，充电连接线不能盘放，会影响散热。\\n- 电池温度过低或过高时，车辆的充电性能会受到影响：\\n\\n- ● 低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n- ● 北方气温较低区域，建议用户在有供暖的室内进行充电。\\n- ● 南方气温较高区域，建议用户在阴凉通风处充电。\\n\\n■ 组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间存在一定偏差，属于正常现象。\", \"chunk_id\": \"xia_p4_c016\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电中注意事项\", \"page_number_end\": \"146\", \"page_number_start\": \"145\"}, {\"score\": 0.62162817, \"content\": \"设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p7_c025\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"设备说明\", \"page_number_end\": \"149\", \"page_number_start\": \"148\"}, {\"score\": 0.61764705, \"content\": \"注意\\n\\n■ 智慧充电功能只针对比亚迪配送的交流慢充设备研发，车主使用非比亚迪认证的交流慢充充电设备时，应关闭本功能，否则可能因充电设备不响应导致无法预约或立即充电，造成车辆亏电、电池电量不足。如需要在公共充电设施上应用，请确认设施可支持车端预约。\", \"chunk_id\": \"xia_p15_c056\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"156\", \"page_number_start\": \"156\"}, {\"score\": 0.6027433, \"content\": \"i 温馨提示\\n\\n- 电源挡位处于“OFF”挡时，车内放电无法使用。\\n- 车内最大放电容量为 2.2kW。\", \"chunk_id\": \"xia_p19_c073\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"160\", \"page_number_start\": \"160\"}]',5,17108,1,NULL,'2026-06-18 16:18:56'),(7,1,NULL,NULL,NULL,'怎么充电？','为确保用电安全，充电前请务必仔细检查供电设备、充电枪及充电口，确保无电缆磨损、端子生锈、壳体破裂或进水潮湿。**严禁在设备异常或潮湿状态下充电，以防短路或电击。**具体操作步骤如下：\n\n1. **打开充电口盖**：参照家用便携式交流充电指引，打开车辆右侧的充电口盖及内部保护盖。\n2. **连接供电端（按需）**：若使用未配备充电枪的单相交流充电桩，需将供电插头连接至充电桩插座（使用充电盒或自带充电枪的充电桩可跳过此步）。\n3. **连接车辆接口**：将充电枪插入车辆充电口，并确认已可靠锁止。\n4. **充电设置**：对于公共场所有设置选项的充电桩/盒，请按说明书刷卡或扫码；家用或无设置选项的设备可直接跳过。\n5. **启动充电**：按充电设备指导步骤操作启动充电。\n6. **确认连接**：观察组合仪表，充电连接指示灯点亮即表示充电已成功建立。\n\n**📌 重要注意事项：**\n- 充电前建议将电源挡位退至“OFF”，充电期间车辆无法进入“OK”挡。\n- 外部电网短时断电恢复后，原装充电设备会自动重启，无需重新插拔。\n- 未满电需提前结束，请通过充电桩设置正常结束，**尽量避免带载直接断电拔枪**。\n- 车辆长期停放建议至少每1个月充电一次。\n\n**⚠️ 安全提示**：充电涉及高压用电安全，雨天操作请做好设备防水保护。如遇到设备报警、连接异常或任何不确定情况，请立即停止操作，并严格以车辆实时提示及官方售后服务指导为准。','xia.pdf','[{\"score\": 0.73156, \"content\": \"充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\", \"chunk_id\": \"xia_p7_c023\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电方法\", \"page_number_end\": \"148\", \"page_number_start\": \"148\"}, {\"score\": 0.7196156, \"content\": \"4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\", \"chunk_id\": \"xia_p13_c047\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"4. 启动充电:\", \"page_number_end\": \"154\", \"page_number_start\": \"154\"}, {\"score\": 0.6948289, \"content\": \"充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p11_c038\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"152\", \"page_number_start\": \"152\"}, {\"score\": 0.6936755, \"content\": \"温馨提示\\n\\n如整车电量低，可使用原地发电功能，建议您参考充电说明章节。\", \"chunk_id\": \"xia_p53_c199\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"194\", \"page_number_start\": \"194\"}, {\"score\": 0.6852413, \"content\": \"充电注意事项\\n\\n- 任何电源挡位下都可以进行交流充电、直流充电^{*}，为保证安全，充电前，建议退电至“OFF”挡，充电时车辆无法进入“OK”挡。\\n- 当外部电网短时间断电并再次供电时，原装充电设备会自动重新启动充电，无需重新连接充电设备。\\n- 在未充满电的情况下，需要提前结束充电，请通过充电设备设置提前结束充电，尽量不要带载断电。\\n- 如果车辆长时间不使用，建议至少 1 个月充电一次。\", \"chunk_id\": \"xia_p3_c013\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电注意事项\", \"page_number_end\": \"144\", \"page_number_start\": \"144\"}]',5,18637,1,NULL,'2026-06-18 16:21:25'),(8,1,NULL,NULL,NULL,'直流充电怎么操作？','根据提供的用户手册资料，直流充电操作步骤如下：\n\n1. **充电前准备**：仔细阅读并遵守手册中的充电安全警告事项及安全注意事项；查阅充电机设备规格说明。\n2. **启动充电**：直接**按充电设备的指导步骤操作**以启动充电。期间可参考组合仪表显示的充电时间提醒。\n3. **充电结束**：\n   - 关闭充电口保护盖与车辆充电口盖。\n   - 整理充电设备，将充电枪放回直流充电桩的指定位置。\n   - 若充电结束后充电枪无法拔出，请及时联系充电站客服人员。\n\n💡 **使用提示**：高温环境下直流充电，电池热管理性能可能受乘员舱空调影响，导致充电效率下降或时间延长。为保证充电速度，建议充电过程中关闭空调。\n\n⚠️ **安全提醒**：直流充电涉及高压设备，请务必注意人身与设备安全。具体操作流程请以充电桩屏幕实际提示及官方售后建议为准。','xia.pdf','[{\"score\": 0.71124566, \"content\": \"充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\", \"chunk_id\": \"xia_p12_c042\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电桩直流充电* / 使用充电桩直流充电前：\", \"page_number_end\": \"153\", \"page_number_start\": \"153\"}, {\"score\": 0.7053739, \"content\": \"设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p12_c043\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"设备说明\", \"page_number_end\": \"153\", \"page_number_start\": \"153\"}, {\"score\": 0.6989114, \"content\": \"3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\", \"chunk_id\": \"xia_p13_c051\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 关闭充电口保护盖与车辆充电口盖。 / 4. 整理充电设备:\", \"page_number_end\": \"154\", \"page_number_start\": \"154\"}, {\"score\": 0.6868113, \"content\": \"4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\", \"chunk_id\": \"xia_p13_c047\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"4. 启动充电:\", \"page_number_end\": \"154\", \"page_number_start\": \"154\"}, {\"score\": 0.6820468, \"content\": \"注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\", \"chunk_id\": \"xia_p13_c052\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"154\", \"page_number_start\": \"154\"}]',5,13562,1,NULL,'2026-06-18 16:32:09'),(9,1,NULL,NULL,NULL,'怎么充电？','根据用户手册资料，标准充电操作步骤及安全提示如下：\n\n### 🔌 核心操作步骤\n1. **开启充电口**：确认车辆解锁后，打开车辆右侧充电口盖及内部保护盖。\n2. **连接电源端**（按设备类型选择）：\n   - 使用充电盒或已配备充电枪的交流充电桩：跳过此步。\n   - 使用未配枪的单相交流充电桩：需使用转接器，将供电插头连接至充电桩插座。\n3. **连接车辆**：手握充电枪对准车辆充电口平稳推入，确保插入到位并可靠锁止。\n4. **启动充电**：部分公共桩需刷卡或扫描二维码（具体依桩端说明）。连接成功后，组合仪表充电指示灯点亮即开始充电。\n5. **结束充电**：充满或暂停后，先断开供电插头，再拔下充电枪；随后关闭车辆充电口盖与保护盖，将充电枪放回指定位置并妥善收纳设备。\n\n### ⚠️ 关键注意事项\n- **充电前必查**：检查充电枪、充电口、线缆是否有磨损、生锈、破损、潮湿或异物。**如有异常严禁充电**，否则可能导致短路、电击或人身伤害。雨天需做好防水保护。\n- **充电中规范**：\n  - 建议人员不要停留在车内。\n  - 停放在通风处，车头半米内请勿遮挡；充电线切勿盘放。\n  - 空调可正常使用，但会延长充电时间；高温直流充电建议关闭空调以提升效率。\n  - 电池加热/冷却工作产生的声音或功率短时波动属正常现象。\n- **特殊提示**：直流充电建议充至 `80%~90%` 即可；电量较低时不支持预约充电；仪表显示的剩余时间受温度/设施影响存在合理偏差。\n\n📱 **快捷设置**：如需调整充电模式或预约充电，可通过中控屏“智慧充电”App/设置菜单，或直接语音呼唤“你好小迪，打开/退出智慧充电”进行设置。\n\n> 🔔 **安全提醒**：电气操作存在一定风险，请务必以车辆组合仪表实时提示为准。如遇充电枪无法拔出、设备异常报警等情况，请立即停止操作，及时联系充电站客服或官方售后服务点。','xia.pdf','[{\"score\": 0.731977, \"content\": \"充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\", \"chunk_id\": \"xia_p7_c014\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电方法\", \"page_number_end\": \"148\", \"page_number_start\": \"148\"}, {\"score\": 0.6999055, \"content\": \"充电前注意事项\\n\\n- 当充电口盖未解锁时，请勿强行开启充电口盖。\\n- 先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n- 当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n- ■ 充电时建议人员不要停留在车辆内。\\n- 充电时空调可正常使用，但会降低充电功率。\\n- ■ 建议将车辆停放在通风处，车头半米内请勿遮挡。\\n- 当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n- 电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n- 充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n- 在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\\n\\n- 充电时，充电连接线不能盘放，会影响散热。\\n- 电池温度过低或过高时，车辆的充电性能会受到影响：\\n\\n- ● 低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n- ● 北方气温较低区域，建议用户在有供暖的室内进行充电。\\n- ● 南方气温较高区域，建议用户在阴凉通风处充电。\\n\\n■ 组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间存在一定偏差，属于正常现象。\", \"chunk_id\": \"xia_p4_c008\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"146\", \"page_number_start\": \"145\"}, {\"score\": 0.6970895, \"content\": \"i 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"page_number_start\": \"151\"}, {\"score\": 0.6949059, \"content\": \"i 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"page_number_start\": \"151\"}, {\"score\": 0.6903857, \"content\": \"3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\", \"chunk_id\": \"xia_p13_c023\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 关闭充电口保护盖与车辆充电口盖。\", \"page_number_end\": \"155\", \"page_number_start\": \"154\"}]',5,21763,1,NULL,'2026-06-19 23:34:15'),(10,1,NULL,NULL,NULL,'我车子冲电冲到一半，充不上了，怎么回事？','根据用户手册资料，充电中途停止（充到一半充不上）通常由以下原因导致，请按顺序排查并操作：\n\n1. **充电电缆未连接完全**：重新握紧充电枪拔出，对准充电口推入，确保插头完全到位且无虚接。\n2. **充电连接装置开关被误按**：误触开关会直接停止充电。请检查开关状态，重新连接充电枪并手动启动充电。\n3. **外部电源短暂断电**：电网恢复后不会自动续充，需在供电稳定后重新连接充电枪并启动充电。\n4. **动力电池温度过高**：系统为保护电池会自动中止充电。请将车辆停放在阴凉通风处，待电池温度自然下降后再继续充电。\n5. **车辆或充电桩发生硬件故障**：观察组合仪表是否有“动力系统故障”指示灯点亮或明确的充电故障提示语。\n\n💡 **操作优先级建议**：先检查充电枪是否插紧、开关是否被误触；若无异常，检查插座是否恢复正常供电，并留意电池温度。\n\n⚠️ **安全提醒**：充电涉及高压系统与电池热管理，操作中请勿强行撬动接口或带载断电。若重新插拔并重启后仍无法充电，或仪表盘持续报警，请以车辆实际提示为准，并注意用电与操作安全，建议尽快联系比亚迪汽车授权服务店进行专业检测与维修。','xia.pdf','[{\"score\": 0.6915405, \"content\": \"表格：一般充电故障诊断\\n\\n第1条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：充电卡欠费或充电桩故障\\n解决方法：充电卡费用查询或联系场站工作人员解决。\\n\\n第2条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：交流充电连接装置未正确连接\\n解决方法：确认充电枪开关已弹起,注意充电设备的插头长短不同和连接位置不同。\\n\\n第3条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：12V低压蓄电池过度放电220V 50Hz 10A 标准带接地插座无电\\n解决方法：从其他车辆上搭接12V电源,车辆启动后,会给低压蓄电池充电。确认电源是否已过载保护,请换至另外插座使用。\\n\\n第4条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：车辆或交流充电连接装置故障\\n解决方法：确定仪表盘上有动力系统故障灯点亮,或是有充电系统故障提示语,则停止充电,建议与比亚迪汽车授权服务店联系。\\n\\n第5条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：动力电池温度过低或过高时\\n解决方法：在充电前允许动力电池加热或冷却,将车辆置于适宜温度的环境内,待温度正常后再充电。\\n\\n第6条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：动力电池已充满\\n解决方法：动力电池已充满时,充电会自动停止。\\n\\n第7条：\\n故障状态：充电中途停止充电\\n可能原因：充电电缆没有连接完全\\n解决方法：确认充电连接装置电缆没有虚接。\\n\\n第8条：\\n故障状态：充电中途停止充电\\n可能原因：充电连接装置开关被按下\\n解决方法：充电连接装置开关被按下则停止充电,需重新连接充电连接装置,启动充电。\\n\\n第9条：\\n故障状态：充电中途停止充电\\n可能原因：电源断电\\n解决方法：在一定时间内,电源恢复后,需重新连接充电连接装置,启动充电。\\n\\n第10条：\\n故障状态：充电中途停止充电\\n可能原因：动力电池温度过高\\n解决方法：充电会自动停止,待电池冷却后再充电。\", \"chunk_id\": \"xia_p5_c010\", \"chunk_type\": \"table\", \"source_file\": \"xia.pdf\", \"section_title\": \"为提升用车体验建议如下：\", \"page_number_end\": \"146\", \"page_number_start\": \"146\"}, {\"score\": 0.6672692, \"content\": \"表格：一般充电故障诊断\\n\\n第11条：\\n故障状态：充电中途停止充电\\n可能原因：车辆或充电桩发生故障\\n解决方法：确认充电桩或车辆有故障提示,建议联系比亚迪汽车授权服务店。\", \"chunk_id\": \"xia_p5_c011\", \"chunk_type\": \"table\", \"source_file\": \"xia.pdf\", \"section_title\": \"为提升用车体验建议如下：\", \"page_number_end\": \"146\", \"page_number_start\": \"146\"}, {\"score\": 0.6599096, \"content\": \"充电前注意事项\\n\\n- 当充电口盖未解锁时，请勿强行开启充电口盖。\\n- 先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n- 当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n- ■ 充电时建议人员不要停留在车辆内。\\n- 充电时空调可正常使用，但会降低充电功率。\\n- ■ 建议将车辆停放在通风处，车头半米内请勿遮挡。\\n- 当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n- 电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n- 充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n- 在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\\n\\n- 充电时，充电连接线不能盘放，会影响散热。\\n- 电池温度过低或过高时，车辆的充电性能会受到影响：\\n\\n- ● 低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n- ● 北方气温较低区域，建议用户在有供暖的室内进行充电。\\n- ● 南方气温较高区域，建议用户在阴凉通风处充电。\\n\\n■ 组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间存在一定偏差，属于正常现象。\", \"chunk_id\": \"xia_p4_c008\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"146\", \"page_number_start\": \"145\"}, {\"score\": 0.6450335, \"content\": \"充电结束后警告事项\\n\\n车辆行驶前，请确保拔出充放电设备，并关闭充电口盖。\\n\\n充电注意事项\\n\\n- 任何电源挡位下都可以进行交流充电、直流充电^{*}，为保证安全，充电前，建议退电至“OFF”挡，充电时车辆无法进入“OK”挡。\\n- 当外部电网短时间断电并再次供电时，原装充电设备会自动重新启动充电，无需重新连接充电设备。\\n- 在未充满电的情况下，需要提前结束充电，请通过充电设备设置提前结束充电，尽量不要带载断电。\\n- 如果车辆长时间不使用，建议至少 1 个月充电一次。\", \"chunk_id\": \"xia_p3_c006\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电结束后警告事项\", \"page_number_end\": \"144\", \"page_number_start\": \"144\"}, {\"score\": 0.6441281, \"content\": \"3. 停止放电指南\\n\\n■ 可通过拔下用电设备插头或者将整车退电至“OFF”挡结束放电并拔下插头。\\n\\ni 温馨提示\\n\\n- 电源挡位处于“OFF”挡时，车内放电无法使用。\\n- 车内最大放电容量为 2.2kW。\\n\\n电量平衡功能\\n\\n- 本车在双模模式下行驶时具有电量平衡功能，为急加速等工况储备电量。当车辆以较稳定的工况行驶时，SOC会在平衡点附近波动。\\n- 整车控制器拥有记忆功能，会记忆上一次设置的电量平衡点。\\n\\ni 温馨提示\\n\\n- ■ 发动机启动后，车辆以一定车速较稳定行驶时，发动机输出的一部分扭矩会驱动发电机进行发电，对动力电池进行充电。\\n- 若当前 SOC 与电量平衡点的差值较大时，平衡时间可能会较长。\", \"chunk_id\": \"xia_p19_c032\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 停止放电指南\", \"page_number_end\": \"161\", \"page_number_start\": \"160\"}]',5,16706,1,NULL,'2026-06-19 23:46:08'),(11,1,NULL,NULL,NULL,'家用充电我应该怎么做？','根据您提供的用户手册资料，家用充电（使用家用便携式交流充电设备）的操作步骤如下：\n\n### 🔌 家用充电操作步骤\n1. **充电前安全检查**\n   - 仔细查看供电插座、充电线缆、充电枪及车辆充电口是否有电缆磨损、端子生锈/烧蚀、壳体破裂或异物。\n   - 如有污渍或潮湿，务必用干燥清洁的布擦拭干净，确保连接处干燥洁净。\n   - ⚠️ **异常严禁充电**：若发现端口损坏、松动或明显潮湿，禁止充电，以防短路或电击。下雨天请注意对充电装置做好防雨防水保护。\n\n2. **准备电源**\n   - 使用符合国家标准的家用插座（推荐 `220V 50Hz 10A` 专用交流线路与插座），避免因线路不匹配导致跳闸或损坏。\n   - 将便携充电器（三转七）的供电插头插入该家用插座。\n\n3. **打开车辆充电口**\n   - 整车解锁，电源挡位建议退至 `OFF` 挡。\n   - 按下车辆右侧充电口盖，盖体自动弹开后，打开内部保护盖，确保枪头与插座端部无障碍物。\n\n4. **连接车辆**\n   - 将充电枪完全插入车辆充电口，确认已可靠锁止。\n\n5. **开始充电**\n   - 连接成功后，组合仪表上的**充电连接指示灯会点亮**，并开始显示充电参数与预计时间。（家用便携交流充电通常为即插即充，无需额外刷卡或扫码设置）\n\n6. **结束充电**\n   - 充满电或需提前结束时，按下直流/交流充电枪上的机械锁止按钮，平稳拔出充电枪。\n   - 拔掉家用插座端的供电插头，关闭车辆充电口及保护盖，妥善收纳充电设备。\n\n---\n💡 **温馨提示与安全提醒**\n- **预约充电限制**：电量较低时，系统不支持使用预约充电功能。\n- **拔枪不畅处理**：若解锁后无法拔出充电枪，可多次尝试解锁；仍无法取出时，请按手册指引操作“充电口应急解锁”。\n- 充电过程中请随时关注组合仪表提示。如遇到设备报警、异味、异响或任何异常状况，请立即停止操作。**所有电气操作请务必注意安全，具体请以车辆实时提示及官方售后服务指导为准。**','xia.pdf','[{\"score\": 0.7288262, \"content\": \"充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\", \"chunk_id\": \"xia_p7_c014\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电方法\", \"page_number_end\": \"148\", \"page_number_start\": \"148\"}, {\"score\": 0.71527714, \"content\": \"i 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"page_number_start\": \"151\"}, {\"score\": 0.7096076, \"content\": \"家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p7_c015\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"家用便携式交流充电\", \"page_number_end\": \"149\", \"page_number_start\": \"148\"}, {\"score\": 0.7021039, \"content\": \"充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\", \"chunk_id\": \"xia_p12_c022\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"page_number_start\": \"153\"}, {\"score\": 0.7009735, \"content\": \"i 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"page_number_start\": \"151\"}]',5,19106,1,NULL,'2026-06-19 23:48:09'),(12,1,NULL,NULL,NULL,'请问充电有哪些方法？','根据【用户手册资料】，车辆充电主要分为以下两种方式：\n\n1. **外接电源充电**：包括家用便携式充电、交流充电桩充电、直流充电桩充电。\n2. **行驶中自动充电**：车辆在制动、滑行或发动机开启时，可通过电机回收能量为动力电池充电。\n\n⚠️ **安全提示**：充电前请务必仔细检查供电设备、充电枪、充电口等部件，确保无电缆磨损、端口生锈、壳体破裂、异物或潮湿等情况。若发现连接松动或异常，请**禁止充电**，以免引发短路或电击。具体操作请以对应充电设备说明书及车辆组合仪表提示为准，如需协助请及时联系官方售后。','xia.pdf','[{\"score\": 0.7367869, \"content\": \"充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\", \"chunk_id\": \"xia_p7_c014\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电方法\", \"page_number_end\": \"148\", \"page_number_start\": \"148\"}, {\"score\": 0.70893085, \"content\": \"i 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"page_number_start\": \"151\"}, {\"score\": 0.70448685, \"content\": \"i 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"page_number_start\": \"151\"}, {\"score\": 0.6973594, \"content\": \"3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\", \"chunk_id\": \"xia_p13_c023\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 关闭充电口保护盖与车辆充电口盖。\", \"page_number_end\": \"155\", \"page_number_start\": \"154\"}, {\"score\": 0.6923963, \"content\": \"动力电池\\n\\n车辆主要动力源之一是动力电池，位于车辆地板下，可进行多次反复充电。通过外接电源给动力电池进行充电的主要方式为：家用便携式充电、交流充电桩充电、直流充电桩充电^{*}，车辆在制动、滑行或发动机开启时，亦可通过电机为动力电池充电。\\n\\n注意\\n\\n■ 动力电池位于车身底部，如遇崎岖路面，请谨慎驾驶。\\n\\ni 温馨提示\\n\\n- 车辆上“ON”挡或“OK”挡时高压线路都将处于连通状态。\\n- 对于新车在动力电池状态正常的情况下，由于驾驶习惯、路况、气温和用电设备开启与否等不同，纯电里程会有所增减。\\n- 为了延长电池使用寿命以及保证电池安全，电池系统在充电至高电量时会切换至涓流充电模式，充电时间可能会加长。\\n- 由于电池本身化学特性所致，已使用一段时间的车辆，电池容量存在自然衰减现象，其纯电里程会有所减少。当您发现爱车纯电里程有所减少时，可以到比亚迪汽车授权服务店进行检查。店端检查可以确认纯电里程的减少是否属于正常衰减。\", \"chunk_id\": \"xia_p25_c041\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"动力电池\", \"page_number_end\": \"166\", \"page_number_start\": \"166\"}]',5,13126,1,NULL,'2026-06-20 18:35:04'),(13,1,NULL,NULL,NULL,'充电操作','根据您提供的用户手册资料，充电操作主要分为直流与交流两种模式。以下为标准操作步骤及安全提醒：\n\n**🔹 直流充电操作步骤**\n1. **开启车盖**：整车解锁，电源挡位建议退至“OFF”，按压车辆右侧充电口盖自动弹开。\n2. **打开保护盖**：掀开直流充电口保护盖，确认充电枪头与车辆插座端部无障碍物。\n3. **连接车辆**：将充电桩充电枪插入车辆直流充电口，并确保可靠锁止。\n4. **启动充电**：按充电桩设备指导步骤启动。组合仪表充电指示灯点亮，同步显示充电参数与画面。\n\n**🔹 交流充电操作步骤**\n1. **开启车盖**：参照家用便携式方法，打开车辆右侧充电口盖及保护盖。\n2. **连接电源端**：若使用未配备充电枪的公共单相桩，需使用“七转七”连接供电插头；使用充电盒或已配枪的充电桩则跳过此步。\n3. **连接车辆**：将充电枪插入车辆充电口并可靠锁止。\n4. **充电设置**：部分公共桩/盒需刷卡或扫码激活（具体见设备说明）；使用充电盒或无设置选项的桩可直接跳过。\n5. **开始充电**：组合仪表指示灯点亮，显示充电时间及参数。此时可通过多媒体设置预约充电（注：电量较低时不可使用预约充电）。\n\n**🛑 结束充电操作**\n- **直流**：充满或提前结束后，按下充电枪上的机械锁止按钮，拔出充电枪。\n- **交流**：充满或手动结束后 → 拔下充电枪（若使用七转七，请先拔枪再拔供电插头）→ 关闭车辆充电口保护盖及外盖 → 将设备放回指定位置妥善收纳。\n- *异常提示*：若解锁后无法拔枪，可多次尝试重新解锁；仍无效请按手册指引进行“充电口应急解锁”。\n\n**⚠️ 安全与注意事项提醒**\n充电操作涉及高压电气系统，请务必注意用电安全。**如果涉及驾驶安全、维修、充电、故障处理，请提醒用户注意安全，并建议以车辆实际提示和官方售后为准。** 充电前请严格检查供电设备、线缆、枪头及接口是否有磨损、生锈、腐蚀、破损或潮湿，如有异常禁止充电，以免引发短路或电击；雨天充电请注意对设备进行防水保护。以上内容均基于当前用户手册资料整理。','xia.pdf','[{\"score\": 0.7219005, \"content\": \"充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\", \"chunk_id\": \"xia_p12_c022\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"page_number_start\": \"153\"}, {\"score\": 0.7135648, \"content\": \"充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\", \"chunk_id\": \"xia_p7_c014\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电方法\", \"page_number_end\": \"148\", \"page_number_start\": \"148\"}, {\"score\": 0.70732087, \"content\": \"温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p11_c020\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"153\", \"page_number_start\": \"152\"}, {\"score\": 0.7050649, \"content\": \"i 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"page_number_start\": \"151\"}, {\"score\": 0.7031615, \"content\": \"i 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"page_number_start\": \"151\"}]',5,23568,1,NULL,'2026-06-20 18:36:30'),(14,1,NULL,NULL,NULL,'能家用充电吗？','可以，车辆支持家用便携式交流充电。请按以下步骤操作：\n\n**🔌 操作步骤：**\n1. **充电前检查**：仔细检查供电线缆、充电枪、充电口有无磨损、锈蚀、壳体破裂、潮湿或异物。若有异常，禁止充电。\n2. **连接供电端**：将充电装置的供电插头牢固插入符合国标的220V 50Hz 10A家用标准插座中（确保插座接地良好）。\n3. **连接车辆端**：将充电枪插入车辆右侧充电口，确认充电枪已可靠锁止。\n4. **开始充电**：组合仪表充电连接指示灯点亮即表示已正常接通，充电时间请以组合仪表显示为准。\n5. **结束充电**：充满后，请先断开供电插头，再拔出充电枪，随后关闭车辆充电口保护盖和外盖，将设备妥善收纳。\n\n**⚠️ 重要安全提示：**\n- **环境要求**：推荐使用220V 50Hz 10A的专用交流线路和插座。设备规格为220V AC 50Hz 8A。下雨或环境潮湿时，请注意对充电装置做防水保护。\n- **严禁行为**：严禁在插排线变软、电缆磨损、绝缘层破裂、插头/枪外壳损坏、端子烧蚀或明显污渍的情况下使用。充电时禁止将设备放置于后备箱、车头下或轮胎附近。\n- **故障处理**：若上电后无法拔枪，可多次尝试解锁仍无效时，请按手册提示进行应急解锁；如有任何故障、异响或跳闸，请立即停止使用，切勿私自拆装或维修，并及时联系比亚迪授权服务店。\n\n如涉及用电安全及设备状态判断，请以车辆组合仪表实际提示及官方售后指导为准，确保操作安全。','xia.pdf','[{\"score\": 0.67691404, \"content\": \"家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p7_c015\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"家用便携式交流充电\", \"page_number_end\": \"149\", \"page_number_start\": \"148\"}, {\"score\": 0.66665363, \"content\": \"充电设备警告事项\\n\\n使用满足国家相关标准的电动汽车专用充电设备：\\n\\n- 请勿私自对充电设备及相关端口进行改装、拆卸或擅自维修，若有故障请联系比亚迪汽车授权服务店进行处理，避免导致充电故障，引起火灾。\\n- - 严禁使用不合格产品。\\n\\n严禁在家用供电插排线变软、充电枪电缆磨损、绝缘层破裂或者其他任何损坏的情况下，使用该充电设备。\\n\\n严禁充电枪、供电插头或供电插排断开、破裂或者表面露出有任何损坏的情况下，使用该设备。\\n\\n充电设备接地说明：\\n\\n- ● 设备必须接地良好，如果充电设备出现故障或者损坏时，接地线可提供最小阻抗电路放电，从而减少触电的危险。\\n- ● 设备装有设备接地点与供电插头接地点相连的接地线，供电插头必须与符合安全标准要求、安装正确且接地良好的供电插座互配。\\n\\n充电时，禁止将设备放置于后备箱、车头下以及轮胎附近。\", \"chunk_id\": \"xia_p2_c004\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电设备警告事项\", \"page_number_end\": \"143\", \"page_number_start\": \"143\"}, {\"score\": 0.6573477, \"content\": \"充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\", \"chunk_id\": \"xia_p7_c014\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电方法\", \"page_number_end\": \"148\", \"page_number_start\": \"148\"}, {\"score\": 0.6509682, \"content\": \"i 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"page_number_start\": \"151\"}, {\"score\": 0.64802355, \"content\": \"i 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"page_number_start\": \"151\"}]',5,20478,1,NULL,'2026-06-20 18:38:12'),(15,1,NULL,NULL,NULL,'车子很长时间不用，建议电量冲到多少？','根据用户手册资料，车辆长时间停放时，建议将动力电池电量保持在 **40%~60%** 的SOC区间。\n\n**具体存放与保养建议：**\n* **短期停放（超过7天但不足3个月）**：直接调整电量至40%~60%后存放。\n* **长期停放（超过3个月）**：须先充电至100%，再放电至40%~60%后存放。\n* **日常维护**：存放期间请关好车门、车窗；建议每3个月进行一次“满充+满放”循环，之后再次充电至40%~60%存放，以防电池性能降低。\n\n（注：车辆长时间不用时，电量不宜长期处于过高或过低状态，以免加速电池衰减。如需进一步操作，请以车辆实际提示及官方售后指导为准。）','xia.pdf','[{\"score\": 0.6947655, \"content\": \"保持车辆处于安全驾驶状态\\n\\n轮胎爆裂或机械故障都是极端危险的，为减少这类故障发生的可能性，应经常检查车况，并定期完成规定的各个检查项目。\\n\\n警告\\n\\n- ■ 驾驶员必须取得驾驶证后才能驾驶车辆。\\n- ■ 请勿疲劳驾驶。\\n- ■ 驾驶车辆时务必遵守交通法则。\\n- ■ 驾驶时请务必专注驾驶，不要进行与驾驶无关的操作(如接打电话、调节按钮等)。\\n\\n用车建议\\n\\n为了延长动力电池使用寿命，有以下建议：\\n\\n- 车辆长时间存放前，建议充满电后放电至 40%~60%，电量不宜太高或太低，车辆存放时请关好车门、窗。\\n- 车辆长时间存放时，建议每3个月满充和满放电一次，再充电至40%~60%存放。\\n- 车辆使用时，若仪表 SOC 指示条进入红色警戒格时，电池电量已不足，请及时充电避免长时间低电量使用。\\n- 车辆使用时，建议每 1~2 周可以使用车载充电设备为车辆满充电一次。\\n- 气温较高时，应避免车辆长期满电存放，建议车辆充满电后放电至95%以下。\\n- 温度很低或很高时，建议车辆不要长时间室外停放。\\n- 使用车辆时，应尽量避免反复急加速和急减速。\\n\\n- 使用车辆时，应尽量避免长时间连续使用，长时间工作可能会导致电池温度过高，影响车辆性能。\\n- 使用车辆时，若仪表出现故障指示，建议及时前往比亚迪汽车授权服务店检查。\\n- 电池温度较高时，车辆性能会有一定限制，请将车辆静置待电池温度下降后再使用。\", \"chunk_id\": \"xia_p30_c050\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"保持车辆处于安全驾驶状态\", \"page_number_end\": \"172\", \"page_number_start\": \"171\"}, {\"score\": 0.69285345, \"content\": \"动力电池保养\\n\\n- 为了使电池处于最佳状态，请定期使用交流充电连接装置为电池充满电，建议每周至少充满一次。\\n- 当车辆不使用超过 7 天时，为延长其使用寿命，建议电池电量保持在 40%~60% SOC 区间内。超过 3 个月不使用时，须先充电至 100% 再放电至 40%~60% SOC，以避免电池性能降低，甚至损坏。\\n\\n动力电池低温加热功能\\n\\n当外界温度较低时，动力电池加热系统将启动并加热电池，提升低温充电速度和保证整车动力性及续航里程。\", \"chunk_id\": \"xia_p25_c042\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"动力电池保养\", \"page_number_end\": \"167\", \"page_number_start\": \"166\"}, {\"score\": 0.6871891, \"content\": \"3. 停止放电指南\\n\\n■ 可通过拔下用电设备插头或者将整车退电至“OFF”挡结束放电并拔下插头。\\n\\ni 温馨提示\\n\\n- 电源挡位处于“OFF”挡时，车内放电无法使用。\\n- 车内最大放电容量为 2.2kW。\\n\\n电量平衡功能\\n\\n- 本车在双模模式下行驶时具有电量平衡功能，为急加速等工况储备电量。当车辆以较稳定的工况行驶时，SOC会在平衡点附近波动。\\n- 整车控制器拥有记忆功能，会记忆上一次设置的电量平衡点。\\n\\ni 温馨提示\\n\\n- ■ 发动机启动后，车辆以一定车速较稳定行驶时，发动机输出的一部分扭矩会驱动发电机进行发电，对动力电池进行充电。\\n- 若当前 SOC 与电量平衡点的差值较大时，平衡时间可能会较长。\", \"chunk_id\": \"xia_p19_c032\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 停止放电指南\", \"page_number_end\": \"161\", \"page_number_start\": \"160\"}, {\"score\": 0.6713194, \"content\": \"充电结束后警告事项\\n\\n车辆行驶前，请确保拔出充放电设备，并关闭充电口盖。\\n\\n充电注意事项\\n\\n- 任何电源挡位下都可以进行交流充电、直流充电^{*}，为保证安全，充电前，建议退电至“OFF”挡，充电时车辆无法进入“OK”挡。\\n- 当外部电网短时间断电并再次供电时，原装充电设备会自动重新启动充电，无需重新连接充电设备。\\n- 在未充满电的情况下，需要提前结束充电，请通过充电设备设置提前结束充电，尽量不要带载断电。\\n- 如果车辆长时间不使用，建议至少 1 个月充电一次。\", \"chunk_id\": \"xia_p3_c006\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电结束后警告事项\", \"page_number_end\": \"144\", \"page_number_start\": \"144\"}, {\"score\": 0.6689982, \"content\": \"充电前注意事项\\n\\n- 当充电口盖未解锁时，请勿强行开启充电口盖。\\n- 先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n- 当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n- ■ 充电时建议人员不要停留在车辆内。\\n- 充电时空调可正常使用，但会降低充电功率。\\n- ■ 建议将车辆停放在通风处，车头半米内请勿遮挡。\\n- 当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n- 电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n- 充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n- 在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\\n\\n- 充电时，充电连接线不能盘放，会影响散热。\\n- 电池温度过低或过高时，车辆的充电性能会受到影响：\\n\\n- ● 低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n- ● 北方气温较低区域，建议用户在有供暖的室内进行充电。\\n- ● 南方气温较高区域，建议用户在阴凉通风处充电。\\n\\n■ 组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间存在一定偏差，属于正常现象。\", \"chunk_id\": \"xia_p4_c008\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"146\", \"page_number_start\": \"145\"}]',5,19596,1,NULL,'2026-06-20 18:42:11'),(16,1,NULL,NULL,NULL,'车辆怎么充电？','根据您的用户手册，车辆支持**家用便携式交流充电**、**公共场所交流充电桩充电**及**直流快充**三种方式。具体操作步骤如下：\n\n### 🔌 一、 家用便携式交流充电\n1. **准备**：整车解锁（建议挡位置于`OFF`），按下车辆右侧充电口盖自动弹开，再掀开保护盖。\n2. **连接供电端**：将专用供电插头（三转七）接入符合国标的家用220V插座。\n3. **连接车辆**：将充电枪插入车辆交流充电口，听到锁止声即表示可靠锁止（组合仪表充电指示灯点亮）。\n4. **结束充电**：充满或手动提前结束后，若开启防盗模式需先按键匙解锁按钮或按压门把手微动开关整车解锁，并在 **2分钟内** 按下充电枪机械按钮拔出。随后拔下电源插头，关闭保护盖与充电口盖。\n\n### 🏢 二、 交流充电桩充电\n1. **准备**：解锁车辆，打开右侧充电口盖及保护盖。\n2. **连接供电端**：若桩已配充电枪则跳过；若桩未配枪，需使用专用连接器（七转七）连接桩体供电插座。\n3. **连接车辆**：将充电枪插入车辆充电口并可靠锁止。\n4. **启充设置**：无特殊设置的桩直接充电；有计费/设置选项的桩需按提示刷卡或扫码。可在多媒体“智慧充电”App或语音助手处设置预约充电。\n5. **结束充电**：设备设定结束或充满 → 断开充电口连接（同家用拔枪步骤） → 拔除供电插头（如有） → 关盖，将充电枪放回桩体指定位置。\n\n### ⚡ 三、 直流快充充电\n1. **准备**：整车解锁，电源挡位置于`OFF`，按下车辆右侧充电口盖自动弹开。\n2. **开盖检查**：掀开直流充电口保护盖，确保枪头与插座端部无遮挡物。\n3. **连接车辆**：将直流充电枪插入车辆直流充电口并锁止。\n4. **启动充电**：按充电桩屏幕或卡片指引启动充电（仪表显示实时参数与充电画面）。\n5. **结束充电**：桩端设定结束或充满后，**按下直流充电枪上的机械锁止按钮**，平稳拔出充电枪。关闭各保护盖，将枪放回桩位。\n\n---\n### 💡 核心提示与安全提醒\n- **拔枪卡滞处理**：交流充电解锁后多次尝试仍无法拔枪，可参照手册“充电口应急解锁”操作；直流充电结束后若枪无法拔出，请及时联系充电站客服。**涉及高压操作请注意人身安全**。\n- **预约充电限制**：电量较低时，系统不支持预约充电功能。\n- **高温直流充电**：环境温度较高时充电，空调运行可能影响电池热管理导致充电降速，建议充电过程中关闭空调以提升效率。\n- **安全声明**：以上为手册标准操作指引。实际操作请以车辆组合仪表提示为准，如遇设备异常、漏液、异响或故障报警，请立即停止充电，疏散人员，并优先联系比亚迪官方授权售后服务中心处理。','xia.pdf','[{\"score\": 0.8636363636363635, \"content\": \"[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"context_chunk_ids\": [\"xia_p10_c018\", \"xia_p10_c019\", \"xia_p11_c020\"], \"page_number_start\": \"151\"}, {\"score\": 0.8527877864005912, \"content\": \"[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[neighbor chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\", \"chunk_id\": \"xia_p12_c022\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"context_chunk_ids\": [\"xia_p12_c021\", \"xia_p12_c022\", \"xia_p13_c023\"], \"page_number_start\": \"153\"}, {\"score\": 0.8469245298513589, \"content\": \"[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"context_chunk_ids\": [\"xia_p9_c017\", \"xia_p10_c018\", \"xia_p10_c019\"], \"page_number_start\": \"151\"}, {\"score\": 0.8208831277123958, \"content\": \"[neighbor chunk_id=xia_p7_c015 page=148-149]\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p8_c016 page=149-150]\\ni 温馨提示\\n\\n- 请联系比亚迪汽车授权服务店，按充电设备要求选择合适的电源。\\n- ■ 使用三转七充电时，注意开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n打开充电枪和充电口的保护盖^{*}，确保充电枪插头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n■ 将三转七插头插入家用插座中，三转七充电指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n- 将三转七的充电枪连接至充电口，并可靠锁止。\\n- 插好充电枪，组合仪表充电连接指示灯点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n- 车辆电量充满会自动结束充电。\\n- 如需提前结束充电直接进入下一步。\\n\\n[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\", \"chunk_id\": \"xia_p8_c016\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"150\", \"context_chunk_ids\": [\"xia_p7_c015\", \"xia_p8_c016\", \"xia_p9_c017\"], \"page_number_start\": \"149\"}, {\"score\": 0.8164654525890177, \"content\": \"[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[seed chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\\n\\n[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p11_c020\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"153\", \"context_chunk_ids\": [\"xia_p10_c019\", \"xia_p11_c020\", \"xia_p12_c021\"], \"page_number_start\": \"152\"}]',5,20459,1,NULL,'2026-06-21 13:29:47'),(17,1,NULL,NULL,NULL,'怎么充电？','根据您提供的《用户手册资料》，车辆支持**直流充电**与**交流充电**两种方式。具体操作步骤如下：\n\n### 🔌 一、直流充电操作步骤\n1. **打开充电口盖**：整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧充电口盖，盖体自动弹开。\n2. **打开保护盖**：掀开充电枪及车辆直流充电口的保护盖，确保内部无异物或障碍物。\n3. **连接车辆接口**：将充电桩的充电枪插入车辆直流充电口，确认已可靠锁止。\n4. **启动充电**：按照充电桩设备的引导步骤操作即可启动。充电过程中，组合仪表将亮起充电连接指示灯并显示实时参数与充电画面。\n5. **结束与整理**：充满后自动结束或设备手动结束。拔出前请**按下直流充电枪上的机械锁止按钮**，取出充电枪。最后关闭充电口保护盖与车辆充电口盖，将设备放回指定位置。\n\n### 🔋 二、交流充电操作步骤\n1. **打开充电口盖**：整车解锁，打开车辆右侧的充电口盖及充电口保护盖。\n2. **连接供电端**：\n   - 使用交流充电盒或未配备充电枪的单相交流桩：需使用七转七适配器，先将供电插头接入充电桩插座。\n   - 使用已配枪的交流桩或充电盒：无需此步。\n3. **连接车辆接口**：将充电装置的充电枪插入车辆充电口，确保可靠锁止。\n4. **充电设置**：部分公共交流桩/盒需刷卡或扫描二维码激活，具体请按设备说明操作。\n5. **结束与整理**：充满或手动结束后，先拔出充电枪，再断开供电插头（如适用），关闭盖板并妥善收纳设备。\n\n---\n### ⚠️ 安全与使用提示\n- **防盗模式注意**：若车辆电锁防盗已启用，拔枪前必须操作整车解锁解除电锁，并在2分钟内拔出充电枪，否则电锁会自动重新锁止。\n- **拔枪异常处理**：若充电完成后无法拔枪，可多次尝试解锁；仍无效时请按手册“充电口应急解锁”操作，或直接联系充电站客服人员。\n- **温度与效率**：高温直流充电时，电池热管理易受乘员舱空调影响导致充电变慢。为保证充电效率，建议充电过程中**关闭空调**。\n- **预约充电限制**：当剩余电量较低时，系统不支持使用预约充电功能。\n- **设备保护**：切勿在充电口冻住或带电锁状态强行开闭/拔插；充电时请勿晃动充电枪；移动线缆需轻拿轻放，严禁强行拉扯、扭转或撞击。\n\n> 📢 **安全提醒**：充电涉及高压电气系统，请务必严格遵守本手册安全警告事项。实际操作请以车辆组合仪表实时提示为准，如遇故障或异常，请联系官方售后服务中心处理。','xia.pdf','[{\"score\": 0.8285714285714285, \"content\": \"[neighbor chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[seed chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\\n\\n[neighbor chunk_id=xia_p14_c024 page=155-156]\\n智慧充电设置页面\\n\\n- ①预约充电开关\\n- ②充电起止时间\\n- ③重复周期\\n- ④切换预约用车模式*\\n\\n⑤设置\\n\\n- 出厂时车辆默认设置为立即充电，预约充电开关关闭。\\n- 如需进行预约充电，点击预约充电开启按钮①，设置充电起止时间②和重复周期③，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪或按下电源按键使车辆下电，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n预约用车*设置页面\\n\\n- ①预约用车开关\\n- ②预约用车时间\\n- ③重复周期\\n- ④电价优惠时段\\n- ⑤切换预约充电模式\\n\\n- 如需进行预约用车，点击预约用车开启按钮①，设置用车时间②，重复周期③和电价优惠时段④，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n- 用户可点击智慧充电设置图标，在“预约充电提醒”中关闭连接充电枪及下电提醒功能。\", \"chunk_id\": \"xia_p13_c023\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 关闭充电口保护盖与车辆充电口盖。\", \"page_number_end\": \"155\", \"context_chunk_ids\": [\"xia_p12_c022\", \"xia_p13_c023\", \"xia_p14_c024\"], \"page_number_start\": \"154\"}, {\"score\": 0.8242437061405983, \"content\": \"[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[neighbor chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\", \"chunk_id\": \"xia_p12_c022\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"context_chunk_ids\": [\"xia_p12_c021\", \"xia_p12_c022\", \"xia_p13_c023\"], \"page_number_start\": \"153\"}, {\"score\": 0.8228846394200724, \"content\": \"[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"context_chunk_ids\": [\"xia_p10_c018\", \"xia_p10_c019\", \"xia_p11_c020\"], \"page_number_start\": \"151\"}, {\"score\": 0.8227151293588301, \"content\": \"[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"context_chunk_ids\": [\"xia_p9_c017\", \"xia_p10_c018\", \"xia_p10_c019\"], \"page_number_start\": \"151\"}, {\"score\": 0.8087608614140623, \"content\": \"[neighbor chunk_id=xia_p3_c007 page=144-145]\\n充电设备注意事项\\n\\n■ 为了避免对充电设备及车辆造成损坏，注意以下预防事项：\\n\\n- 启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n- 请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n- - 为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n- ● 充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n- ● 充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n- 请勿在电锁锁止状态强行插入充电枪。\\n\\n■ 应小心使用充放电设备：\\n\\n- - 充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n- 请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n- 请勿在温度高于50^{\\\\circ} \\\\mathrm{C}的环境下存放或者使用充电设备。\\n- 请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n■ 不建议使用外加的电线或者适配器/转接器。\\n\\n[seed chunk_id=xia_p4_c008 page=145-146]\\n充电前注意事项\\n\\n- 当充电口盖未解锁时，请勿强行开启充电口盖。\\n- 先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n- 当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n- ■ 充电时建议人员不要停留在车辆内。\\n- 充电时空调可正常使用，但会降低充电功率。\\n- ■ 建议将车辆停放在通风处，车头半米内请勿遮挡。\\n- 当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n- 电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n- 充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n- 在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\\n\\n- 充电时，充电连接线不能盘放，会影响散热。\\n- 电池温度过低或过高时，车辆的充电性能会受到影响：\\n\\n- ● 低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n- ● 北方气温较低区域，建议用户在有供暖的室内进行充电。\\n- ● 南方气温较高区域，建议用户在阴凉通风处充电。\\n\\n■ 组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间存在一定偏差，属于正常现象。\\n\\n[neighbor chunk_id=xia_p5_c009 page=146-146]\\n充电结束时注意事项：\\n\\n- 先停止充电，并确保充电口已解锁。\\n- ■ 手握充电枪，并按住充电枪上的按钮，拔出充电枪。\\n- ■ 充电结束后，请先解锁后，再拔出充电插头。\\n- 使用家用便携式交流充电连接装置建议：停止充电时先断开充电设备的车辆插头，再断开电源端供电插头。\\n- ☑ 拔下充电枪后，请确保充电口保护盖及充电口盖处于闭合状态，避免水等异物进入充电端口，影响正常使用。\\n\\n为提升用车体验建议如下：\\n\\n- 当组合仪表动力电池剩余电量(SOC)指示条颜色到达红色区域时，表明动力电池电量即将耗尽，请及时充电。\\n- ■ 建议用车结束后立即充电，充电性能更佳。\", \"chunk_id\": \"xia_p4_c008\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"146\", \"context_chunk_ids\": [\"xia_p3_c007\", \"xia_p4_c008\", \"xia_p5_c009\"], \"page_number_start\": \"145\"}]',5,20338,1,NULL,'2026-06-21 13:30:56'),(18,1,NULL,NULL,NULL,'我的车怎么充电？','根据您提供的【用户手册资料】，您的车辆支持**家用便携式充电、交流充电桩充电和直流充电桩充电**。以下是标准化操作步骤：\n\n### 🔌 通用准备\n1. 整车解锁，建议将电源挡位退至“OFF”挡。\n2. 按下车辆右侧的充电口盖，自动弹开后打开内部保护盖。\n\n### 🔋 交流/便携式充电步骤\n1. **连接供电**（仅七转七设备需要）：将供电插头连接至公共单相交流桩插座。\n2. **连接车辆**：将充电枪插入车辆交流充电口，确认听到锁止声。\n3. **启动充电**：\n   - 家用充电盒/无设置桩：直连即可。\n   - 公共桩：按提示刷卡或扫码启动。\n   - 组合仪表充电连接指示灯点亮即开始充电。\n\n### ⚡ 直流充电步骤\n1. 打开车辆直流充电口内侧的保护盖。\n2. 将直流充电枪插入车辆直流充电口，确认可靠锁止。\n3. **启动充电**：按充电桩屏幕提示或刷卡启动，仪表指示灯点亮即开始。\n\n### 📱 智能/预约充电设置（可选）\n- **进入路径**：点击中控屏“智慧充电”App / `设置 → 能量 → 充电与放电设置` / 语音唤醒“你好小迪，打开智慧充电”。\n- **设置方法**：开启预约充电开关，设定充电起止时间与重复周期，点击“确定”保存。\n- ⚠️ 注意：电量较低时，系统不支持使用预约充电功能。\n\n### 🛑 停止充电操作\n- **拔枪**：按下充电枪上的机械锁止按钮，直接拔出。\n- **收尾**：关闭充电口保护盖与车辆充电口盖 → 整理并妥善放置充电设备/枪头。\n- 充满或中途结束后，充电将自动停止。\n\n---\n⚠️ **安全与注意事项**\n- 充电前请务必阅读手册中的《充电安全警告》与《安全注意事项》。\n- **高温直流充电**时，电池热管理性能可能受空调影响导致充电变慢，为保证效率建议充电过程中关闭乘员舱空调。\n- **拔枪时限**：解锁充电枪后需在 **2分钟内** 拔出，超时电锁会自动重新闭合。\n- **拔枪异常**：若充电枪卡滞无法拔出，请勿强行拉扯。可尝试多次解锁，仍无效时请拉动**后备箱右侧的应急解锁拉绳**（应急操作不建议频繁使用），并请及时联系充电站客服或比亚迪授权服务店。\n- 涉及车辆充电、电路及设备操作，请务必以车辆实际仪表盘提示为准，并严格遵守官方售后规范。','xia.pdf','[{\"score\": 0.8384615384615384, \"content\": \"[neighbor chunk_id=xia_p24_c040 page=165-165]\\n如上面表格，车辆若处于 2/3/4/6 状态下，用户除上述解锁操作外，可通过按充电枪按钮进行解锁拔枪，但此操作有可能影响充电口或充电枪的使用寿命，为应急操作，不建议频繁进行此操作。\\n\\ni 温馨提示\\n\\n- ■ 解锁充电枪后，2min 内可拔枪，2min 后电锁会重新闭合。\\n- ■ 锁车后充满电，在“停用”模式下电锁会自动解开，在“启用/智能”模式下电锁须按上述方法手动解开。\\n- 为保证充电完成后正常行车，拔枪后请关闭充电口盖。\\n\\n交流充电口应急解锁\\n\\n当电锁出现故障，导致交流充电枪不能拔出时，可通过使用应急解锁拔出交流充电枪。\\n\\n- 电锁位于后备箱右侧。轻拉应急解锁拉绳即可解锁充电枪。\\n- ■ 解锁完成后复位拉索卡扣。\\n\\n温馨提示\\n\\n若上述功能异常或失效，建议联系比亚迪汽车授权服务店。\\n\\n[seed chunk_id=xia_p25_c041 page=166-166]\\n动力电池\\n\\n车辆主要动力源之一是动力电池，位于车辆地板下，可进行多次反复充电。通过外接电源给动力电池进行充电的主要方式为：家用便携式充电、交流充电桩充电、直流充电桩充电^{*}，车辆在制动、滑行或发动机开启时，亦可通过电机为动力电池充电。\\n\\n注意\\n\\n■ 动力电池位于车身底部，如遇崎岖路面，请谨慎驾驶。\\n\\ni 温馨提示\\n\\n- 车辆上“ON”挡或“OK”挡时高压线路都将处于连通状态。\\n- 对于新车在动力电池状态正常的情况下，由于驾驶习惯、路况、气温和用电设备开启与否等不同，纯电里程会有所增减。\\n- 为了延长电池使用寿命以及保证电池安全，电池系统在充电至高电量时会切换至涓流充电模式，充电时间可能会加长。\\n- 由于电池本身化学特性所致，已使用一段时间的车辆，电池容量存在自然衰减现象，其纯电里程会有所减少。当您发现爱车纯电里程有所减少时，可以到比亚迪汽车授权服务店进行检查。店端检查可以确认纯电里程的减少是否属于正常衰减。\\n\\n[neighbor chunk_id=xia_p25_c042 page=166-167]\\n动力电池保养\\n\\n- 为了使电池处于最佳状态，请定期使用交流充电连接装置为电池充满电，建议每周至少充满一次。\\n- 当车辆不使用超过 7 天时，为延长其使用寿命，建议电池电量保持在 40%~60% SOC 区间内。超过 3 个月不使用时，须先充电至 100% 再放电至 40%~60% SOC，以避免电池性能降低，甚至损坏。\\n\\n动力电池低温加热功能\\n\\n当外界温度较低时，动力电池加热系统将启动并加热电池，提升低温充电速度和保证整车动力性及续航里程。\", \"chunk_id\": \"xia_p25_c041\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"动力电池\", \"page_number_end\": \"166\", \"context_chunk_ids\": [\"xia_p24_c040\", \"xia_p25_c041\", \"xia_p25_c042\"], \"page_number_start\": \"166\"}, {\"score\": 0.8284633268370973, \"content\": \"[neighbor chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[seed chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\\n\\n[neighbor chunk_id=xia_p14_c024 page=155-156]\\n智慧充电设置页面\\n\\n- ①预约充电开关\\n- ②充电起止时间\\n- ③重复周期\\n- ④切换预约用车模式*\\n\\n⑤设置\\n\\n- 出厂时车辆默认设置为立即充电，预约充电开关关闭。\\n- 如需进行预约充电，点击预约充电开启按钮①，设置充电起止时间②和重复周期③，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪或按下电源按键使车辆下电，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n预约用车*设置页面\\n\\n- ①预约用车开关\\n- ②预约用车时间\\n- ③重复周期\\n- ④电价优惠时段\\n- ⑤切换预约充电模式\\n\\n- 如需进行预约用车，点击预约用车开启按钮①，设置用车时间②，重复周期③和电价优惠时段④，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n- 用户可点击智慧充电设置图标，在“预约充电提醒”中关闭连接充电枪及下电提醒功能。\", \"chunk_id\": \"xia_p13_c023\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 关闭充电口保护盖与车辆充电口盖。\", \"page_number_end\": \"155\", \"context_chunk_ids\": [\"xia_p12_c022\", \"xia_p13_c023\", \"xia_p14_c024\"], \"page_number_start\": \"154\"}, {\"score\": 0.8104851450189157, \"content\": \"[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"context_chunk_ids\": [\"xia_p10_c018\", \"xia_p10_c019\", \"xia_p11_c020\"], \"page_number_start\": \"151\"}, {\"score\": 0.7989346153846154, \"content\": \"[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[neighbor chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\", \"chunk_id\": \"xia_p12_c022\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"context_chunk_ids\": [\"xia_p12_c021\", \"xia_p12_c022\", \"xia_p13_c023\"], \"page_number_start\": \"153\"}, {\"score\": 0.7940027972027972, \"content\": \"[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"context_chunk_ids\": [\"xia_p9_c017\", \"xia_p10_c018\", \"xia_p10_c019\"], \"page_number_start\": \"151\"}]',5,18085,1,NULL,'2026-06-21 13:31:42'),(19,1,NULL,NULL,NULL,'noa功能是什么？','根据【用户手册资料】，NOA（领航辅助）在手册中后续统一指代**高快领航(HNOA)**，是一项组合驾驶辅助功能。具体内容如下：\n\n- **核心作用**：辅助驾驶员控制车辆沿着中控屏导航App预设的路线行驶。\n- **工作原理**：通过毫米波雷达、摄像头等传感器检测前方环境与自车位置，在NOA可用路段上按导航路线辅助完成驾驶任务。\n- **辅助能力**：可按导航规划路径自动辅助完成车道保持、超车变道、导航变道、上/下匝道、进出互通立交及进出服务区等操作。\n- **适用场景**：需在导航App设置好目的地并开启导航，当车辆行驶至功能覆盖的高速公路或城市快速路时进入待机状态，驾驶员可主动拨动方向盘拨片激活。\n\n⚠️ **安全提示**：激活与使用NOA期间，驾驶员必须始终手握方向盘，密切注视仪表显示与语音提示，高度关注周边交通状况，做好随时人工干预（制动、转向等）的准备。请勿过度依赖系统，如遇复杂路况或系统提示请及时手动接管，以确保行车安全。详细操作与安全规范请以车辆实际提示及官方售后服务为准。','xia.pdf','[{\"score\": 0.85, \"content\": \"[neighbor chunk_id=xia_p83_c140 page=224-225]\\n注意\\n\\n- ■ 拨杆变道每次只能辅助驾驶员变换一条车道，不能连续变道。\\n- 除驾驶员主动取消外，变道过程也可能因旁车占道等原因受阻或取消，如果始终不满足变道条件，导致无法执行变道，则自车会在等待超时后取消变道；如果在执行变道的过程中，出现突发情况导致自车无法继续变道，则自车会尝试返回原车道。\\n\\n领航辅助(NOA)*\\n\\n领航辅助(NOA)是一项可以辅助驾驶员控制车辆沿导航路线行驶的组合驾驶辅助功能，适用于驾驶员在中控屏的导航 App 上设置好导航路线并已开启导航的场景。\\n\\n- NOA 通过毫米波雷达、摄像头等传感器检测车辆前方行驶环境并确定自车位置，在此基础上辅助驾驶员控制车辆在 NOA 可用路段上按照导航路线完成驾驶任务。\\n- 使用 NOA 时，驾驶员应始终保持手握方向盘，注意仪表显示屏和声音提示，做好随时干预或控制车辆的准备，确保车辆正确、安全行驶。驾驶员运动脱离超过规定时长会触发驾驶员运动脱离提醒，直至安全停车。\\n\\n[seed chunk_id=xia_p84_c141 page=225-225]\\ni 温馨提示\\n\\n- NOA 功能配置了语音播报提醒，驾驶员可通过中控屏→设置→DiPilot→行车辅助→驾驶辅助提示模式设置“简洁/详细”的语音播报模式。\\n- NOA 功能激活运行需使用车辆定位数据，驾驶员在开启车辆定位权限后，可通过中控屏→设置→DiPilot→行车辅助设置界面开启或关闭本功能。\\n- NOA 使用时，安全辅助中的车道偏离预警、车道保持辅助和红绿灯提醒等功能不生效（无论对应的功能开关是否开启）。\\n- NOA 使用时，车辆会在不满足 NOA 条件但满足 ICC/ACC 条件（例如驶离 NOA 可用路段、车辆偏航）时自动降级到 ICC/ACC，并可以在再次满足 NOA 条件时，主动升级到 NOA。\\n\\n高快领航(HNOA)适用于高速公路和城市快速路上的 NOA 路段。在设置好导航后行驶至功能覆盖的高速或城市快速路，驾驶员可主动激活功能，车辆会按照导航规划的路径辅助驾驶员完成车道保持、超车变道、导航变道、上/下匝道、进/出互通立交、进/出服务区等驾驶任务。（后续无特别说明，NOA 统一指高快领航辅助 HNOA）\\n\\n[neighbor chunk_id=xia_p84_c142 page=225-225]\\n表格：功能状态\\n\\n第1条：\\n显示状态：点亮\\n含义：NOA 可用,但未激活\\n说明：满足 NOA 条件时显示\\n\\n第2条：\\n显示状态：闪烁\\n含义：NOA 不再辅助驾驶员减速\\n说明：驾驶员踩加速踏板时显示\\n\\n第3条：\\n显示状态：闪烁\\n含义：NOA 已暂停(NOA 不再辅助驾驶员控制车辆方向)\\n说明：驾驶员干预方向盘时显示\\n\\n第4条：\\n显示状态：点亮\\n含义：NOA 已激活,正在使用中\\n说明：-\\n\\n第5条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时目标限速\\n说明：-\\n\\n第6条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时道路限速\\n说明：-\", \"chunk_id\": \"xia_p84_c141\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"225\", \"context_chunk_ids\": [\"xia_p83_c140\", \"xia_p84_c141\", \"xia_p84_c142\"], \"page_number_start\": \"225\"}, {\"score\": 0.8383680555555555, \"content\": \"[neighbor chunk_id=xia_p84_c142 page=225-225]\\n表格：功能状态\\n\\n第1条：\\n显示状态：点亮\\n含义：NOA 可用,但未激活\\n说明：满足 NOA 条件时显示\\n\\n第2条：\\n显示状态：闪烁\\n含义：NOA 不再辅助驾驶员减速\\n说明：驾驶员踩加速踏板时显示\\n\\n第3条：\\n显示状态：闪烁\\n含义：NOA 已暂停(NOA 不再辅助驾驶员控制车辆方向)\\n说明：驾驶员干预方向盘时显示\\n\\n第4条：\\n显示状态：点亮\\n含义：NOA 已激活,正在使用中\\n说明：-\\n\\n第5条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时目标限速\\n说明：-\\n\\n第6条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时道路限速\\n说明：-\\n\\n[seed chunk_id=xia_p85_c143 page=226-226]\\n功能设置\\n\\n- NOA 功能可在中控屏→设置→DiPilot→行车辅助中开启“领航辅助”。\\n- 在设置项中选择到“领航辅助”时也视为 ACC、ICC 功能开启。驾驶员主动激活功能时将优先激活 NOA 功能，若 NOA 功能无法激活，但满足 ACC/ICC 功能条件时则可激活 ACC/ICC 功能。\\n- ■ 进入中控屏→设置DiPilot→行车辅助界面，可根据需要和个人偏好设置NOA的功能参数。\\n- 设置拨杆变道的激活方式。中控屏→设置→DiPilot→行车辅助→拨杆变道→激活方式选择仅重拨、重拨或轻拨都可拨杆变道。\\n- 设置 NOA 的变道风格*。变道风格是驾驶员偏好的辅助驾驶员变道的风格，可设置的参数如下表所示。参数默认值分别为保守、标准。\\n\\n[neighbor chunk_id=xia_p85_c144 page=226-226]\\n第1条：\\n选项：保守\\n说明：超车变道仅在前车明显阻碍自车行驶时发起导航变道发起时机会早一些,确保车辆变道至正确车道的成功率\\n\\n第2条：\\n选项：标准\\n说明：超车变道将在前车阻碍自车行驶时尽快发起导航变道发起时机会更灵活,再保证成功率的前提下,尽量提升通行效率\", \"chunk_id\": \"xia_p85_c143\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"功能设置\", \"page_number_end\": \"226\", \"context_chunk_ids\": [\"xia_p84_c142\", \"xia_p85_c143\", \"xia_p85_c144\"], \"page_number_start\": \"226\"}, {\"score\": 0.804059541004654, \"content\": \"[neighbor chunk_id=xia_p86_c147 page=227-228]\\n使用方法\\n\\nNOA 激活条件\\n\\n- NOA 功能激活受限于以下 NOA 使用条件，如果 NOA 使用条件有不满足项，则无法成功激活。\\n- NOA 使用条件（包括但不限于）：\\n\\n- 车辆定位权限已打开。\\n\\n● 功能开关已开启，且驾驶员完成功能学习并通过考试。\\n\\n- 导航规划路线设置完毕。\\n\\n- 车辆当前位置位于本功能覆盖的道路。\\n\\n- 自车道双侧车道线清晰且自车处于车道中央。\\n\\n- EPB 未开启。\\n\\n- 车辆挡位处于前进挡（D 挡）上。\\n\\n- 车辆无后溜。\\n\\n- - 车辆四门两盖关闭。\\n- - 主驾安全带未系提示灯已灭。\\n- - 电子车身稳定系统开启。\\n- - 自车车速≤130km/h。\\n- - 车速 > 0km/h 时，未踩下制动踏板。\\n- - 自动紧急制动（AEB）功能未激活。\\n\\n[seed chunk_id=xia_p87_c148 page=228-228]\\nNOA 功能激活\\n\\n■ 驾驶员在导航地图界面设置目的地、确认导航路线，如系统检测到车辆按照导航路线行驶至功能覆盖的道路，则进入待机状态，此时仪表显示图标，此状态表示驾驶员可以激活 NOA 功能。\\n\\n■ 功能待机状态下，驾驶员可以通过单拨方向盘拨片以激活该功能。\\n\\n■ 激活成功后，仪表屏上的 NOA 图标显示为▲，伴有提示音。目标车速在中显示。\\n\\n■ 激活 NOA 时的初始目标车速：取决于激活 NOA 时的路况、车辆实时车速和道路限速：\\n\\n- 若车辆的实时车速 < 道路限速，则初始目标车速为道路限速。\\n- 若车辆的实时车速≥道路限速，则初始目标车速为实时车速。\\n- - 初始目标车速不低于 30km/h。\\n\\n[neighbor chunk_id=xia_p87_c149 page=228-229]\\n警告\\n\\n- ■ 激活 NOA 功能中，驾驶员应全程手握方向盘，确保车辆安全行驶在正确的道路内，并高度关注车辆驾驶情况，必要时及时人工干预或控制车辆。\\n- ■ 激活 NOA 功能中，驾驶员应保证车辆周边安全，避免过度依赖系统。例如：\\n\\n警告(续)\\n\\n- - 当自车距离前方车辆过近时，车辆可能无法正确识别目标.\\n- - 当车辆从静止状态起步时，车辆可能需汇入主路，驾驶员应充分目视检查判断，并及时应对。\\n\\n■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\", \"chunk_id\": \"xia_p87_c148\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"NOA 功能激活\", \"page_number_end\": \"228\", \"context_chunk_ids\": [\"xia_p86_c147\", \"xia_p87_c148\", \"xia_p87_c149\"], \"page_number_start\": \"228\"}, {\"score\": 0.7691392801251955, \"content\": \"[neighbor chunk_id=xia_p84_c141 page=225-225]\\ni 温馨提示\\n\\n- NOA 功能配置了语音播报提醒，驾驶员可通过中控屏→设置→DiPilot→行车辅助→驾驶辅助提示模式设置“简洁/详细”的语音播报模式。\\n- NOA 功能激活运行需使用车辆定位数据，驾驶员在开启车辆定位权限后，可通过中控屏→设置→DiPilot→行车辅助设置界面开启或关闭本功能。\\n- NOA 使用时，安全辅助中的车道偏离预警、车道保持辅助和红绿灯提醒等功能不生效（无论对应的功能开关是否开启）。\\n- NOA 使用时，车辆会在不满足 NOA 条件但满足 ICC/ACC 条件（例如驶离 NOA 可用路段、车辆偏航）时自动降级到 ICC/ACC，并可以在再次满足 NOA 条件时，主动升级到 NOA。\\n\\n高快领航(HNOA)适用于高速公路和城市快速路上的 NOA 路段。在设置好导航后行驶至功能覆盖的高速或城市快速路，驾驶员可主动激活功能，车辆会按照导航规划的路径辅助驾驶员完成车道保持、超车变道、导航变道、上/下匝道、进/出互通立交、进/出服务区等驾驶任务。（后续无特别说明，NOA 统一指高快领航辅助 HNOA）\\n\\n[seed chunk_id=xia_p84_c142 page=225-225]\\n表格：功能状态\\n\\n第1条：\\n显示状态：点亮\\n含义：NOA 可用,但未激活\\n说明：满足 NOA 条件时显示\\n\\n第2条：\\n显示状态：闪烁\\n含义：NOA 不再辅助驾驶员减速\\n说明：驾驶员踩加速踏板时显示\\n\\n第3条：\\n显示状态：闪烁\\n含义：NOA 已暂停(NOA 不再辅助驾驶员控制车辆方向)\\n说明：驾驶员干预方向盘时显示\\n\\n第4条：\\n显示状态：点亮\\n含义：NOA 已激活,正在使用中\\n说明：-\\n\\n第5条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时目标限速\\n说明：-\\n\\n第6条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时道路限速\\n说明：-\\n\\n[neighbor chunk_id=xia_p85_c143 page=226-226]\\n功能设置\\n\\n- NOA 功能可在中控屏→设置→DiPilot→行车辅助中开启“领航辅助”。\\n- 在设置项中选择到“领航辅助”时也视为 ACC、ICC 功能开启。驾驶员主动激活功能时将优先激活 NOA 功能，若 NOA 功能无法激活，但满足 ACC/ICC 功能条件时则可激活 ACC/ICC 功能。\\n- ■ 进入中控屏→设置DiPilot→行车辅助界面，可根据需要和个人偏好设置NOA的功能参数。\\n- 设置拨杆变道的激活方式。中控屏→设置→DiPilot→行车辅助→拨杆变道→激活方式选择仅重拨、重拨或轻拨都可拨杆变道。\\n- 设置 NOA 的变道风格*。变道风格是驾驶员偏好的辅助驾驶员变道的风格，可设置的参数如下表所示。参数默认值分别为保守、标准。\", \"chunk_id\": \"xia_p84_c142\", \"chunk_type\": \"table\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"225\", \"context_chunk_ids\": [\"xia_p84_c141\", \"xia_p84_c142\", \"xia_p85_c143\"], \"page_number_start\": \"225\"}, {\"score\": 0.7631810646964098, \"content\": \"[neighbor chunk_id=xia_p86_c146 page=227-227]\\n警告\\n\\n- ■ 开启通行效率优先开关后，车辆可能会在一些场景下超速行驶，驾驶员应注意时刻保持安全驾驶，必要时及时控制车辆。\\n- ■ 将目标车速偏移量设置为正数可能导致车辆的目标车速超过道路限速。请严格遵守交通法律法规。\\n\\n驾驶辅助指示灯状态设定\\n\\n- ■ 可在中控屏→设置 →DiPilot→行车辅助→驾驶辅助指示灯进行设置。\\n- ■ 驾驶辅助指示灯设置项具备记忆功能，默认出厂为开启。\\n- ■ 驾驶辅助指示灯开关开启且驾驶辅助功能激活时，蓝绿色驾驶辅助指示灯亮起。\\n- ■ 驾驶辅助指示灯开关关闭时，驾驶辅助指示灯不点亮。\\n- 灯光优先级：转向灯、双闪灯优先于驾驶辅助指示灯。\\n- - 转向灯开启时：对应侧驾驶辅助指示灯不再亮起，另一侧驾驶辅助指示灯保持蓝绿色常亮。\\n- - 双闪开启时：两侧驾驶辅助指示灯均不再亮起。\\n\\n[seed chunk_id=xia_p86_c147 page=227-228]\\n使用方法\\n\\nNOA 激活条件\\n\\n- NOA 功能激活受限于以下 NOA 使用条件，如果 NOA 使用条件有不满足项，则无法成功激活。\\n- NOA 使用条件（包括但不限于）：\\n\\n- 车辆定位权限已打开。\\n\\n● 功能开关已开启，且驾驶员完成功能学习并通过考试。\\n\\n- 导航规划路线设置完毕。\\n\\n- 车辆当前位置位于本功能覆盖的道路。\\n\\n- 自车道双侧车道线清晰且自车处于车道中央。\\n\\n- EPB 未开启。\\n\\n- 车辆挡位处于前进挡（D 挡）上。\\n\\n- 车辆无后溜。\\n\\n- - 车辆四门两盖关闭。\\n- - 主驾安全带未系提示灯已灭。\\n- - 电子车身稳定系统开启。\\n- - 自车车速≤130km/h。\\n- - 车速 > 0km/h 时，未踩下制动踏板。\\n- - 自动紧急制动（AEB）功能未激活。\\n\\n[neighbor chunk_id=xia_p87_c148 page=228-228]\\nNOA 功能激活\\n\\n■ 驾驶员在导航地图界面设置目的地、确认导航路线，如系统检测到车辆按照导航路线行驶至功能覆盖的道路，则进入待机状态，此时仪表显示图标，此状态表示驾驶员可以激活 NOA 功能。\\n\\n■ 功能待机状态下，驾驶员可以通过单拨方向盘拨片以激活该功能。\\n\\n■ 激活成功后，仪表屏上的 NOA 图标显示为▲，伴有提示音。目标车速在中显示。\\n\\n■ 激活 NOA 时的初始目标车速：取决于激活 NOA 时的路况、车辆实时车速和道路限速：\\n\\n- 若车辆的实时车速 < 道路限速，则初始目标车速为道路限速。\\n- 若车辆的实时车速≥道路限速，则初始目标车速为实时车速。\\n- - 初始目标车速不低于 30km/h。\", \"chunk_id\": \"xia_p86_c147\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"使用方法\", \"page_number_end\": \"228\", \"context_chunk_ids\": [\"xia_p86_c146\", \"xia_p86_c147\", \"xia_p87_c148\"], \"page_number_start\": \"227\"}]',5,13667,1,NULL,'2026-06-21 13:33:26'),(20,1,NULL,NULL,NULL,'对于我们车主来说，noa有什么作用，让我们能听明白','根据用户手册资料，用通俗的话为您解释 NOA（领航辅助）的作用和使用方法：\n\n### 🎯 NOA 的核心作用\n简单说，NOA 就是**帮您“顺着导航路线自己开”的辅助功能**。在您提前设好导航的前提下，它能自动帮您处理高速和城市快速路上最费精力的常规驾驶动作，具体包括：\n1. **自动车道保持**：让车辆始终稳定在车道中央。\n2. **自动变道超车/跟导航变道**：遇到前车较慢时自动寻找空档超车；需要按导航行驶路线时，自动调整所在车道。\n3. **自动上下匝道与进出枢纽**：到达出口、入口、互通立交或服务区时，辅助您完成打方向、加速/减速、汇入或驶出的动作。\n\n### 📍 如何使用（操作步骤）\n1. 在中控屏导航 App 设置好目的地路线并**开启导航**。\n2. 车辆驶入该功能支持覆盖的**高速公路或城市快速路**。\n3. 满足条件后，通过方向盘拨杆或相应按键**主动激活**（仪表盘 NOA 图标变为**蓝色常亮**即表示已激活使用中）。\n4. 若中途离开覆盖路段或偏航，系统会自动降级为普通的 ACC/ICC（仅跟车+车道保持）；再次进入合适路段且满足条件时，可重新激活升级到 NOA。\n\n### ⚠️ 重要安全提醒\n- NOA 是**驾驶辅助**，**不是自动驾驶**。使用时请**始终保持手握方向盘**，注视仪表提示和周围路况，随时准备接管。\n- 遇到路口、突发路况或您主动转动方向盘干预时，系统会暂停方向辅助（图标闪烁+语音提示），此时需您完全负责车辆的方向与安全。\n- 系统会根据您的干预时长自动升级提醒或退出功能。若提示升级退出，请立即轻踩刹车并人工控制方向与速度。\n- 以上说明基于当前手册，实际体验与系统提示可能因软件版本或路况有所差异，请务必以车辆实时显示提示及官方售后指导为准。','xia.pdf','[{\"score\": 0.7771428571428571, \"content\": \"[neighbor chunk_id=xia_p83_c140 page=224-225]\\n注意\\n\\n- ■ 拨杆变道每次只能辅助驾驶员变换一条车道，不能连续变道。\\n- 除驾驶员主动取消外，变道过程也可能因旁车占道等原因受阻或取消，如果始终不满足变道条件，导致无法执行变道，则自车会在等待超时后取消变道；如果在执行变道的过程中，出现突发情况导致自车无法继续变道，则自车会尝试返回原车道。\\n\\n领航辅助(NOA)*\\n\\n领航辅助(NOA)是一项可以辅助驾驶员控制车辆沿导航路线行驶的组合驾驶辅助功能，适用于驾驶员在中控屏的导航 App 上设置好导航路线并已开启导航的场景。\\n\\n- NOA 通过毫米波雷达、摄像头等传感器检测车辆前方行驶环境并确定自车位置，在此基础上辅助驾驶员控制车辆在 NOA 可用路段上按照导航路线完成驾驶任务。\\n- 使用 NOA 时，驾驶员应始终保持手握方向盘，注意仪表显示屏和声音提示，做好随时干预或控制车辆的准备，确保车辆正确、安全行驶。驾驶员运动脱离超过规定时长会触发驾驶员运动脱离提醒，直至安全停车。\\n\\n[seed chunk_id=xia_p84_c141 page=225-225]\\ni 温馨提示\\n\\n- NOA 功能配置了语音播报提醒，驾驶员可通过中控屏→设置→DiPilot→行车辅助→驾驶辅助提示模式设置“简洁/详细”的语音播报模式。\\n- NOA 功能激活运行需使用车辆定位数据，驾驶员在开启车辆定位权限后，可通过中控屏→设置→DiPilot→行车辅助设置界面开启或关闭本功能。\\n- NOA 使用时，安全辅助中的车道偏离预警、车道保持辅助和红绿灯提醒等功能不生效（无论对应的功能开关是否开启）。\\n- NOA 使用时，车辆会在不满足 NOA 条件但满足 ICC/ACC 条件（例如驶离 NOA 可用路段、车辆偏航）时自动降级到 ICC/ACC，并可以在再次满足 NOA 条件时，主动升级到 NOA。\\n\\n高快领航(HNOA)适用于高速公路和城市快速路上的 NOA 路段。在设置好导航后行驶至功能覆盖的高速或城市快速路，驾驶员可主动激活功能，车辆会按照导航规划的路径辅助驾驶员完成车道保持、超车变道、导航变道、上/下匝道、进/出互通立交、进/出服务区等驾驶任务。（后续无特别说明，NOA 统一指高快领航辅助 HNOA）\\n\\n[neighbor chunk_id=xia_p84_c142 page=225-225]\\n表格：功能状态\\n\\n第1条：\\n显示状态：点亮\\n含义：NOA 可用,但未激活\\n说明：满足 NOA 条件时显示\\n\\n第2条：\\n显示状态：闪烁\\n含义：NOA 不再辅助驾驶员减速\\n说明：驾驶员踩加速踏板时显示\\n\\n第3条：\\n显示状态：闪烁\\n含义：NOA 已暂停(NOA 不再辅助驾驶员控制车辆方向)\\n说明：驾驶员干预方向盘时显示\\n\\n第4条：\\n显示状态：点亮\\n含义：NOA 已激活,正在使用中\\n说明：-\\n\\n第5条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时目标限速\\n说明：-\\n\\n第6条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时道路限速\\n说明：-\", \"chunk_id\": \"xia_p84_c141\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"225\", \"context_chunk_ids\": [\"xia_p83_c140\", \"xia_p84_c141\", \"xia_p84_c142\"], \"page_number_start\": \"225\"}, {\"score\": 0.7452460782944654, \"content\": \"[neighbor chunk_id=xia_p98_c171 page=239-239]\\n警告\\n\\n- ■ 驾驶员应充分了解 ICC 和 NOA 的差异后，再决定是否切换至 ICC。\\n- 驾驶员应充分了解，ICC 的基本功能是辅助驾驶员控制车辆保持在车道中央区域行驶，无法像 NOA 一样辅助驾驶员控制车辆沿导航行驶、限速辅助、变道辅助等。切换至 ICC 后，驾驶员应根据行驶目的地实际道路状况来控制车辆的行驶路线和速度，并在情况变化时及时调节，始终确保安全驾驶。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n[seed chunk_id=xia_p98_c172 page=239-239]\\n干预和控制\\n\\n- NOA 使用过程中，驾驶员可以根据实际交通情况干预方向盘、干预加速踏板以及控制车辆。\\n- 在经过路口、变道、脱困避让等场景时，驾驶员可以在使用 NOA 的过程中短时间主动转动方向盘来临时控制车辆的行驶方向。\\n- 干预方向盘期间，系统不再辅助驾驶员控制行车方向，且不会对机动车交通信号灯的信号做出反应，不会因为路口的机动车交通信号灯为红灯而减速或刹停。\\n- ■ 干预方向盘期间仪表显示屏上显示的蓝色高亮自车行驶轨迹会消失，NOA 图标变为灰色（▲）闪烁，伴有弹窗、提示音和语音播报。\\n- ■ 干预方向盘后，请确保车辆已在车道中央行驶且 NOA 已恢复后，再停止干预方向盘。\\n- 长时间干预方向盘会导致仪表显示屏和声音提示逐步升级，若干预方向盘超过规定时长会导致 NOA 主动退出。主动退出 NOA 前，系统会发出连续告警音，并升级弹窗和语音播报。此时，驾驶员应立即轻踩刹车控制车辆。若驾驶员始终未控制车辆，则系统提示会升级为请立即控制车辆并主动退出 NOA，驾驶员需及时响应，主动控制车辆方向和速度，确保安全驾驶。\\n\\n[neighbor chunk_id=xia_p99_c173 page=240-240]\\n警告\\n\\n- ■ 干预方向盘时，请时刻注意行车速度及周边环境，确保安全驾驶。例如，干预方向盘时，如果前方自车道机动车交通信号灯为红灯，驾驶员应主动刹停车辆，避免违反交通规则。\\n- 在驾驶员干预方向盘期间，车辆行驶方向完全由驾驶员控制，系统不再辅助驾驶员控制车辆行驶方向。\\n- ■ 驾驶员无意触碰方向盘、物体卡压方向盘等场景可能也会导致系统进入干预方向盘的状态。请注意系统提示，若发生误触发干预方向盘的情形，请及时纠正并主动控制车辆，确保安全驾驶。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n- 驾驶员可以在使用 NOA 的过程中主动踩加速踏板来干预车辆行驶速度。干预加速踏板期间，系统不再辅助驾驶员控制车速，仪表显示屏上的 NOA 图标蓝色（▲）闪烁，伴有弹窗、提示音和语音播报。\\n- 长时间干预加速踏板会导致仪表显示屏和声音提示逐步升级，若干预加速踏板超过规定时长或加速到车速超过最高可行驶车速会导致NOA主动退出。主动退出NOA前，系统会发出连续告警音，并升级弹窗和语音播报。此时，驾驶员应立即轻踩刹车控制车辆。\\n- 若驾驶员始终未控制车辆，则系统提示会升级为请立即控制车辆并主动退出 NOA。\", \"chunk_id\": \"xia_p98_c172\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"干预和控制\", \"page_number_end\": \"239\", \"context_chunk_ids\": [\"xia_p98_c171\", \"xia_p98_c172\", \"xia_p99_c173\"], \"page_number_start\": \"239\"}, {\"score\": 0.7126696587725998, \"content\": \"[neighbor chunk_id=xia_p84_c141 page=225-225]\\ni 温馨提示\\n\\n- NOA 功能配置了语音播报提醒，驾驶员可通过中控屏→设置→DiPilot→行车辅助→驾驶辅助提示模式设置“简洁/详细”的语音播报模式。\\n- NOA 功能激活运行需使用车辆定位数据，驾驶员在开启车辆定位权限后，可通过中控屏→设置→DiPilot→行车辅助设置界面开启或关闭本功能。\\n- NOA 使用时，安全辅助中的车道偏离预警、车道保持辅助和红绿灯提醒等功能不生效（无论对应的功能开关是否开启）。\\n- NOA 使用时，车辆会在不满足 NOA 条件但满足 ICC/ACC 条件（例如驶离 NOA 可用路段、车辆偏航）时自动降级到 ICC/ACC，并可以在再次满足 NOA 条件时，主动升级到 NOA。\\n\\n高快领航(HNOA)适用于高速公路和城市快速路上的 NOA 路段。在设置好导航后行驶至功能覆盖的高速或城市快速路，驾驶员可主动激活功能，车辆会按照导航规划的路径辅助驾驶员完成车道保持、超车变道、导航变道、上/下匝道、进/出互通立交、进/出服务区等驾驶任务。（后续无特别说明，NOA 统一指高快领航辅助 HNOA）\\n\\n[seed chunk_id=xia_p84_c142 page=225-225]\\n表格：功能状态\\n\\n第1条：\\n显示状态：点亮\\n含义：NOA 可用,但未激活\\n说明：满足 NOA 条件时显示\\n\\n第2条：\\n显示状态：闪烁\\n含义：NOA 不再辅助驾驶员减速\\n说明：驾驶员踩加速踏板时显示\\n\\n第3条：\\n显示状态：闪烁\\n含义：NOA 已暂停(NOA 不再辅助驾驶员控制车辆方向)\\n说明：驾驶员干预方向盘时显示\\n\\n第4条：\\n显示状态：点亮\\n含义：NOA 已激活,正在使用中\\n说明：-\\n\\n第5条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时目标限速\\n说明：-\\n\\n第6条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时道路限速\\n说明：-\\n\\n[neighbor chunk_id=xia_p85_c143 page=226-226]\\n功能设置\\n\\n- NOA 功能可在中控屏→设置→DiPilot→行车辅助中开启“领航辅助”。\\n- 在设置项中选择到“领航辅助”时也视为 ACC、ICC 功能开启。驾驶员主动激活功能时将优先激活 NOA 功能，若 NOA 功能无法激活，但满足 ACC/ICC 功能条件时则可激活 ACC/ICC 功能。\\n- ■ 进入中控屏→设置DiPilot→行车辅助界面，可根据需要和个人偏好设置NOA的功能参数。\\n- 设置拨杆变道的激活方式。中控屏→设置→DiPilot→行车辅助→拨杆变道→激活方式选择仅重拨、重拨或轻拨都可拨杆变道。\\n- 设置 NOA 的变道风格*。变道风格是驾驶员偏好的辅助驾驶员变道的风格，可设置的参数如下表所示。参数默认值分别为保守、标准。\", \"chunk_id\": \"xia_p84_c142\", \"chunk_type\": \"table\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"225\", \"context_chunk_ids\": [\"xia_p84_c141\", \"xia_p84_c142\", \"xia_p85_c143\"], \"page_number_start\": \"225\"}, {\"score\": 0.4450865800865801, \"content\": \"[neighbor chunk_id=xia_p113_c199 page=254-254]\\n泊车辅助(APA)*\\n\\n- 泊车辅助(Auto Parking Assist, APA)通过摄像头、超声波雷达等传感器感知车位及障碍物信息，辅助驾驶员将车辆泊入或泊出车位。泊车辅助功能默认开启。\\n- ■ APA 可支持车位线清晰、完整，且光照条件良好的平行、垂直、斜列车位，同时支持一些没有车位线，但车位区域一侧或两侧有其他车辆的空间车位。此外，在没有车位线场景下，驾驶员还可以使用自选车位泊车。\\n- 泊车辅助功能暂不支持机械车位。\\n\\n[seed chunk_id=xia_p113_c200 page=254-254]\\ni 温馨提示\\n\\n为确保驾驶员能充分理解泊车辅助功能的适用范围、使用方法和注意事项，确保安全驾驶，我们为驾驶员准备了安全教学视频和考试。使用泊车辅助功能前，建议驾驶员先完整观看安全教学视频并通过考试。\\n\\n功能设置\\n\\n- ■ 进入中控屏泊车辅助界面，点触设置按钮，进入设置项界面，驾驶员可以设置倒挡联动状态*（开启、关闭）、车外语音交互*（开启、关闭）、泊车速度参数*（极速、标准、舒适）。\\n- 各个设置项的说明如下：\\n\\n[neighbor chunk_id=xia_p113_c201 page=254-254]\\n第1条：\\n倒挡联动*：车外语音交互*\\n泊车辅助为驾驶员提供了快捷进入的方式,驾驶员可根据需要进行开启或关闭。系统后台搜索到可泊车位后,车辆刹停,挡位由非“R”挡切换至“R”挡,系统将进入泊车辅助界面;若后台未搜索到可泊车位,切换至“R”挡将进入全景影像界面。倒挡联动进入泊车辅助界面后,切换至“D”挡继续向前行驶,车速达到15km/h时,泊车辅助界面将退出。：代客泊车为驾驶员提供了车外语音播报功能,此功能默认开启,驾驶员可根据需要进行关闭或重新开启。\", \"chunk_id\": \"xia_p113_c200\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"254\", \"context_chunk_ids\": [\"xia_p113_c199\", \"xia_p113_c200\", \"xia_p113_c201\"], \"page_number_start\": \"254\"}, {\"score\": 0.4370830910383149, \"content\": \"[neighbor chunk_id=xia_p1_c002 page=142-142]\\n4 使用和驾驶\\n\\n换挡操纵机构.... 186\\n\\n电子驻车(EPB)...... 187\\n\\n自动驻车(AVH)....191\\n\\n驾驶要领....193\\n\\n4-5 驾驶辅助功能......197\\n\\n驾驶辅助系统简介……197\\n\\n行车辅助....206\\n\\n泊车辅助....247\\n\\n前向安全辅助…… 275\\n\\n侧向安全辅助.... 291\\n\\n后向安全辅助…… 302\\n\\n驾驶辅助拓展功能……309\\n\\n灯光系统....311\\n\\n驾驶员监测辅助(DMS)*..313\\n\\n胎压监测....316\\n\\n低速提示音(AVAS)......318\\n\\n儿童遗留检测(CPD)*......319\\n\\n驾驶安全系统…… 321\\n\\n[seed chunk_id=xia_p1_c003 page=142-143]\\n4-6 其他主要功能说明.... 327\\n\\n行车记录仪*......327\\n\\n车载 ETC* 329\\n\\n充电说明\\n\\n充电安全警告\\n\\n- ■ 禁止未成年人进行充电作业或触摸使用充电设备，充电枪为高压用电器件，在充电时请勿让未成年人靠近。\\n- 请选择在相对较安全的环境下充电，如避免有危化液体、火源、热源、雷电、易燃易爆等环境。\\n- 严禁湿手操作，触摸充电口或充电座的裸露金属，否则可能引起触电、电击，造成人身伤害。\\n- 由于充电可能影响医疗电子设备，甚至造成严重的人身伤害或者死亡，如果您使用任何医疗电子设备(如可移植心脏起搏器或者可移植心脏血管去纤颤器)，在启动充电操作之前与医疗电子设备的制造商确认充电是否影响设备的正常工作。\\n\\n[neighbor chunk_id=xia_p2_c004 page=143-143]\\n充电设备警告事项\\n\\n使用满足国家相关标准的电动汽车专用充电设备：\\n\\n- 请勿私自对充电设备及相关端口进行改装、拆卸或擅自维修，若有故障请联系比亚迪汽车授权服务店进行处理，避免导致充电故障，引起火灾。\\n- - 严禁使用不合格产品。\\n\\n严禁在家用供电插排线变软、充电枪电缆磨损、绝缘层破裂或者其他任何损坏的情况下，使用该充电设备。\\n\\n严禁充电枪、供电插头或供电插排断开、破裂或者表面露出有任何损坏的情况下，使用该设备。\\n\\n充电设备接地说明：\\n\\n- ● 设备必须接地良好，如果充电设备出现故障或者损坏时，接地线可提供最小阻抗电路放电，从而减少触电的危险。\\n- ● 设备装有设备接地点与供电插头接地点相连的接地线，供电插头必须与符合安全标准要求、安装正确且接地良好的供电插座互配。\\n\\n充电时，禁止将设备放置于后备箱、车头下以及轮胎附近。\", \"chunk_id\": \"xia_p1_c003\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"4-6 其他主要功能说明.... 327\", \"page_number_end\": \"143\", \"context_chunk_ids\": [\"xia_p1_c002\", \"xia_p1_c003\", \"xia_p2_c004\"], \"page_number_start\": \"142\"}]',5,16007,1,NULL,'2026-06-21 13:35:14'),(21,1,NULL,NULL,NULL,'hnoa车速范围是多少？','根据用户手册资料，HNOA可调节的目标车速范围为 **5km/h～130km/h**。\n\n⚠️ **安全提醒**：该功能为目标车速辅助参考，导航或系统识别的限速可能存在偏差，且车速调整会受实际路况影响。请驾驶员务必时刻关注真实道路限速与周围环境，遵守交通法规，必要时及时人工干预（如手动调速或制动），确保安全驾驶。具体请以车辆实际提示和官方售后为准。','xia.pdf','[{\"score\": 0.9142857142857144, \"content\": \"[neighbor chunk_id=xia_p89_c152 page=230-230]\\n警告\\n\\n- ■ 导航 App 提供的道路限速并非始终准确，可能导致车辆采用错误的（高于或低于真实道路限速的）道路限速行驶。请驾驶员务必时刻关注道路限速，必要时调整车辆速度，确保安全驾驶。\\n- ■ 驾驶员应始终注意车辆周围环境并安全驾驶。例如，在匝道等道路限速过低的场景，车辆的目标车速可能会高于道路限速，驾驶员应确保车辆以安全合适的速度行驶。\\n- 切勿过度依赖限速辅助来确定目标车速。驾驶员应遵守当地的交通法律法规规定，根据实际道路状态设置目标车速，确保车辆始终在安全车速范围内行驶。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n[seed chunk_id=xia_p89_c153 page=230-231]\\n温馨提示\\n\\n驾驶员应充分了解，将目标车速偏移方式设置为正数、开启通行效率优先开关等情况下可能导致车辆的目标车速超过道路限速，请严格遵守交通法律法规。\\n\\n人工调节限速\\n\\n■ 激活 NOA 后，默认按照限速辅助调节巡航车速，用户可通过按键③手动调节巡航车速，也可以通过踩加速踏板调节巡航车速。人工调节巡航车速后，本次功能激活期间系统将不会根据道路限速主动调节巡航车速。\\n\\n■ HNOA 的可调节的目标车速范围为 5km/h~130km/h。\\n\\n■ 调节限速方法\\n\\n- 向上短拨一次按键③，当前车速如果是5的倍数时目标车速增加5\\\\mathrm{km / h}。当前车速如果不是5的倍数时增加为最近的5的倍数值。\\n\\n（例如，当前车速为 63km/h，向上短拨一次按键③，车速调整为 65km/h）。\\n\\n- 向下短拨一次按键③，当前车速如果是5的倍数时目标车速减少5km/h。当前车速如果不是5的倍数时减少为最近的5的倍数值。（例如，当前车速为63km/h，向下短拨一次按键③，车速调整为60km/h）。\\n\\n- 向上持续拨动按键③，目标巡航车速以1 \\\\mathrm{~km} / \\\\mathrm{h}为步进连续增加。\\n\\n- 向下持续拨动按键③，目标巡航车速以1 \\\\mathrm{~km} / \\\\mathrm{h}为步进连续减小。\\n\\n● 踩加速踏板至实时车速低于最大可调节目标车速，松开加速踏板，目标车速调节为加速后的实时车速。\\n\\n● 一键限速：点击一键限速按键主动恢复到当前道路限速，并恢复限速辅助控制。\\n\\n仪表显示屏中会显示新设置的目标速度。车辆会辅助驾驶员逐步调整到目标车速，具体耗时取决于调整的速度差值和实际交通情况。\\n\\n[neighbor chunk_id=xia_p90_c154 page=231-231]\\n警告\\n\\n- ■ 驾驶员应根据当地的交通法律法规和实际道路状况来设置目标车速，并在情况变化时及时调节，始终确保安全驾驶。\\n- ■ 通过按键调节目标车速，可能无法立即将车速降低到期望的数值。切勿过度依赖调速拨杆调节来充分降低车速。\\n- 在干预加速踏板期间调节的目标车速不会立即生效，车辆的实时速度完全取决于干预加速踏板情况。驾驶员应确定当前速度是否合理并相应调整。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\", \"chunk_id\": \"xia_p89_c153\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"231\", \"context_chunk_ids\": [\"xia_p89_c152\", \"xia_p89_c153\", \"xia_p90_c154\"], \"page_number_start\": \"230\"}, {\"score\": 0.7752754859855333, \"content\": \"[neighbor chunk_id=xia_p105_c184 page=246-246]\\n温馨提示\\n\\n- NOA 功能可能产生不当工作（包括但不限于）：偏离导航路线、偏离车道、压线行驶、超速行驶、异常刹停、非预期加速、非预期制动、非预期转向、碰撞 VRU/车辆、剐蹭障碍物、轮胎压到小障碍物、走错车道等。\\n- NOA 依赖导航 App 导航。使用 NOA 时需全程开启导航 App 导航，否则会导致 NOA 退出。\\n- 由于车辆的导航 App 未及时更新到最新版本，或道路建设、城市环境发展等难以预测的客观因素的影响，地图数据可能会与现实环境不符。\\n- 由于卫星状况、天气情况（例如冰、雨、雪等）、道路情况（例如道路施工）、交通状况（例如交通拥堵）等因素影响，车辆定位可能不准。\\n\\n[seed chunk_id=xia_p105_c185 page=246-247]\\n限速控制(ISLC)*\\n\\n- ■ 限速控制有两种工作模式：手动确认速度控制和系统速度控制。系统工作车速范围为 30~130km/h。\\n- 手动确认：当交通标志识别系统识别到的限速值大于 60km/h 并且本车辆设定 ACC 目标巡航车速值与用户设定的偏移值加限速值偏差小于 40km/h 时，系统会提示用户是否按照限速值进行目标巡航车速控制。当用户按下“设定”按键时，将按照限速值加偏移值进行目标巡航车速控制\\n\\n系统控速：当交通标志识别系统识别到的限速值大于 60km/h 并且本车辆设定 ACC 目标巡航车速值与用户设定的偏移值加限速值偏差小于 40km/h 时，系统会直接按照限速值加偏移值进行目标巡航车速控制。\\n\\n[neighbor chunk_id=xia_p106_c186 page=247-247]\\n功能设置\\n\\n用户可在中控屏→设置→DiPilot→行车辅助中进行“限速控制”设置。限速控制功能默认为关闭。车辆启动时，系统默认为上一次下电前的设置状态。\\n\\n- - 关闭：不开启任何限速控制功能；\\n- - 手动确认：功能激活时提示用户是否按照限速值加偏移值进行目标巡航车速控制；\\n- - 系统控速：功能激活时系统直接按照限速值加偏移值进行目标巡航车速控制。\\n\\n用户可在中控屏→设置→DiPilot→行车辅助中进行“目标车速偏移值”设置。目标车速偏移值默认为百分比，默认值为0%。车辆启动时，系统默认为上一次下电前的设置状态。\\n\\n- 数值：限速控制功能激活时 ACC 目标巡航车速设定为限速值加用户设定的偏移数值；\\n- ● 百分比：限速控制功能激活时 ACC 目标巡航车速设定为限速值加用户设定的偏移百分比。\", \"chunk_id\": \"xia_p105_c185\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"限速控制(ISLC)*\", \"page_number_end\": \"247\", \"context_chunk_ids\": [\"xia_p105_c184\", \"xia_p105_c185\", \"xia_p106_c186\"], \"page_number_start\": \"246\"}, {\"score\": 0.7557342657342657, \"content\": \"[neighbor chunk_id=xia_p66_c111 page=207-208]\\n功能使用\\n\\nACC 激活条件\\n\\n■ EPB 未拉起。\\n\\n- 车辆挡位处于“D”挡上。\\n- 车辆无后溜。\\n- 车辆四门两盖关闭。\\n- 主驾安全带系上。\\n- ■ 电子车身稳定系统未被关闭。\\n- ■ 自车车速≤130km/h。\\n- 停车时（车速为 0），驾驶员踩住制动踏板，或者开启自动驻车功能时可激活。\\n- 车辆行驶中（车速大于 0），驾驶员不踩制动踏板时可激活。\\n- 仪表上无整车网络通讯故障提示。\\n- ■ 自动紧急制动功能未激活。\\n\\n注意\\n\\n- 当电子车身稳定系统没有开启的情况下 ACC 不能被激活。\\n- ACC 适合在高速公路和路况良好的道路上使用，不适合在复杂城市道路或者山路上使用。\\n\\nACC 激活方式\\n\\n当仪表显示^{80}时，代表ACC可以激活，此时驾驶员可以通过以下操作激活功能。在本次车辆上电周期内，首次使用功能时，只可以通过单拨拨片①激活功能。每次车辆上电周期内，非首次使用ACC时，可单拨拨片①或上拨按键③激活ACC。\\n\\n首次功能激活时，系统将主动把当前车速设置为目标巡航车速，若当前车速小于 30km/h，则目标巡航车速将设置为 30km/h；非首次使用 ACC 时，若通过上拨按键③激活 ACC，目标巡航车速设为上次退出功能前设定的车速。（若上次巡航车速低于 30km/h，则在通过上拨按键③恢复 ACC 激活状态时，恢复的上次巡航车速也可低于 30km/h）。\\n\\n[seed chunk_id=xia_p68_c112 page=209-209]\\n警告\\n\\n■ ACC 无法基于路况和驾驶条件主动调节行驶速度。驾驶员应根据当地的交通法律法规和实际道路状况来设置目标车速，并在情况变化时及时调节，始终确保安全驾驶。\\n\\n设定目标巡航车速\\n\\n功能处于激活状态，通过向上或向下拨动按键③，可以在 5~130km/h 范围内设置目标巡航车速。短促向上拨动按键③，目标巡航车速单次增加 5km/h；短促向下拨动按键③，目标巡航车速单次减少 5km/h；持续向上拨动按键③，目标巡航车速连续增加 1km/h；持续向下拨动按键③，目标巡航车速连续减少 1km/h。\\n\\n[neighbor chunk_id=xia_p68_c113 page=209-209]\\n警告\\n\\n- ■ ACC 可能无法立即将车速降低到期望的数值。切勿过度依赖定速巡航来充分降低车速。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（例如适当减速、制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n一键限速设置\\n\\n功能处于激活状态，通过按下“一键限速”按键，系统主动将当前路段道路限速值设置为当前的 ACC 巡航车速。\\n\\n- “一键限速”按键触发时刻根据道路限速调整 ACC 巡航车速，如后续道路限速值变化，ACC 巡航车速不会跟随道路限速值变化进行主动调整。\\n- ■ 一键限速的最终限速值，综合用户对限速偏移的设置值，即一键限速值 = 【道路限速值】 + 目标车速偏移值。\", \"chunk_id\": \"xia_p68_c112\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"209\", \"context_chunk_ids\": [\"xia_p66_c111\", \"xia_p68_c112\", \"xia_p68_c113\"], \"page_number_start\": \"209\"}, {\"score\": 0.739007796780684, \"content\": \"[neighbor chunk_id=xia_p153_c266 page=294-294]\\n注意\\n\\n- ■ 以下情况建议关闭车道偏离辅助，包括但不限于：\\n- 以极具运动的风格驾驶车辆时；\\n- - 遇到恶劣天气时；\\n- - 驶经劣质路段时。\\n- ■ 以下场景不保证一定被识别，包括但不限于：\\n- - 不清晰的车道线；\\n- 有缺失的车道线。\\n- ■ 以下情况可能导致摄像头识别障碍或功能激活不及时，包括但不限于：\\n- - 摄像头位置松动、脱落或被遮挡；\\n- 雨、雪、雾、霾等极端天气；\\n- ● 车辆处于带拖车行驶、雪地、泥地、沙地、山地等特殊驾驶模式时 LDW 和 LDP 不能激活。\\n\\n■ 以下场景，车道偏离辅助功能可能不工作、不当工作或退出：\\n\\n● 驾驶辅助系统启动过程中（例如车辆刚上电，或驾驶辅助系统重启等）。\\n\\n[seed chunk_id=xia_p154_c267 page=295-295]\\n注意(续)\\n\\n- ● 驾驶辅助系统通用局限性中提到的场景。\\n- ● 驾驶辅助系统故障或需要维修。\\n\\n邻车靠近避让(ELKA)*\\n\\n- 在车辆无意识偏离当前路面或者无意识偏离车道且与相邻同向车道后方车辆或对向车道来车存在碰撞风险时，辅助转动方向盘进行纠偏，以规避和减轻可能的碰撞风险。\\n- 邻车靠近避让(ELKA)是通过摄像头等传感器探测前方道路边界和车道线，并结合角毫米波雷达来探测邻车道车辆。如果系统识别到驾驶员出现无意识偏离路面或者判断自车有偏离风险且与目标车辆之间存在的碰撞风险时，将会辅助控制方向盘进行转向纠偏，从而实现控制车辆保持在当前车道行驶，以避免或减轻车辆无意识穿越道路边界或者与对向迎面来车或者相邻车道超车来车发生碰撞的风险。\\n- ■ 系统工作车速范围：60km/h~150km/h。\\n\\n[neighbor chunk_id=xia_p154_c268 page=295-295]\\n功能设置\\n\\n驾驶员可通过中控屏→设置→DiPilot→安全辅助→邻车靠近避让设置界面开启或关闭邻车靠近避让功能。车辆出厂功能默认关闭。车辆启动时，系统默认为上一次下电前的设置状态。\\n\\ni 温馨提示\\n\\n- 邻车靠近避让功能激活过程中如果驾驶员此时大力踩下制动踏板、加速踏板或转动方向盘，功能会退出。\\n- 若驾驶员开启了转向灯且向转向灯方向进行变道，“向道路边沿偏离”场景和“向对向车道偏离且有对向来车”场景，邻车靠近避让功能将被抑制。\\n- 若驾驶员持续压线或压道路边沿行驶，邻车靠近避让功能将被抑制。\\n- 如果出现了偏离路面或者侧面碰撞的风险，但车辆可能与纠偏后路径上的其他障碍物发生碰撞，则邻车靠近避让功能不会干预车辆行驶方向。\", \"chunk_id\": \"xia_p154_c267\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意(续)\", \"page_number_end\": \"295\", \"context_chunk_ids\": [\"xia_p153_c266\", \"xia_p154_c267\", \"xia_p154_c268\"], \"page_number_start\": \"295\"}, {\"score\": 0.5586405529953916, \"content\": \"[neighbor chunk_id=xia_p33_c054 page=174-176]\\n如何节省燃油并延长车辆的使用寿命\\n\\n节省燃油是简单的也是轻松的，这也有助于延长车辆的使用寿命。以下是一些节省燃油和修理费的要领：\\n\\n- - 匀速驾驶有助于节省燃油。急加速、急转弯及急刹车都将消耗更多的燃油。\\n- - 根据交通状况，尽量保持匀速。车辆的每次减速或加速都将额外地消耗燃油。\\n- 在适当的驾驶条件下，使用定速巡航控制能更节省燃油。\\n\\n[seed chunk_id=xia_p33_c055 page=174-176]\\n- - 空调的开启使发动机增加额外的负荷，从而消耗更多的燃油。关闭空调，以减少燃油消耗。当车外大气温度适宜时，应采用外循环模式通风。\\n- - 保持正确的轮胎气压。轮胎气压的不足将导致轮胎磨损和燃油浪费。\\n- 请勿在车辆上装载不需要的重量。过多的重量，将增加发动机的负荷量，导致消耗大量的燃油。\\n- 切勿停车预热发动机，启动后应立即起步缓慢行驶，这样做可以使发动机尽快达到工作温度，并能减少有害物质的排放。除非是在极端低温环境，可以在 HEV-运动模式及 N 挡下用轻踩加速踏板保持较高的怠速，暖车后即可起步缓慢行驶。\\n- ● 发动机处于冷态时，启动后，切勿马上高速运转或大油门行驶，以防损坏发动机。\\n- ● 避免发动机长时间空转。如果在交通不繁忙的地区而又要长时间等人，则最好关闭发动机，过后再启动。\\n- - 避免发动机加载减速或超速运转。应根据行车的路面条件来选择适当的速度挡位。\\n- 避免连续不断的加速和减速。停停走走的驾驶方式将浪费燃油。\\n- 避免不必要的停车或制动。保持平稳的车速，配合交通信号灯进行驾驶，即可将停车的次数减到最少的程度；或利用无交通信号灯的通行大道行驶，与前车应保持适当的行驶距离来避免紧急制动，这也将减少制动器的磨损。\\n- - 尽可能避开交通繁忙或交通堵塞的道路。\\n- - 脚不要长时间放在制动踏板上，这将引起过早的磨损、过热和消耗大量燃油。\\n- 在高速公路上应保持适当的车速。车速越高，耗油量也就越多。将车速保持在经济时速范围内，可节省燃油。\\n- 前轮应保持正确的定位。避免碰撞路边侧石，在崎岖路面上要缓慢驾驶。前轮定位不准，不仅会引起轮胎的过快磨损，还会使发动机增加负荷，也就是会增加油耗。\\n- ● 车底盘应保持洁净、没有泥浆等物。这不但可以减轻车身的重量，也可防止腐蚀。\\n\\n[neighbor chunk_id=xia_p33_c056 page=174-176]\\n- ● 调整车辆并保持在最佳的工作状态。空气滤清器过脏；火花塞过多积碳；机油和润滑油过脏、变质或粘稠；未调整好的制动器等，均会影响发动机的性能并浪费燃油。为了使所有的部件都保持较长的使用寿命\", \"chunk_id\": \"xia_p33_c055\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"如何节省燃油并延长车辆的使用寿命\", \"page_number_end\": \"176\", \"context_chunk_ids\": [\"xia_p33_c054\", \"xia_p33_c055\", \"xia_p33_c056\"], \"page_number_start\": \"174\"}]',5,13659,1,NULL,'2026-06-21 13:41:09'),(22,1,NULL,NULL,NULL,'怎么充电？','根据用户手册资料，车辆支持多种充电方式。请您根据实际使用的充电设备，参考对应的操作步骤：\n\n### 🔌 一、家用便携式交流充电（三转七）\n1. **打开充电口盖**：整车解锁，建议将电源挡位退至“OFF”挡，按下车辆右侧充电口盖。\n2. **打开保护盖**：掀开充电枪端与车辆充电口的保护盖。\n3. **连接供电端**：将三转七插头插入符合国家标准的家用插座（推荐使用220V 10A专用线路），设备充电指示灯常亮。\n4. **连接车辆接口**：手握充电枪对准车辆充电口推入，确保可靠锁止。组合仪表充电连接指示灯点亮即开始充电。\n\n### 🏢 二、公共场所交流充电桩充电\n1. **打开充电口盖**：整车解锁，打开车辆右侧充电口盖及内部保护盖。\n2. **连接供电端**：若使用未配备充电枪的单相交流桩，需使用“七转七”转接器将供电插头连接至充电桩插座（若桩已配枪或使用充电盒则跳过此步）。\n3. **连接车辆接口**：将充电枪插入车辆充电口并可靠锁止。\n4. **充电设置**：按充电桩/盒说明进行刷卡、扫码或APP授权等操作。\n5. **开始充电**：组合仪表充电连接指示灯点亮，仪表将显示充电参数与画面。\n\n### ⚡ 三、直流快充充电\n1. **打开充电口盖**：整车解锁，建议电源挡位退至“OFF”挡，按压车辆右侧充电口盖使其自动弹开。\n2. **打开直流保护盖**：取下充电枪头与车辆直流插座的保护盖，确认内部无异物。\n3. **连接车辆接口**：将直流充电枪插入车辆直流充电口，确保可靠锁止。\n4. **启动充电**：严格按照充电桩屏幕或设备说明书的指导步骤操作启动。\n5. **开始充电**：组合仪表充电连接指示灯点亮，并显示实时充电信息。\n\n---\n⚠️ **充电安全与注意事项**\n- **解锁与防盗**：严禁在电锁锁止状态强行插拔枪或开盖。若启用充电防盗模式，拔枪前需先通过钥匙或门把手微动开关解锁整车，并在2分钟内完成拔枪，否则电锁会重新锁止。\n- **环境与散热**：充电时请将车辆停放在通风处，车头半米内请勿遮挡；充电连接线请自然放置，**切勿盘绕、拉扯或碰撞**。\n- **温度影响**：电池过热/过冷会导致充电功率波动或时间延长，属正常热管理现象。高温直流充电时，为保证效率建议关闭乘员舱空调。\n- **其他提示**：电量较低时无法使用预约充电；充电期间建议人员不要停留在车内。\n- **安全提醒**：充电涉及高压电气系统，请务必遵守设备安全规范。如遇充电枪卡滞、设备报警或异常，请立即停止操作并联系充电站客服或比亚迪授权服务店。**请以车辆组合仪表实时提示及官方售后指导为准。**','xia.pdf','[{\"score\": 0.05178246161852719, \"content\": \"[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"context_chunk_ids\": [\"xia_p10_c018\", \"xia_p10_c019\", \"xia_p11_c020\"], \"page_number_start\": \"151\"}, {\"score\": 0.051408090117767535, \"content\": \"[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[neighbor chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\", \"chunk_id\": \"xia_p12_c022\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"context_chunk_ids\": [\"xia_p12_c021\", \"xia_p12_c022\", \"xia_p13_c023\"], \"page_number_start\": \"153\"}, {\"score\": 0.05013880272952854, \"content\": \"[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"context_chunk_ids\": [\"xia_p9_c017\", \"xia_p10_c018\", \"xia_p10_c019\"], \"page_number_start\": \"151\"}, {\"score\": 0.02996031746031746, \"content\": \"[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[seed chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\\n\\n[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p11_c020\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"153\", \"context_chunk_ids\": [\"xia_p10_c019\", \"xia_p11_c020\", \"xia_p12_c021\"], \"page_number_start\": \"152\"}, {\"score\": 0.021311475409836068, \"content\": \"[neighbor chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[seed chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\\n\\n[neighbor chunk_id=xia_p14_c024 page=155-156]\\n智慧充电设置页面\\n\\n- ①预约充电开关\\n- ②充电起止时间\\n- ③重复周期\\n- ④切换预约用车模式*\\n\\n⑤设置\\n\\n- 出厂时车辆默认设置为立即充电，预约充电开关关闭。\\n- 如需进行预约充电，点击预约充电开启按钮①，设置充电起止时间②和重复周期③，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪或按下电源按键使车辆下电，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n预约用车*设置页面\\n\\n- ①预约用车开关\\n- ②预约用车时间\\n- ③重复周期\\n- ④电价优惠时段\\n- ⑤切换预约充电模式\\n\\n- 如需进行预约用车，点击预约用车开启按钮①，设置用车时间②，重复周期③和电价优惠时段④，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n- 用户可点击智慧充电设置图标，在“预约充电提醒”中关闭连接充电枪及下电提醒功能。\", \"chunk_id\": \"xia_p13_c023\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3. 关闭充电口保护盖与车辆充电口盖。\", \"page_number_end\": \"155\", \"context_chunk_ids\": [\"xia_p12_c022\", \"xia_p13_c023\", \"xia_p14_c024\"], \"page_number_start\": \"154\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p3_c007 page=144-145]\\n充电设备注意事项\\n\\n■ 为了避免对充电设备及车辆造成损坏，注意以下预防事项：\\n\\n- 启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n- 请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n- - 为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n- ● 充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n- ● 充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n- 请勿在电锁锁止状态强行插入充电枪。\\n\\n■ 应小心使用充放电设备：\\n\\n- - 充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n- 请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n- 请勿在温度高于50^{\\\\circ} \\\\mathrm{C}的环境下存放或者使用充电设备。\\n- 请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n■ 不建议使用外加的电线或者适配器/转接器。\\n\\n[seed chunk_id=xia_p4_c008 page=145-146]\\n充电前注意事项\\n\\n- 当充电口盖未解锁时，请勿强行开启充电口盖。\\n- 先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n- 当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n- ■ 充电时建议人员不要停留在车辆内。\\n- 充电时空调可正常使用，但会降低充电功率。\\n- ■ 建议将车辆停放在通风处，车头半米内请勿遮挡。\\n- 当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n- 电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n- 充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n- 在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\\n\\n- 充电时，充电连接线不能盘放，会影响散热。\\n- 电池温度过低或过高时，车辆的充电性能会受到影响：\\n\\n- ● 低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n- ● 北方气温较低区域，建议用户在有供暖的室内进行充电。\\n- ● 南方气温较高区域，建议用户在阴凉通风处充电。\\n\\n■ 组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间存在一定偏差，属于正常现象。\\n\\n[neighbor chunk_id=xia_p5_c009 page=146-146]\\n充电结束时注意事项：\\n\\n- 先停止充电，并确保充电口已解锁。\\n- ■ 手握充电枪，并按住充电枪上的按钮，拔出充电枪。\\n- ■ 充电结束后，请先解锁后，再拔出充电插头。\\n- 使用家用便携式交流充电连接装置建议：停止充电时先断开充电设备的车辆插头，再断开电源端供电插头。\\n- ☑ 拔下充电枪后，请确保充电口保护盖及充电口盖处于闭合状态，避免水等异物进入充电端口，影响正常使用。\\n\\n为提升用车体验建议如下：\\n\\n- 当组合仪表动力电池剩余电量(SOC)指示条颜色到达红色区域时，表明动力电池电量即将耗尽，请及时充电。\\n- ■ 建议用车结束后立即充电，充电性能更佳。\", \"chunk_id\": \"xia_p4_c008\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"146\", \"context_chunk_ids\": [\"xia_p3_c007\", \"xia_p4_c008\", \"xia_p5_c009\"], \"page_number_start\": \"145\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=xia_p7_c015 page=148-149]\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p8_c016 page=149-150]\\ni 温馨提示\\n\\n- 请联系比亚迪汽车授权服务店，按充电设备要求选择合适的电源。\\n- ■ 使用三转七充电时，注意开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n打开充电枪和充电口的保护盖^{*}，确保充电枪插头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n■ 将三转七插头插入家用插座中，三转七充电指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n- 将三转七的充电枪连接至充电口，并可靠锁止。\\n- 插好充电枪，组合仪表充电连接指示灯点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n- 车辆电量充满会自动结束充电。\\n- 如需提前结束充电直接进入下一步。\\n\\n[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\", \"chunk_id\": \"xia_p8_c016\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"150\", \"context_chunk_ids\": [\"xia_p7_c015\", \"xia_p8_c016\", \"xia_p9_c017\"], \"page_number_start\": \"149\"}, {\"score\": 0.012307692307692308, \"content\": \"[neighbor chunk_id=xia_p8_c016 page=149-150]\\ni 温馨提示\\n\\n- 请联系比亚迪汽车授权服务店，按充电设备要求选择合适的电源。\\n- ■ 使用三转七充电时，注意开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n打开充电枪和充电口的保护盖^{*}，确保充电枪插头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n■ 将三转七插头插入家用插座中，三转七充电指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n- 将三转七的充电枪连接至充电口，并可靠锁止。\\n- 插好充电枪，组合仪表充电连接指示灯点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n- 车辆电量充满会自动结束充电。\\n- 如需提前结束充电直接进入下一步。\\n\\n[seed chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\", \"chunk_id\": \"xia_p9_c017\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"2. 断开充电口连接:\", \"page_number_end\": \"150\", \"context_chunk_ids\": [\"xia_p8_c016\", \"xia_p9_c017\", \"xia_p10_c018\"], \"page_number_start\": \"150\"}]',5,25924,1,NULL,'2026-06-22 21:37:30'),(23,1,NULL,NULL,NULL,'辅助驾驶可以上高速吗？','根据您提供的用户手册资料，**辅助驾驶功能可以用于高速公路行驶**。手册中明确指出了多项功能的适用场景及使用要求：\n\n### ✅ 适用于高速的辅助驾驶功能\n1. **高快领航(HNOA) / 领航辅助(NOA)**：手册明确说明 `高快领航(HNOA)适用于高速公路和城市快速路上的 NOA 路段`。开启导航后，可辅助完成车道保持、超车变道、导航变道、上下匝道及进出服务区等驾驶任务。\n2. **自适应巡航(ACC)**：手册指出 `ACC 适合在高速公路和路况良好的道路上使用`，可根据设定车速和跟车时距自动调节车速跟随前车。\n3. **车道巡航辅助(ICC)**：支持 `0~130km/h` 速度区间，主要适用于 `车道线清晰、路况良好` 的道路场景，可覆盖高速行车需求。\n\n### 📝 使用前提与操作要点\n- **必须通过考试**：首次使用前，需在手机App登录个人账号，进入 `我的→驾驶辅助考试`，完整观看安全教学视频并考试合格后方可启用相关功能。\n- **全程主动监控**：激活任何辅助驾驶功能后，驾驶员需 `始终手握方向盘`，密切注意仪表屏提示与周围环境，做好随时人工制动、转向或取消功能的准备。\n- **路线控制**：辅助驾驶仅按当前车道或导航规划提供辅助，不替代驾驶员判断。遇弯道曲率过大、车道线模糊或交通复杂时，需手动接管。\n\n### ⚠️ 安全提醒（重要）\n- **系统存在局限性**：辅助驾驶依赖雷达与摄像头，受恶劣天气（大雨、大雪、浓雾）、强反光、积雪覆盖、视线遮挡、施工区域等影响可能降级或退出。手册多次强调：**切勿过度依赖辅助驾驶减速或确定路线，驾驶员始终对驾驶安全负全部责任**。\n- **异常处理**：若车辆发生碰撞、剐蹭导致传感器位置变化，或察觉系统性能下降/报错，请立即停用该功能，并联系比亚迪汽车授权服务店进行专业校准与检修。\n- 具体使用情况请以您车辆的仪表盘实际提示为准，建议严格遵守当地交通法规，谨慎开启。','xia.pdf','[{\"score\": 0.05150052882072978, \"content\": \"[neighbor chunk_id=xia_p59_c100 page=200-2014]\\n通过驾驶辅助系统考试\\n\\n为了确保驾驶员能充分理解驾驶辅助功能的适用范围、使用方法和注意事项，在使用车道巡航辅助(ICC)、高快领航辅助(HNOA)等驾驶辅助功能前，驾驶员需先完整观看安全教学视频并通过考试。\\n\\n使用方法\\n\\n- ■ 确保手机 App 应用已升级到最新版本，且已登录驾驶员的个人账号。\\n- 在手机 App 应用中进入我的→驾驶辅助考试，按提示观看视频并考试。\\n\\n注意\\n\\n- ■ 考试内容对驾驶安全有重要影响，请驾驶员认真学习。\\n- 如果您将车辆授权给他人使用，为安全起见，请确保被授权用户先登录其个人账号完成并通过驾驶辅助考试后，再使用该功能。\\n- 如果车辆更换驾驶员，为安全起见，请新驾驶员进入手机 App 进行学习，未经过学习并通过考试的驾驶员应避免使用驾驶辅助功能。\\n- ■ 驾驶辅助的课程及考试要求可能会随着驾驶辅助功能的变化和法规要求而调整。\\n\\ni 温馨提示\\n\\n- ■ 考试通过的结果仅针对当前登录的账号，如车辆更换登录账号，该登录账号需学习并通过考试后才能开启相应驾驶辅助功能。\\n- 在注册账号前，驾驶员应确保已详细阅读理解并同意使用驾驶辅助软件服务的相关法律文件。\\n\\n[seed chunk_id=xia_p60_c101 page=2014-202]\\n驾驶辅助系统通用局限性\\n\\n辅助驾驶功能应用多传感器融合算法，许多因素都会影响辅助驾驶功能的性能，进而导致其无法实现预期的功能。常见的限制因素包括但不限于系统自身设备问题（含驾驶员误操作导致）、使用环境影响（天气、道路环境等）、周围车辆和其他交通参与者影响等，包括不限于以下因素：\\n\\n系统自身设备因素（包含人为使用原因）\\n\\n- ■ 毫米波雷达、超声波雷达、摄像头未校准、损坏、表面覆盖有异物（如冰雪、水、霜、泥浆、灰尘等物体覆盖）。\\n- 有强烈反光物体的环境中（如高速公路上的交通标识牌、金属围栏，路面积水反光等）。\\n\\n■ 发生如下情况请务必联系比亚迪汽车授权服务店对系统进行专业校准与确认，包括但不限于：\\n\\n- - 拆卸前视摄像头、前挡风玻璃。\\n- 因车轮跑偏，重新进行四轮定位后。\\n- ● 车辆因发生剐蹭、碰撞等而导致车辆传感器异常或者车辆结构异常。特别是保险杠、前挡风玻璃、外后视镜、蒙皮（如翼子板、后尾门）、车架等因车辆碰撞或其他原因变形或损坏，导致传感器安装位置变化。\\n\\n如果装有挂车钩或装载的物体从车辆周围突出。\\n\\n■ 自行安装在车辆后方的物体（如自行车架）造成干扰或阻碍。\\n\\n将过多车漆（车漆厚度发生变化）或胶粘制品（如胶带、贴纸，车衣等）涂抹或粘贴到车辆上造成的阻碍。\\n\\n对于配有电容传感器的车型，请勿安装方向盘套，可能会导致功能异常。\\n\\n下列的情况下，本系统可能无法总是达到最优的性能水平，包括但不限于：\\n\\n- - 刹车片过度磨损或者制动系统异常时。\\n- - 轮胎充气不当或轮胎过度磨损时。\\n- ● 安装了不符合规定的轮胎时。\\n- - 安装了轮胎防滑链时。\\n- - 使用小型备胎或应急补胎工具时。\\n- - 车辆重载时。\\n\\n[neighbor chunk_id=xia_p61_c102 page=202-204]\\n使用环境影响因素\\n\\n若车辆长时间行驶在环形停车场、隧道等特殊道路条件下，雷达因探测特性局限性，可能会出现短暂的功能故障，当离开当前特殊道路后，功能恢复。\\n\\n当进入和驶出弯道时，目标的选择有可能延迟或受到干扰。在这些情况下车辆将可能不按预期减速或延迟减速。\\n\\n在急转弯道路（如蛇行道路）上或道路弯道曲率过大时可能出现前车由于传感器视野限制在几秒钟内发生丢失，这可能导致车辆自动加速。\", \"chunk_id\": \"xia_p60_c101\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"驾驶辅助系统通用局限性\", \"page_number_end\": \"202\", \"context_chunk_ids\": [\"xia_p59_c100\", \"xia_p60_c101\", \"xia_p61_c102\"], \"page_number_start\": \"2014\"}, {\"score\": 0.03905341089370704, \"content\": \"[neighbor chunk_id=xia_p63_c105 page=204-205]\\n周围车辆和其他交通参与者的影响因素\\n\\n- ■ 被其他物体遮挡的行人。\\n- ■ 行人的典型轮廓无法与背景相互区别。\\n- 近距离非机动车包括但不限于二轮车、三轮车、自行车、摩托车等，其他近距离的小推车、婴儿车、购物车，小动物及行人（尤其是儿童）。\\n\\n- ☑ 异形车辆（例如工程车，大型板车，公路养护车，车外装载钢筋水泥管等物品的车辆等），侧翻车辆，尺寸严重异常车辆等。\\n- ■ 附近存在形状不规则的非典型目标物，如透明凳子、桌椅、水马、雪糕筒以及其他各类难以被系统识别的障碍物等。\\n- ■ 大片单一背景颜色过于接近的车辆等。\\n- 交通情况复杂，例如遇到突然快速出现并快速靠近自车的车辆，行人，骑行人，小动物或其他障碍物，或者车辆进出匝道，交叉路口，收费站等。\\n\\n[seed chunk_id=xia_p64_c106 page=205-205]\\n警告\\n\\n- 车辆发生剐蹭或碰撞后（含轻微碰撞）传感器可能发生位置变化或损坏，请勿使用驾驶辅助功能，可以联系比亚迪汽车授权服务店进行检修。\\n- ■ 出于安全考虑，请尽量不要在恶劣天气条件下或光照条件极差情况下使用辅助驾驶功能。\\n- ■ 出于安全考虑，请不要故意测试辅助驾驶功能，例如碰到紧急突发情况不采取行动，等待驾驶辅助功能触发等。\\n- 请详细阅读各个子功能使用说明，避免由于操作不当引发的功能退出或危险情况发生，例如在开启自动紧急制动功能时猛踩加速踏板时系统会优先响应加速请求而不触发紧急刹停。\\n- 由于系统限制，驾驶辅助系统可能在监测周围环境时产生不当告警或干预。驾驶辅助系统也可能因未正确理解驾驶员的操作而误告警，驾驶员应始终保持警惕。\\n- 由于系统限制，辅助驾驶系统目前无法准确检测和应对周围环境中的突发状况，驾驶员应始终保持警惕，必要时及时干预或控制车辆（例如减速，制动，转向等），确保驾驶安全。违反以上操作可能会引发事故，甚至导致人员伤亡。\\n\\n[neighbor chunk_id=xia_p64_c107 page=205-206]\\n注意\\n\\n根据《汽车雷达无线电管理暂行规定》对有关射电天文业务保护的有关规定，车辆不得在我国相关射电天文台的干扰保护距离内使用毫米波雷达。\\n\\n行车辅助\\n\\n自适应巡航(ACC)*\\n\\n自适应巡航(ACC)是在传统定速巡航的基础上，采用前置毫米波雷达或前视摄像头等传感器探测前方车辆与自车的相对距离和相对速度，根据驾驶员在使用时设定的跟车时距和目标巡航车速，控制自车行驶速度，以达到辅助驾驶员进行自适应巡航的目的。如果自车前方畅通，自车将保持设定的目标巡航速度向前行驶。如果检测到前方有车辆，自车将根据驾驶员设定的跟车时距调整车速，以跟随前车行驶。\\n\\n注意\\n\\n- ACC 功能默认开启且无法关闭，驾驶员激活 ACC 后可使用，可在中控屏→设置 →DiPilot→行车辅助中进行“ACC 功能设置项”设置。\\n- ■ ACC 功能仅能辅助驾驶员进行巡航控制，仍需要驾驶员主动操控方向盘，确保车辆行驶方向正确。\", \"chunk_id\": \"xia_p64_c106\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"205\", \"context_chunk_ids\": [\"xia_p63_c105\", \"xia_p64_c106\", \"xia_p64_c107\"], \"page_number_start\": \"205\"}, {\"score\": 0.0380952380952381, \"content\": \"[neighbor chunk_id=xia_p75_c123 page=216-216]\\n注意(续)\\n\\n- 在能见度较差、坡道及多弯路段，或在湿滑路面(例如冰雪、潮湿、或积水路段)上行驶时，切勿使用 ACC。\\n- 系统对道路限速的识别结果，易受道路环境的影响，从而道路限速值识别错误，用户需要时刻保持对当前道路限速的关注，以保证 ACC 巡航车速满足交通法规的要求。\\n- ■ 发生如下情况请务必前往比亚迪汽车授权服务店对前视摄像头进行专业校准与确认，包括但不限于：\\n- ● 拆卸前视摄像头、前风窗玻璃。\\n- - 因车轮跑偏，重新进行四轮定位后。\\n- - 车辆发生碰撞后。\\n- ● 察觉 ACC 性能下降或仪表提示系统异常。\\n\\n[seed chunk_id=xia_p75_c124 page=216-216]\\n车道巡航辅助(ICC)*\\n\\n- 车道巡航辅助(ICC)可以在 0~130km/h 辅助驾驶员速度范围内控制车辆沿当前车道行驶，主要适用于车道线清晰、路况良好的道路场景。使用 ICC 时，驾驶员需自行控制行车路线，功能激活运行时，驾驶员需要始终手握方向盘并在必要时人工主动控制车辆。\\n- ICC 通过雷达、摄像头等传感器检测车辆前方行驶环境，在此基础上辅助驾驶员控制车辆的行驶方向和速度，使车辆在 ACC 功能的基础上保持在当前车道内行驶。\\n- ICC 仅辅助驾驶员控制车辆沿当前车道行驶，不辅助控制车辆的导航路线。在用户使用 ICC 时，驾驶员需要始终手握方向盘，驾驶员应在需要调整行车路线时主动操控方向盘，并注意仪表屏提示、声音提示，做好随时主动控制车辆的准备，确保车辆正确、安全行驶。驾驶员双手离开方向盘超过规定时长会触发驾驶员运动脱离提醒。\\n\\n[neighbor chunk_id=xia_p75_c125 page=216-216]\\n表格：ICC 图标含义\\n\\n第1条：\\n图标：[°VBA]\\n显示状态：点亮\\n含义：ICC 可用,但未激活\\n说明：满足 ICC 条件时显示\\n\\n第2条：\\n图标：[°VBA]\\n显示状态：闪烁点亮\\n含义：ICC 已暂停(ICC 不再辅助驾驶员控制方向)ICC 已激活,正在使用中\\n说明：驾驶员干预方向盘时显示/\\n\\n第3条：\\n图标：[°VBA]\\n显示状态：闪烁\\n含义：ICC 已激活,驾驶员正在干预加速踏板\\n说明：驾驶员踩加速踏板时显示\", \"chunk_id\": \"xia_p75_c124\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"车道巡航辅助(ICC)*\", \"page_number_end\": \"216\", \"context_chunk_ids\": [\"xia_p75_c123\", \"xia_p75_c124\", \"xia_p75_c125\"], \"page_number_start\": \"216\"}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p91_c156 page=232-232]\\n警告\\n\\n- ■ 驾驶员应根据当地的交通法律法规和实际道路状况来设置目标车速和跟车时距，并在情况变化时及时调节，始终确保安全驾驶。\\n- 请驾驶员务必始终双手握住方向盘，并观察道路及周围环境，随时准备迅速控制车辆，采取纠正措施。\\n- ■ NOA 不能取代碰撞提醒、紧急制动等主动安全辅助功能。强烈建议驾驶员始终开启防撞制动等各项主动安全辅助功能。\\n- ■ 导航 App 提供的信息并非始终准确。请驾驶员务必时刻关注路况，当发现地图显示数据与现实情况不一致时及时主动控制车辆，确保安全驾驶。\\n- ■ 切勿过度依赖 NOA 对车辆进行充分减速来避免碰撞。\\n- 切勿过度依赖 NOA 来确定行驶路线（例如当车道超宽时，NOA 可能辅助驾驶员控制车辆在车道中央区域行驶，存在与对向车辆碰撞的风险）。驾驶员应根据交通和道路状况，及时调整行驶路线。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n[seed chunk_id=xia_p91_c157 page=232-233]\\n变道辅助\\n\\n变道辅助可以根据实时交通情况和导航路线辅助驾驶员控制车辆变道，从而快速、准确地到达目的地。常见的变道辅助场景包括：\\n\\n- ● 超车变道：因前车阻碍而无法在当前车道按目标车速行驶时发起的变道；\\n- - 导航变道：因导航要求在匝道口汇入或汇出、路口左/右转等场景时发起的变道；\\n- ● 避让变道：因本车道前方存在锥桶、施工工程车等静止障碍物而发起的变道等。\\n\\n满足变道辅助条件时，仪表屏会显示变道提醒（伴有提示音），车辆同时打开相应方向的转向灯。此时，驾驶员应检查盲区、车道线和周围环境，判断是否可以安全合规地驶入目标车道，进而确认或取消变道。车辆变道过程中，驾驶员应注意观察仪表屏提示、声音提示和周围环境，随时做好人工干预或控制车辆的准备，确保安全驾驶。变道辅助完成后，车辆会主动熄灭相应方向的转向灯。\\n\\n[neighbor chunk_id=xia_p92_c158 page=233-233]\\n取消变道\\n\\n若满足取消变道的条件，驾驶员可以择机取消变道，具体如下表所示。\", \"chunk_id\": \"xia_p91_c157\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"变道辅助\", \"page_number_end\": \"233\", \"context_chunk_ids\": [\"xia_p91_c156\", \"xia_p91_c157\", \"xia_p92_c158\"], \"page_number_start\": \"232\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p83_c139 page=224-224]\\n警告\\n\\n- ■ 拨杆变道是一项驾驶辅助功能，切勿在以下场景使用拨杆变道：\\n- ■ 结冰、湿滑或崎岖不平的道路；\\n- ■ 急转弯的连续弯路、新旧车道线交替或车道线磨损严重的道路；\\n- ■ 天气恶劣（例如大雨、大雪、浓雾等）。\\n- 驾驶员应有责任遵守当地交通法律法规，在开始变道前，务必检查盲区、车道线和周围环境，确认可以安全合规地驶入目标车道；在车辆变道过程中，注意观察仪表屏提示和周围环境，随时做好人工主动控制车辆的准备，确保安全驾驶。\\n- 车辆可能会错误识别车道线类型，务必在确认好车道线类型后再发起拨杆变道，避免违反交通规则。\\n- 如果变道时经过虚线变实线或实线变虚线的路段，车辆可能在接近虚实线交界处压到实线。\\n- ■ 拨杆变道可能因实时车流过于拥堵等原因而导致变道失败，也可能因车道线误检而导致变道错误。切勿过度依赖拨杆变道功能来确定行驶路线。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工主动控制车辆，确保安全驾驶。\\n\\n[seed chunk_id=xia_p83_c140 page=224-225]\\n注意\\n\\n- ■ 拨杆变道每次只能辅助驾驶员变换一条车道，不能连续变道。\\n- 除驾驶员主动取消外，变道过程也可能因旁车占道等原因受阻或取消，如果始终不满足变道条件，导致无法执行变道，则自车会在等待超时后取消变道；如果在执行变道的过程中，出现突发情况导致自车无法继续变道，则自车会尝试返回原车道。\\n\\n领航辅助(NOA)*\\n\\n领航辅助(NOA)是一项可以辅助驾驶员控制车辆沿导航路线行驶的组合驾驶辅助功能，适用于驾驶员在中控屏的导航 App 上设置好导航路线并已开启导航的场景。\\n\\n- NOA 通过毫米波雷达、摄像头等传感器检测车辆前方行驶环境并确定自车位置，在此基础上辅助驾驶员控制车辆在 NOA 可用路段上按照导航路线完成驾驶任务。\\n- 使用 NOA 时，驾驶员应始终保持手握方向盘，注意仪表显示屏和声音提示，做好随时干预或控制车辆的准备，确保车辆正确、安全行驶。驾驶员运动脱离超过规定时长会触发驾驶员运动脱离提醒，直至安全停车。\\n\\n[neighbor chunk_id=xia_p84_c141 page=225-225]\\ni 温馨提示\\n\\n- NOA 功能配置了语音播报提醒，驾驶员可通过中控屏→设置→DiPilot→行车辅助→驾驶辅助提示模式设置“简洁/详细”的语音播报模式。\\n- NOA 功能激活运行需使用车辆定位数据，驾驶员在开启车辆定位权限后，可通过中控屏→设置→DiPilot→行车辅助设置界面开启或关闭本功能。\\n- NOA 使用时，安全辅助中的车道偏离预警、车道保持辅助和红绿灯提醒等功能不生效（无论对应的功能开关是否开启）。\\n- NOA 使用时，车辆会在不满足 NOA 条件但满足 ICC/ACC 条件（例如驶离 NOA 可用路段、车辆偏航）时自动降级到 ICC/ACC，并可以在再次满足 NOA 条件时，主动升级到 NOA。\\n\\n高快领航(HNOA)适用于高速公路和城市快速路上的 NOA 路段。在设置好导航后行驶至功能覆盖的高速或城市快速路，驾驶员可主动激活功能，车辆会按照导航规划的路径辅助驾驶员完成车道保持、超车变道、导航变道、上/下匝道、进/出互通立交、进/出服务区等驾驶任务。（后续无特别说明，NOA 统一指高快领航辅助 HNOA）\", \"chunk_id\": \"xia_p83_c140\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"225\", \"context_chunk_ids\": [\"xia_p83_c139\", \"xia_p83_c140\", \"xia_p84_c141\"], \"page_number_start\": \"224\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=xia_p73_c121 page=214-215]\\n警告\\n\\n■ 自适应巡航功能仅作为一种驾驶辅助功能，注意事项仅包含常见影响自适应巡航功能的情况，除此之外可能还有其他因素也可能影响功能的性能。请驾驶员始终注意观察周边情况，并对驾驶安全负全部责任。\\n\\n警告(续)\\n\\n■ 请根据个人需求结合交通状况及道路环境自行决定是否使用自适应巡航功能。\\n\\n注意\\n\\n[seed chunk_id=xia_p73_c122 page=214-215]\\n- 当电子车身稳定系统没有开启的情况下 ACC 不能被激活。\\n- ACC 适合在高速公路和路况良好的道路上使用，不适合在复杂城市道路或者山路上使用。\\n- 与前车保持车距是驾驶员应有的责任。驾驶员设定的 ACC 跟车时距应符合当地驾驶环境中的最小车距要求。\\n- 在 ACC 工作时，如果驾驶员踩踏加速踏板或制动踏板，车辆将被驾驶员控制，此时驾驶员应注意保持与前车的安全距离。\\n- ■ 如果前车突然制动(紧急制动)，ACC 无法作出反应或对前车的反应过慢，从而导致制动过晚的风险。\\n- 在某些情况下(前车相对自车速度过慢，自车过快变道，或与前车安全距离过小等)，系统可能没有足够的时间来减小相对速度，系统无法在每种情况下都及时发出警告，在这种情况下驾驶员必须适当及时地作出反应。\\n- 在车辆静止情况下激活 ACC，系统会将车辆前方的静止障碍物识别为车辆并保持静止，目的是确保车辆的安全起步，避免不预期的起步导致与静止目标碰撞。但该功能并不能覆盖所有障碍物，因此驾驶员必须保证在车辆的正前方没有障碍物或者其他的交通参与者。\\n- 如果激活了 ACC 车辆与相邻车道距离过小(或者是相邻车道上的车辆太靠近自车所在车道)，有可能发生 ACC 对该车辆作出反应并制动。\\n- ■ 如果车辆变道到 ACC 车辆的路径中，且在前视摄像头的探测范围中，则将被识别成目标车辆，并且按照目标车辆进行反应，这有可能导致强力制动或较晚制动。\\n- 当 ACC 无法将前方车辆识别为目标车辆（无仪表上高亮目标），此时需驾驶员保持对车辆的控制。\\n- 当在跟随前车停止过程中，在极少数情况下，系统将不能识别前方车辆的尾部(例如有较高底盘的卡车后轴或者车辆的保险杠)。系统可能无法保证适当的跟车距离，驾驶员必须保持警惕并且随时准备制动。\\n- ■ 结构性改装车辆，例如，降低底盘高度可能影响 ACC。\\n\\n[neighbor chunk_id=xia_p75_c123 page=216-216]\\n注意(续)\\n\\n- 在能见度较差、坡道及多弯路段，或在湿滑路面(例如冰雪、潮湿、或积水路段)上行驶时，切勿使用 ACC。\\n- 系统对道路限速的识别结果，易受道路环境的影响，从而道路限速值识别错误，用户需要时刻保持对当前道路限速的关注，以保证 ACC 巡航车速满足交通法规的要求。\\n- ■ 发生如下情况请务必前往比亚迪汽车授权服务店对前视摄像头进行专业校准与确认，包括但不限于：\\n- ● 拆卸前视摄像头、前风窗玻璃。\\n- - 因车轮跑偏，重新进行四轮定位后。\\n- - 车辆发生碰撞后。\\n- ● 察觉 ACC 性能下降或仪表提示系统异常。\", \"chunk_id\": \"xia_p73_c122\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"215\", \"context_chunk_ids\": [\"xia_p73_c121\", \"xia_p73_c122\", \"xia_p75_c123\"], \"page_number_start\": \"214\"}, {\"score\": 0.016923076923076926, \"content\": \"[neighbor chunk_id=xia_p151_c263 page=292-292]\\n功能设置\\n\\n驾驶员可通过中控屏→设置→DiPilot→安全辅助→车道偏离辅助设置界面设置车道偏离辅助功能。车辆出厂功能默认关闭。车辆启动时，系统默认为上一次下电前的设置状态。\\n\\n- - 关闭：不开启任何车道偏离辅助功能。\\n- - 方向盘振动：仅开启车道偏离提醒功能，不会辅助转动方向盘。\\n- - 纠偏：仅开启车道偏离抑制功能，转动方向盘对车辆纠偏。\\n\\ni 温馨提示\\n\\n- 若驾驶员开启了转向灯且向转向灯方向进行变道，车道偏离辅助功能将被抑制。\\n- 若驾驶员持续压线行驶车道偏离辅助功能将被抑制。\\n- 车道偏离抑制功能激活过程中如果驾驶员此时大力踩下制动踏板、加速踏板或转动方向盘，功能会退出。\\n- 车辆任一车门或前舱盖、后背门未关闭或发生故障车道偏离辅助功能将被抑制。\\n- 摄像头的视野不能被物体遮挡，或强光干扰。视野短暂性的覆盖和强光干扰，功能会暂时退出，待视野正常后可自行恢复。若不能自行恢复，建议联系比亚迪汽车授权服务店处理。\\n- LDP 功能激活期间，驾驶员双手不能脱离方向盘，否则仪表会弹窗提示驾驶员控制车辆方向盘。文字提示根据驾驶员运动脱离频次有所不同，短时间首次脱离方向盘提示“请轻转方向盘”，二次脱离提示“请轻转方向盘”，三次脱离提示“请立即控制车辆”。\\n\\n[seed chunk_id=xia_p152_c264 page=293-293]\\ni 温馨提示(续)\\n\\n车道偏离辅助功能故障时，仪表显示故障图标和发出声音提示，并伴随文字提醒，此时车道偏离辅助功能不可用。请联系比亚迪汽车授权服务店。\\n\\n系统局限性\\n\\n- 车道偏离辅助功能是一项驾驶辅助功能，无法应对所有交通、天气、能见度、道路和车辆状况。\\n- 车道偏离辅助系统对车道线的检测容易受环境干扰，在下列情况下，系统可能会不起作用或性能显著下降，包括但不限于：\\n\\n- 前风窗玻璃脏污、起雾或前视摄像头前方有遮挡物。\\n- 由于阳光直射、路面积水反射、对向来车等造成眩光。\\n- - 环境亮度发生骤变，如进/出隧道。\\n- - 晴天阳光直射路面，车道线被树荫等干扰。\\n- - 下雪、下雨、有雾等造成的视线不佳。\\n- 车道线混乱，例如新旧标线重叠或车道线因道路施工临时调整。\\n- 车道线迅速变化，例如车道分叉、横穿或合并。\\n- 车道线不明显、过细、磨损、模糊或被污垢/积雪覆盖。\\n- ● 车道过窄，车道数增多或减少，短时变换标线，如匝道或高速公路出口，或者车道线穿行复杂时。\\n- - 行驶在陡坡或急弯道路上，与前车距离过近或前车遮挡了车道标线。\\n\\n系统可能因道路湿滑、自车侧向偏离速度过大等原因无法及时纠偏，例如：\\n\\n- ● 道路状况不佳，如洒水车作业后或雨雪后路面湿滑等。\\n- - 自车侧向偏离速度过大或过小。\\n- - 其他影响或降低车辆转向性能的情形。\\n\\n前视摄像头视野内风窗玻璃破裂，车辆挡风玻璃着色、增加不符合规范的涂层，仪表板上放置反射光线的物品，及任何影响前视摄像头视线的外加物品都有可能影响系统正常工作。\\n\\n[neighbor chunk_id=xia_p153_c265 page=294-294]\\n警告\\n\\n- ■ 为了驾驶员的驾驶安全，请不要自行测试车道偏离辅助功能。\\n- 切勿过度依赖车道偏离辅助功能，车道偏离提醒功能仅可发出车道偏离的预警信息，无法辅助控制车辆行驶方向。车道偏离抑制功能只会在车辆偏离车道时辅助纠正车辆回到原车道，无法持续辅助驾驶员控制车辆保持在车道中央区域行驶，切勿过度依赖车道偏离抑制功能来避免侧面碰撞。\\n- 车道偏离辅助功能仅作为一种驾驶辅助功能，局限性及注意事项仅包含常见影响车道偏离辅助功能的情况，许多因素都可能影响功能性能。请驾驶员始终观察周边情况，功能被抑制或退出时及时采取必要的措施控制车辆。驾驶员应对驾驶安全负全部责任。\\n- ■ 请根据个人需求结合交通状况及道路环境自行决定是否使用车道偏离辅助功能。\", \"chunk_id\": \"xia_p152_c264\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"293\", \"context_chunk_ids\": [\"xia_p151_c263\", \"xia_p152_c264\", \"xia_p153_c265\"], \"page_number_start\": \"293\"}, {\"score\": 0.013114754098360656, \"content\": \"[neighbor chunk_id=xia_p83_c140 page=224-225]\\n注意\\n\\n- ■ 拨杆变道每次只能辅助驾驶员变换一条车道，不能连续变道。\\n- 除驾驶员主动取消外，变道过程也可能因旁车占道等原因受阻或取消，如果始终不满足变道条件，导致无法执行变道，则自车会在等待超时后取消变道；如果在执行变道的过程中，出现突发情况导致自车无法继续变道，则自车会尝试返回原车道。\\n\\n领航辅助(NOA)*\\n\\n领航辅助(NOA)是一项可以辅助驾驶员控制车辆沿导航路线行驶的组合驾驶辅助功能，适用于驾驶员在中控屏的导航 App 上设置好导航路线并已开启导航的场景。\\n\\n- NOA 通过毫米波雷达、摄像头等传感器检测车辆前方行驶环境并确定自车位置，在此基础上辅助驾驶员控制车辆在 NOA 可用路段上按照导航路线完成驾驶任务。\\n- 使用 NOA 时，驾驶员应始终保持手握方向盘，注意仪表显示屏和声音提示，做好随时干预或控制车辆的准备，确保车辆正确、安全行驶。驾驶员运动脱离超过规定时长会触发驾驶员运动脱离提醒，直至安全停车。\\n\\n[seed chunk_id=xia_p84_c141 page=225-225]\\ni 温馨提示\\n\\n- NOA 功能配置了语音播报提醒，驾驶员可通过中控屏→设置→DiPilot→行车辅助→驾驶辅助提示模式设置“简洁/详细”的语音播报模式。\\n- NOA 功能激活运行需使用车辆定位数据，驾驶员在开启车辆定位权限后，可通过中控屏→设置→DiPilot→行车辅助设置界面开启或关闭本功能。\\n- NOA 使用时，安全辅助中的车道偏离预警、车道保持辅助和红绿灯提醒等功能不生效（无论对应的功能开关是否开启）。\\n- NOA 使用时，车辆会在不满足 NOA 条件但满足 ICC/ACC 条件（例如驶离 NOA 可用路段、车辆偏航）时自动降级到 ICC/ACC，并可以在再次满足 NOA 条件时，主动升级到 NOA。\\n\\n高快领航(HNOA)适用于高速公路和城市快速路上的 NOA 路段。在设置好导航后行驶至功能覆盖的高速或城市快速路，驾驶员可主动激活功能，车辆会按照导航规划的路径辅助驾驶员完成车道保持、超车变道、导航变道、上/下匝道、进/出互通立交、进/出服务区等驾驶任务。（后续无特别说明，NOA 统一指高快领航辅助 HNOA）\\n\\n[neighbor chunk_id=xia_p84_c142 page=225-225]\\n表格：功能状态\\n\\n第1条：\\n显示状态：点亮\\n含义：NOA 可用,但未激活\\n说明：满足 NOA 条件时显示\\n\\n第2条：\\n显示状态：闪烁\\n含义：NOA 不再辅助驾驶员减速\\n说明：驾驶员踩加速踏板时显示\\n\\n第3条：\\n显示状态：闪烁\\n含义：NOA 已暂停(NOA 不再辅助驾驶员控制车辆方向)\\n说明：驾驶员干预方向盘时显示\\n\\n第4条：\\n显示状态：点亮\\n含义：NOA 已激活,正在使用中\\n说明：-\\n\\n第5条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时目标限速\\n说明：-\\n\\n第6条：\\n图标：80MAX\\n显示状态：点亮\\n含义：NOA 的实时道路限速\\n说明：-\", \"chunk_id\": \"xia_p84_c141\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"225\", \"context_chunk_ids\": [\"xia_p83_c140\", \"xia_p84_c141\", \"xia_p84_c142\"], \"page_number_start\": \"225\"}, {\"score\": 0.012903225806451611, \"content\": \"[neighbor chunk_id=xia_p168_c290 page=309-309]\\n警告\\n\\n- 后方横向碰撞制动仅作为一种驾驶辅助功能，局限性仅包含常见影响后方横向碰撞制动的情况，许多因素都可能影响功能性能。请驾驶员始终观察周边情况，发现危险时及时采取必要的措施控制车辆。驾驶员对驾驶安全负全部责任。\\n- ■ 后方横向碰撞制动受天气和道路环境等若干因素影响可能会失效或制动不及时。\\n- 请根据个人需求结合交通状况及道路环境自行决定是否使用后方横向碰撞制动。\\n- ■ 由于系统性能限制，后方横向碰撞制动可能无法及时制动、漏制动或误制动。\\n\\n[seed chunk_id=xia_p168_c291 page=309-310]\\n驾驶辅助拓展功能\\n\\n路面预瞄系统*\\n\\n路面预瞄是一个检测车前方路面信息的感知系统，通过车前的摄像头实时监测识别路面情况，一旦发现坑洼、井盖和减速带时，就会提前调整主动悬架*状态来吸收路面激励，提高驾乘体验。\\n\\n使用方法\\n\\n用户可通过点击中控屏\\\\rightarrow应用中心\\\\square \\\\square \\\\rightarrow云辇 App*\\\\rightarrow悬架^*，选择开启或关闭路面预瞄功能。车辆出厂时系统默认为开启状态。在车辆重新上电后仍保持为开启状态。\\n\\n路面预瞄功能运行的前提条件(以下条件需同时满足)\\n\\n- 路面预瞄功能为开启状态。\\n- ■ 摄像头姿态正常且无遮挡及损坏。\\n- 车辆行驶在常规路面(如普通公路、高速公路和水泥路等)时。\\n- 光照及车速条件需满足以下三种情况：\\n\\n- - 白天光线充足且无强光、眩光干扰的情况下，车速在 0~100km/h。\\n- - 夜晚环境，路灯、车灯光线充足情况下，车速在 0~80km/h。\\n- - 特殊气候和环境下(如小到中雨、小雪或薄雾等)，车速在0~80km/h。\\n\\n[neighbor chunk_id=xia_p169_c292 page=310-310]\\n系统局限性\\n\\n根据不同的道路和交通状况，路面预瞄功能在以下场景可能无法实现预期功能，包括但不限于：\\n\\n- 夜间道路光线不充足时。\\n- - 环境条件过于恶劣(如：暴雨、暴雪、沙尘暴等)时。\\n- 摄像头有脏污、模糊不清、损坏或被遮挡时。\\n- 有强光、太阳直射或者剧烈变化的环境光线下。\\n- - 路面没有光学结构或没有反射光线。\\n- ● 驾驶时距离前车过近。\\n- 某段路面的转弯半径过小。\\n- ● 进行突然的驾驶操作，如急刹或突然加速。\\n\\n驾驶辅助节能功能*\\n\\n■ 驾驶辅助节能功能是指一键关闭驾驶辅助功能，仅保留全景影像（AVM）功能，使用该功能可一定程度上提升车辆续航表现。\", \"chunk_id\": \"xia_p168_c291\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"驾驶辅助拓展功能\", \"page_number_end\": \"310\", \"context_chunk_ids\": [\"xia_p168_c290\", \"xia_p168_c291\", \"xia_p169_c292\"], \"page_number_start\": \"309\"}, {\"score\": 0.012698412698412698, \"content\": \"[neighbor chunk_id=xia_p171_c295 page=312-312]\\n远光灯开启/关闭条件\\n\\n自动开启条件：\\n\\n- - 灯光处于自动挡。\\n- - 车速大于35 \\\\mathrm{~km} / \\\\mathrm{h}，且小于140 \\\\mathrm{~km} / \\\\mathrm{h}。\\n- - 车辆前方区域为黑暗环境。\\n\\n自动关闭条件：\\n\\n- - 白天/夜晚工况下，驾驶环境周围道路光源照明充足时会抑制远光灯。\\n- - 夜间工况，自车前方一定范围内有其他道路交通参与者时会抑制远光灯。\\n- - 夜间工况，若驾驶员开启转向灯时会抑制远光灯，转向灯关闭后，若满足激活条件，会重新开启远光灯。\\n\\n[seed chunk_id=xia_p171_c296 page=312-313]\\n警告\\n\\n■ 受限于多种环境因素和条件，自适应前照灯可能会错误的触发或失效。典型情况包括但不限于：\\n\\n- ● 大雾、大雨或大雪等极为不利于行车的气候条件下。\\n- ● 自身照明差的交通参与者(诸如行人、自行车)，道路附近的铁路或水路交通，以及有野生动物出没的路段。\\n\\n警告(续)\\n\\n- ● 有强烈反光景物的环境中(如高速公路上的交通标识牌、路面积水反光等)。\\n- ● 前风窗玻璃蒙有雾气、脏污或被标签、饰物等遮住的情况下。\\n\\n注意\\n\\n- 自适应前照灯系统是对灯光控制的辅助功能，但系统无法完全代替驾驶员，驾驶员应时刻按照道路法规要求，根据道路环境变化主动切换远近光灯。\\n- 当车辆发生碰撞事故或传感器被重新拆装时，建议联系比亚迪汽车授权服务店对传感器进行校准，避免影响系统的性能。\\n\\ni 温馨提示\\n\\n- ■ 系统功能异常或灯光系统故障会影响自适应前照灯功能。\\n- ■ 驾驶员手动开启远光灯会抑制自适应前照灯功能。\\n\\n[neighbor chunk_id=xia_p172_c297 page=313-314]\\n驾驶员监测辅助(DMS)*\\n\\n驾驶员监测辅助系统包含疲劳驾驶提醒、分心驾驶提醒、手持打电话提醒等功能，主要通过驾驶员监测辅助系统摄像头拍摄车内环境照片，在车辆本地对驾驶员驾驶状态进行监测和判断(原始照片将在判断完成后立即删除，不会保存或者上传服务器)，根据判断结果及时提醒驾驶员谨慎驾驶，注意行车安全。\\n\\n使用方法\\n\\n该功能使用的驾驶员监测辅助系统摄像头在主驾 A 柱位置。使用前请确认驾驶员监测辅助摄像头滑盖 * 已打开或者无遮挡。\\n\\n整车电源处于“OK”状态，用户可通过点击中控屏→设置→驾驶→座舱感知来设置驾驶员监测辅助的开启或关闭。\\n\\n如驾驶员监测辅助摄像头开启，驾驶员监测辅助按钮为“关闭”时，驾驶员监测辅助系统不会向驾驶员发送任何监测提醒。\", \"chunk_id\": \"xia_p171_c296\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"313\", \"context_chunk_ids\": [\"xia_p171_c295\", \"xia_p171_c296\", \"xia_p172_c297\"], \"page_number_start\": \"312\"}]',5,13924,1,NULL,'2026-06-22 21:41:10'),(24,1,NULL,NULL,NULL,'你这车子防水有什么功能？','根据提供的用户手册资料，手册中未专门介绍具体的“防水功能”配置，而是重点明确了**涉水使用界限、操作步骤及防水安全规范**。具体内容如下：\n\n**⚠️ 涉水驾驶操作规范**\n1. **确认水深**：驶入积水前必须查明深度，积水高度不得超过车身下边缘；**严禁**在积水超过轮胎一半的路面行驶。\n2. **正确通过**：起步前关闭空调，轻踩加速踏板且不要松脚（防止排气回压将水倒吸入发动机），以稳定缓慢的速度通过。\n3. **禁止行为**：切勿将车辆停在水中，也切不可在水中倒车或关闭发动机。\n\n**💧 涉水后处理与高压系统防水注意**\n- **恢复制动性能**：顺利通过积水区后，必须连续轻踩制动踏板数次，将制动盘上的水蒸发以恢复制动效果；随后应尽量避免紧急制动，小心驾驶。\n- **高压部件进水风险**：如车辆泡水或涉水超过门槛位置，可能导致高压零部件内部进水。晒干、风干等方式无法保证水分充分蒸发，可能引起绝缘性下降、内部短路等严重安全风险。\n- **质保说明**：发动机进水，或传动系统、行驶系统、电气系统等因涉水导致的故障与损坏，**将无法进行质保**。\n\n**📢 安全提醒**\n涉水行车涉及制动效能衰减与高压用电安全。驾驶时请严格遵守上述界限与操作要求。如需了解整车底盘密封等级、IP防护认证等具体技术参数，或车辆已遭遇涉水/泡水，请务必以车辆实际仪表提示为准，并立即联系比亚迪汽车授权服务店进行专业检测与处理。','xia.pdf','[{\"score\": 0.05195663670015865, \"content\": \"[neighbor chunk_id=xia_p37_c061 page=178-178]\\n车辆涉水\\n\\n- 驶入积水路段前必须查明积水深度，积水高度不得超过车身下边缘。\\n- 如需涉水行车，在车辆起步前将空调关掉，然后轻踩加速踏板且不要松脚，否则会造成排气回压将水倒吸入发动机而造成发动机的严重损坏，轻踩加速踏板以稳定而缓慢的速度通过积水路段。\\n\\n- 切勿将车辆停在水中，也切不可在水中倒车和关闭发动机。\\n- ■ 顺利涉水通过积水区后，必须连续轻踩制动踏板数次将制动盘上的水蒸发，以便尽快恢复正常的制动性能。\\n- ■ 驾驶经过深水时可能会弄湿制动器，应小心驾驶。\\n\\n[seed chunk_id=xia_p37_c062 page=178-179]\\n警告\\n\\n- 制动盘表面如有水、泥浆时可能导致制动器反应滞后，从而延长制动距离，谨防引发事故。\\n- ■ 驾驶经过积水路段后尽可能避免紧急制动。\\n- ■ 发动机切忌进水。若汽车在低洼积水路面行驶。请注意避免发动机进水，否则势必严重损坏发动机。由此导致的车辆故障及损坏，将无法进行质保。\\n- 车辆驾驶经过积水路段后，传动系统、行驶系统和汽车电气系统等汽车部件也可能严重受损。由此导致的车辆故障及损坏，也将无法进行质保。\\n- ■ 注意强对流天气下尽量选择有避雨条件的场所充电；如车辆泡水或涉水超过门槛位置，可能导致高压零部件内部进水，建议及时联系比亚迪汽车授权服务店进行妥善检测和处理。\\n- ■ 严禁在积水超过轮胎一半的路面行驶。\\n\\n高压零部件内部进水的影响：\\n\\n- 高压零部件属于电子器件，车辆泡水后对高压零部件进行晒干、风干等方式均无法保证水分充分蒸发。\\n- 高压零部件内部进水后对自身的绝缘性有很大的影响；同时，水分中含有较多导电物质，导电物质可能引起高压零部件内部短路或者使高压系统存在短路风险。在这种情况下，整车的安全性能和使用性能受到严重的影响。\\n- 高压零部件内部进水后对产品防护等级、耐压值等性能均有较大影响，存在较大的安全风险。\\n\\n[neighbor chunk_id=xia_p38_c063 page=179-180]\\n预防火灾\\n\\n为及时有效的预防车辆火灾，在使用中要注意以下事项：\\n\\n- ■ 禁止持续踩加速踏板使发动机高转速运转。\\n- 车内禁止存放易燃易爆物品。\\n\\n在炎热的夏季，停在阳光下的车辆内部温度可高达70^{\\\\circ} \\\\mathrm{C}以上，如车内存放有打火机、清洗剂、香水等易燃易爆物品，极易引起火灾甚至爆炸。\\n\\n■ 吸烟后要确认烟头已完全熄灭。\\n\\n● 吸烟，不但有害身体健康，还可能会引发火灾。如果烟头在没有完全熄灭的状态下，有可能会引起火灾。\\n\\n■ 建议定期联系比亚迪汽车授权服务店进行检查。\\n\\n- ● 定期检查发动机舱有无漏油现象，及时清理发动机上的油垢、油污等。\\n- - 对于全车线路也要定期检查，电器接插件和线束的连接、绝缘及固定位置等是否正常，如果发现问题应及时进行处理。\\n\\n■ 禁止改装车辆线路、不建议加装电器部件。\\n\\n- - 加装其他用电器(如大功率音响、灯具等)会造成线路负荷过大，线束容易发热造成火灾。电器、线路改装不规范，会产生接触电阻而异常发热引发火灾。\\n- - 严禁使用超出用电器额定规格的保险丝或其他金属丝代替保险丝。\\n\\n■ 正确选择停车位置。\\n\\n- ● 车辆在停放期间，尤其是在夏季，一定要注意车底是否有易燃物，比如干草、枯枝树叶或麦秆等，因车辆长时间行驶后三元催化器温度升高，如果车底有易燃物，很有可能引起火灾。\\n- ● 车辆在行驶过程中，也应尽量避开堆积有干树叶、麦秆、杂草等易燃物的路段，或在经过此类路段后及时停车检查车底是否挂有易燃物等。在停车时，也要尽量避开太阳曝晒的地方。\\n\\n- 车辆在维修或保养时，需断开低压蓄电池负极线。\\n- 车上要常备轻便的灭火器，并要掌握使用方法。\\n\\n为保证车辆安全，应在车上配备灭火器，并且要定期检查和更换。同时要熟悉灭火器的使用方法，做到有备无患，以免发生意外时束手无策。\\n\\n如果车辆发生火灾，应及时冷静的采取有效措施进行处理，最大限度的降低损失。\", \"chunk_id\": \"xia_p37_c062\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"179\", \"context_chunk_ids\": [\"xia_p37_c061\", \"xia_p37_c062\", \"xia_p38_c063\"], \"page_number_start\": \"178\"}, {\"score\": 0.03114754098360656, \"content\": \"[neighbor chunk_id=xia_p36_c060 page=177-177]\\n警告\\n\\n在车里堆满儿童玩具存在安全隐患，特别是在出现紧急制动或碰撞等情况时，这不仅会影响行车安全，还可能对孩子造成伤害。\\n\\n在后备箱内运载行李\\n\\n- ■ 将行李均匀地放置在后备箱地板上，将最重的行李放在底部并尽可能往前放。\\n- 用绳子或锁链将物品固定好，使其不会在驾驶过程中移动。请勿使堆积的物品高于前排座椅的椅背。\\n\\n一氧化碳中毒的危险性\\n\\n- ■ 发动机排气中含有一氧化碳气体。如果您正确保养车辆，在正常驾驶中，一氧化碳不会进入车内。\\n- 在下列几种情况下，应检查排气系统是否泄漏：\\n\\n- 排气声音有异常。\\n\\n- 车辆经受过可能损坏车辆底部的事故。\\n\\n警告\\n\\n- ■ 一氧化碳气体有毒。吸入该气体会导致丧失知觉甚至危及生命。应避开任何会导致一氧化碳中毒的封闭环境及活动。\\n- 高浓度的一氧化碳气体会迅速集中在封闭的区域，例如在车库里，不要在车库门关闭时起动发动机。即使车库的门是开着的，发动机的运转时间亦应被控制在能将车辆开出车库的时间为限。\\n- ■ 当后背门打开时，气流会将排出的废气带入车内，造成危险的环境。如必须在后背门打开的情况下发动车辆，应将所有车窗打开，并按照下列提示，调节车内空气环境控制系统：\\n\\n- - 选择“外循环”模式。\\n- - 选择“吹面吹脚”模式。\\n- - 风扇速度设定在“高转速”。\\n\\n[seed chunk_id=xia_p37_c061 page=178-178]\\n车辆涉水\\n\\n- 驶入积水路段前必须查明积水深度，积水高度不得超过车身下边缘。\\n- 如需涉水行车，在车辆起步前将空调关掉，然后轻踩加速踏板且不要松脚，否则会造成排气回压将水倒吸入发动机而造成发动机的严重损坏，轻踩加速踏板以稳定而缓慢的速度通过积水路段。\\n\\n- 切勿将车辆停在水中，也切不可在水中倒车和关闭发动机。\\n- ■ 顺利涉水通过积水区后，必须连续轻踩制动踏板数次将制动盘上的水蒸发，以便尽快恢复正常的制动性能。\\n- ■ 驾驶经过深水时可能会弄湿制动器，应小心驾驶。\\n\\n[neighbor chunk_id=xia_p37_c062 page=178-179]\\n警告\\n\\n- 制动盘表面如有水、泥浆时可能导致制动器反应滞后，从而延长制动距离，谨防引发事故。\\n- ■ 驾驶经过积水路段后尽可能避免紧急制动。\\n- ■ 发动机切忌进水。若汽车在低洼积水路面行驶。请注意避免发动机进水，否则势必严重损坏发动机。由此导致的车辆故障及损坏，将无法进行质保。\\n- 车辆驾驶经过积水路段后，传动系统、行驶系统和汽车电气系统等汽车部件也可能严重受损。由此导致的车辆故障及损坏，也将无法进行质保。\\n- ■ 注意强对流天气下尽量选择有避雨条件的场所充电；如车辆泡水或涉水超过门槛位置，可能导致高压零部件内部进水，建议及时联系比亚迪汽车授权服务店进行妥善检测和处理。\\n- ■ 严禁在积水超过轮胎一半的路面行驶。\\n\\n高压零部件内部进水的影响：\\n\\n- 高压零部件属于电子器件，车辆泡水后对高压零部件进行晒干、风干等方式均无法保证水分充分蒸发。\\n- 高压零部件内部进水后对自身的绝缘性有很大的影响；同时，水分中含有较多导电物质，导电物质可能引起高压零部件内部短路或者使高压系统存在短路风险。在这种情况下，整车的安全性能和使用性能受到严重的影响。\\n- 高压零部件内部进水后对产品防护等级、耐压值等性能均有较大影响，存在较大的安全风险。\", \"chunk_id\": \"xia_p37_c061\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"车辆涉水\", \"page_number_end\": \"178\", \"context_chunk_ids\": [\"xia_p36_c060\", \"xia_p37_c061\", \"xia_p37_c062\"], \"page_number_start\": \"178\"}, {\"score\": 0.02996031746031746, \"content\": \"[seed chunk_id=xia_p0_c001 page=141-141]\\n使用和驾驶\\n\\n4\\n\\n4-1 充/放电说明.... 143\\n\\n充电说明....143\\n\\n充电方法....148\\n\\n放电说明*...... 156\\n\\n电量平衡功能.... 161\\n\\n续航里程显示.... 163\\n\\n充电口电锁控制....164\\n\\n4-2 电池.....166\\n\\n动力电池....166\\n\\n低压蓄电池....168\\n\\n4-3 使用要领.....170\\n\\n磨合期.... 170\\n\\n挂车拖曳....170\\n\\n安全驾驶注意事项……170\\n\\n用车建议....171\\n\\n燃油....172\\n\\n如何节省燃油并延长车辆的使用\\n\\n寿命....174\\n\\n运载行李....176\\n\\n一氧化碳中毒的危险性……177\\n\\n车辆涉水....178\\n\\n预防火灾....179\\n\\n4-4 启动和驾驶..... 181\\n\\n启动车辆....181\\n\\n驾驶车辆....183\\n\\n低油耗驾驶车辆....184\\n\\n云辇-C^{*}186\\n\\n[neighbor chunk_id=xia_p1_c002 page=142-142]\\n4 使用和驾驶\\n\\n换挡操纵机构.... 186\\n\\n电子驻车(EPB)...... 187\\n\\n自动驻车(AVH)....191\\n\\n驾驶要领....193\\n\\n4-5 驾驶辅助功能......197\\n\\n驾驶辅助系统简介……197\\n\\n行车辅助....206\\n\\n泊车辅助....247\\n\\n前向安全辅助…… 275\\n\\n侧向安全辅助.... 291\\n\\n后向安全辅助…… 302\\n\\n驾驶辅助拓展功能……309\\n\\n灯光系统....311\\n\\n驾驶员监测辅助(DMS)*..313\\n\\n胎压监测....316\\n\\n低速提示音(AVAS)......318\\n\\n儿童遗留检测(CPD)*......319\\n\\n驾驶安全系统…… 321\", \"chunk_id\": \"xia_p0_c001\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"使用和驾驶\", \"page_number_end\": \"141\", \"context_chunk_ids\": [\"xia_p0_c001\", \"xia_p1_c002\"], \"page_number_start\": \"141\"}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=xia_p119_c211 page=260-263]\\n系统局限性\\n\\n在使用泊车辅助功能前，请确保满足以下条件：\\n\\n- 车辆未开启行车辅助功能。\\n\\n- ● 车辆车门、前舱盖、后备箱均已关闭，后视镜处于展开（窄车位泊出场景除外）状态，且车辆未在充电。\\n- - 坡度小于5^{\\\\circ}。\\n- ● 驾驶员处于驾驶位，且驾驶员视线避免离开泊车范围。\\n- - 超声波传感器和摄像头功能正常。\\n- 泊车辅助功能无故障，车辆其他执行器无故障。\\n- ● 车辆处于普通的驾驶模式（经济、舒适、运动）未在运输、洗车模式或其他特殊驾驶场景。\\n\\n传感器可能无法识别以下障碍物，请驾驶员注意观察周围环境，及时控制车辆，包括但不限于：\\n\\n- - 能见度差，如恶劣天气（大雨、大雪、浓雾、重霾、沙尘暴等），周边环境视野差（车辆排出的尾气、溅起的水花、雪花、车辆扬尘等）。\\n- ● 周围环境昏暗，如黎明、黄昏、夜晚或光线不足的停车场。\\n- - 强光，如摄像头被太阳直射或斜射、被对向或尾随车辆的前照灯灯光干扰等。\\n- - 温度极高或极低。\\n- - 附近存在有同频干扰源的设备或者噪声。\\n- - 电磁干扰，电子产品与物理钥匙接触，电磁干扰导致蓝牙、射频等信号无法传递。\\n\\n泊车辅助在遇到车辆传感器状态异常及车辆结构异常时，无法正常使用，驾驶员需注意车辆状态，包括但不限于：\\n\\n超声波雷达、组合定位或摄像头未校准、损坏、表面覆盖有异物（如冰雪、水、霜、泥浆、灰尘等物体覆盖）或者工作状态异常时。\\n\\n● 车辆过于靠近前方车辆，导致摄像头视野被遮挡。\\n\\n- 车辆外后视镜未处于正确展开状态。\\n\\n● 车辆因发生剐蹭、碰撞等而导致车辆传感器异常或者车辆结构异常。特别是保险杠、前挡风玻璃、外后视镜、蒙皮（如翼子板、后尾门）、车架等因车辆碰撞或其他原因变形或损坏，导致传感器安装位置变化。\\n\\n- 使用泊车辅助功能前，轮胎气压与轮胎尺寸不满足规格要求（如使用尺寸偏小的备胎、轮胎气压过低等），会影响泊车辅助性能。\\n\\n[seed chunk_id=xia_p119_c212 page=260-263]\\n- - 改装车辆可能会导致泊车辅助受影响，容易在泊车过程中发生刮碰或碰撞。如车身存在附着物、改装件导致阻碍和干扰，像安装自行车架、门踏板、较大的车牌框、重新喷漆导致的车漆过厚、粘贴遮挡超声波雷达或摄像头的贴膜、或在车身上粘贴胶带、贴纸、橡胶涂料等。\\n- - 如果装有挂车钩或装载的物体从车辆周围突出，请勿使用泊车辅助功能。\\n\\n泊车辅助在遇到下面车位场景时，无法正常使用，驾驶员需时刻注意周围环境，包括但不限于：\\n\\n- - 不具备必要的操纵空间的狭窄停车位。\\n- ● 车位附近有透明度较高的玻璃墙或门。\\n- 机械车位。\\n\\n- 道路情况复杂，如陡坡、急弯、连续弯道、蜿蜒小路、窄路、越野路、崎岖道路或带沟槽、凹坑（如消防井等）的道路、一侧有向下的台阶或悬崖的道路、凸起路肩、超宽车道、施工区域（例如布置了锥桶的区域）或者车辆进出匝道、交叉路口、闸机等。 - 道路情况不佳，如路面湿滑或松软（路面积水、结冰、积雪或烂泥路、石子路、沙土路等）、车道线或道路标志不清晰、破损等。\\n\\n泊车辅助可能无法识别以下障碍物或及时应对复杂情况，驾驶员需时刻注意车辆周围环境，及时踩下刹车控制车辆，包括但不限于：\\n\\n- ● 道路情况复杂，如陡坡、急弯、连续弯道、蜿蜒小路、窄路、越野路、崎岖道路或带沟槽、凹坑（如消防井等）的道路、一侧有向下的台阶或悬崖的道路、凸起路肩、超宽车道、施工区域（例如布置了锥桶的区域）或者车辆进出匝道、交叉路口、闸机等。\\n- ● 道路情况不佳，如路面湿滑或松软（路面积水、结冰、积雪或烂泥路、石子路、沙土路等）、车道线或道路标志不清晰、破损等。\\n\\n泊车辅助可能无法识别以下障碍物或及时应对复杂情况，驾驶员需时刻注意车辆周围环境，及时控制车辆，包括但不限于：\\n\\n[neighbor chunk_id=xia_p119_c213 page=260-263]\\n- - 交通情况复杂，如遇突然快速出现并快速靠近自车的车辆、自行车、行人、小动物或其他障碍物。\\n- ● 紧贴车位的障碍物，例如处于感知盲区的方柱、紧贴车位或部分侵入车位的铁门、破损不完整的墙体等。\\n- - 狭窄车位，如狭窄道路、墙角处、拐角处、极限小车位。\\n- ● 车位内侧存在立柱、立柱靠近泊车路径。\\n\\n- - 附近存在悬空类障碍物，如悬空箱式大车、消防箱、消防阀、消防栓、充电箱、外卖箱、车辆后方或者前方外凸拖车钩、车辆后备胎、空调外机、悬空广告牌、悬空（倾斜或笔直）的水管、悬空墙壁/横梁、墙面上有突出的墙块、悬空阳台、消防门上的悬空锁、消防类器材上的悬空开关旋钮尖角、打开的车门、半开的上卷式车门等。\\n- - 附近存在低矮和细小障碍物，如低矮的石头、灌木丛、花台、花坛、石墩、石板凳、石狮子、矮墙（40cm以下）、窄墙、细杆、细小立柱、铁丝、铁丝网篱笆、卷闸门、牵引杆、纸箱、打开的地锁、限位块或其他无法正常反射雷达探测波的物体。\\n- ● 附近有下行台阶、凸起路肩、凹坑、凹陷水槽或其他地面不平。\\n- - 附近存尖锐的障碍物，如直角柱子、多棱柱、墙尖角、悬挂及落地消防箱、落地充电箱等。\\n- ● 附近及车位上方存在高度变化，易剐蹭碰撞顶部，如通风管道、倾斜顶棚等。\\n- ● 附近存在具备特殊表面和结构的物品，如海绵、泡沫等，或者表面反光的物体，如玻璃、地面积水、反光的地坪漆车位等。\\n- - 附近有近距离非机动车包括但不限于二轮车、三轮车、自行车、摩托车等，其他近距离的小推车、婴儿车、购物车，小动物及行人（尤其是儿童）。\\n- ● 附近存在形状不规则的非典型目标物，如大型板车、公路养护车、与大片单一背景色颜色过于接近的车辆、透明凳子、桌椅、水马、雪糕筒以及其他各类难以被系统识别的障碍物等，均需要额外注意。\", \"chunk_id\": \"xia_p119_c212\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"系统局限性\", \"page_number_end\": \"263\", \"context_chunk_ids\": [\"xia_p119_c211\", \"xia_p119_c212\", \"xia_p119_c213\"], \"page_number_start\": \"260\"}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=xia_p181_c311 page=322-322]\\n车身动态控制系统(VDC)\\n\\n在车辆行驶过程中突然转向时，VDC 系统根据转向盘转角和车速等信息确定驾驶员的驾驶意图，并持续与车辆实际状况进行对比，如果车辆出现偏离正常行驶路线情况，VDC 将通过对相应的车轮施加制动进行修正，以帮助驾驶员控制侧滑，保持车辆的方向稳定性。\\n\\n牵引力控制系统(TCS)\\n\\nTCS 通过降低发动机功率防止车辆的驱动轮在加速行驶时打滑，必要时施加制动力控制，以防止驱动轮空转。在不利的行驶条件下 TCS 可使车辆易于起步、加速和爬坡。\\n\\n[seed chunk_id=xia_p181_c312 page=322-323]\\n警告\\n\\n■ 下列情况下，TCS 可能无法有效工作：\\n\\n- - 在湿滑路面上行驶时，即使 TCS 系统正常工作，也可能无法控制方向和达到动力要求。\\n- - 请勿在可能失去稳定性和动力的状况下驾驶车辆。\\n\\n坡起辅助系统(HHC)\\n\\n在松开制动踏板后，HHC 能保持驾驶员所施加的制动压力 1s 时间，防止车辆后溜。\\n\\n液压制动辅助系统(HBA)\\n\\n驾驶员快速踩下制动踏板时，HBA 能识别出车辆处于紧急状态，迅速将制动压力提高至最大值，从而使 ABS 更迅速介入，有效地缩短制动距离。\\n\\n减速度控制系统(CDP)\\n\\n开启电子驻车时，CDP 功能开始工作，车辆会以恒定的减速度(只拉起电子驻车开关不踩制动时减速度为 0.4g，在拉起电子驻车开关同时踩下制动踏板时减速度为 0.8g)制动，直至车辆停止，如果驾驶员松开电子驻车开关，CDP 功能就会停止工作。\\n\\n[neighbor chunk_id=xia_p182_c313 page=323-323]\\n陡坡缓降系统(HDC)\\n\\n工作原理：HDC 是一项改善汽车舒适性的 ESC 系统增值功能。HDC 功能可以通过点击中控屏→设置 →驾驶→智能辅助→陡坡缓降按键选择开启或关闭。HDC 的主要作用是通过主动制动的方式帮助驾驶员以低速上下坡。在 HDC 工作期间，当车轮滑移率超过 ABS 触发门限时，ABS 就会激活。能让驾驶员能安全而平稳下坡，甚至倒车。\\n\\n■ 打开 HDC:\\n\\n在车速低于 38km/h 的情况下，可以通过点击中控触摸屏“陡坡缓降”打开功能，打开时，仪表的 HDC 功能状态指示灯会常亮。\\n\\nHDC 车速的控制：\\n\\n- HDC 功能约在 11~38km/h 车速范围内起作用，在此范围内时，您可以通过踩下/松开加速踏板或制动踏板调整车速，会以加速踏板、制动踏板松开时的为准。HDC 正在工作时，仪表的 HDC 状态指示灯闪烁代表 HDC 工作正在起作用。\\n\\n关闭 HDC:\\n\\n- 如无需使用 HDC 功能时，可再次点击中控触摸屏“陡坡缓降”关闭，此时仪表的指示灯随即熄灭。\\n- - 当车速超过约 65km/h 时，HDC 也会自动停用。\\n\\nHDC 功能故障:\\n\\n- - 在下长坡等一些特殊工况下，HDC 功能会因制动器温度过高而暂时不可使用。\\n- - 此时仪表会提示“请检查 HDC 系统”，您需要注意安全驾驶。如需要恢复功能，需要停车待制动器温度冷却。\", \"chunk_id\": \"xia_p181_c312\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"323\", \"context_chunk_ids\": [\"xia_p181_c311\", \"xia_p181_c312\", \"xia_p182_c313\"], \"page_number_start\": \"322\"}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p168_c290 page=309-309]\\n警告\\n\\n- 后方横向碰撞制动仅作为一种驾驶辅助功能，局限性仅包含常见影响后方横向碰撞制动的情况，许多因素都可能影响功能性能。请驾驶员始终观察周边情况，发现危险时及时采取必要的措施控制车辆。驾驶员对驾驶安全负全部责任。\\n- ■ 后方横向碰撞制动受天气和道路环境等若干因素影响可能会失效或制动不及时。\\n- 请根据个人需求结合交通状况及道路环境自行决定是否使用后方横向碰撞制动。\\n- ■ 由于系统性能限制，后方横向碰撞制动可能无法及时制动、漏制动或误制动。\\n\\n[seed chunk_id=xia_p168_c291 page=309-310]\\n驾驶辅助拓展功能\\n\\n路面预瞄系统*\\n\\n路面预瞄是一个检测车前方路面信息的感知系统，通过车前的摄像头实时监测识别路面情况，一旦发现坑洼、井盖和减速带时，就会提前调整主动悬架*状态来吸收路面激励，提高驾乘体验。\\n\\n使用方法\\n\\n用户可通过点击中控屏\\\\rightarrow应用中心\\\\square \\\\square \\\\rightarrow云辇 App*\\\\rightarrow悬架^*，选择开启或关闭路面预瞄功能。车辆出厂时系统默认为开启状态。在车辆重新上电后仍保持为开启状态。\\n\\n路面预瞄功能运行的前提条件(以下条件需同时满足)\\n\\n- 路面预瞄功能为开启状态。\\n- ■ 摄像头姿态正常且无遮挡及损坏。\\n- 车辆行驶在常规路面(如普通公路、高速公路和水泥路等)时。\\n- 光照及车速条件需满足以下三种情况：\\n\\n- - 白天光线充足且无强光、眩光干扰的情况下，车速在 0~100km/h。\\n- - 夜晚环境，路灯、车灯光线充足情况下，车速在 0~80km/h。\\n- - 特殊气候和环境下(如小到中雨、小雪或薄雾等)，车速在0~80km/h。\\n\\n[neighbor chunk_id=xia_p169_c292 page=310-310]\\n系统局限性\\n\\n根据不同的道路和交通状况，路面预瞄功能在以下场景可能无法实现预期功能，包括但不限于：\\n\\n- 夜间道路光线不充足时。\\n- - 环境条件过于恶劣(如：暴雨、暴雪、沙尘暴等)时。\\n- 摄像头有脏污、模糊不清、损坏或被遮挡时。\\n- 有强光、太阳直射或者剧烈变化的环境光线下。\\n- - 路面没有光学结构或没有反射光线。\\n- ● 驾驶时距离前车过近。\\n- 某段路面的转弯半径过小。\\n- ● 进行突然的驾驶操作，如急刹或突然加速。\\n\\n驾驶辅助节能功能*\\n\\n■ 驾驶辅助节能功能是指一键关闭驾驶辅助功能，仅保留全景影像（AVM）功能，使用该功能可一定程度上提升车辆续航表现。\", \"chunk_id\": \"xia_p168_c291\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"驾驶辅助拓展功能\", \"page_number_end\": \"310\", \"context_chunk_ids\": [\"xia_p168_c290\", \"xia_p168_c291\", \"xia_p169_c292\"], \"page_number_start\": \"309\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p44_c073 page=185-186]\\n正确使用空调系统\\n\\n● 加热和制冷过程是非常耗能的，会明显减少续驶里程和增大耗油量，合理的使用空调系统能有效的降低耗电量和耗油量。\\n\\n关闭暂时不需要的功能\\n\\n- 车内加热装置会消耗大量电能(例如座椅加热*等)，当不需要这些功能时，应将其关闭。\\n\\n温馨提示\\n\\n- ■ 磨合期间，车辆不要大负荷运行，车速不能超过最高车速。\\n- 有加速需求时建议缓加油门，减少急加油门对车辆带来的损耗。\\n\\n云辇-C*\\n\\n云辇-C 系统是一种电控减振器悬架系统，云辇-C 系统通过控制电控减振器阻尼力调节乘坐舒适性和操作稳定性。用户可通过点击中控屏→应用中心→云辇 App，进入云辇模式设置界面，选择“舒适”/“运动”模式设置项。\\n\\n[seed chunk_id=xia_p45_c074 page=186-187]\\n舒适控制\\n\\n- 舒适控制功能：车辆加速和减速时由于载荷转移产生俯仰动作，通过对车辆电控悬架阻尼和制动末端压力协调融合控制抑制车辆俯仰，提高乘坐舒适性。\\n- 用户可通过点击中控屏→应用中心→云辇 App，进入舒适控制设置界面，选择“偏弱”/“适中”/“较强”模式设置项。\\n\\n注意\\n\\n车辆在紧急制动情况下，功能效果可能会降低。\\n\\n换挡操纵机构\\n\\n- 换挡操纵机构挡位标示在换挡手柄上，上下拨动手柄进行“R”、“N”、“D”挡切换，按下右侧按键切换至“P”挡。\\n- 启动车辆后，踩下制动踏板并向上或向下拨动换挡手柄，即可从“P”挡切换至其他挡位。\\n- “P”挡是驻车挡，按下“P”挡按键，可实现驻车。\\n\\n警告\\n\\n■ 按下“P”挡按键时，为了避免造成伤害，必须在车辆完全停止后再按下“P”挡按键。\\n\\n- “R”挡是倒车挡，必须在车辆完全停止后方可使用。\\n- “N”挡是空挡，作为临时停车时使用。无论出于什么原因，只要离开车辆，须切换至驻车挡。\\n- “D”挡是行车挡，正常行驶时使用此挡位。\\n- 换挡成功后，手松开，换挡杆自动回到中间位置。\\n- 必须在电源“OK”挡下才能将挡位切换至行驶挡。\\n- - 挂出“P”挡或切换至行驶挡位需要同时踩制动，详细操作可参考仪表提示。\\n\\n[neighbor chunk_id=xia_p46_c075 page=187-187]\\n警告\\n\\n- 如关闭电机并切换至“N”挡后仍让车辆长时间移动，变速箱可能因无法得到润滑而严重受损。\\n- 如发动机或电机运转且已切换至“R”/“D”挡时，务必踩住制动踏板停止车辆，因为即使在怠速工况下，传动器仍可传递动力，车辆可能缓慢前行。\\n- 车辆行驶时如换挡，切勿踩加速踏板，谨防发生事故。\\n- 车辆行驶中切勿将换挡手柄切换至“R”挡或按下“P”挡按键，谨防发生事故。\\n- ■ 请勿在“N”或“P”挡时，将车辆沿斜坡下行。\\n- 为了防止车辆无意间移动，车辆停稳后请按下“P”挡按键，“P”挡切换成功后如电子驻车指示灯未点亮，则需要通过中控屏手动拉起电子驻车，以确保车辆安全。\", \"chunk_id\": \"xia_p45_c074\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"舒适控制\", \"page_number_end\": \"187\", \"context_chunk_ids\": [\"xia_p44_c073\", \"xia_p45_c074\", \"xia_p46_c075\"], \"page_number_start\": \"186\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=xia_p53_c088 page=194-1954]\\n温馨提示\\n\\n如整车电量低，可使用原地发电功能，建议您参考充电说明章节。\\n\\n冬季驾驶要领\\n\\n确认冷却液具有正确的防冻保护作用。\\n\\n- - 使用与原车型号相同的冷却液，根据环境温度选择合适的冷却液型号加注到冷却系统中。\\n- - 使用不适当的冷却液将损坏冷却系统。\\n\\n检查电池和电缆状况。\\n\\n- 寒冷的天气会使低压蓄电池的能量降低，因此，低压蓄电池应保持有充分的电量以用于冬季启动。\\n\\n确认机油的粘度适合冬季驾驶。\\n\\n避免冰雪冻结车门锁。\\n\\n在车门锁孔内，喷入一些除冰剂或甘油，以防结冰。\\n\\n使用含有抗冻剂的洗涤液。\\n\\n- 这类产品在比亚迪汽车授权服务店和所有的汽车零件店，均有供应。\\n- 水和抗冻剂的混合比率要符合厂商的说明。\\n\\n[seed chunk_id=xia_p54_c089 page=1954-1954]\\n注意\\n\\n■ 为防止车辆漆面的损伤，请使用专用洗涤液。\\n\\n避免挡泥板的下方积有冰雪。\\n\\n- 挡泥板的下方积有冰雪，会造成转向困难。在严寒的冬季驾驶时，应时常停车，检查挡泥板下是否积有冰雪。\\n\\n根据行驶路况的不同，建议携带若干必要的紧急用具或物品。\\n\\n● 防滑链、车窗刮刀、一袋沙或盐、信号闪光装置、小铲、连接电缆等物品最好能放在车中。\\n\\n冬季轮胎\\n\\n冬季轮胎在积雪路面上具有较好的抓地力。特殊的橡胶胎面设计使轮胎受低温环境的影响较小，并提供优异的制动性能，从而提高驾驶安全性。\\n\\n[neighbor chunk_id=xia_p54_c090 page=1954-1954]\\n使用建议\\n\\n- 建议车辆在冰雪路面行驶、温度低于7^{\\\\circ}C 时使用冬季轮胎。当温度上升到7^{\\\\circ}C 时，应迅速更换为夏季轮胎或四季轮胎，以保证行车安全和性能。\\n- 使用冬季轮胎时，应选用与车辆原厂设计相同的轮胎规格、负荷等级、速度等级。\\n- 冬季轮胎要有足够的花纹深度。花纹深度不能低于 4mm，否则在冬季的适用性会受限制。\\n- 冬季轮胎与夏季轮胎是为相应季节的特定加速条件而设计的，建议在对应的季节使用，否则可能会导致轮胎附着力差、制动能力差等。\\n- ■ 冬季轮胎的最大速度相对较低，所以不要超过最大速度。\\n- ■ 冬季轮胎安装后，需按设计胎压进行胎压检测。\", \"chunk_id\": \"xia_p54_c089\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"1954\", \"context_chunk_ids\": [\"xia_p53_c088\", \"xia_p54_c089\", \"xia_p54_c090\"], \"page_number_start\": \"1954\"}, {\"score\": 0.016923076923076926, \"content\": \"[neighbor chunk_id=xia_p51_c084 page=192-193]\\n自动驻车(AVH)功能退出\\n\\n当自动驻车(AVH)功能正常运行时，若驾驶员进行以下操作，会导致车辆退出自动驻车功能，从“D”挡自动切换为“P”挡：\\n\\n- - 打开主驾车门。\\n- - 解锁驾驶员安全带。\\n- - 停车时车辆处于“D”挡，激活 EPB。\\n- - 制动踏板松开时，点击自动驻车(AVH)开关，关闭自动驻车(AVH)功能。\\n\\n自动驻车(AVH)功能抑制\\n\\n- ☑ 切换“R”挡进入低速挪车工况，此时自动驻车(AVH)功能进入挪车工况状态。在“R”挡低速倒车，或由“R”挡切换“D”挡低速行驶，自动驻车(AVH)都处于无法激活状态，维持待命，以便于挪车操作。\\n- ■ 进入挪车工况后，通过点击自动驻车(AVH)开关，或控制车速超过10km/h，即可退出挪车工况。此时自动驻车(AVH)功能处于待命状态，可以正常激活。\\n\\n[seed chunk_id=xia_p52_c085 page=193-193]\\n驾驶要领\\n\\n- 在逆风中应缓慢行驶，这样便于控制车辆。\\n- 在有镶边石道路行驶时，应缓慢行驶，并尽可能保持正确的角度。避免在具有高而尖锐边缘的物体上或其他道路障碍物上行驶。否则将导致轮胎严重损坏。\\n- 在经过颠簸路面或在坎坷不平的道路上行驶时要减慢车速。否则，冲击将严重损坏车轮。\\n- 清洗车辆或驾驶经过深水将弄湿制动器。检查它们是否被弄湿时，先要确认周围是否安全，然后轻轻地踩制动踏板。如果没有感到正常的制动力，则制动器可能被弄湿了，需使其干燥，可以在使用电子驻车开关的情况下，小心驾驶的同时轻踩制动踏板。\\n\\n[neighbor chunk_id=xia_p52_c086 page=193-194]\\n警告\\n\\n- ■ 驾驶员应确保车内乘员的乘车安全，指导乘员正确使用车辆配置功能，避免车内儿童等乘客出现错误操作车内车窗等控制开关的情况。\\n- 车辆在行驶中请勿将头、手伸出窗外，避免发生交通事故，危及生命，特别是车中有儿童时请随时保持警惕。\\n- ■ 进行长距离下陡坡行驶时，应减速慢行。须记住，如果踩制动踏板次数过多，就会产生制动盘过热的现象而无法正常工作。\\n\\n警告(续)\\n\\n- ■ 加速或是在光滑的路面制动时，都应小心。急剧的加速或制动，都将导致车辆打滑或跑偏。\\n- ■ 发动机或者驱动电机在运转中，请勿离开车辆。\", \"chunk_id\": \"xia_p52_c085\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"驾驶要领\", \"page_number_end\": \"193\", \"context_chunk_ids\": [\"xia_p51_c084\", \"xia_p52_c085\", \"xia_p52_c086\"], \"page_number_start\": \"193\"}, {\"score\": 0.012698412698412698, \"content\": \"[neighbor chunk_id=xia_p109_c192 page=250-250]\\n第1条：\\n大致距离(cm)：约31~50\\n报警声：/\\n\\n第2条：\\n大致距离(cm)：约0~30\\n报警声：/\\n\\n[seed chunk_id=xia_p109_c193 page=250-250]\\n注意\\n\\n- 0~200mm 为系统盲区，探测精度差，报警提示信息不够准确，因此此段距离的报警提示仅供参考。\\n- ■ 不同挡位下，报警距离存在差异，请谨慎驾驶。\\n- 当驻车辅助系统异常时，仪表屏会进行不可用的弹窗提示，如“泊车雷达系统暂不可用”等。\\n- 当车辆处于涉水模式*、浮水模式*、深雪模式*、极限续航*、洗车模式*、驾驶辅助节能模式时，驻车辅助系统无法工作。\\n- 若周边无障碍物，而报警现象持续存在，建议到比亚迪汽车授权服务店进行检修。\\n\\n[neighbor chunk_id=xia_p109_c194 page=250-251]\\n系统局限性\\n\\n驻车辅助系统在以下条件（包括但不限于）可能无法正常工作，导致功能出现失效、未及时报警或误报警。\\n\\n- ● 雷达表面脏污、安装位置发生变动或错位。\\n- - 雷达受雨雪等极端天气影响时。\\n- ● 雷达被异物（如树叶、泥巴等）、水、冰雪、车衣、弯曲变形的车辆牌照、牌照框等物体遮挡或被其他物体近距离遮挡时。\\n\\n■ 遇到以下场景（包括但不限于）时，驻车辅助系统可能因为障碍物材质、形状等多种因素影响，导致功能出现失效、未及时报警或误报警。\\n\\n- - 细、尖、低矮或悬空的障碍物，如线缆、锁链、柱子棱角、低矮的石墩、花坛、悬空的消防箱等。\\n- ● 障碍物表面材质具有吸波特性，如积雪、棉质材料等。\\n\\n- - 系统可能会对反射率不同的道路交界处发生误报警，如坡道连接处、路面接缝、减速带、井盖等。\\n- ● 处于传感器探测盲区的障碍物，或过于贴近车辆的障碍物。\\n- - 穿行的动态障碍物，如成人、儿童、二轮车等。\\n- ● 车辆周围外界超声波所造成的同频干扰。\\n- - 车辆安装了外部防护装置或牵引装置。\\n- 车速过快。\", \"chunk_id\": \"xia_p109_c193\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"250\", \"context_chunk_ids\": [\"xia_p109_c192\", \"xia_p109_c193\", \"xia_p109_c194\"], \"page_number_start\": \"250\"}]',5,21171,1,NULL,'2026-06-22 22:24:32'),(25,1,NULL,NULL,NULL,'那你觉应该有什么？','根据当前用户手册资料，无法确定您具体指的是哪个场景或部位“应该有什么”。您的问题缺少上下文，手册中针对不同的操作模块（如行车安全、应急装备、充电放电、泊车辅助等）均有明确的规定与提示。\n\n如果您能补充说明具体想了解的内容（例如：车内应常备什么物品？涉水/冬季/夜间行驶应具备什么条件？或某项功能应如何设置？），我将立即为您在手册中精准定位并给出操作步骤。\n\n⚠️ **安全提醒**：若您的提问涉及行车安全、故障排查、高压系统或维修事项，请务必以车辆仪表盘实际提示及比亚迪官方授权服务店的专业建议为准，切勿仅依赖非官方信息操作。','xia.pdf','[{\"score\": 0.07985193019566368, \"content\": \"[neighbor chunk_id=xia_p36_c060 page=177-177]\\n警告\\n\\n在车里堆满儿童玩具存在安全隐患，特别是在出现紧急制动或碰撞等情况时，这不仅会影响行车安全，还可能对孩子造成伤害。\\n\\n在后备箱内运载行李\\n\\n- ■ 将行李均匀地放置在后备箱地板上，将最重的行李放在底部并尽可能往前放。\\n- 用绳子或锁链将物品固定好，使其不会在驾驶过程中移动。请勿使堆积的物品高于前排座椅的椅背。\\n\\n一氧化碳中毒的危险性\\n\\n- ■ 发动机排气中含有一氧化碳气体。如果您正确保养车辆，在正常驾驶中，一氧化碳不会进入车内。\\n- 在下列几种情况下，应检查排气系统是否泄漏：\\n\\n- 排气声音有异常。\\n\\n- 车辆经受过可能损坏车辆底部的事故。\\n\\n警告\\n\\n- ■ 一氧化碳气体有毒。吸入该气体会导致丧失知觉甚至危及生命。应避开任何会导致一氧化碳中毒的封闭环境及活动。\\n- 高浓度的一氧化碳气体会迅速集中在封闭的区域，例如在车库里，不要在车库门关闭时起动发动机。即使车库的门是开着的，发动机的运转时间亦应被控制在能将车辆开出车库的时间为限。\\n- ■ 当后背门打开时，气流会将排出的废气带入车内，造成危险的环境。如必须在后背门打开的情况下发动车辆，应将所有车窗打开，并按照下列提示，调节车内空气环境控制系统：\\n\\n- - 选择“外循环”模式。\\n- - 选择“吹面吹脚”模式。\\n- - 风扇速度设定在“高转速”。\\n\\n[seed chunk_id=xia_p37_c061 page=178-178]\\n车辆涉水\\n\\n- 驶入积水路段前必须查明积水深度，积水高度不得超过车身下边缘。\\n- 如需涉水行车，在车辆起步前将空调关掉，然后轻踩加速踏板且不要松脚，否则会造成排气回压将水倒吸入发动机而造成发动机的严重损坏，轻踩加速踏板以稳定而缓慢的速度通过积水路段。\\n\\n- 切勿将车辆停在水中，也切不可在水中倒车和关闭发动机。\\n- ■ 顺利涉水通过积水区后，必须连续轻踩制动踏板数次将制动盘上的水蒸发，以便尽快恢复正常的制动性能。\\n- ■ 驾驶经过深水时可能会弄湿制动器，应小心驾驶。\\n\\n[neighbor chunk_id=xia_p37_c062 page=178-179]\\n警告\\n\\n- 制动盘表面如有水、泥浆时可能导致制动器反应滞后，从而延长制动距离，谨防引发事故。\\n- ■ 驾驶经过积水路段后尽可能避免紧急制动。\\n- ■ 发动机切忌进水。若汽车在低洼积水路面行驶。请注意避免发动机进水，否则势必严重损坏发动机。由此导致的车辆故障及损坏，将无法进行质保。\\n- 车辆驾驶经过积水路段后，传动系统、行驶系统和汽车电气系统等汽车部件也可能严重受损。由此导致的车辆故障及损坏，也将无法进行质保。\\n- ■ 注意强对流天气下尽量选择有避雨条件的场所充电；如车辆泡水或涉水超过门槛位置，可能导致高压零部件内部进水，建议及时联系比亚迪汽车授权服务店进行妥善检测和处理。\\n- ■ 严禁在积水超过轮胎一半的路面行驶。\\n\\n高压零部件内部进水的影响：\\n\\n- 高压零部件属于电子器件，车辆泡水后对高压零部件进行晒干、风干等方式均无法保证水分充分蒸发。\\n- 高压零部件内部进水后对自身的绝缘性有很大的影响；同时，水分中含有较多导电物质，导电物质可能引起高压零部件内部短路或者使高压系统存在短路风险。在这种情况下，整车的安全性能和使用性能受到严重的影响。\\n- 高压零部件内部进水后对产品防护等级、耐压值等性能均有较大影响，存在较大的安全风险。\", \"chunk_id\": \"xia_p37_c061\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"车辆涉水\", \"page_number_end\": \"178\", \"context_chunk_ids\": [\"xia_p36_c060\", \"xia_p37_c061\", \"xia_p37_c062\"], \"page_number_start\": \"178\"}, {\"score\": 0.07925218033626284, \"content\": \"[neighbor chunk_id=xia_p37_c061 page=178-178]\\n车辆涉水\\n\\n- 驶入积水路段前必须查明积水深度，积水高度不得超过车身下边缘。\\n- 如需涉水行车，在车辆起步前将空调关掉，然后轻踩加速踏板且不要松脚，否则会造成排气回压将水倒吸入发动机而造成发动机的严重损坏，轻踩加速踏板以稳定而缓慢的速度通过积水路段。\\n\\n- 切勿将车辆停在水中，也切不可在水中倒车和关闭发动机。\\n- ■ 顺利涉水通过积水区后，必须连续轻踩制动踏板数次将制动盘上的水蒸发，以便尽快恢复正常的制动性能。\\n- ■ 驾驶经过深水时可能会弄湿制动器，应小心驾驶。\\n\\n[seed chunk_id=xia_p37_c062 page=178-179]\\n警告\\n\\n- 制动盘表面如有水、泥浆时可能导致制动器反应滞后，从而延长制动距离，谨防引发事故。\\n- ■ 驾驶经过积水路段后尽可能避免紧急制动。\\n- ■ 发动机切忌进水。若汽车在低洼积水路面行驶。请注意避免发动机进水，否则势必严重损坏发动机。由此导致的车辆故障及损坏，将无法进行质保。\\n- 车辆驾驶经过积水路段后，传动系统、行驶系统和汽车电气系统等汽车部件也可能严重受损。由此导致的车辆故障及损坏，也将无法进行质保。\\n- ■ 注意强对流天气下尽量选择有避雨条件的场所充电；如车辆泡水或涉水超过门槛位置，可能导致高压零部件内部进水，建议及时联系比亚迪汽车授权服务店进行妥善检测和处理。\\n- ■ 严禁在积水超过轮胎一半的路面行驶。\\n\\n高压零部件内部进水的影响：\\n\\n- 高压零部件属于电子器件，车辆泡水后对高压零部件进行晒干、风干等方式均无法保证水分充分蒸发。\\n- 高压零部件内部进水后对自身的绝缘性有很大的影响；同时，水分中含有较多导电物质，导电物质可能引起高压零部件内部短路或者使高压系统存在短路风险。在这种情况下，整车的安全性能和使用性能受到严重的影响。\\n- 高压零部件内部进水后对产品防护等级、耐压值等性能均有较大影响，存在较大的安全风险。\\n\\n[neighbor chunk_id=xia_p38_c063 page=179-180]\\n预防火灾\\n\\n为及时有效的预防车辆火灾，在使用中要注意以下事项：\\n\\n- ■ 禁止持续踩加速踏板使发动机高转速运转。\\n- 车内禁止存放易燃易爆物品。\\n\\n在炎热的夏季，停在阳光下的车辆内部温度可高达70^{\\\\circ} \\\\mathrm{C}以上，如车内存放有打火机、清洗剂、香水等易燃易爆物品，极易引起火灾甚至爆炸。\\n\\n■ 吸烟后要确认烟头已完全熄灭。\\n\\n● 吸烟，不但有害身体健康，还可能会引发火灾。如果烟头在没有完全熄灭的状态下，有可能会引起火灾。\\n\\n■ 建议定期联系比亚迪汽车授权服务店进行检查。\\n\\n- ● 定期检查发动机舱有无漏油现象，及时清理发动机上的油垢、油污等。\\n- - 对于全车线路也要定期检查，电器接插件和线束的连接、绝缘及固定位置等是否正常，如果发现问题应及时进行处理。\\n\\n■ 禁止改装车辆线路、不建议加装电器部件。\\n\\n- - 加装其他用电器(如大功率音响、灯具等)会造成线路负荷过大，线束容易发热造成火灾。电器、线路改装不规范，会产生接触电阻而异常发热引发火灾。\\n- - 严禁使用超出用电器额定规格的保险丝或其他金属丝代替保险丝。\\n\\n■ 正确选择停车位置。\\n\\n- ● 车辆在停放期间，尤其是在夏季，一定要注意车底是否有易燃物，比如干草、枯枝树叶或麦秆等，因车辆长时间行驶后三元催化器温度升高，如果车底有易燃物，很有可能引起火灾。\\n- ● 车辆在行驶过程中，也应尽量避开堆积有干树叶、麦秆、杂草等易燃物的路段，或在经过此类路段后及时停车检查车底是否挂有易燃物等。在停车时，也要尽量避开太阳曝晒的地方。\\n\\n- 车辆在维修或保养时，需断开低压蓄电池负极线。\\n- 车上要常备轻便的灭火器，并要掌握使用方法。\\n\\n为保证车辆安全，应在车上配备灭火器，并且要定期检查和更换。同时要熟悉灭火器的使用方法，做到有备无患，以免发生意外时束手无策。\\n\\n如果车辆发生火灾，应及时冷静的采取有效措施进行处理，最大限度的降低损失。\", \"chunk_id\": \"xia_p37_c062\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"179\", \"context_chunk_ids\": [\"xia_p37_c061\", \"xia_p37_c062\", \"xia_p38_c063\"], \"page_number_start\": \"178\"}, {\"score\": 0.031009615384615385, \"content\": \"[neighbor chunk_id=xia_p51_c084 page=192-193]\\n自动驻车(AVH)功能退出\\n\\n当自动驻车(AVH)功能正常运行时，若驾驶员进行以下操作，会导致车辆退出自动驻车功能，从“D”挡自动切换为“P”挡：\\n\\n- - 打开主驾车门。\\n- - 解锁驾驶员安全带。\\n- - 停车时车辆处于“D”挡，激活 EPB。\\n- - 制动踏板松开时，点击自动驻车(AVH)开关，关闭自动驻车(AVH)功能。\\n\\n自动驻车(AVH)功能抑制\\n\\n- ☑ 切换“R”挡进入低速挪车工况，此时自动驻车(AVH)功能进入挪车工况状态。在“R”挡低速倒车，或由“R”挡切换“D”挡低速行驶，自动驻车(AVH)都处于无法激活状态，维持待命，以便于挪车操作。\\n- ■ 进入挪车工况后，通过点击自动驻车(AVH)开关，或控制车速超过10km/h，即可退出挪车工况。此时自动驻车(AVH)功能处于待命状态，可以正常激活。\\n\\n[seed chunk_id=xia_p52_c085 page=193-193]\\n驾驶要领\\n\\n- 在逆风中应缓慢行驶，这样便于控制车辆。\\n- 在有镶边石道路行驶时，应缓慢行驶，并尽可能保持正确的角度。避免在具有高而尖锐边缘的物体上或其他道路障碍物上行驶。否则将导致轮胎严重损坏。\\n- 在经过颠簸路面或在坎坷不平的道路上行驶时要减慢车速。否则，冲击将严重损坏车轮。\\n- 清洗车辆或驾驶经过深水将弄湿制动器。检查它们是否被弄湿时，先要确认周围是否安全，然后轻轻地踩制动踏板。如果没有感到正常的制动力，则制动器可能被弄湿了，需使其干燥，可以在使用电子驻车开关的情况下，小心驾驶的同时轻踩制动踏板。\\n\\n[neighbor chunk_id=xia_p52_c086 page=193-194]\\n警告\\n\\n- ■ 驾驶员应确保车内乘员的乘车安全，指导乘员正确使用车辆配置功能，避免车内儿童等乘客出现错误操作车内车窗等控制开关的情况。\\n- 车辆在行驶中请勿将头、手伸出窗外，避免发生交通事故，危及生命，特别是车中有儿童时请随时保持警惕。\\n- ■ 进行长距离下陡坡行驶时，应减速慢行。须记住，如果踩制动踏板次数过多，就会产生制动盘过热的现象而无法正常工作。\\n\\n警告(续)\\n\\n- ■ 加速或是在光滑的路面制动时，都应小心。急剧的加速或制动，都将导致车辆打滑或跑偏。\\n- ■ 发动机或者驱动电机在运转中，请勿离开车辆。\", \"chunk_id\": \"xia_p52_c085\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"驾驶要领\", \"page_number_end\": \"193\", \"context_chunk_ids\": [\"xia_p51_c084\", \"xia_p52_c085\", \"xia_p52_c086\"], \"page_number_start\": \"193\"}, {\"score\": 0.02857142857142857, \"content\": \"[neighbor chunk_id=xia_p174_c300 page=315-316]\\n注意事项\\n\\n- 驾驶员监测是辅助性系统，无法确保在任何情况下都能有效识别并报警。本系统不能完全代替驾驶员的主观观察判断，驾驶员必须一直保持对车辆的控制和正常驾驶，遵守所有的道路法规，并且对车辆负有全部责任。\\n- 驾驶员监测辅助系统的功能正常运行及其准确率可能会受到多种因素影响，包括但不限于：\\n\\n- - 车内摄像头权限未打开。\\n- - 驾驶员监测辅助系统功能被关闭。\\n- ● 驾驶员监测辅助系统摄像头被遮挡或摄像头滑盖未完全打开。\\n- ● 驾驶员监测辅助系统摄像头被强光直射时。\\n- ● 驾驶员脸部被光线局部照射或脸部特征不完整。\\n- ● 驾驶员戴红外线阻隔眼镜或高度近视厚镜片眼镜。\\n- - 驾驶员戴口罩或者其它物体遮挡嘴部。\\n\\n● 驾驶员坐姿异常超出常规驾驶姿态范围，或者驾驶员脸部在摄像头盲区范围内。\\n\\n[seed chunk_id=xia_p175_c301 page=316-316]\\n警告\\n\\n当驾驶员发觉疲劳驾驶时，请尽快安全停车休息。\\n\\n胎压监测\\n\\n- 直接胎压监测系统是实时监测轮胎气压，提高整车行驶安全性和舒适性，并减少因气压不足造成的轮胎加速磨损和车辆能耗增加的辅助系统。\\n- - 用户可通过转向盘上按钮，选择切换到胎压显示界面。\\n\\n胎压系统报警\\n\\n- 当四轮中的任意一轮胎胎压值低于标准胎压值的 75% 且系统运行状态下，胎压故障灯点亮，胎压值变为黄色，建议您停车检查相应的轮胎是否有慢漏气的现象，并将气压充到合理的范围。\\n- 当四轮中的任意一轮胎胎温值连续 3min 高于 85℃时，胎压系统会进行高温报警，相应轮胎胎温值变为黄色显示，建议您停车待胎温冷却后再继续行驶。\\n- 在系统运行状态下，发生故障后胎压故障灯闪烁后常亮，组合仪表上显示“信号异常”或“请检查胎压监测系统”，请检查相应的胎压监测模块是否正常，是否长时间处于大电场范围内，如果长时间报警，请联系比亚迪汽车授权服务店处理。\\n\\n[neighbor chunk_id=xia_p175_c302 page=316-3174]\\n警告\\n\\n- 如果轮胎气压不正常，本系统不会阻止汽车行驶。因此，在每次行驶前，用户应确保轮胎的气压符合厂家规定的胎压值。如果不符合厂家规定胎压，请勿驾驶车辆，否则将可能损坏车辆，或对自己或他人造成可能的人身伤害。\\n- ■ 驾驶时如果发现轮胎气压不正常，应立即检查轮胎气压。如果低压警告灯点亮，请避免突然转向或紧急刹车，同时降低车速，把车辆开向路边并尽快停车。低胎压行驶可能造成轮胎永久性损坏，并增加轮胎\\n\\n警告(续)\\n\\n报废的可能性。若轮胎损坏严重，可能导致交通事故引起严重的人员伤亡。\", \"chunk_id\": \"xia_p175_c301\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"316\", \"context_chunk_ids\": [\"xia_p174_c300\", \"xia_p175_c301\", \"xia_p175_c302\"], \"page_number_start\": \"316\"}, {\"score\": 0.021311475409836068, \"content\": \"[neighbor chunk_id=xia_p35_c059 page=176-176]\\n警告\\n\\n- 超载及不当的装载都会影响车辆的操纵性及稳定性，并可能导致撞车事故。\\n- ■ 请遵守本手册中有关总载荷极限及其他装载准则。\\n- ■ 请勿随车携带具有强磁性的物品，以免干扰车辆正常运行。\\n\\n在乘员区运载物品\\n\\n- 必须将碰撞时可能被抛向车内伤及乘员的所有物品收放好或固定好。\\n- 要保证放置在前排座椅后侧地板上的物品不会在座椅下滚动，从而避免影响驾驶员操纵踏板的能力或对座椅的正常调节。不可将货物堆至超过前排椅背。\\n- ■ 驾驶时，要保证杂物箱一直关闭。如果杂物箱处于打开状态，在碰撞或急停车时，可能会伤及乘员的膝部。\\n\\n[seed chunk_id=xia_p36_c060 page=177-177]\\n警告\\n\\n在车里堆满儿童玩具存在安全隐患，特别是在出现紧急制动或碰撞等情况时，这不仅会影响行车安全，还可能对孩子造成伤害。\\n\\n在后备箱内运载行李\\n\\n- ■ 将行李均匀地放置在后备箱地板上，将最重的行李放在底部并尽可能往前放。\\n- 用绳子或锁链将物品固定好，使其不会在驾驶过程中移动。请勿使堆积的物品高于前排座椅的椅背。\\n\\n一氧化碳中毒的危险性\\n\\n- ■ 发动机排气中含有一氧化碳气体。如果您正确保养车辆，在正常驾驶中，一氧化碳不会进入车内。\\n- 在下列几种情况下，应检查排气系统是否泄漏：\\n\\n- 排气声音有异常。\\n\\n- 车辆经受过可能损坏车辆底部的事故。\\n\\n警告\\n\\n- ■ 一氧化碳气体有毒。吸入该气体会导致丧失知觉甚至危及生命。应避开任何会导致一氧化碳中毒的封闭环境及活动。\\n- 高浓度的一氧化碳气体会迅速集中在封闭的区域，例如在车库里，不要在车库门关闭时起动发动机。即使车库的门是开着的，发动机的运转时间亦应被控制在能将车辆开出车库的时间为限。\\n- ■ 当后背门打开时，气流会将排出的废气带入车内，造成危险的环境。如必须在后背门打开的情况下发动车辆，应将所有车窗打开，并按照下列提示，调节车内空气环境控制系统：\\n\\n- - 选择“外循环”模式。\\n- - 选择“吹面吹脚”模式。\\n- - 风扇速度设定在“高转速”。\\n\\n[neighbor chunk_id=xia_p37_c061 page=178-178]\\n车辆涉水\\n\\n- 驶入积水路段前必须查明积水深度，积水高度不得超过车身下边缘。\\n- 如需涉水行车，在车辆起步前将空调关掉，然后轻踩加速踏板且不要松脚，否则会造成排气回压将水倒吸入发动机而造成发动机的严重损坏，轻踩加速踏板以稳定而缓慢的速度通过积水路段。\\n\\n- 切勿将车辆停在水中，也切不可在水中倒车和关闭发动机。\\n- ■ 顺利涉水通过积水区后，必须连续轻踩制动踏板数次将制动盘上的水蒸发，以便尽快恢复正常的制动性能。\\n- ■ 驾驶经过深水时可能会弄湿制动器，应小心驾驶。\", \"chunk_id\": \"xia_p36_c060\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"177\", \"context_chunk_ids\": [\"xia_p35_c059\", \"xia_p36_c060\", \"xia_p37_c061\"], \"page_number_start\": \"177\"}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=xia_p15_c025 page=156-156]\\n注意\\n\\n■ 智慧充电功能只针对比亚迪配送的交流慢充设备研发，车主使用非比亚迪认证的交流慢充充电设备时，应关闭本功能，否则可能因充电设备不响应导致无法预约或立即充电，造成车辆亏电、电池电量不足。如需要在公共充电设施上应用，请确认设施可支持车端预约。\\n\\n温馨提示\\n\\n- ■ 智慧充电功能仅针对比亚迪配送交流充电桩，如需在公共充电设施上应用，请确定设施可支持车端预约。\\n- 电池电量过低时，车辆在进入预约前将进行保底充电，保底充电时多媒体仍会进行下电提醒和充电枪连接提醒，仪表下方将出现相应的温馨提示。\\n- 若车辆处于寒冷环境中，预约用车将智能开启电池预加热，电池加热功能不连接充电枪也可以使用，这将消耗部分电量。\\n- ■ 提醒弹框“改为立即充电”只针对本次预约，如需取消全部预约，请在设置界面关闭预约充电开关。\\n- ■ 连接直流充电枪^{*}，预约设置无效，车辆将进入立即充电。\\n\\n[seed chunk_id=xia_p15_c026 page=156-157]\\n放电说明*\\n\\n■ 本车拥有车辆对外放电(V2L)和车内放电功能。\\n\\n警告\\n\\n切勿在放电时接触放电排插、车辆充电口的金属端子。\\n\\n警告(续)\\n\\n- ■ 放电期间，若出现异味、冒烟等异常情况，请立即停止使用放电功能。\\n- ■ 放电安全警告同充电安全警告(见充电说明)。\\n- ■ 不使用时请将该产品存放于阴凉干燥处。\\n- ■ 放电时，切勿将设备放置于后备箱、车头下以及轮胎附近。以免车辆碾压、设备掉落及人为踩踏。\\n- 严禁在插排线变软以及放电枪电缆磨损、绝缘层破裂或者其他任何损坏的情况下，使用该设备。\\n- 当放电枪、供电插排断开、破裂或者表面露出有任何损坏状况的情况时，严禁使用该设备。\\n\\n[neighbor chunk_id=xia_p16_c027 page=157-157]\\n注意\\n\\n- ■ 放电连接装置使用注意事项参照充电注意事项中的充电设备注意事项。\\n- ■ V2L 放电前，请确保负载处于关闭状态。\\n- 整车在使用车辆对外放电时，在整车电量较低时发动机会启动，请注意避免在密闭空间或易燃易爆物附近使用。\\n\\ni 温馨提示\\n\\n- ■ 放电车辆尽量在 SOC 较高时使用该功能。\\n- “OFF”挡长期连接 V2L 连接装置而不输出时，整车静态功耗增加，建议用户在不用设备时拔下放电枪。\\n- ■ 车内放电和车外放电可同时使用。\\n- 充电时不允许车内放电。\", \"chunk_id\": \"xia_p15_c026\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"放电说明*\", \"page_number_end\": \"157\", \"context_chunk_ids\": [\"xia_p15_c025\", \"xia_p15_c026\", \"xia_p16_c027\"], \"page_number_start\": \"156\"}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=xia_p160_c278 page=3014-302]\\n使用方法\\n\\n驾驶员可通过中控屏→设置 →DiPilot→安全辅助→盲区辅助设置界面开启或关闭开门安全提醒功能。功能设置默认为开启。\\n\\n系统局限性\\n\\n- ■ 开门安全提醒是一项驾驶辅助功能，无法应对所有交通、天气、能见度、道路和车辆状况。\\n- ■ 遇到以下场景（包括但不限于）时，开门安全提醒及其相关功能可能不当工作或退出：\\n\\n● 能见度差，例如雨、雪、雾等恶劣天气、浓烟等。\\n\\n- 自车在转弯处或墙体旁等位置停留。\\n\\n- 自车后方存在大型车辆，遮挡自车的雷达探测区域。\\n\\n- 存在较小的目标或缓慢移动的目标。\\n\\n- 目标速度太快或有转向行为，例如目标车辆变道至自车正后方、其他车辆在自车正后方突然变道出现在检测区域中。\\n\\n- 系统启动过程中（例如车辆刚上电，或驾驶辅助系统重启等）。\\n- ■ 系统通用局限性中提到的场景。\\n- 系统发生故障或需要维修。\\n\\n强光、反光等光线不佳场景下，系统可能误检，例如系统可能将铁轨、龙门架、限高杆或交通指示牌、反光的地面道钉等误检为障碍物，进而触发预警。\\n\\n[seed chunk_id=xia_p161_c279 page=302-302]\\n警告\\n\\n- ■ 开门安全提醒不能透过其他车辆或障碍物探测到其后的物体。\\n- ■ 开门安全提醒不能取代内外后视镜及驾乘人员的目视检查。开门下车前主动观察开门环境是驾乘人员保证人身安全最有效的措施和责任。\\n- ■ 开门安全提醒可能会在不存在碰撞风险时发出预警。请保持警觉，时刻关注交通状态，以便预测是否需要采取任何措施。\\n- ■ 开门安全提醒仅能通过预警提示碰撞风险，不能避免碰撞事故。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（例如适当减速、制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n[neighbor chunk_id=xia_p161_c280 page=302-302]\\n后向安全辅助\\n\\n后向碰撞提醒(RCW)\\n\\n- 车辆前行时，在检测到车辆可能被后方车辆追尾时发出提醒。本功能默认开启。\\n- 当车辆以约 150km/h 以下的速度前行时，后向碰撞预警(RCW)系统通过雷达和摄像头等传感器实时检测车辆后方行驶环境，当识别到后方车辆可能碰撞到自车（即追尾）时发出提醒。\\n- ■ 提醒时，车内氛围灯及前排左右侧氛围灯（对应方向）常亮，仪表车尾红色区域高亮提示。除通过仪表向自车驾驶员预警外，车辆还会同时打开危险报警灯，向后车驾驶员提示碰撞风险。\\n- ■ 倒车时，后向碰撞提醒系统不起作用。\", \"chunk_id\": \"xia_p161_c279\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"302\", \"context_chunk_ids\": [\"xia_p160_c278\", \"xia_p161_c279\", \"xia_p161_c280\"], \"page_number_start\": \"302\"}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p119_c212 page=260-263]\\n- - 改装车辆可能会导致泊车辅助受影响，容易在泊车过程中发生刮碰或碰撞。如车身存在附着物、改装件导致阻碍和干扰，像安装自行车架、门踏板、较大的车牌框、重新喷漆导致的车漆过厚、粘贴遮挡超声波雷达或摄像头的贴膜、或在车身上粘贴胶带、贴纸、橡胶涂料等。\\n- - 如果装有挂车钩或装载的物体从车辆周围突出，请勿使用泊车辅助功能。\\n\\n泊车辅助在遇到下面车位场景时，无法正常使用，驾驶员需时刻注意周围环境，包括但不限于：\\n\\n- - 不具备必要的操纵空间的狭窄停车位。\\n- ● 车位附近有透明度较高的玻璃墙或门。\\n- 机械车位。\\n\\n- 道路情况复杂，如陡坡、急弯、连续弯道、蜿蜒小路、窄路、越野路、崎岖道路或带沟槽、凹坑（如消防井等）的道路、一侧有向下的台阶或悬崖的道路、凸起路肩、超宽车道、施工区域（例如布置了锥桶的区域）或者车辆进出匝道、交叉路口、闸机等。 - 道路情况不佳，如路面湿滑或松软（路面积水、结冰、积雪或烂泥路、石子路、沙土路等）、车道线或道路标志不清晰、破损等。\\n\\n泊车辅助可能无法识别以下障碍物或及时应对复杂情况，驾驶员需时刻注意车辆周围环境，及时踩下刹车控制车辆，包括但不限于：\\n\\n- ● 道路情况复杂，如陡坡、急弯、连续弯道、蜿蜒小路、窄路、越野路、崎岖道路或带沟槽、凹坑（如消防井等）的道路、一侧有向下的台阶或悬崖的道路、凸起路肩、超宽车道、施工区域（例如布置了锥桶的区域）或者车辆进出匝道、交叉路口、闸机等。\\n- ● 道路情况不佳，如路面湿滑或松软（路面积水、结冰、积雪或烂泥路、石子路、沙土路等）、车道线或道路标志不清晰、破损等。\\n\\n泊车辅助可能无法识别以下障碍物或及时应对复杂情况，驾驶员需时刻注意车辆周围环境，及时控制车辆，包括但不限于：\\n\\n[seed chunk_id=xia_p119_c213 page=260-263]\\n- - 交通情况复杂，如遇突然快速出现并快速靠近自车的车辆、自行车、行人、小动物或其他障碍物。\\n- ● 紧贴车位的障碍物，例如处于感知盲区的方柱、紧贴车位或部分侵入车位的铁门、破损不完整的墙体等。\\n- - 狭窄车位，如狭窄道路、墙角处、拐角处、极限小车位。\\n- ● 车位内侧存在立柱、立柱靠近泊车路径。\\n\\n- - 附近存在悬空类障碍物，如悬空箱式大车、消防箱、消防阀、消防栓、充电箱、外卖箱、车辆后方或者前方外凸拖车钩、车辆后备胎、空调外机、悬空广告牌、悬空（倾斜或笔直）的水管、悬空墙壁/横梁、墙面上有突出的墙块、悬空阳台、消防门上的悬空锁、消防类器材上的悬空开关旋钮尖角、打开的车门、半开的上卷式车门等。\\n- - 附近存在低矮和细小障碍物，如低矮的石头、灌木丛、花台、花坛、石墩、石板凳、石狮子、矮墙（40cm以下）、窄墙、细杆、细小立柱、铁丝、铁丝网篱笆、卷闸门、牵引杆、纸箱、打开的地锁、限位块或其他无法正常反射雷达探测波的物体。\\n- ● 附近有下行台阶、凸起路肩、凹坑、凹陷水槽或其他地面不平。\\n- - 附近存尖锐的障碍物，如直角柱子、多棱柱、墙尖角、悬挂及落地消防箱、落地充电箱等。\\n- ● 附近及车位上方存在高度变化，易剐蹭碰撞顶部，如通风管道、倾斜顶棚等。\\n- ● 附近存在具备特殊表面和结构的物品，如海绵、泡沫等，或者表面反光的物体，如玻璃、地面积水、反光的地坪漆车位等。\\n- - 附近有近距离非机动车包括但不限于二轮车、三轮车、自行车、摩托车等，其他近距离的小推车、婴儿车、购物车，小动物及行人（尤其是儿童）。\\n- ● 附近存在形状不规则的非典型目标物，如大型板车、公路养护车、与大片单一背景色颜色过于接近的车辆、透明凳子、桌椅、水马、雪糕筒以及其他各类难以被系统识别的障碍物等，均需要额外注意。\\n\\n[neighbor chunk_id=xia_p122_c214 page=263-263]\\n警告\\n\\n- 泊车辅助功能仅作为一种驾驶辅助功能，驾驶员应对驾驶安全负全部责任。\\n- 上述注意事项并未尽述影响泊车辅助功能正常工作的全部情形，许多不可预见的情况都可能影响泊车能力。驾驶员必须时刻关注泊车状况和车辆周边环境，根据个人需求谨慎判断是否使用本功能并确保泊车安全。如遇突发状况，驾驶员需及时暂停并控制车辆，否则可能造成严重财产损坏或人员伤害。\\n- ■ 使用泊车辅助功能的过程中，请务必遵守当地的道路交通及其他相关法律法规。\", \"chunk_id\": \"xia_p119_c213\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"系统局限性\", \"page_number_end\": \"263\", \"context_chunk_ids\": [\"xia_p119_c212\", \"xia_p119_c213\", \"xia_p122_c214\"], \"page_number_start\": \"260\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p136_c240 page=277-278]\\n- - 快速移入传感器探测范围内的行人或车辆；\\n- - 被其他物体遮挡的行人；\\n- - 行人的典型轮廓无法与背景相互区别；\\n- ● 未探测到行人，例如由于特殊衣物或其他物体覆盖；\\n- - 在半径很小的弯道上；\\n- 在某些环境中探测有可能受到影响或者发生延迟，如目标的雷达反射截面积过小(可能是自行车、三轮车、四轮马车、行人、电动自行车、摩托车或异型车等)时，系统存在无法确认与前方目标距离的风险，可能出现对该类目标反应延迟或无法反应的情况；\\n- 毫米波雷达由于受到其它毫米波雷达源干扰导致故障或者误识别；\\n- ● 探测还可能被噪声或电磁波影响，从而产生延迟或受到干扰；\\n- - 前向碰撞提醒可能会对地面的水渍、路面阴影、井盖、铁板或道路指示牌等触发非必要的提醒；\\n- 若车辆长时间行驶在环形停车场、隧道等特殊道路条件下，前置毫米波雷达因探测特性可能会出现短暂的功能受限，当离开当前特殊道路后，功能将恢复。\\n\\n[seed chunk_id=xia_p137_c241 page=278-278]\\n警告\\n\\n- 请驾驶员务必安全驾驶，时刻注意观察周围交通状况，在任何情况下，均不得使用前向碰撞提醒代替正常的驾驶员判断和操作。\\n- ■ 如果前向碰撞提醒发出警报，则驾驶员必须根据交通状况施加制动来降低车速或通过转向避开障碍物。\\n- ■ 如果长时间近距离跟车行驶，那么安全距离报警会发出距离警告。如果在前方行驶的车辆紧急制动，那么碰撞无法避免。\\n- ■ 行人保护场景因无法克服一些物理条件的限制，在系统规定的速度区间内，功能可能无法完全施展开。因此，采取及时有效的制动行为的责任始终依赖于驾驶员。行人保护场景是否发出警告，需要基于实际情况。\\n- ■ 行人保护场景无法依托系统自身，完全避免事故和严重伤害。\\n- ■ 人保护场景在一些复杂工况下，可能会误触发不需要的提醒，例如，在弯曲的主路上。\\n- ■ 功能故障时，可能会有不需要的警报介入，例如，由于雷达/前视摄像头角度失准。\\n\\n[neighbor chunk_id=xia_p138_c242 page=279-279]\\n警告(续)\\n\\n- ■ 请勿自行尝试使用纸箱、铁板、假人等物体测试前向碰撞提醒，系统可能不会正常工作，从而导致事故发生。\\n- ■ 发生如下情况请务必前往比亚迪汽车授权服务店对毫米波雷达进行专业校准：\\n- ● 拆卸毫米波雷达或前视摄像头。\\n- ● 在进行四轮定位的过程中已调节前束或后桥车轮外倾。\\n- - 车辆发生过碰撞后。\\n- - ACC 系统性能下降或异常。\\n\\n■ 请根据个人需求结合交通状况及道路环境自行决定是否使用前向碰撞提醒功能。\\n\\ni 温馨提示\\n\\n- ■ 前向碰撞提醒功能不能保证在任何情况下都发出提醒，在复杂的交通状况下，系统无法总是清楚地识别车辆、行人或骑行人。\\n- 雷达或前视摄像头表面出现污浊或异物覆盖时，组合仪表显示屏将显示相应信息，则应按要求清除传感器表面异物（表面污浊或被异物覆盖会导致传感器致盲）。在传感器污浊或被异物覆盖时，前向碰撞提醒功能关闭，清除之后，前向碰撞提醒功能正常。\", \"chunk_id\": \"xia_p137_c241\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"278\", \"context_chunk_ids\": [\"xia_p136_c240\", \"xia_p137_c241\", \"xia_p138_c242\"], \"page_number_start\": \"278\"}, {\"score\": 0.01746031746031746, \"content\": \"[neighbor chunk_id=xia_p29_c049 page=170-171]\\n挂车拖曳\\n\\n- 本车主要是为运载乘客而设计的，为了自己和他人的安全，请勿过载或拖车。\\n- 拖曳挂车，将对车辆的操纵、性能、制动、耐久、经济驾驶以及能耗等各方面产生不良影响。\\n- ■ 驾驶的安全和舒适，完全依靠设备的正确使用和养成小心驾驶的习惯。\\n- 因拖曳挂车造成的损坏或故障不在保修范围之内。\\n\\n安全驾驶注意事项\\n\\n严禁酒后驾车\\n\\n即使少量饮酒也会降低您对道路交通条件变化的应变能力，饮酒越多，反应越迟钝，因此，严禁酒后驾车。\\n\\n控制车速\\n\\n超速是发生撞车伤亡事故的主要原因，一般来说，速度越快危险性就越大，请您根据道路交通情况保持安全车速。\\n\\n[seed chunk_id=xia_p30_c050 page=171-172]\\n保持车辆处于安全驾驶状态\\n\\n轮胎爆裂或机械故障都是极端危险的，为减少这类故障发生的可能性，应经常检查车况，并定期完成规定的各个检查项目。\\n\\n警告\\n\\n- ■ 驾驶员必须取得驾驶证后才能驾驶车辆。\\n- ■ 请勿疲劳驾驶。\\n- ■ 驾驶车辆时务必遵守交通法则。\\n- ■ 驾驶时请务必专注驾驶，不要进行与驾驶无关的操作(如接打电话、调节按钮等)。\\n\\n用车建议\\n\\n为了延长动力电池使用寿命，有以下建议：\\n\\n- 车辆长时间存放前，建议充满电后放电至 40%~60%，电量不宜太高或太低，车辆存放时请关好车门、窗。\\n- 车辆长时间存放时，建议每3个月满充和满放电一次，再充电至40%~60%存放。\\n- 车辆使用时，若仪表 SOC 指示条进入红色警戒格时，电池电量已不足，请及时充电避免长时间低电量使用。\\n- 车辆使用时，建议每 1~2 周可以使用车载充电设备为车辆满充电一次。\\n- 气温较高时，应避免车辆长期满电存放，建议车辆充满电后放电至95%以下。\\n- 温度很低或很高时，建议车辆不要长时间室外停放。\\n- 使用车辆时，应尽量避免反复急加速和急减速。\\n\\n- 使用车辆时，应尽量避免长时间连续使用，长时间工作可能会导致电池温度过高，影响车辆性能。\\n- 使用车辆时，若仪表出现故障指示，建议及时前往比亚迪汽车授权服务店检查。\\n- 电池温度较高时，车辆性能会有一定限制，请将车辆静置待电池温度下降后再使用。\\n\\n[neighbor chunk_id=xia_p31_c051 page=172-172]\\n警告\\n\\n在低温或高温环境下，纯电续航里程较常温下有所减少，动力性能会受到影响。\\n\\n注意\\n\\n- 如果仪表显示的电里程下降到 0，必须充电，如果 7 天之内未充电，会导致永久损坏电池，由此造成的动力电池包损坏比亚迪将不再履行质保条款。\\n- ■ 续驶里程取决于车辆的可用电量、车龄(当前电池寿命)、天气、温度、路况、驾驶习惯等。\\n\\n燃油\\n\\n燃油选用\\n\\n- 正确地选择燃油是充分发挥发动机性能的基础，也是控制排放及保护相关零部件的关键。\\n- ■ 请使用 92# 或以上的无铅汽油。\", \"chunk_id\": \"xia_p30_c050\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"保持车辆处于安全驾驶状态\", \"page_number_end\": \"172\", \"context_chunk_ids\": [\"xia_p29_c049\", \"xia_p30_c050\", \"xia_p31_c051\"], \"page_number_start\": \"171\"}]',5,10240,1,NULL,'2026-06-22 22:26:14'),(26,1,NULL,NULL,NULL,'交流充电怎么用？','根据您提供的《用户手册》资料，车辆的交流充电主要包含**家用便携式交流充电**和**公共交流充电桩充电**两种场景。具体操作步骤及安全注意事项如下：\n\n### 🔌 一、 家用便携式交流充电（使用“三转七”）\n1. **充电前检查**：检查供电设备、充电枪及充电口是否有线缆磨损、端口生锈、壳体破裂或潮湿异物。如有异常请擦拭干燥，严禁带病充电；雨天需注意设备防水。\n2. **打开充电口**：整车解锁，电源挡位建议退至`OFF`挡，按下车辆右侧充电口盖使其自动弹开，随后打开内部保护盖，确插拔端无障碍物。\n3. **连接供电端**：将“三转七”供电插头插入符合国标的家用220V插座，设备充电指示灯常亮。\n4. **连接车辆接口**：将充电枪插入车辆充电口并可靠锁止。组合仪表充电连接指示灯点亮，“三转七”指示灯闪烁，即开始充电。\n5. **停止充电**：电量充满自动结束。如需提前结束，直接进入断开步骤。\n\n### 🏢 二、 公共交流充电桩充电\n1. **打开充电口**：同家用方式，打开车辆右侧充电口盖及保护盖。\n2. **连接供电端**：\n   - 若充电桩已配备充电枪或您使用充电盒，无需此步。\n   - 若使用未配枪的单相交流充电桩，需准备“七转七”转接器，将供电插头接入插座。（注：移动时需轻拿轻放，禁止拉扯线缆或跌落）。\n3. **连接车辆接口**：将充电枪插入车辆充电口并可靠锁止。\n4. **启动设置**：普通设备可跳过。若公共桩有设置选项，请按桩体说明刷卡或扫码。\n5. **确认充电**：操作完成后，组合仪表充电连接指示灯点亮，屏幕显示充电参数及画面。\n6. **停止充电**：设备设置提前结束或充满自动结束。参照以下步骤断开连接。\n\n### 🔚 通用停止与拔枪步骤\n1. **结束充电**：车辆充满会自动停止，或按需通过设备提前结束。\n2. **解锁拔枪**：\n   - **停用防盗模式**：直接按下充电枪上的机械按钮即可拔出。\n   - **启用防盗模式**：必须先按钥匙解锁按钮或门把手微动开关（钥匙在附近）进行整车解锁，再按下充电枪机械按钮拔出。**注意：拔枪前已解锁的车辆，需在2分钟内拔出枪头，否则电锁会重新锁止。**\n3. **断开电源与收纳**：若使用“七转七”，建议先拔充电枪，后拔供电插头。关闭充电口保护盖及车辆充电口盖，将设备放回指定位置或阴凉处妥善存放。\n\n### ⚠️ 重要安全与功能提示\n- **防盗电锁**：若解锁后仍无法拔枪，可多次尝试解锁；仍无效请参考手册“充电口应急解锁”操作。电锁工作模式可在多媒体“充电口电锁控制功能”中设置。\n- **预约充电限制**：电池电量较低时，系统不支持预约充电功能。\n- **安全红线**：雷雨天气禁止充电；充电时严禁触摸金属端子；发现异味、冒烟等异常请立即停止并联系授权服务店；充电过程中请勿晃动充电枪，严禁在未解锁防盗状态下强行拔枪。\n- **智慧充电设置**：可通过中控屏“智慧充电”App、能量设置菜单，或智能语音（如：“你好小迪，打开预约充电”）进行设置。直流充电枪连接时预约设置无效，将直接立即充电。\n\n以上步骤均基于《用户手册》标准说明。高压充电涉及人身安全，实际操作请严格遵循车载多媒体提示，遇故障或不确定情况请以官方授权售后服务中心指导为准。','xia.pdf','[{\"score\": 0.05245901639344262, \"content\": \"[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"context_chunk_ids\": [\"xia_p10_c018\", \"xia_p10_c019\", \"xia_p11_c020\"], \"page_number_start\": \"151\"}, {\"score\": 0.051408090117767535, \"content\": \"[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"context_chunk_ids\": [\"xia_p9_c017\", \"xia_p10_c018\", \"xia_p10_c019\"], \"page_number_start\": \"151\"}, {\"score\": 0.05067604326676907, \"content\": \"[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[seed chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\\n\\n[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p11_c020\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"153\", \"context_chunk_ids\": [\"xia_p10_c019\", \"xia_p11_c020\", \"xia_p12_c021\"], \"page_number_start\": \"152\"}, {\"score\": 0.0296875, \"content\": \"[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n[neighbor chunk_id=xia_p13_c023 page=154-155]\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备:\\n\\n■ 直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n- ■ 充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n- 高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n智慧充电\\n\\n- 用户可通过多媒体或智能语音设置充电模式，以下方式均可进入设置界面：\\n\\n- ● 通过点击中控屏桌面应用图标“智慧充电”App 进入；\\n- ● 通过点击中控屏→设置 → 能量→充电与放电设置进入“智慧充电”界面；\\n- ● 通过呼唤“你好小迪，打开智慧充电/预约充电”、“你好小迪，我要智慧充电/预约充电”、“你好小迪，请帮我打开智慧充电/预约充电”等快速进入。\\n\\n本车可通过点击返回键←/home 键或智能语音退出智慧充电页面：\\n\\n● 通过呼唤“你好小迪，关闭智慧充电/预约充电”、“你好小迪，退出智慧充电/预约充电”等快速退出。\", \"chunk_id\": \"xia_p12_c022\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"context_chunk_ids\": [\"xia_p12_c021\", \"xia_p12_c022\", \"xia_p13_c023\"], \"page_number_start\": \"153\"}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=xia_p7_c014 page=148-148]\\n充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\\n\\n[seed chunk_id=xia_p7_c015 page=148-149]\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[neighbor chunk_id=xia_p8_c016 page=149-150]\\ni 温馨提示\\n\\n- 请联系比亚迪汽车授权服务店，按充电设备要求选择合适的电源。\\n- ■ 使用三转七充电时，注意开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n打开充电枪和充电口的保护盖^{*}，确保充电枪插头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n■ 将三转七插头插入家用插座中，三转七充电指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n- 将三转七的充电枪连接至充电口，并可靠锁止。\\n- 插好充电枪，组合仪表充电连接指示灯点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n- 车辆电量充满会自动结束充电。\\n- 如需提前结束充电直接进入下一步。\", \"chunk_id\": \"xia_p7_c015\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"家用便携式交流充电\", \"page_number_end\": \"149\", \"context_chunk_ids\": [\"xia_p7_c014\", \"xia_p7_c015\", \"xia_p8_c016\"], \"page_number_start\": \"148\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p2_c005 page=143-144]\\n充电前警告事项\\n\\n请确保车辆、供电设备和充电设备的充电端口内没有水等异物，并确保金属端子没有因生锈或腐蚀而造成的破坏、影响等情况，若出现上述情况，请勿充电。\\n\\n充电中警告事项\\n\\n■ 为了避免造成严重的人身伤害，车辆正在充电时，注意以下预防事项：\\n\\n- - 禁止接触充电端口、充电连接器或者插头的金属连接处。\\n- - 当有雷雨天气时，禁止给车辆充电或触摸车辆，闪电击中可能导致充电设备损坏、引起人身伤害。\\n- - 在直流充电*时，请保持交流充电口保护盖处于关闭状态；在交流充电时，请保持直流充电口保护盖处于关闭状态。\\n- ● 充电时，如果发现车辆或充电设备异常，如产生异味、冒烟等现象，请立即停止充电，并建议与比亚迪汽车授权服务店联系。\\n- - 充电时，禁止对车辆进行维修。\\n\\n[seed chunk_id=xia_p3_c006 page=144-144]\\n充电结束后警告事项\\n\\n车辆行驶前，请确保拔出充放电设备，并关闭充电口盖。\\n\\n充电注意事项\\n\\n- 任何电源挡位下都可以进行交流充电、直流充电^{*}，为保证安全，充电前，建议退电至“OFF”挡，充电时车辆无法进入“OK”挡。\\n- 当外部电网短时间断电并再次供电时，原装充电设备会自动重新启动充电，无需重新连接充电设备。\\n- 在未充满电的情况下，需要提前结束充电，请通过充电设备设置提前结束充电，尽量不要带载断电。\\n- 如果车辆长时间不使用，建议至少 1 个月充电一次。\\n\\n[neighbor chunk_id=xia_p3_c007 page=144-145]\\n充电设备注意事项\\n\\n■ 为了避免对充电设备及车辆造成损坏，注意以下预防事项：\\n\\n- 启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n- 请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n- - 为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n- ● 充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n- ● 充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n- 请勿在电锁锁止状态强行插入充电枪。\\n\\n■ 应小心使用充放电设备：\\n\\n- - 充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n- 请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n- 请勿在温度高于50^{\\\\circ} \\\\mathrm{C}的环境下存放或者使用充电设备。\\n- 请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n■ 不建议使用外加的电线或者适配器/转接器。\", \"chunk_id\": \"xia_p3_c006\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电结束后警告事项\", \"page_number_end\": \"144\", \"context_chunk_ids\": [\"xia_p2_c005\", \"xia_p3_c006\", \"xia_p3_c007\"], \"page_number_start\": \"144\"}, {\"score\": 0.016923076923076926, \"content\": \"[neighbor chunk_id=xia_p7_c015 page=148-149]\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p8_c016 page=149-150]\\ni 温馨提示\\n\\n- 请联系比亚迪汽车授权服务店，按充电设备要求选择合适的电源。\\n- ■ 使用三转七充电时，注意开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n打开充电枪和充电口的保护盖^{*}，确保充电枪插头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n■ 将三转七插头插入家用插座中，三转七充电指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n- 将三转七的充电枪连接至充电口，并可靠锁止。\\n- 插好充电枪，组合仪表充电连接指示灯点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n- 车辆电量充满会自动结束充电。\\n- 如需提前结束充电直接进入下一步。\\n\\n[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\", \"chunk_id\": \"xia_p8_c016\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"150\", \"context_chunk_ids\": [\"xia_p7_c015\", \"xia_p8_c016\", \"xia_p9_c017\"], \"page_number_start\": \"149\"}, {\"score\": 0.012307692307692308, \"content\": \"[neighbor chunk_id=xia_p14_c024 page=155-156]\\n智慧充电设置页面\\n\\n- ①预约充电开关\\n- ②充电起止时间\\n- ③重复周期\\n- ④切换预约用车模式*\\n\\n⑤设置\\n\\n- 出厂时车辆默认设置为立即充电，预约充电开关关闭。\\n- 如需进行预约充电，点击预约充电开启按钮①，设置充电起止时间②和重复周期③，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪或按下电源按键使车辆下电，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n预约用车*设置页面\\n\\n- ①预约用车开关\\n- ②预约用车时间\\n- ③重复周期\\n- ④电价优惠时段\\n- ⑤切换预约充电模式\\n\\n- 如需进行预约用车，点击预约用车开启按钮①，设置用车时间②，重复周期③和电价优惠时段④，点击“确定”保存设置。\\n- ■ 预约设置成功后，若您连接充电枪，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n- 用户可点击智慧充电设置图标，在“预约充电提醒”中关闭连接充电枪及下电提醒功能。\\n\\n[seed chunk_id=xia_p15_c025 page=156-156]\\n注意\\n\\n■ 智慧充电功能只针对比亚迪配送的交流慢充设备研发，车主使用非比亚迪认证的交流慢充充电设备时，应关闭本功能，否则可能因充电设备不响应导致无法预约或立即充电，造成车辆亏电、电池电量不足。如需要在公共充电设施上应用，请确认设施可支持车端预约。\\n\\n温馨提示\\n\\n- ■ 智慧充电功能仅针对比亚迪配送交流充电桩，如需在公共充电设施上应用，请确定设施可支持车端预约。\\n- 电池电量过低时，车辆在进入预约前将进行保底充电，保底充电时多媒体仍会进行下电提醒和充电枪连接提醒，仪表下方将出现相应的温馨提示。\\n- 若车辆处于寒冷环境中，预约用车将智能开启电池预加热，电池加热功能不连接充电枪也可以使用，这将消耗部分电量。\\n- ■ 提醒弹框“改为立即充电”只针对本次预约，如需取消全部预约，请在设置界面关闭预约充电开关。\\n- ■ 连接直流充电枪^{*}，预约设置无效，车辆将进入立即充电。\\n\\n[neighbor chunk_id=xia_p15_c026 page=156-157]\\n放电说明*\\n\\n■ 本车拥有车辆对外放电(V2L)和车内放电功能。\\n\\n警告\\n\\n切勿在放电时接触放电排插、车辆充电口的金属端子。\\n\\n警告(续)\\n\\n- ■ 放电期间，若出现异味、冒烟等异常情况，请立即停止使用放电功能。\\n- ■ 放电安全警告同充电安全警告(见充电说明)。\\n- ■ 不使用时请将该产品存放于阴凉干燥处。\\n- ■ 放电时，切勿将设备放置于后备箱、车头下以及轮胎附近。以免车辆碾压、设备掉落及人为踩踏。\\n- 严禁在插排线变软以及放电枪电缆磨损、绝缘层破裂或者其他任何损坏的情况下，使用该设备。\\n- 当放电枪、供电插排断开、破裂或者表面露出有任何损坏状况的情况时，严禁使用该设备。\", \"chunk_id\": \"xia_p15_c025\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"156\", \"context_chunk_ids\": [\"xia_p14_c024\", \"xia_p15_c025\", \"xia_p15_c026\"], \"page_number_start\": \"156\"}]',5,26577,1,NULL,'2026-06-22 22:40:13'),(27,1,NULL,NULL,NULL,'这两个有什么区别？','根据《用户手册》资料，家用便携式交流充电与公共场所交流充电桩充电的主要区别如下：\n\n**1. 适用场景与配套设备不同**\n* **家用便携式充电**：使用随车配置的“交流充电连接装置（简称三转七）”，直接将供电插头插入家庭标准供电插座。手册推荐使用 `220V 10A` 的专用交流线路和电源插座。\n* **公共交流充电**：在大型超市、购物广场、停车场等公共场所使用充电桩或充电盒。部分公用充电桩**不配备充电枪**，需额外准备“七转七”连接器；此外也支持使用比亚迪三相交流充电桩。\n\n**2. 启动前的身份验证/设置不同**\n* **家用**：完成插电和插枪锁止后，组合仪表充电连接指示灯即会点亮，**无需额外认证或设置**。\n* **公共**：连接好接口后，若该充电桩/盒带有管理功能，通常**需要进行刷卡或扫描二维码**等操作方可启动充电（具体依现场设备指引）。\n\n**3. 结束充电后的设备放置不同**\n* **家用**：充电结束后，将充电装置自行整理并妥善放置在阴凉干燥处保管。\n* **公共**：充电结束后，建议**将充电枪放回充电桩或充电盒的指定挂放位置**，并整理好连接线。\n\n**4. 核心注意事项差异**\n* **家用**：严禁使用非国标插座，防止大功率充电导致线路损坏或跳闸；使用“三转七”时需注意**开启充电防盗功能**；雨天充电须做好防水保护。\n* **公共**：不同运营商设备操作逻辑可能不同，使用前务必阅读并遵守该场所充电桩的使用说明及安全警告事项。\n\n⚠️ **安全提醒**：充电涉及高压用电安全，请务必保持充电口及周边环境干燥清洁，定期检查线缆与端子有无磨损或异常。实际操作中请以车辆组合仪表提示为准，如遇故障或疑问，请及时联系比亚迪汽车授权服务店进行处理。','xia.pdf','[{\"score\": 0.03114754098360656, \"content\": \"[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"context_chunk_ids\": [\"xia_p10_c018\", \"xia_p10_c019\", \"xia_p11_c020\"], \"page_number_start\": \"151\"}, {\"score\": 0.030440348182283663, \"content\": \"[neighbor chunk_id=xia_p7_c014 page=148-148]\\n充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\\n\\n[seed chunk_id=xia_p7_c015 page=148-149]\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[neighbor chunk_id=xia_p8_c016 page=149-150]\\ni 温馨提示\\n\\n- 请联系比亚迪汽车授权服务店，按充电设备要求选择合适的电源。\\n- ■ 使用三转七充电时，注意开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n打开充电枪和充电口的保护盖^{*}，确保充电枪插头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n■ 将三转七插头插入家用插座中，三转七充电指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n- 将三转七的充电枪连接至充电口，并可靠锁止。\\n- 插好充电枪，组合仪表充电连接指示灯点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n- 车辆电量充满会自动结束充电。\\n- 如需提前结束充电直接进入下一步。\", \"chunk_id\": \"xia_p7_c015\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"家用便携式交流充电\", \"page_number_end\": \"149\", \"context_chunk_ids\": [\"xia_p7_c014\", \"xia_p7_c015\", \"xia_p8_c016\"], \"page_number_start\": \"148\"}, {\"score\": 0.030363543266769072, \"content\": \"[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[seed chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\\n\\n[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p11_c020\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"153\", \"context_chunk_ids\": [\"xia_p10_c019\", \"xia_p11_c020\", \"xia_p12_c021\"], \"page_number_start\": \"152\"}, {\"score\": 0.021311475409836068, \"content\": \"[neighbor chunk_id=xia_p136_c239 page=277-278]\\ni 温馨提示(续)\\n\\n若本次行程中关闭前向碰撞提醒开关。当车辆重新启动后，前向碰撞提醒会重新开启，参数设置为默认值“适中”。\\n\\n系统局限性\\n\\n针对以下目标，前向碰撞提醒可能不会发出提醒，包括但不限于：\\n\\n- ● 迎面向自车驶来的车辆、行人或骑行人；\\n- - 斜向切入到自车行驶路径的车辆、行人或骑行人；\\n- 相邻车道行驶的车辆、行人或骑行人；\\n- - 各类动物；\\n- 各类异型车辆，如洒水车，厢式货车，道路施工车等。\\n\\n在下列情况下，前向碰撞提醒可能会受影响或不起作用，包括但不限于：\\n\\n- - 天气条件差，如雨、雪、雾等天气；\\n- 光照条件差，如黑夜、眩光、太阳直射等环境；\\n- 传感器脏污、起雾、损坏或被遮挡；\\n- 前舱盖和后背箱未关好或行驶中打开前舱引擎盖和后备箱；\\n- - 驾驶员未系安全带或行驶中解开安全带；\\n- - 驾驶员踩刹车；\\n- - 驾驶员猛踩加速踏板；\\n- ● 驾驶员在行驶过程中频繁切换加速踏板和刹车；\\n- ● 电子车身稳定系统关闭或故障灯点亮时；\\n- ● 驾驶员改装车辆，如重新喷漆导致车身车漆过厚，贴膜或粘贴胶带、装饰等，影响摄像头或毫米波雷达性能；\\n- - 系统启动过程中（例如车辆刚上电或系统重启等）；\\n- - 系统通用局限性中提到的场景；\\n- - 系统发生故障或需要维修。\\n\\n在复杂的交通情况下，前向碰撞提醒可能无法对以下情况做出正确反应，包括但不限于：\\n\\n[seed chunk_id=xia_p136_c240 page=277-278]\\n- - 快速移入传感器探测范围内的行人或车辆；\\n- - 被其他物体遮挡的行人；\\n- - 行人的典型轮廓无法与背景相互区别；\\n- ● 未探测到行人，例如由于特殊衣物或其他物体覆盖；\\n- - 在半径很小的弯道上；\\n- 在某些环境中探测有可能受到影响或者发生延迟，如目标的雷达反射截面积过小(可能是自行车、三轮车、四轮马车、行人、电动自行车、摩托车或异型车等)时，系统存在无法确认与前方目标距离的风险，可能出现对该类目标反应延迟或无法反应的情况；\\n- 毫米波雷达由于受到其它毫米波雷达源干扰导致故障或者误识别；\\n- ● 探测还可能被噪声或电磁波影响，从而产生延迟或受到干扰；\\n- - 前向碰撞提醒可能会对地面的水渍、路面阴影、井盖、铁板或道路指示牌等触发非必要的提醒；\\n- 若车辆长时间行驶在环形停车场、隧道等特殊道路条件下，前置毫米波雷达因探测特性可能会出现短暂的功能受限，当离开当前特殊道路后，功能将恢复。\\n\\n[neighbor chunk_id=xia_p137_c241 page=278-278]\\n警告\\n\\n- 请驾驶员务必安全驾驶，时刻注意观察周围交通状况，在任何情况下，均不得使用前向碰撞提醒代替正常的驾驶员判断和操作。\\n- ■ 如果前向碰撞提醒发出警报，则驾驶员必须根据交通状况施加制动来降低车速或通过转向避开障碍物。\\n- ■ 如果长时间近距离跟车行驶，那么安全距离报警会发出距离警告。如果在前方行驶的车辆紧急制动，那么碰撞无法避免。\\n- ■ 行人保护场景因无法克服一些物理条件的限制，在系统规定的速度区间内，功能可能无法完全施展开。因此，采取及时有效的制动行为的责任始终依赖于驾驶员。行人保护场景是否发出警告，需要基于实际情况。\\n- ■ 行人保护场景无法依托系统自身，完全避免事故和严重伤害。\\n- ■ 人保护场景在一些复杂工况下，可能会误触发不需要的提醒，例如，在弯曲的主路上。\\n- ■ 功能故障时，可能会有不需要的警报介入，例如，由于雷达/前视摄像头角度失准。\", \"chunk_id\": \"xia_p136_c240\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"278\", \"context_chunk_ids\": [\"xia_p136_c239\", \"xia_p136_c240\", \"xia_p137_c241\"], \"page_number_start\": \"277\"}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=xia_p97_c170 page=238-238]\\n温馨提示\\n\\n- 若点触提示框后无法切换至 ICC，则提示框会显示暂无法切换的文字提示，数秒后消失。驾驶员可以等待数秒，检查车辆满足切换至 ICC 的条件后重试。\\n- ■ 切换至 ICC 后，驾驶员再次点触提示框，可以重新切换回 NOA。\\n\\n使用领航辅助图标升降级：驾驶员快速双击（5秒内）中控导航地图界面的▲图标，功能将会从NOA降级到ICC，且系统不会主动恢复至NOA。如驾驶员在功能降级至ICC后，再次单击图标，系统会恢复至NOA。\\n\\n- NOA 功能可能在不满足使用条件的情况下主动降级。\\n- ■ 再次满足条件后，功能会主动升级。\\n\\n[seed chunk_id=xia_p98_c171 page=239-239]\\n警告\\n\\n- ■ 驾驶员应充分了解 ICC 和 NOA 的差异后，再决定是否切换至 ICC。\\n- 驾驶员应充分了解，ICC 的基本功能是辅助驾驶员控制车辆保持在车道中央区域行驶，无法像 NOA 一样辅助驾驶员控制车辆沿导航行驶、限速辅助、变道辅助等。切换至 ICC 后，驾驶员应根据行驶目的地实际道路状况来控制车辆的行驶路线和速度，并在情况变化时及时调节，始终确保安全驾驶。\\n- ■ 驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n[neighbor chunk_id=xia_p98_c172 page=239-239]\\n干预和控制\\n\\n- NOA 使用过程中，驾驶员可以根据实际交通情况干预方向盘、干预加速踏板以及控制车辆。\\n- 在经过路口、变道、脱困避让等场景时，驾驶员可以在使用 NOA 的过程中短时间主动转动方向盘来临时控制车辆的行驶方向。\\n- 干预方向盘期间，系统不再辅助驾驶员控制行车方向，且不会对机动车交通信号灯的信号做出反应，不会因为路口的机动车交通信号灯为红灯而减速或刹停。\\n- ■ 干预方向盘期间仪表显示屏上显示的蓝色高亮自车行驶轨迹会消失，NOA 图标变为灰色（▲）闪烁，伴有弹窗、提示音和语音播报。\\n- ■ 干预方向盘后，请确保车辆已在车道中央行驶且 NOA 已恢复后，再停止干预方向盘。\\n- 长时间干预方向盘会导致仪表显示屏和声音提示逐步升级，若干预方向盘超过规定时长会导致 NOA 主动退出。主动退出 NOA 前，系统会发出连续告警音，并升级弹窗和语音播报。此时，驾驶员应立即轻踩刹车控制车辆。若驾驶员始终未控制车辆，则系统提示会升级为请立即控制车辆并主动退出 NOA，驾驶员需及时响应，主动控制车辆方向和速度，确保安全驾驶。\", \"chunk_id\": \"xia_p98_c171\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"239\", \"context_chunk_ids\": [\"xia_p97_c170\", \"xia_p98_c171\", \"xia_p98_c172\"], \"page_number_start\": \"239\"}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=xia_p183_c316 page=324-325]\\nESC 系统操作说明\\n\\nESC 系统工作时\\n\\n● 如果车辆在斜坡上启动时有打滑或倒退的危险，或任何一个驱动轮有空转，则 ESC 指示灯闪烁，表示 ESC 系统正在工作。\\n\\n■ 禁用 ESC 系统\\n\\n● 如果车辆陷入积雪或泥地中，ESC 系统可能会降低从发动机输出至车轮的动力。您可能需要关闭该系统以便摆脱陷车困境。\\n\\n关闭 ESC 系统\\n\\n- - 需要关闭 ESC 系统时，用户可通过点击中控屏→设置 →驾驶→驾驶控制→电子车身稳定系统关闭按键，选择关闭此功能。此外，ESC 会实时检查其工作状态。如果 ESC 系统正在工作，此时按下电子车身稳定关闭按键关闭 ESC 系统，ESC 系统不会立即执行此“关闭”命令，而是先完成这一次的主动干预控制，干预控制完成后，ESC 系统才会执行电子车身稳定关闭的命令。\\n- - 当电子车身稳定系统关闭后，如果再次点击“电子车身稳定系统关闭”按键或者车速超过阈值(80km/h)，被关闭的 ESC 系统部分功能将会重新打开。为了避免 ESC 系统功能打开的过于突然，只有在 ESC 系统没有处于车辆动态干预保留的状态下才能重新激活 ESC 系统功能。\\n\\n■ 重新启动 ESC 系统\\n\\n- 关闭 ESC 系统后，重新启动车辆将自动再启动 ESC 系统。\\n\\nESC 系统的启动与车速联动\\n\\n如果 ESC 系统被关闭，在车速增加并超过阈值(80km/h)时，车辆变得极其不稳定，此时 ESC 系统将会自行启动。\\n\\nESC 系统激活时\\n\\n如果 ESC 故障指示灯闪烁，请谨慎驾驶。\\n\\nESC 系统关闭时\\n\\n应特别小心，并以与路况相适合的车速驾驶，ESC 系统能保证车辆的稳定性和驱动力，如无必要，请勿关闭。\\n\\n更换轮胎\\n\\n- ● 确保所有轮胎具有相同尺寸、品牌、胎面花纹和总负载量。另外，确保将轮胎充气至建议的胎压。\\n- 如果车辆混装了不同的轮胎，则 ABS 和 ESC 系统将无法正常工作。\\n- 有关更换轮胎或车轮的详情，建议联系比亚迪汽车授权服务店。\\n\\n轮胎和悬架的处理\\n\\n- 使用有任何问题的轮胎或改装悬架都将对驾驶安全系统造成影响，并可能引起该系统的故障。\\n\\n[seed chunk_id=xia_p184_c317 page=325-325]\\n防抱死制动系统\\n\\nABS 液压系统有两个独立的回路。每个回路都沿着对角线方向穿过车辆(左前轮制动器与右后轮制动器连接等)。若一个回路出了问题，仍然有两个车轮能被制动。\\n\\nABS 在突然施加制动时或在湿滑路面行驶施加制动时，有助于防止车轮抱死，从而有助于保持转向控制。\\n\\nABS 工作时，仪表 ESC 指示灯将闪烁，您将会感到制动踏板振动，并且可能会听到噪声。这是正常现象，是 ABS 正在脉动式快速制动的缘故。此时，应一直踩下制动踏板，切勿脉动式地反复踩踏制动踏板，否则，会使 ABS 无法正常工作。在打转向盘回避危险时，应该一直保持给制动踏板一个有力而稳定的踏板力，以便 ABS 发挥作用。\\n\\n[neighbor chunk_id=xia_p185_c318 page=326-326]\\n警告\\n\\n■ 下列情况下，ABS 不能有效工作：\\n\\n- - 使用了抓地力不足的轮胎(如在积雪覆盖的路面上使用磨损过度的轮胎)。\\n- ● 高速行驶在湿滑路面时车辆打滑。\\n\\n■ ABS 并非为缩短车辆的制动距离而设计。下列情况下，务必与前方行驶的车辆保持安全距离：\\n\\n- - 在湿滑、泥泞、砂石或积雪路面上行驶时。\\n- - 在多坑路面或不平路面行驶时。\\n- - 在颠簸路面行驶时。\\n\\n注意\\n\\n- ■ 如果制动系统警告灯点亮的同时，ABS 故障警告灯仍然点亮，立刻将车辆停在安全的地方，建议与比亚迪汽车授权服务店联系。\\n- 在这种场合制动时不但防抱死制动系统不起作用，且车辆也将变得极端不稳定。\\n- ABS(防抱死制动装置)不能减少刹住车辆所需要的时间与距离。该装置只是在制动时帮助您控制转向。您始终都应与其他车辆保持安全的车距。\\n- ABS 不能防止稳定性的降低。紧急制动时，转向要适度。行驶中大转弯或急转弯，可能使车辆转向迎面而来的车流或者冲出路面。\\n- ABS 不能防止由于突然改变方向所造成的打滑，比如试图快速地拐弯或突然变换车道。不论路面情况及天气条件如何，都应始终谨慎地以安全速度驾驶车辆。\\n- 在湿滑或松软或者凹凸不平的路面(如积水水泥路面或积水环氧油漆路面或砂石或积雪路面等)上行驶时，与没有ABS的车辆相比，配备有ABS的车辆有可能需要更长的制动距离。在此类情况下，应降低车速，并与其他车辆保持较大的车距。\", \"chunk_id\": \"xia_p184_c317\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"防抱死制动系统\", \"page_number_end\": \"325\", \"context_chunk_ids\": [\"xia_p183_c316\", \"xia_p184_c317\", \"xia_p185_c318\"], \"page_number_start\": \"325\"}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p108_c191 page=249-249]\\n侧边距离提醒工作示例\\n\\n[seed chunk_id=xia_p109_c192 page=250-250]\\n第1条：\\n大致距离(cm)：约31~50\\n报警声：/\\n\\n第2条：\\n大致距离(cm)：约0~30\\n报警声：/\\n\\n[neighbor chunk_id=xia_p109_c193 page=250-250]\\n注意\\n\\n- 0~200mm 为系统盲区，探测精度差，报警提示信息不够准确，因此此段距离的报警提示仅供参考。\\n- ■ 不同挡位下，报警距离存在差异，请谨慎驾驶。\\n- 当驻车辅助系统异常时，仪表屏会进行不可用的弹窗提示，如“泊车雷达系统暂不可用”等。\\n- 当车辆处于涉水模式*、浮水模式*、深雪模式*、极限续航*、洗车模式*、驾驶辅助节能模式时，驻车辅助系统无法工作。\\n- 若周边无障碍物，而报警现象持续存在，建议到比亚迪汽车授权服务店进行检修。\", \"chunk_id\": \"xia_p109_c192\", \"chunk_type\": \"table\", \"source_file\": \"xia.pdf\", \"section_title\": \"视觉提示和声音报警\", \"page_number_end\": \"250\", \"context_chunk_ids\": [\"xia_p108_c191\", \"xia_p109_c192\", \"xia_p109_c193\"], \"page_number_start\": \"250\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p44_c073 page=185-186]\\n正确使用空调系统\\n\\n● 加热和制冷过程是非常耗能的，会明显减少续驶里程和增大耗油量，合理的使用空调系统能有效的降低耗电量和耗油量。\\n\\n关闭暂时不需要的功能\\n\\n- 车内加热装置会消耗大量电能(例如座椅加热*等)，当不需要这些功能时，应将其关闭。\\n\\n温馨提示\\n\\n- ■ 磨合期间，车辆不要大负荷运行，车速不能超过最高车速。\\n- 有加速需求时建议缓加油门，减少急加油门对车辆带来的损耗。\\n\\n云辇-C*\\n\\n云辇-C 系统是一种电控减振器悬架系统，云辇-C 系统通过控制电控减振器阻尼力调节乘坐舒适性和操作稳定性。用户可通过点击中控屏→应用中心→云辇 App，进入云辇模式设置界面，选择“舒适”/“运动”模式设置项。\\n\\n[seed chunk_id=xia_p45_c074 page=186-187]\\n舒适控制\\n\\n- 舒适控制功能：车辆加速和减速时由于载荷转移产生俯仰动作，通过对车辆电控悬架阻尼和制动末端压力协调融合控制抑制车辆俯仰，提高乘坐舒适性。\\n- 用户可通过点击中控屏→应用中心→云辇 App，进入舒适控制设置界面，选择“偏弱”/“适中”/“较强”模式设置项。\\n\\n注意\\n\\n车辆在紧急制动情况下，功能效果可能会降低。\\n\\n换挡操纵机构\\n\\n- 换挡操纵机构挡位标示在换挡手柄上，上下拨动手柄进行“R”、“N”、“D”挡切换，按下右侧按键切换至“P”挡。\\n- 启动车辆后，踩下制动踏板并向上或向下拨动换挡手柄，即可从“P”挡切换至其他挡位。\\n- “P”挡是驻车挡，按下“P”挡按键，可实现驻车。\\n\\n警告\\n\\n■ 按下“P”挡按键时，为了避免造成伤害，必须在车辆完全停止后再按下“P”挡按键。\\n\\n- “R”挡是倒车挡，必须在车辆完全停止后方可使用。\\n- “N”挡是空挡，作为临时停车时使用。无论出于什么原因，只要离开车辆，须切换至驻车挡。\\n- “D”挡是行车挡，正常行驶时使用此挡位。\\n- 换挡成功后，手松开，换挡杆自动回到中间位置。\\n- 必须在电源“OK”挡下才能将挡位切换至行驶挡。\\n- - 挂出“P”挡或切换至行驶挡位需要同时踩制动，详细操作可参考仪表提示。\\n\\n[neighbor chunk_id=xia_p46_c075 page=187-187]\\n警告\\n\\n- 如关闭电机并切换至“N”挡后仍让车辆长时间移动，变速箱可能因无法得到润滑而严重受损。\\n- 如发动机或电机运转且已切换至“R”/“D”挡时，务必踩住制动踏板停止车辆，因为即使在怠速工况下，传动器仍可传递动力，车辆可能缓慢前行。\\n- 车辆行驶时如换挡，切勿踩加速踏板，谨防发生事故。\\n- 车辆行驶中切勿将换挡手柄切换至“R”挡或按下“P”挡按键，谨防发生事故。\\n- ■ 请勿在“N”或“P”挡时，将车辆沿斜坡下行。\\n- 为了防止车辆无意间移动，车辆停稳后请按下“P”挡按键，“P”挡切换成功后如电子驻车指示灯未点亮，则需要通过中控屏手动拉起电子驻车，以确保车辆安全。\", \"chunk_id\": \"xia_p45_c074\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"舒适控制\", \"page_number_end\": \"187\", \"context_chunk_ids\": [\"xia_p44_c073\", \"xia_p45_c074\", \"xia_p46_c075\"], \"page_number_start\": \"186\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"context_chunk_ids\": [\"xia_p9_c017\", \"xia_p10_c018\", \"xia_p10_c019\"], \"page_number_start\": \"151\"}, {\"score\": 0.016923076923076926, \"content\": \"[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\\n\\n[seed chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[neighbor chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\", \"chunk_id\": \"xia_p12_c021\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"153\", \"context_chunk_ids\": [\"xia_p11_c020\", \"xia_p12_c021\", \"xia_p12_c022\"], \"page_number_start\": \"153\"}]',5,16863,1,NULL,'2026-06-22 22:40:46'),(28,1,NULL,NULL,NULL,'简单回答','根据用户手册资料，家用便携式交流充电与公共交流充电桩充电的主要区别如下：\n\n1. **供电设备与连接方式**\n   - **家用充电**：使用专用的“三转七”连接装置，需插入符合标准的家用插座（推荐220V 10A专用线路/插座）。\n   - **公共桩充电**：直接使用场站的供电接口。部分桩已配备充电枪；若桩未配枪，需自备“七转七”交流充电连接器进行转接。\n\n2. **启动/停止操作细节**\n   - **家用充电**：即插即用，连接后三转七指示灯会闪烁/常亮。使用期间需注意在车机端开启“充电防盗”。\n   - **公共桩充电**：若公共桩带有设置选项，通常需刷卡或扫描二维码完成授权/支付（无选项的可跳过）。结束充电时，若使用了七转七，规范顺序为**先拔出充电枪，后拔出供电插头**。\n\n3. **设备归位与维护**\n   - **家用充电**：使用完毕后由车主自行整理线缆并妥善放置。\n   - **公共桩充电**：通常需将充电枪放回充电桩/盒的指定挂架位置。特别提醒：“七转七”设备严禁跌落或直接拉扯线缆移动，使用后需轻拿轻放并存放在阴凉处。\n\n⚠️ **安全提醒**：充电涉及高压用电，请务必确保供电插头、充电枪及车辆充电口的金属端子干燥、洁净、无锈蚀烧蚀，雨天需注意对设备进行防水保护，严禁湿手触摸裸露金属部分。若遇电锁无法拔枪、设备异常等情况，请以车辆实际提示为准，并及时联系比亚迪授权服务店检修。','xia.pdf','[{\"score\": 0.03114754098360656, \"content\": \"[neighbor chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p10_c019\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示\", \"page_number_end\": \"152\", \"context_chunk_ids\": [\"xia_p10_c018\", \"xia_p10_c019\", \"xia_p11_c020\"], \"page_number_start\": \"151\"}, {\"score\": 0.030049627791563276, \"content\": \"[neighbor chunk_id=xia_p7_c014 page=148-148]\\n充电方法\\n\\n充电前检查：\\n\\n- ● 确保供电设备、充电枪、充电口、充电连接装置等没有电缆磨损、端口生锈、壳体破裂或端口内有异物等异常情况。\\n- - 当供电插头/供电插座或充电枪/充电口的金属端子因生锈、腐蚀、烧蚀而造成有损坏或连接松动时。\\n- - 当充电枪/充电口和供电插头/供电插座有明显污渍或潮湿时，请用干燥清洁的布擦拭，确保连接处干燥、洁净。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n■ 下雨充电时，请注意对充电装置进行保护，避免进水。\\n\\n[seed chunk_id=xia_p7_c015 page=148-149]\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- ■ 交流充电连接装置可将车辆与家用标准(220V 50Hz 10A 单相两极带地)插座相连，为车辆充电。\\n- 该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n- 供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n- ■ 推荐使用 220V 10A 的专用交流线路和电源插座。\\n- ■ 设备规格：220V AC 50Hz 8A\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[neighbor chunk_id=xia_p8_c016 page=149-150]\\ni 温馨提示\\n\\n- 请联系比亚迪汽车授权服务店，按充电设备要求选择合适的电源。\\n- ■ 使用三转七充电时，注意开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n打开充电枪和充电口的保护盖^{*}，确保充电枪插头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n■ 将三转七插头插入家用插座中，三转七充电指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n- 将三转七的充电枪连接至充电口，并可靠锁止。\\n- 插好充电枪，组合仪表充电连接指示灯点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n- 车辆电量充满会自动结束充电。\\n- 如需提前结束充电直接进入下一步。\", \"chunk_id\": \"xia_p7_c015\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"家用便携式交流充电\", \"page_number_end\": \"149\", \"context_chunk_ids\": [\"xia_p7_c014\", \"xia_p7_c015\", \"xia_p8_c016\"], \"page_number_start\": \"148\"}, {\"score\": 0.02996031746031746, \"content\": \"[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\\n\\n[seed chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\\n\\n[neighbor chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\", \"chunk_id\": \"xia_p11_c020\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"153\", \"context_chunk_ids\": [\"xia_p10_c019\", \"xia_p11_c020\", \"xia_p12_c021\"], \"page_number_start\": \"152\"}, {\"score\": 0.0298859126984127, \"content\": \"[neighbor chunk_id=xia_p9_c017 page=150-150]\\n2. 断开充电口连接:\\n\\n- 若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n- 若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n- 整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n- 启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在 2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n- 电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p10_c018 page=151-151]\\ni 温馨提示(续)\\n\\n- 若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n- 电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n- - 单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n- - 使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n- 使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p10_c019 page=151-152]\\ni 温馨提示\\n\\n- 使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n- ■ 也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n- 若使用充电盒为车辆充电，则无需此步操作。\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七^{*}，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置:\\n\\n- 对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n- 对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯点亮。\", \"chunk_id\": \"xia_p10_c018\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"i 温馨提示(续)\", \"page_number_end\": \"151\", \"context_chunk_ids\": [\"xia_p9_c017\", \"xia_p10_c018\", \"xia_p10_c019\"], \"page_number_start\": \"151\"}, {\"score\": 0.021311475409836068, \"content\": \"[neighbor chunk_id=xia_p0_c001 page=141-141]\\n使用和驾驶\\n\\n4\\n\\n4-1 充/放电说明.... 143\\n\\n充电说明....143\\n\\n充电方法....148\\n\\n放电说明*...... 156\\n\\n电量平衡功能.... 161\\n\\n续航里程显示.... 163\\n\\n充电口电锁控制....164\\n\\n4-2 电池.....166\\n\\n动力电池....166\\n\\n低压蓄电池....168\\n\\n4-3 使用要领.....170\\n\\n磨合期.... 170\\n\\n挂车拖曳....170\\n\\n安全驾驶注意事项……170\\n\\n用车建议....171\\n\\n燃油....172\\n\\n如何节省燃油并延长车辆的使用\\n\\n寿命....174\\n\\n运载行李....176\\n\\n一氧化碳中毒的危险性……177\\n\\n车辆涉水....178\\n\\n预防火灾....179\\n\\n4-4 启动和驾驶..... 181\\n\\n启动车辆....181\\n\\n驾驶车辆....183\\n\\n低油耗驾驶车辆....184\\n\\n云辇-C^{*}186\\n\\n[seed chunk_id=xia_p1_c002 page=142-142]\\n4 使用和驾驶\\n\\n换挡操纵机构.... 186\\n\\n电子驻车(EPB)...... 187\\n\\n自动驻车(AVH)....191\\n\\n驾驶要领....193\\n\\n4-5 驾驶辅助功能......197\\n\\n驾驶辅助系统简介……197\\n\\n行车辅助....206\\n\\n泊车辅助....247\\n\\n前向安全辅助…… 275\\n\\n侧向安全辅助.... 291\\n\\n后向安全辅助…… 302\\n\\n驾驶辅助拓展功能……309\\n\\n灯光系统....311\\n\\n驾驶员监测辅助(DMS)*..313\\n\\n胎压监测....316\\n\\n低速提示音(AVAS)......318\\n\\n儿童遗留检测(CPD)*......319\\n\\n驾驶安全系统…… 321\\n\\n[neighbor chunk_id=xia_p1_c003 page=142-143]\\n4-6 其他主要功能说明.... 327\\n\\n行车记录仪*......327\\n\\n车载 ETC* 329\\n\\n充电说明\\n\\n充电安全警告\\n\\n- ■ 禁止未成年人进行充电作业或触摸使用充电设备，充电枪为高压用电器件，在充电时请勿让未成年人靠近。\\n- 请选择在相对较安全的环境下充电，如避免有危化液体、火源、热源、雷电、易燃易爆等环境。\\n- 严禁湿手操作，触摸充电口或充电座的裸露金属，否则可能引起触电、电击，造成人身伤害。\\n- 由于充电可能影响医疗电子设备，甚至造成严重的人身伤害或者死亡，如果您使用任何医疗电子设备(如可移植心脏起搏器或者可移植心脏血管去纤颤器)，在启动充电操作之前与医疗电子设备的制造商确认充电是否影响设备的正常工作。\", \"chunk_id\": \"xia_p1_c002\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"4 使用和驾驶\", \"page_number_end\": \"142\", \"context_chunk_ids\": [\"xia_p0_c001\", \"xia_p1_c002\", \"xia_p1_c003\"], \"page_number_start\": \"142\"}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=xia_p188_c321 page=329-329]\\n车载 ETC*\\n\\n车载 ETC 介绍\\n\\n电子不停车收费系统(ETC)在出厂时已经在车内预装，不影响车窗美观度，无须插卡。激活后，可帮助本车实现过高速不停车电子收费。车载ETC可与DiLink系统互联互通，支持车主在车机开关ETC功能。\\n\\n激活方法\\n\\n- 1. 用户可通过点击中控屏→应用中心→ETC，调出二维码，使用比亚迪 App 扫描多媒体触摸屏上的二维码，按照提示上传驾驶证、身份信息等资料，选择自动扣款方式；\\n- 2. 在车机 ETC 激活引导界面中点击“开启 ETC 蓝牙”，并保持手机蓝牙开启，在 App 端验证设备列表中选择本车 ETC 蓝牙名称完成激活。\\n\\n使用方法\\n\\n车载 ETC 内载有车辆信息，汽车在经过收费站时，可行驶至 ETC 专用收费通道，无须停车，收费站机器自动感应抬闸，车辆即可通过。通行费将从您设置的缴费渠道中自动扣除。\\n\\n[seed chunk_id=xia_p188_c322 page=329-329]\\n温馨提示\\n\\nETC 仅支持个人账号开通使用。\", \"chunk_id\": \"xia_p188_c322\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"329\", \"context_chunk_ids\": [\"xia_p188_c321\", \"xia_p188_c322\"], \"page_number_start\": \"329\"}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=xia_p33_c053 page=174-174]\\n警告\\n\\n■ 燃油易燃烧和爆炸，加注燃油时，应注意以下事项：\\n\\n- ● 建议在室外加注燃油。\\n- - 在加燃油时，禁止吸烟，以防止产生火花或明火，明火容易引起燃烧。\\n- ● 加油与充电不得同时进行，在插上充电枪时，不要加油并且应与易燃品保持足够的安全距离，否则在未按规定插拔充电枪时存在设备受损和人员受伤的危险，例如燃烧的燃油。\\n\\ni 温馨提示\\n\\n- 在加油枪自动切断后，应停止加油。严禁将油箱加得太满，应留出温度变化时燃油膨胀的空间。\\n- ■ 加注燃油完成后应及时检查燃油箱盖和加油口盖是否关紧。\\n- ■ 如果燃油箱盖未拧紧，可能会导致仪表上 🔍 点亮。\\n- 如果加油口盖打开 15min 内未完成燃油加注，请将加油口盖板关闭后再次打开，然后再加注燃油，否则加油时可能会出现油液反喷现象。\\n\\n[seed chunk_id=xia_p33_c054 page=174-176]\\n如何节省燃油并延长车辆的使用寿命\\n\\n节省燃油是简单的也是轻松的，这也有助于延长车辆的使用寿命。以下是一些节省燃油和修理费的要领：\\n\\n- - 匀速驾驶有助于节省燃油。急加速、急转弯及急刹车都将消耗更多的燃油。\\n- - 根据交通状况，尽量保持匀速。车辆的每次减速或加速都将额外地消耗燃油。\\n- 在适当的驾驶条件下，使用定速巡航控制能更节省燃油。\\n\\n[neighbor chunk_id=xia_p33_c055 page=174-176]\\n- - 空调的开启使发动机增加额外的负荷，从而消耗更多的燃油。关闭空调，以减少燃油消耗。当车外大气温度适宜时，应采用外循环模式通风。\\n- - 保持正确的轮胎气压。轮胎气压的不足将导致轮胎磨损和燃油浪费。\\n- 请勿在车辆上装载不需要的重量。过多的重量，将增加发动机的负荷量，导致消耗大量的燃油。\\n- 切勿停车预热发动机，启动后应立即起步缓慢行驶，这样做可以使发动机尽快达到工作温度，并能减少有害物质的排放。除非是在极端低温环境，可以在 HEV-运动模式及 N 挡下用轻踩加速踏板保持较高的怠速，暖车后即可起步缓慢行驶。\\n- ● 发动机处于冷态时，启动后，切勿马上高速运转或大油门行驶，以防损坏发动机。\\n- ● 避免发动机长时间空转。如果在交通不繁忙的地区而又要长时间等人，则最好关闭发动机，过后再启动。\\n- - 避免发动机加载减速或超速运转。应根据行车的路面条件来选择适当的速度挡位。\\n- 避免连续不断的加速和减速。停停走走的驾驶方式将浪费燃油。\\n- 避免不必要的停车或制动。保持平稳的车速，配合交通信号灯进行驾驶，即可将停车的次数减到最少的程度；或利用无交通信号灯的通行大道行驶，与前车应保持适当的行驶距离来避免紧急制动，这也将减少制动器的磨损。\\n- - 尽可能避开交通繁忙或交通堵塞的道路。\\n- - 脚不要长时间放在制动踏板上，这将引起过早的磨损、过热和消耗大量燃油。\\n- 在高速公路上应保持适当的车速。车速越高，耗油量也就越多。将车速保持在经济时速范围内，可节省燃油。\\n- 前轮应保持正确的定位。避免碰撞路边侧石，在崎岖路面上要缓慢驾驶。前轮定位不准，不仅会引起轮胎的过快磨损，还会使发动机增加负荷，也就是会增加油耗。\\n- ● 车底盘应保持洁净、没有泥浆等物。这不但可以减轻车身的重量，也可防止腐蚀。\", \"chunk_id\": \"xia_p33_c054\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"如何节省燃油并延长车辆的使用寿命\", \"page_number_end\": \"176\", \"context_chunk_ids\": [\"xia_p33_c053\", \"xia_p33_c054\", \"xia_p33_c055\"], \"page_number_start\": \"174\"}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p108_c191 page=249-249]\\n侧边距离提醒工作示例\\n\\n[seed chunk_id=xia_p109_c192 page=250-250]\\n第1条：\\n大致距离(cm)：约31~50\\n报警声：/\\n\\n第2条：\\n大致距离(cm)：约0~30\\n报警声：/\\n\\n[neighbor chunk_id=xia_p109_c193 page=250-250]\\n注意\\n\\n- 0~200mm 为系统盲区，探测精度差，报警提示信息不够准确，因此此段距离的报警提示仅供参考。\\n- ■ 不同挡位下，报警距离存在差异，请谨慎驾驶。\\n- 当驻车辅助系统异常时，仪表屏会进行不可用的弹窗提示，如“泊车雷达系统暂不可用”等。\\n- 当车辆处于涉水模式*、浮水模式*、深雪模式*、极限续航*、洗车模式*、驾驶辅助节能模式时，驻车辅助系统无法工作。\\n- 若周边无障碍物，而报警现象持续存在，建议到比亚迪汽车授权服务店进行检修。\", \"chunk_id\": \"xia_p109_c192\", \"chunk_type\": \"table\", \"source_file\": \"xia.pdf\", \"section_title\": \"视觉提示和声音报警\", \"page_number_end\": \"250\", \"context_chunk_ids\": [\"xia_p108_c191\", \"xia_p109_c192\", \"xia_p109_c193\"], \"page_number_start\": \"250\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p28_c047 page=169-169]\\n智能充电功能\\n\\n- 当低压蓄电池电量低时，会触发智能充电功能，以延长低压蓄电池续航时长。\\n- 当动力电池电量低时，车辆可能启动发动机发电，以满足智能充电功能需求。\\n- 本车具有智能充电功能，长时间停放时，无需断开低压蓄电池负极。\\n\\ni 温馨提示\\n\\n- 低压蓄电池电量低时会触发智能充电功能，导致仪表显示动力电池SOC或纯电续航里程下降，属于正常现象。\\n- ■ 锁车后，动力电池电量低至触发启动发动机发电功能时，会消耗少量燃油，并有少量废气排出。\\n\\n[seed chunk_id=xia_p29_c048 page=170-170]\\n磨合期\\n\\n- 如果动力总成难以启动或经常停止转动，须立刻检查车辆。\\n- ■ 如果动力总成有异常的响声，应停车检查。\\n- 如果动力总成有严重的冷却液、润滑油泄露现象，应停车检查。\\n- ■ 动力总成需要进行磨合，建议 HEV-经济模式下的最初 2000km 进行磨合，平稳驾驶，避免高速驾驶，遵守以下的简单要领，可有效延长车辆的使用寿命：\\n\\n- 在启动和驾驶时，避免将加速踏板踩到底。\\n- - 使用过程中避免车辆超速行驶。\\n- - 在最初的 300km 之内，避免紧急制动。\\n- - 不要以单一的速度长时间地进行快速或慢速行驶。\\n- - 磨合期 HEV 模式驾驶里程数(发动机参与工作)不少于总里程数的 50%。\\n\\n[neighbor chunk_id=xia_p29_c049 page=170-171]\\n挂车拖曳\\n\\n- 本车主要是为运载乘客而设计的，为了自己和他人的安全，请勿过载或拖车。\\n- 拖曳挂车，将对车辆的操纵、性能、制动、耐久、经济驾驶以及能耗等各方面产生不良影响。\\n- ■ 驾驶的安全和舒适，完全依靠设备的正确使用和养成小心驾驶的习惯。\\n- 因拖曳挂车造成的损坏或故障不在保修范围之内。\\n\\n安全驾驶注意事项\\n\\n严禁酒后驾车\\n\\n即使少量饮酒也会降低您对道路交通条件变化的应变能力，饮酒越多，反应越迟钝，因此，严禁酒后驾车。\\n\\n控制车速\\n\\n超速是发生撞车伤亡事故的主要原因，一般来说，速度越快危险性就越大，请您根据道路交通情况保持安全车速。\", \"chunk_id\": \"xia_p29_c048\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"磨合期\", \"page_number_end\": \"170\", \"context_chunk_ids\": [\"xia_p28_c047\", \"xia_p29_c048\", \"xia_p29_c049\"], \"page_number_start\": \"170\"}, {\"score\": 0.016923076923076926, \"content\": \"[neighbor chunk_id=xia_p11_c020 page=152-153]\\n温馨提示\\n\\n- 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n- 此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n- 若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n- 若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n■ 若使用充电盒为车辆充电，则无需此步操作。\\n\\n- 4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n- 5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\\n\\n[seed chunk_id=xia_p12_c021 page=153-153]\\n警告\\n\\n■ 七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n- 为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n- 为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n- 使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n- ■ 设备规格：请查看充电机相关说明。\\n- 充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[neighbor chunk_id=xia_p12_c022 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖:\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n■ 打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n■ 将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电:\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯s点亮。\\n\\n■ 充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n停止充电操作指南\\n\\n1. 结束充电:\\n\\n■ 直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接:\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\", \"chunk_id\": \"xia_p12_c021\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"153\", \"context_chunk_ids\": [\"xia_p11_c020\", \"xia_p12_c021\", \"xia_p12_c022\"], \"page_number_start\": \"153\"}]',5,17699,1,NULL,'2026-06-22 22:41:27'),(29,1,NULL,NULL,NULL,'汉车的雨刷功能怎么开启？','根据《用户手册》资料，开启和操作汉车型雨刮功能的具体方法如下：\n\n### 🔧 开启与操作方法\n1. **手动/档位控制**\n   通过方向盘右侧的**雨刮控制杆**上下拨动，可选择以下5个档位：\n   - 自动雨刮1挡 / 间歇挡位1挡\n   - 自动雨刮2挡 / 间歇挡位2挡\n   - 低速刮水模式\n   - 高速刮水模式\n   - 前雨刮关闭\n   *(注：低速与高速档位时，雨刮会连续刮水)*\n\n2. **开启自动雨刮（雨量感应模式）**\n   - 路径：在中控屏依次点击 **【设置】→【驾驶】→【舒适用车】**，打开“自动雨刮开关”。\n   - 效果：系统激活后，雨刮会先刮刷一次作为初始化，随后进入自动档，根据实际雨量自动调节刮刷频率。\n   - 灵敏度调节：处于自动雨刮档位时，可直接**旋转雨刮开关旋钮**调高或调低感应灵敏度。\n\n3. **临时点刮与喷水清洗**\n   - **点刮模式**：向驾驶员方向**按压**控制杆端部按键至第一档位置，雨刮将低速刮水，直至松开按键即停。\n   - **喷水洗涤**：**按压**控制杆端部按键至第二档位置，洗涤器持续喷水，雨刮随即开始工作；松开控制杆或持续按压超过10秒时，喷水停止，雨刮会继续刮刷1~2个循环后自动复位。\n\n### ⚠️ 重要安全提示（依据手册）\n- **防误触警告**：电源处于“OK”挡且开启自动雨刮时，切勿用手或布擦拭传感器上部的挡风玻璃区域，否则极易引发雨刮意外运转，造成危险。\n- **干燥/洗车环境**：在洗车、较干燥季节或无雨天气时，请**务必关闭自动雨刮功能**，以免传感器干摩擦或误判导致雨刮无意间频繁运转，损坏橡胶刮片。\n- **雪天特别注意**：雪花形状可能导致雨量传感器无法正常感知或延迟响应，雪融化后还可能触发自动刮刷。如遇积雪导致雨刮中途卡滞，请立即关闭雨刮，将车停至安全地点清理杂物后再恢复使用。\n\n📢 **温馨提示**：以上操作均以车辆当前配置及实际显示为准。涉及行车视线与安全辅助功能的操作，请注意路况安全，如有异响、刮不净或功能受限等异常，建议优先参考仪表提示并及时联系比亚迪授权服务店检测。','han.pdf','[{\"score\": 0.05245901639344262, \"content\": \"[neighbor chunk_id=han_p101_c113 page=101-102]\\n警告\\n\\n电源挡位处于“OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n注意\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压操作杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开为止。\\n\\n[seed chunk_id=han_p102_c114 page=102-103]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压操作杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n松开控制杆或者持续操作的时间超过10s时，洗涤器将停止喷水，雨刮刮刷1~2个循环后停止工作。\\n\\n更换雨刮\\n\\n至少每六个月检查一次雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n注意\\n\\n请勿在雨刮器臂被拉起时打开前舱盖，否则会损坏前舱盖和雨刮器臂。\\n\\n更换雨刮片\\n\\n整车电源在“ON”挡或“OK”挡，用户可通过中控屏→设置 →DiLink→检修设置界面开启雨刮检修功能，开启后雨刮会运行至高位后停止，以便于检修和更换雨刮；检修完毕后关闭雨刮检修功能，雨刮会回到复位位置。\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①\\n\\n3. 握住刮片卡扣处，沿图示方向②将刮片取出。\\n\\n4. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n[neighbor chunk_id=han_p103_c115 page=103-104]\\n注意\\n\\n提起刮臂时，禁止打开前舱盖，否则会损坏前舱盖和刮水器臂。\\n\\n洗完车放下雨刮刮片时，禁止直接推雨刮刮臂让刮片直接撞击到风窗玻璃上。\\n\\n禁止折弯雨刮刮片、雨刮运行时禁止阻挡雨刮刮片。\\n\\n关于雨刮保养详见雨刮器刮片保养\\n\\n内后视镜\\n\\n手动调节内后视镜\\n\\n上下、左右转动内后视镜，将内后视镜调至合适位置。\\n\\n警告\\n\\n请在车辆行驶前调节好内后视镜。应避免行驶过程中调节内后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n请勿在内后视镜上悬挂重物，或用力摇晃、拖拽。\\n\\n手动调节内后视镜时，若有卡顿情况切勿暴力调节，以免造成内后视镜脱落。\", \"chunk_id\": \"han_p102_c114\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"前风窗玻璃洗涤器\", \"page_number_end\": 103, \"context_chunk_ids\": [\"han_p101_c113\", \"han_p102_c114\", \"han_p103_c115\"], \"page_number_start\": 102}, {\"score\": 0.05133128520225295, \"content\": \"[neighbor chunk_id=han_p101_c112 page=101]\\n前风窗玻璃刮水器与洗涤器\\n\\n自动雨刮/间歇挡位\\n\\n控制杆用来控制风窗玻璃刮水器和洗涤器，此杆共分五个挡位：\\n\\n：自动雨刮1挡/间歇挡位1挡\\n\\n：自动雨刮 2 挡/间歇挡位 2 挡\\n\\n：低速刮水模式\\n\\n：高速刮水模式\\n\\n：前雨刮关闭\\n\\n如需选择挡位，上拨或下拨手柄即可。\\n\\n在低速与高速挡位时，雨刮连续刮水。\\n\\n一在中控屏→设置 →驾驶→舒适用车打开自动雨刮开关时，雨刮刮刷一次，然后进入自动雨刮挡位，雨刮根据雨量自动工作。\\n\\n在自动雨刮挡位时，旋转雨刮开关旋钮可调节自动雨刮挡位。\\n\\n[seed chunk_id=han_p101_c113 page=101-102]\\n警告\\n\\n电源挡位处于“OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n注意\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压操作杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开为止。\\n\\n[neighbor chunk_id=han_p102_c114 page=102-103]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压操作杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n松开控制杆或者持续操作的时间超过10s时，洗涤器将停止喷水，雨刮刮刷1~2个循环后停止工作。\\n\\n更换雨刮\\n\\n至少每六个月检查一次雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n注意\\n\\n请勿在雨刮器臂被拉起时打开前舱盖，否则会损坏前舱盖和雨刮器臂。\\n\\n更换雨刮片\\n\\n整车电源在“ON”挡或“OK”挡，用户可通过中控屏→设置 →DiLink→检修设置界面开启雨刮检修功能，开启后雨刮会运行至高位后停止，以便于检修和更换雨刮；检修完毕后关闭雨刮检修功能，雨刮会回到复位位置。\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①\\n\\n3. 握住刮片卡扣处，沿图示方向②将刮片取出。\\n\\n4. 新刮片装配时，按照取出刮片相反的步骤进行操作。\", \"chunk_id\": \"han_p101_c113\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"警告\", \"page_number_end\": 102, \"context_chunk_ids\": [\"han_p101_c112\", \"han_p101_c113\", \"han_p102_c114\"], \"page_number_start\": 101}, {\"score\": 0.03782242063492064, \"content\": \"[neighbor chunk_id=han_p99_c111 page=99-101]\\n转向迎宾功能*\\n\\n若整车OFF挡且左前门打开，则管柱从当前位置上倾缩回，方便驾驶员下车，待关门后管柱下倾伸出至之前位置。\\n\\n转向盘加热功能*\\n\\n用户可通过中控屏→座椅 →座椅加热或主页 →我的车→座椅加热，点击方向盘加热图标选择开启或关闭。\\n\\n–用户也可通过中控屏→空调 →通风加热，点击方向盘加热图标选择开启或关闭\\n\\n语音控制：唤醒语音功能，控制转向盘加热开启和关闭。\\n\\n注意\\n\\n每次开启转向盘加热，当达到目标温度后(38±2°)，将维持在目标温度。\\n\\n雨刮开关\\n\\n[seed chunk_id=han_p101_c112 page=101]\\n前风窗玻璃刮水器与洗涤器\\n\\n自动雨刮/间歇挡位\\n\\n控制杆用来控制风窗玻璃刮水器和洗涤器，此杆共分五个挡位：\\n\\n：自动雨刮1挡/间歇挡位1挡\\n\\n：自动雨刮 2 挡/间歇挡位 2 挡\\n\\n：低速刮水模式\\n\\n：高速刮水模式\\n\\n：前雨刮关闭\\n\\n如需选择挡位，上拨或下拨手柄即可。\\n\\n在低速与高速挡位时，雨刮连续刮水。\\n\\n一在中控屏→设置 →驾驶→舒适用车打开自动雨刮开关时，雨刮刮刷一次，然后进入自动雨刮挡位，雨刮根据雨量自动工作。\\n\\n在自动雨刮挡位时，旋转雨刮开关旋钮可调节自动雨刮挡位。\\n\\n[neighbor chunk_id=han_p101_c113 page=101-102]\\n警告\\n\\n电源挡位处于“OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n注意\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压操作杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开为止。\", \"chunk_id\": \"han_p101_c112\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"前风窗玻璃刮水器与洗涤器\", \"page_number_end\": \"101\", \"context_chunk_ids\": [\"han_p99_c111\", \"han_p101_c112\", \"han_p101_c113\"], \"page_number_start\": \"101\"}, {\"score\": 0.030049627791563276, \"content\": \"[neighbor chunk_id=han_p102_c114 page=102-103]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压操作杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n松开控制杆或者持续操作的时间超过10s时，洗涤器将停止喷水，雨刮刮刷1~2个循环后停止工作。\\n\\n更换雨刮\\n\\n至少每六个月检查一次雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n注意\\n\\n请勿在雨刮器臂被拉起时打开前舱盖，否则会损坏前舱盖和雨刮器臂。\\n\\n更换雨刮片\\n\\n整车电源在“ON”挡或“OK”挡，用户可通过中控屏→设置 →DiLink→检修设置界面开启雨刮检修功能，开启后雨刮会运行至高位后停止，以便于检修和更换雨刮；检修完毕后关闭雨刮检修功能，雨刮会回到复位位置。\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①\\n\\n3. 握住刮片卡扣处，沿图示方向②将刮片取出。\\n\\n4. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n[seed chunk_id=han_p103_c115 page=103-104]\\n注意\\n\\n提起刮臂时，禁止打开前舱盖，否则会损坏前舱盖和刮水器臂。\\n\\n洗完车放下雨刮刮片时，禁止直接推雨刮刮臂让刮片直接撞击到风窗玻璃上。\\n\\n禁止折弯雨刮刮片、雨刮运行时禁止阻挡雨刮刮片。\\n\\n关于雨刮保养详见雨刮器刮片保养\\n\\n内后视镜\\n\\n手动调节内后视镜\\n\\n上下、左右转动内后视镜，将内后视镜调至合适位置。\\n\\n警告\\n\\n请在车辆行驶前调节好内后视镜。应避免行驶过程中调节内后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n请勿在内后视镜上悬挂重物，或用力摇晃、拖拽。\\n\\n手动调节内后视镜时，若有卡顿情况切勿暴力调节，以免造成内后视镜脱落。\\n\\n[neighbor chunk_id=han_p104_c116 page=104-105]\\n手动防眩目内后视镜*\\n\\n手动防眩目内后视镜有普通和防眩两种工作模式：\\n\\n普通模式——将控制杆置于位置①，在此位置时，后视镜镜像最清晰。\\n\\n防眩模式——将控制杆置于位置②，在此位置时，能有效降低夜晚后方来车大灯光干扰。需注意，在降低眩光的同时，可能会令后方视野清晰度下降。\\n\\n自动防眩目内后视镜*\\n\\n自动防眩目内后视镜搭载了电子防眩功能，可以根据车辆周边环境对内后视镜镜片颜色进行自动调节，以减弱后方强眩光对驾驶员视野的干扰。\", \"chunk_id\": \"han_p103_c115\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"注意\", \"page_number_end\": 104, \"context_chunk_ids\": [\"han_p102_c114\", \"han_p103_c115\", \"han_p104_c116\"], \"page_number_start\": 103}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=han_p98_c110 page=98-99]\\n仪表/返回按键\\n\\n仪表非菜单模式时，按下仪表/返回按键，弹出仪表菜单。\\n\\n仪表菜单模式时，按下仪表/返回按键，返回上一级界面，无上一级界面则退出菜单。\\n\\n蓝牙通话界面时，短按结束通话。\\n\\n喇叭按键\\n\\n按下喇叭按键区域，喇叭鸣笛，松手后，喇叭停止鸣笛。\\n\\n注意\\n\\n请勿长时间按下喇叭按键区域，否则极易损坏喇叭。\\n\\n温馨提示\\n\\n请遵守交通法规，合理使用喇叭。\\n\\n转向盘手动调节*\\n\\n■调节转向盘的角度或轴向位置时，可握住转向盘，进行以下操作：\\n\\n●向下按转向盘调节手柄，将转向盘调节至需要的位置，然后将手柄恢复至原位。\\n\\n温馨提示\\n\\n车辆在行驶中，禁止调节转向盘，否则可能错误操纵车辆，导致意外事故发生。\\n\\n调节转向盘之后，需上下移动以确认转向盘被牢固锁定。\\n\\n转向助力模式设置\\n\\n转向助力手感因人而异，不同用户对转向助力手感评价及需求也不一样。\\n\\n■用户可通过中控屏→设置 →驾驶→驾驶控制进入“转向助力模式”设置界面，选择“舒适”/“运动”设置项。\\n\\n温馨提示\\n\\n车辆在高速行驶时，若感觉转向盘较轻，建议您将转向助力模式设置为运动模式。\\n\\n[seed chunk_id=han_p99_c111 page=99-101]\\n转向迎宾功能*\\n\\n若整车OFF挡且左前门打开，则管柱从当前位置上倾缩回，方便驾驶员下车，待关门后管柱下倾伸出至之前位置。\\n\\n转向盘加热功能*\\n\\n用户可通过中控屏→座椅 →座椅加热或主页 →我的车→座椅加热，点击方向盘加热图标选择开启或关闭。\\n\\n–用户也可通过中控屏→空调 →通风加热，点击方向盘加热图标选择开启或关闭\\n\\n语音控制：唤醒语音功能，控制转向盘加热开启和关闭。\\n\\n注意\\n\\n每次开启转向盘加热，当达到目标温度后(38±2°)，将维持在目标温度。\\n\\n雨刮开关\\n\\n[neighbor chunk_id=han_p101_c112 page=101]\\n前风窗玻璃刮水器与洗涤器\\n\\n自动雨刮/间歇挡位\\n\\n控制杆用来控制风窗玻璃刮水器和洗涤器，此杆共分五个挡位：\\n\\n：自动雨刮1挡/间歇挡位1挡\\n\\n：自动雨刮 2 挡/间歇挡位 2 挡\\n\\n：低速刮水模式\\n\\n：高速刮水模式\\n\\n：前雨刮关闭\\n\\n如需选择挡位，上拨或下拨手柄即可。\\n\\n在低速与高速挡位时，雨刮连续刮水。\\n\\n一在中控屏→设置 →驾驶→舒适用车打开自动雨刮开关时，雨刮刮刷一次，然后进入自动雨刮挡位，雨刮根据雨量自动工作。\\n\\n在自动雨刮挡位时，旋转雨刮开关旋钮可调节自动雨刮挡位。\", \"chunk_id\": \"han_p99_c111\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"转向迎宾功能*\", \"page_number_end\": \"101\", \"context_chunk_ids\": [\"han_p98_c110\", \"han_p99_c111\", \"han_p101_c112\"], \"page_number_start\": \"99\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=han_p301_c001 page=301]\\n温馨提示(续)\\n\\n●如您在使用驾驶辅助节能功能时需要 OTA，请先退出驾驶辅助节能功能，否则会导致OTA异常；\\n\\n行车辅助、泊车辅助及安全辅助等功能受限，能使用AVM全景影像；\\n\\n抬头显示安全辅助融合及导航融合功能受限；\\n\\n自适应前照灯的调节功能受限。\\n\\n路面预瞄*\\n\\n■路面预瞄*是一个检测车前方路面信息的感知系统，通过车前的摄像头实时监测识别路面情况，一旦发现坑洼、井盖和减速带时，就会提前调整主动悬架状态来吸收路面不平引起的车身颠簸，提高驾乘体验。\\n\\n[seed chunk_id=han_p301_c002 page=301-302]\\n温馨提示\\n\\n部分车型不支持路面预瞄功能，请以实车软件版本为准。\\n\\n功能设置\\n\\n驾驶员可通过中控屏→应用中心 →云辇App→悬架设置→路面预瞄或中控屏→设置 →DiPilot→行车辅助→路面预瞄，设置开启或关闭路面预瞄功能。车辆每次启动或恢复出厂设置后时，功能均默认为开启状态。\\n\\n路面预瞄功能运行的前提条件(以下条件需同时满足)\\n\\nPAD 上路面预瞄开关为“ON”挡。\\n\\n摄像头姿态正常且无遮挡及损坏。\\n\\n汽车行驶在常规路面(包括普通公路、高速路和水泥路等)。\\n\\n光照和车速条件满足以下三种情况：\\n\\n白天光线充足且无强光、眩光干扰的情况下，车速在0~100km/h。\\n\\n夜晚环境，路灯、车灯光线充足情况下，车速在0~80km/h。\\n\\n特殊气候和环境下（如小到中雨、小雪、薄雾等），车速在0~80km/h。\\n\\n[neighbor chunk_id=han_p302_c003 page=302]\\n系统局限性\\n\\n根据不同的道路和交通状况，路面预瞄功能在以下场景可能无法实现预期功能，包括但不限于：\\n\\n夜间道路光线不充足时；\\n\\n环境条件过于恶劣（如：暴雨、暴雪、沙尘暴等）时；\\n\\n摄像头有脏污、模糊不清、损坏或被遮挡时；\\n\\n有强光、太阳直射或者剧烈变化的环境光线下；\\n\\n路面没有光学结构或没有反射光线；\\n\\n驾驶时距离前车过近；\\n\\n某段路面的转弯半径过小；\\n\\n进行突然的驾驶操作，如急刹或突然加速。\\n\\n驾驶员监测辅助(DMS)\\n\\n驾驶员监测辅助系统包含疲劳驾驶提醒、分心驾驶提醒、手持打电话提醒等功能，主要通过驾驶员监测辅助系统摄像头拍摄车内环境照片，在车辆本地对驾驶员驾驶状态进行监测和判断(原始照片将在判断完成后立即删除，不会保存或者上传服务器)，根据判断结果及时提醒驾驶员谨慎驾驶，注意行车安全。\", \"chunk_id\": \"han_p301_c002\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"302\", \"context_chunk_ids\": [\"han_p301_c001\", \"han_p301_c002\", \"han_p302_c003\"], \"page_number_start\": \"301\"}, {\"score\": 0.016923076923076926, \"content\": \"[neighbor chunk_id=han_p381_c106 page=381]\\n警告\\n\\n■无论何时检修空调系统，都应要求检修站保证使用冷媒再循环设备。该设备可回收冷媒进行再利用，将冷媒释放于大气中会污染环境。\\n\\n雨刮器刮片\\n\\n刮片胶条材质为合成橡胶，属于易损件，各种车辆的使用环境和驾驶员使用习惯均可能会对刮片造成损坏，所以为了保证刮片的使用寿命和汽车行驶安全，请您注意以下事项：\\n\\n请勿用刮片刮除风窗玻璃表面上结的冰，应该使用专用的刮冰器。\\n\\n请勿在脏污、有油污或有蜡的风窗玻璃表面刮刷。\\n\\n保持玻璃表面干净，请勿刮刷玻璃表面的灰尘、沙粒、昆虫和异物等。\\n\\n洗车和车身油漆保养时，无需对风窗玻璃打蜡，蜡层在光线不好时会反光，影响视线和行车安全。洗车后应该用纯净水漂洗刮片，使用专用的玻璃蜡层清洗剂去除风窗玻璃上的蜡层。\\n\\n洗车时不能直接用水枪冲洗刮片，防止水压过大损坏刮片。\\n\\n[seed chunk_id=han_p381_c107 page=381]\\n保养细则\\n\\n定期清洗风窗玻璃和刮片(建议一至两周一次)。\\n\\n建议定期刮拭雨刮(建议一至二天一次)。使用刮片刮拭风窗玻璃时，必须保持玻璃充分湿润(未下雨时，必须预先开启洗涤液喷洒玻璃)。\\n\\n使用专用风窗玻璃清洗剂清洗风窗玻璃。\\n\\n风窗玻璃上粘附有泥土、昆虫的尸体时应及时用抹布擦拭干净。\\n\\n风窗玻璃上有碎石敲击的伤痕时，应及时进行保养(建议使用风窗玻璃修复树脂类产品，伤痕较多或过大建议更换风窗玻璃)。\\n\\n定期更换雨刮刮片，建议半年一次。\\n\\n清洗风窗玻璃时必须预先抬起雨刮刮臂，具体操作方法为：\\n\\n1. 进入多媒体车辆保养信息界面开启前/后雨刮检修，雨刮旋转出来。\\n\\n2. 抓住刮臂上端，小心地提起刮臂和刮片总成。\\n\\n[neighbor chunk_id=han_p382_c108 page=382]\\n轮胎\\n\\n为安全驾驶车辆，轮胎的型号和尺寸必须适合您的车型，并具有状态良好的胎纹和标准胎压。\\n\\n以下内容，将详细地介绍如何检查胎压、轮胎的损伤和磨耗及轮胎换位时的操作方法。\\n\\n警告\\n\\n使用过度磨损、胎压不足或胎压过高的轮胎将会引发事故，造成人身伤亡。\\n\\n须遵照本手册中关于轮胎充气及保养的所有说明。\\n\\n充气\\n\\n保持轮胎适当充气，可提供操纵性、胎面寿命和驾驶舒适性三者的最佳组合。\\n\\n使用充气不足的轮胎会导致轮胎磨损不均匀，并且影响操纵和能耗，更可能由于过热而漏气。\\n\\n一使用充气过度的轮胎会降低车辆的舒适性，也更容易因路面的不平而受损，严重时有爆胎风险，严重威胁整车安全；同时也会导致轮胎磨损不均匀，影响轮胎寿命。\\n\\n冷胎时(车辆配有胎压监测装置)，您可以根据仪表上显示的各轮胎压值，决定是否需要补充胎压。\\n\\n应该在轮胎处于冷态时测量胎压。这意味着至少要在停车三个小时之后再测量。如果您必须在测量胎压之前行驶，只要行驶距离不超过1.6km，仍可以认为轮胎是处于冷态。\\n\\n一如果在轮胎处于热态时(行驶数千米后)检查胎压，压力读数将比冷态时的读数高 30~40kPa(0.3~0.4bar)，此类现象属正常，请勿为了达到规定的冷态胎压读数而放气，否则将导致轮胎胎压不足。\", \"chunk_id\": \"han_p381_c107\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"保养细则\", \"page_number_end\": \"381\", \"context_chunk_ids\": [\"han_p381_c106\", \"han_p381_c107\", \"han_p382_c108\"], \"page_number_start\": \"381\"}, {\"score\": 0.012698412698412698, \"content\": \"[neighbor chunk_id=han_p63_c070 page=63]\\n第1条：\\n故障提示：请检查车载充电系统\\n处理方法：车载充电系统有故障,请检查充电连接有无异常,重新连接充电设备。如不能解决,建议尽快与比亚迪汽车授权服务店联系。\\n\\n第2条：\\n故障提示：为了您的安全,遥控驾驶暂停使用\\n处理方法：遥控驾驶出现异常,请暂停使用。\\n\\n第3条：\\n故障提示：请检查车辆网络\\n处理方法：表示当前车辆的数据网络可能存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n第4条：\\n故障提示：发动机附件功能受限\\n处理方法：发动机附件功能受限,应立即停车并建议尽快与比亚迪汽车授权服务店联系。\\n\\n第5条：\\n故障提示：请检查前照灯系统\\n处理方法：表示当前车辆前照灯系统有故障,建议尽快与比亚迪汽车授权服务店联系。\\n\\n第6条：\\n故障提示：请检查挡位系统*\\n处理方法：表示挡位控制器存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n[seed chunk_id=han_p65_c071 page=65]\\n控制器操作\\n\\n3\\n\\n3-1 车门和钥匙....66 钥匙....66 闭锁/解锁车门....72 智能进入和智能启动系统....82 儿童锁....84 3-2 座椅....86 座椅须知....86 前排座椅调节....87 头枕....92 3-3 转向盘....95 转向盘....95 3-4 雨刮....101 雨刮开关....101 更换雨刮....102 3-5 后视镜....104 内后视镜....104 外后视镜....105 3-6 开关....107 灯光开关....107 驾驶员侧车门开关组....108 乘员侧车窗控制开关....110 里程切换开关....110 紧急警告灯开关....111 天窗开关....111 E-Call/云-Call 开关....113 室内灯开关....115\\n\\n[neighbor chunk_id=han_p66_c072 page=66]\\n钥匙\\n\\n车辆配备的钥匙可以实现解/闭锁车门和启动车辆等功能，钥匙包括电子智能钥匙、蓝牙钥匙*、NFC钥匙* 和机械钥匙(安装在电子智能钥匙内)。\\n\\n电子智能钥匙\\n\\n电子智能钥匙——携带电子智能钥匙按左右前门微动开关，可以解/闭锁所有车门；还可通过智能钥匙上按键进行车门解/闭锁、行李箱开启及遥控启动等功能。\\n\\n① 指示灯\\n\\n② 闭锁按键\\n\\n③ 解锁按键\\n\\n④ 行李箱解锁按键\\n\\n⑤ 启动/熄火按键\\n\\n⑥ 机械钥匙\\n\\n警告\\n\\n智能钥匙中的纽扣电池具有危险性，任何纽扣电池都必须始终远离儿童。\\n\\n纽扣锂电池如果被误吞或进入人体任何部位，两个小时内即可造成严重伤害或危及生命。\\n\\n如果怀疑纽扣电池已经被误吞或进入人体任何部位，请立即就医。\\n\\n注意\\n\\n电子智能钥匙为电子元件，应遵守以下说明，以防损坏电子智能钥匙：\\n\\n请勿将智能钥匙放置在高温处，例如夏季暴晒的仪表台上。\\n\\n请勿随意拆解智能钥匙。\", \"chunk_id\": \"han_p65_c071\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"控制器操作\", \"page_number_end\": 65, \"context_chunk_ids\": [\"han_p63_c070\", \"han_p65_c071\", \"han_p66_c072\"], \"page_number_start\": 65}, {\"score\": 0.0125, \"content\": \"[neighbor chunk_id=han_p6_c004 page=6]\\n1 安全\\n\\n1-1 座椅安全带....18 安全带简介....18 使用安全带....19 1-2 安全气囊....23 安全气囊简介....23 安全气囊类型....24 安全气囊触发条件及注意事项....27 1-3 儿童保护装置....32 儿童保护装置....32 安装儿童保护装置....32 1-4 双模系统工作模式....37 双模系统工作模式简介....37 双模系统工作模式选择....39 1-5 防盗系统....44 防盗系统....44 1-6 汽车事件数据记录系统..46 汽车事件数据记录系统(EDR)....46 1-7 哨兵模式*....49 哨兵模式*....49 2 仪表组 2-1 组合仪表....52\\n\\n组合仪表....52 仪表指示灯....53\\n\\n[seed chunk_id=han_p6_c005 page=6]\\n3 控制器操作\\n\\n3-1 车门和钥匙....66 钥匙....66 闭锁/解锁车门....72 智能进入和智能启动系统....82 儿童锁....84 3-2 座椅....86 座椅须知....86 前排座椅调节....87 头枕....92 3-3 转向盘....95 转向盘....95 3-4 雨刮....101 雨刮开关....101 更换雨刮....102 3-5 后视镜....104 内后视镜....104 外后视镜....105 3-6 开关....107 灯光开关....107 驾驶员侧车门开关组....108 乘员侧车窗控制开关....110 里程切换开关....110 紧急警告灯开关....111 天窗开关....111 E-Call/云-Call 开关....113 室内灯开关....115\\n\\n[neighbor chunk_id=han_p7_c006 page=7]\\n4 使用和驾驶\\n\\n4-1 充/放电说明....119 充电说明....119 充电方法....123 充电口电锁防盗功能....132 充电口紧急解锁....133 电量平衡功能....134 放电说明*....136 4-2 电池....140 动力电池....140 低压蓄电池....142 4-3 使用要领....145 磨合期....145 用车建议....145 挂车拖曳....146 燃油....146 如何节省燃油并延长车辆的使用寿命....149 运载行李....150 预防火灾....151 一氧化碳中毒的危险性....153 雨季洪涝防止车辆进水....153 安全驾驶注意事项....155 4-4 启动和驾驶....156 启动车辆....156 遥控启动功能*....158 驾驶车辆....158 驾驶模式....161 云辇....162 换挡操纵机构....164 电子驻车(EPB)....165\\n\\n自动驻车(AVH)....169 驾驶要领....170 4-5 驾驶辅助功能....174 驾驶辅助系统简介....174 行车辅助....183 泊车辅助....232 前向安全辅助....261 侧向安全辅助....281 后向安全辅助....291 驾驶辅助拓展功能....298 驾驶员监测辅助(DMS)....302 抬头显示(HUD)*....305 胎压监测(TPMS)....306 低速提示音(AVAS)....307 驾驶安全系统....308 4-6 其他主要功能说明....315 行车记录仪....315 车载 ETC....317\", \"chunk_id\": \"han_p6_c005\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"3 控制器操作\", \"page_number_end\": 6, \"context_chunk_ids\": [\"han_p6_c004\", \"han_p6_c005\", \"han_p7_c006\"], \"page_number_start\": 6}]',5,22029,1,NULL,'2026-06-23 12:23:10'),(30,1,NULL,NULL,NULL,'唐车的雨刷功能怎么开启？','根据《比亚迪唐用户手册》资料，雨刮功能的开启与操作主要分为**前雨刮**和**后雨刮**，具体操作步骤如下：\n\n### 🔹 前雨刮操作（方向盘右侧控制杆）\n控制杆滚轮共设5个挡位，**向上或向下拨动滚轮**即可切换：\n- **关闭**：前雨刮停止工作。\n- **自动雨刮1挡 / 间歇挡位1挡**：间歇刮水或低灵敏度自动感应刮水。\n- **自动雨刮2挡 / 间歇挡位2挡**：间歇刮水或高灵敏度自动感应刮水。\n- **低速刮水模式**：雨刮连续刮水。\n- **高速刮水模式**：雨刮连续刮水。\n\n💡 **自动雨刮设置方法**：\n点击中控屏 `设置 → 驾驶 → 舒适用车`，打开“自动雨刮开关”。此时雨刮会先刮刷一次并进入自动挡位，之后将根据雨量自动工作。进入自动模式后，拨动滚轮可切换1挡或2挡灵敏度。\n\n💡 **点刮与喷水清洗**：\n- **点刮（应急）**：按压控制杆端部按键至第一挡位置，雨刮低速刮水，直到松开按键即停。\n- **喷水清洗**：将端部按键按压至第二挡位置，洗涤器持续喷水，随后雨刮自动工作。松开按键或持续按压超过10秒，喷水停止，雨刮循环刮刷3~4次后自动停止。\n\n---\n\n### 🔹 后雨刮操作（雨刮开关中段滚轮）\n- 拨至**间歇挡图标**位置：后雨刮进入间歇刮水。\n- 拨至**关闭图标**位置（或后背门开启时）：后雨刮停止工作。\n- **保持拨至**喷水挡图标：后风窗刮水器与洗涤器同时启动。\n- **轻拨后释放**该位置：喷射洗涤液后，刮水器工作2~3次后自动停止。\n\n---\n\n### ⚠️ 重要注意事项\n1. **天气与洗车注意**：洗车、较干燥季节或无雨时请务必关闭自动雨刮，否则雨水传感器可能受布擦拭或触碰影响导致雨刮意外运转。\n2. **雨雪天影响**：雪花形状可能导致传感器误判或不工作，雪停或积雪清除后再使用；雪花融化后也可能触发自动刮刷，属正常现象。\n3. **洗涤器使用限制**：请勿使洗涤器连续工作超过10秒，或在玻璃水空置时操作，以免电机过热损坏。请务必使用专用玻璃清洗剂，用水或其他洗涤剂可能导致电机损坏。\n4. **定期保养**：至少每6个月检查一次前后雨刮片，如发现橡胶裂缝、局部硬化或刮不净/留条纹，应及时更换。\n5. **检修模式**：如需手动抬起雨刮臂，请确保电源处于“ON/OK”挡，并通过中控屏 `设置 → DiLink → 检修设置` 开启前/后雨刮检修功能。\n\n> 📢 **安全提示**：雨刮系统涉及行车视野与电气部件操作，请在驻车或确保安全的前提下使用。如遇雨刮异响、卡滞、不工作或频繁误启动等异常情况，请以车辆实际仪表提示为准，并及时联系官方售后进行专业检测。','tang.pdf','[{\"score\": 0.05157093332661815, \"content\": \"[neighbor chunk_id=tang_p117_c141 page=117-119]\\n注意\\n\\n请勿长时间按下喇叭按键区域，否则极易损坏喇叭。\\n\\n温馨提示\\n\\n请遵守交通法规，合理使用喇叭。\\n\\n转向盘调节\\n\\n转向盘手动调节\\n\\n要调整转向盘的角度时，可握住转向盘，进行以下操作：\\n\\n■将转向盘调节手柄向下按，将转向盘倾斜至需要的角度，或调整至需要的轴向位置，然后将手柄恢复至锁紧位置。\\n\\n警告\\n\\n车辆在行驶中，禁止调节转向盘，否则可能错误操纵车辆，导致意外事故发生。\\n\\n调节转向盘之后，将它上下移动以确认被牢固锁定。\\n\\n转向助力模式设置\\n\\n转向助力手感因人而异，不同用户对转向助力手感评价及需求也不一样。\\n\\n–用户可通过点击中控屏→设置 →驾驶→驾驶控制，进入“转向助力模式”设置界面，选择“舒适”/“运动”转向模式设置项。\\n\\n温馨提示\\n\\n一车辆在高速行驶时，若感觉转向盘较轻，建议您将转向助力模式设置为运动模式。转向助力模式设置在普通地形模式、车道保持功能关闭且车速低于80km/h 时才可设置。\\n\\n转向盘加热功能*\\n\\n–用户可通过操作中控屏顶部状态栏下滑打开“便捷”界面或点击中控屏→我的车选择座椅加热设置，点击“方向盘加热图标”选择开启或关闭。\\n\\n用户也可通过“比亚迪”App控制界面→通风加热→加热界面选择“方向盘加热图标”远程开启方向盘加热功能，提前为用户提供一个舒适的驾驶体验。\\n\\n[seed chunk_id=tang_p120_c142 page=120]\\n雨刮开关\\n\\n风窗玻璃刮水器与洗涤器\\n\\n前雨刮\\n\\n控制杆用来控制前风窗玻璃刮水器和洗涤器，此杆共分五个挡位：\\n\\n：前雨刮关闭\\n\\n：自动雨刮1挡/间歇挡位1挡\\n\\n：自动雨刮2挡/间歇挡位2挡\\n\\n：低速刮水模式\\n\\n：高速刮水模式\\n\\n如需选择挡位，向上或向下拨动挡位滚轮即可。\\n\\n在低速与高速挡位时，雨刮连续刮水。\\n\\n用户通过点击中控屏→设置 →驾驶→舒适用车打开自动雨刮开关时，雨刮刮刷一次，然后进入自动雨刮挡位，雨刮根据雨量自动工作。\\n\\n在自动雨刮挡位时，拨动雨刮滚轮可调节自动雨刮挡位。\\n\\n[neighbor chunk_id=tang_p120_c143 page=120-121]\\n警告\\n\\n电源挡位处于“ON/OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n注意\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压控制杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开位置。\", \"chunk_id\": \"tang_p120_c142\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"雨刮开关\", \"page_number_end\": 120, \"context_chunk_ids\": [\"tang_p117_c141\", \"tang_p120_c142\", \"tang_p120_c143\"], \"page_number_start\": 120}, {\"score\": 0.05155341089370703, \"content\": \"[neighbor chunk_id=tang_p121_c144 page=121-122]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压控制杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n■松开控制杆或者持续操作的时间超过 10s时，洗涤器将停止喷水，雨刮刮刷3~4个循环后停止工作。\\n\\n后雨刮\\n\\n将雨刮开关中段滚轮拨到“ ”位置，后雨刮进入间歇挡；\\n\\n将雨刮开关中段滚轮拨到“ ”位置或者后背门开启时，后雨刮停止工作；\\n\\n一将雨刮开关中段滚轮拨到“ ”位置并保持，后风窗刮水器和洗涤器同时启动；\\n\\n将雨刮开关中段滚轮拨到“ ”位置并释放，在喷射洗涤液之后，刮水器将工作2~3次后停止。\\n\\n[seed chunk_id=tang_p122_c145 page=122]\\n注意\\n\\n定期检查刮片，清除粘在刮片上的污物。\\n\\n尽量避免刚下雨时就开启雨刮，此时雨水混合着泥沙、灰尘，不但刮不干净风窗玻璃，反而在瞬间造成视野一片模糊，影响行车安全。\\n\\n请使用玻璃清洗剂。水或其他类型洗涤剂可能会导致洗涤电机损坏。\\n\\n请勿使洗涤器连续工作10s以上或者在洗涤液罐空置时操作，否则可能导致电机过热损坏。\\n\\n更换雨刮\\n\\n更换雨刮片\\n\\n至少每六个月检查一次前/后雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n一整车电源在“ON”挡或“OK”挡，用户可通过点击中控屏→设置 →DiLink→检修设置界面开启或关闭前/后雨刮检修功能，开启相应的雨刮检修设置，则相应的雨刮旋转出来，便于检修和更换雨刮。\\n\\n更换前雨刮\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①。\\n\\n3. 握住刮片卡扣处，沿图示方向②取出来。\\n\\n4. 手握刮水器臂上喷水管一端，将其从刮片上拔出。\\n\\n5. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n[neighbor chunk_id=tang_p123_c146 page=123]\\n更换后雨刮\\n\\n1. 首先拉起后雨刮的刮水器臂。\\n\\n2. 用手握住刮臂位置①，沿图示方向拔出刮片。\\n\\n3. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n注意\\n\\n提起刮臂时，禁止打开前舱盖，否则会损坏前舱盖和刮水器臂。\\n\\n洗完车放下雨刮刮片时，禁止直接推雨刮刮臂让刮片直接撞击到风窗玻璃上。\\n\\n禁止折弯雨刮刮片、雨刮运行时禁止阻挡雨刮刮片。\\n\\n冬季雨雪天，建议进入多媒体检修界面开启前雨刮检修，将前雨刮手动抬起，以免雨刮被冻住。\\n\\n关于雨刮保养请参见“雨刮器刮片保养”。\", \"chunk_id\": \"tang_p122_c145\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"注意\", \"page_number_end\": 122, \"context_chunk_ids\": [\"tang_p121_c144\", \"tang_p122_c145\", \"tang_p123_c146\"], \"page_number_start\": 122}, {\"score\": 0.050614754098360665, \"content\": \"[neighbor chunk_id=tang_p120_c143 page=120-121]\\n警告\\n\\n电源挡位处于“ON/OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n注意\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压控制杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开位置。\\n\\n[seed chunk_id=tang_p121_c144 page=121-122]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压控制杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n■松开控制杆或者持续操作的时间超过 10s时，洗涤器将停止喷水，雨刮刮刷3~4个循环后停止工作。\\n\\n后雨刮\\n\\n将雨刮开关中段滚轮拨到“ ”位置，后雨刮进入间歇挡；\\n\\n将雨刮开关中段滚轮拨到“ ”位置或者后背门开启时，后雨刮停止工作；\\n\\n一将雨刮开关中段滚轮拨到“ ”位置并保持，后风窗刮水器和洗涤器同时启动；\\n\\n将雨刮开关中段滚轮拨到“ ”位置并释放，在喷射洗涤液之后，刮水器将工作2~3次后停止。\\n\\n[neighbor chunk_id=tang_p122_c145 page=122]\\n注意\\n\\n定期检查刮片，清除粘在刮片上的污物。\\n\\n尽量避免刚下雨时就开启雨刮，此时雨水混合着泥沙、灰尘，不但刮不干净风窗玻璃，反而在瞬间造成视野一片模糊，影响行车安全。\\n\\n请使用玻璃清洗剂。水或其他类型洗涤剂可能会导致洗涤电机损坏。\\n\\n请勿使洗涤器连续工作10s以上或者在洗涤液罐空置时操作，否则可能导致电机过热损坏。\\n\\n更换雨刮\\n\\n更换雨刮片\\n\\n至少每六个月检查一次前/后雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n一整车电源在“ON”挡或“OK”挡，用户可通过点击中控屏→设置 →DiLink→检修设置界面开启或关闭前/后雨刮检修功能，开启相应的雨刮检修设置，则相应的雨刮旋转出来，便于检修和更换雨刮。\\n\\n更换前雨刮\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①。\\n\\n3. 握住刮片卡扣处，沿图示方向②取出来。\\n\\n4. 手握刮水器臂上喷水管一端，将其从刮片上拔出。\\n\\n5. 新刮片装配时，按照取出刮片相反的步骤进行操作。\", \"chunk_id\": \"tang_p121_c144\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"前风窗玻璃洗涤器\", \"page_number_end\": 122, \"context_chunk_ids\": [\"tang_p120_c143\", \"tang_p121_c144\", \"tang_p122_c145\"], \"page_number_start\": 121}, {\"score\": 0.050589231556973493, \"content\": \"[neighbor chunk_id=tang_p120_c142 page=120]\\n雨刮开关\\n\\n风窗玻璃刮水器与洗涤器\\n\\n前雨刮\\n\\n控制杆用来控制前风窗玻璃刮水器和洗涤器，此杆共分五个挡位：\\n\\n：前雨刮关闭\\n\\n：自动雨刮1挡/间歇挡位1挡\\n\\n：自动雨刮2挡/间歇挡位2挡\\n\\n：低速刮水模式\\n\\n：高速刮水模式\\n\\n如需选择挡位，向上或向下拨动挡位滚轮即可。\\n\\n在低速与高速挡位时，雨刮连续刮水。\\n\\n用户通过点击中控屏→设置 →驾驶→舒适用车打开自动雨刮开关时，雨刮刮刷一次，然后进入自动雨刮挡位，雨刮根据雨量自动工作。\\n\\n在自动雨刮挡位时，拨动雨刮滚轮可调节自动雨刮挡位。\\n\\n[seed chunk_id=tang_p120_c143 page=120-121]\\n警告\\n\\n电源挡位处于“ON/OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n注意\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压控制杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开位置。\\n\\n[neighbor chunk_id=tang_p121_c144 page=121-122]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压控制杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n■松开控制杆或者持续操作的时间超过 10s时，洗涤器将停止喷水，雨刮刮刷3~4个循环后停止工作。\\n\\n后雨刮\\n\\n将雨刮开关中段滚轮拨到“ ”位置，后雨刮进入间歇挡；\\n\\n将雨刮开关中段滚轮拨到“ ”位置或者后背门开启时，后雨刮停止工作；\\n\\n一将雨刮开关中段滚轮拨到“ ”位置并保持，后风窗刮水器和洗涤器同时启动；\\n\\n将雨刮开关中段滚轮拨到“ ”位置并释放，在喷射洗涤液之后，刮水器将工作2~3次后停止。\", \"chunk_id\": \"tang_p120_c143\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"警告\", \"page_number_end\": 121, \"context_chunk_ids\": [\"tang_p120_c142\", \"tang_p120_c143\", \"tang_p121_c144\"], \"page_number_start\": 120}, {\"score\": 0.02976800976800977, \"content\": \"[neighbor chunk_id=tang_p122_c145 page=122]\\n注意\\n\\n定期检查刮片，清除粘在刮片上的污物。\\n\\n尽量避免刚下雨时就开启雨刮，此时雨水混合着泥沙、灰尘，不但刮不干净风窗玻璃，反而在瞬间造成视野一片模糊，影响行车安全。\\n\\n请使用玻璃清洗剂。水或其他类型洗涤剂可能会导致洗涤电机损坏。\\n\\n请勿使洗涤器连续工作10s以上或者在洗涤液罐空置时操作，否则可能导致电机过热损坏。\\n\\n更换雨刮\\n\\n更换雨刮片\\n\\n至少每六个月检查一次前/后雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n一整车电源在“ON”挡或“OK”挡，用户可通过点击中控屏→设置 →DiLink→检修设置界面开启或关闭前/后雨刮检修功能，开启相应的雨刮检修设置，则相应的雨刮旋转出来，便于检修和更换雨刮。\\n\\n更换前雨刮\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①。\\n\\n3. 握住刮片卡扣处，沿图示方向②取出来。\\n\\n4. 手握刮水器臂上喷水管一端，将其从刮片上拔出。\\n\\n5. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n[seed chunk_id=tang_p123_c146 page=123]\\n更换后雨刮\\n\\n1. 首先拉起后雨刮的刮水器臂。\\n\\n2. 用手握住刮臂位置①，沿图示方向拔出刮片。\\n\\n3. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n注意\\n\\n提起刮臂时，禁止打开前舱盖，否则会损坏前舱盖和刮水器臂。\\n\\n洗完车放下雨刮刮片时，禁止直接推雨刮刮臂让刮片直接撞击到风窗玻璃上。\\n\\n禁止折弯雨刮刮片、雨刮运行时禁止阻挡雨刮刮片。\\n\\n冬季雨雪天，建议进入多媒体检修界面开启前雨刮检修，将前雨刮手动抬起，以免雨刮被冻住。\\n\\n关于雨刮保养请参见“雨刮器刮片保养”。\\n\\n[neighbor chunk_id=tang_p124_c147 page=124]\\n内后视镜\\n\\n上下、左右转动内后视镜，将内后视镜调至合适位置。\\n\\n警告\\n\\n请勿在内后视镜上悬挂重物，或用力摇晃、拖拽。\\n\\n手动调节内后视镜时，卡滞后切勿暴力调节，以免造成内后视镜脱落。\\n\\n请在车辆行驶前调节好内后视镜。应避免行驶过程中调节内后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n流媒体内后视镜*\\n\\n流媒体内后视镜有流媒体和传统内后视镜两种工作模式。\\n\\n流媒体模式\\n\\n通过实体开关按键(内后视镜背面后侧)或点击中控屏→设置→声音显示→流媒体后视镜按键，可选择开启或关闭流媒体内后视镜。\\n\\n●开启流媒体后视镜屏幕上可显示后方摄像头采集的实时画面，点击中控屏→设置 →声音显示→流媒体后视镜按键，打开屏幕调节选项后，可通过转向盘右侧左、右按键选择视角缩放、视野高度调节和屏幕亮度设置项，并通过滑动转向盘右侧滚轮进行挡位调节。\", \"chunk_id\": \"tang_p123_c146\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"更换后雨刮\", \"page_number_end\": 123, \"context_chunk_ids\": [\"tang_p122_c145\", \"tang_p123_c146\", \"tang_p124_c147\"], \"page_number_start\": 123}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=tang_p130_c156 page=130-131]\\n②闭锁\\n\\n按“中控锁闭锁”按键，四门门锁同时闭锁，闭锁红色指示灯点亮。\\n\\n车窗锁止按键\\n\\n驾驶员侧车门配置有车窗锁止按键。车窗锁止按键能控制乘员侧的车窗控制开关功能。\\n\\n按下左侧车窗锁止按键①，指示灯点亮；驾驶员侧车窗控制开关能控制四门窗控开关的升降；右前窗控开关可以控制升降玻璃；左后侧门窗控开关不能控制升降玻璃，右后侧窗控开关不受限。\\n\\n再次按下左侧车窗锁止按键，指示灯熄灭，恢复各乘员的车窗控制开关功能。\\n\\n右侧车窗锁止按键②操作同左侧。\\n\\n同时按下车窗锁止按键①和②，仅驾驶员侧车窗控制开关能控制四门窗控开关的升降，其他乘员侧窗控开关不可用。\\n\\n[seed chunk_id=tang_p131_c157 page=131-133]\\n乘员侧车窗控制开关\\n\\n前排乘员侧车窗控制开关\\n\\n整车电源挡位处于“ON/OK”挡时，前排乘员侧车窗控制开关可控制前排乘员侧玻璃升/降。\\n\\n二排乘员侧车窗控制开关\\n\\n二排乘员侧车窗控制开关位于左右两侧滑门门板上。\\n\\n整车电源挡位处于“ON/OK”挡时，上下拨动二排乘员侧车窗控制开关可分别控制对应侧滑门玻璃升/降。\\n\\n自动关窗*\\n\\n用户通过点击中控屏→设置 →门窗与锁→车窗，进入车窗设置界面可开启或关闭自动关窗相关设置。\\n\\n锁车自动升窗\\n\\n■当“锁车自动升窗”设置项开启时，整车电源挡位处于“OFF”挡，左前门有开启操作，且前舱盖、后背门、四门关闭状态时，短按遥控钥匙闭锁按键，四门玻璃自动上升。\\n\\n雨天自动关窗\\n\\n–当“雨天自动关窗”设置项开启时，整车处于\\\" { \\\\mathsf { O N } } / { \\\\mathsf { O K } } \\\"挡，雨刮感应器感受到一定的雨量后，四门车窗自动关闭。\\n\\n车辆启动后，自动车窗功能仅生效一次，熄火重启后，功能再次生效。\\n\\n高速自动关窗\\n\\n■当“高速自动关窗”设置项开启时，车辆行驶速度超过一定车速后，四门车窗会自动关闭。\\n\\n紧急告警灯开关\\n\\n按下开关 ，所有的转向信号灯开始闪烁，仪表转向指示灯同步闪烁；再次按下开关 停止闪烁。\\n\\n[neighbor chunk_id=tang_p133_c158 page=133-134]\\n天窗开关\\n\\n小天窗开关\\n\\n操纵天窗时，整车电源挡位处于\\\" { \\\\mathsf { O N } } / { \\\\mathsf { O K } } \\\"挡或{ } ^ { \\\\mathfrak { s e } } \\\\mathsf { P } \\\\mathsf { F } \\\\mathsf { F } ^ { \\\\mathfrak { * } }”挡退电延时时间范围内。\\n\\n打开天窗\\n\\n触摸天窗开启按键①，天窗上倾通风。\\n\\n关闭天窗\\n\\n触摸天窗关闭按键②，天窗自动关闭。\\n\\n天窗防夹功能\\n\\n在天窗关闭过程中，有人或物体被夹住，则天窗会自动打开一段距离。\\n\\n警告\\n\\n开闭天窗时，如果夹住某乘员的手或头部，可能会造成极为严重的伤害。\\n\\n警告(续)\\n\\n车辆行驶中，请勿将头、手或身体的任何部位伸出天窗外，否则可能造成严重的伤害甚至危及生命。\\n\\n注意\\n\\n如果雨、雪或洗车后操作天窗，则水可能会进入车内。操作之前，请用干布将天窗擦拭干净。\\n\\n如果试图在0 \\\\%以下的环境中，或者被冰雪覆盖时打开天窗，则可能会损坏天窗或电机。\", \"chunk_id\": \"tang_p131_c157\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"乘员侧车窗控制开关\", \"page_number_end\": \"133\", \"context_chunk_ids\": [\"tang_p130_c156\", \"tang_p131_c157\", \"tang_p133_c158\"], \"page_number_start\": \"131\"}]',5,19760,1,NULL,'2026-06-23 12:23:56'),(31,1,NULL,NULL,NULL,'这两个有什么区别？','根据当前用户手册资料，无法确定。\n\n提供的资料仅包含单一车型（`tang.pdf`）的雨刮开关挡位、洗涤器操作、自动雨刮使用注意事项及刮片更换保养等说明，并未提及比亚迪汉车型，也未提供任何跨车型的功能对比信息。如需了解具体车型之间的差异，请以各自对应的官方用户手册为准。若您有该车型雨刮的具体操作或保养疑问，可随时提供详细问题，我将为您精准解答。','tang.pdf','[{\"score\": 0.05081967213114755, \"content\": \"[neighbor chunk_id=tang_p121_c144 page=121-122]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压控制杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n■松开控制杆或者持续操作的时间超过 10s时，洗涤器将停止喷水，雨刮刮刷3~4个循环后停止工作。\\n\\n后雨刮\\n\\n将雨刮开关中段滚轮拨到“ ”位置，后雨刮进入间歇挡；\\n\\n将雨刮开关中段滚轮拨到“ ”位置或者后背门开启时，后雨刮停止工作；\\n\\n一将雨刮开关中段滚轮拨到“ ”位置并保持，后风窗刮水器和洗涤器同时启动；\\n\\n将雨刮开关中段滚轮拨到“ ”位置并释放，在喷射洗涤液之后，刮水器将工作2~3次后停止。\\n\\n[seed chunk_id=tang_p122_c145 page=122]\\n注意\\n\\n定期检查刮片，清除粘在刮片上的污物。\\n\\n尽量避免刚下雨时就开启雨刮，此时雨水混合着泥沙、灰尘，不但刮不干净风窗玻璃，反而在瞬间造成视野一片模糊，影响行车安全。\\n\\n请使用玻璃清洗剂。水或其他类型洗涤剂可能会导致洗涤电机损坏。\\n\\n请勿使洗涤器连续工作10s以上或者在洗涤液罐空置时操作，否则可能导致电机过热损坏。\\n\\n更换雨刮\\n\\n更换雨刮片\\n\\n至少每六个月检查一次前/后雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n一整车电源在“ON”挡或“OK”挡，用户可通过点击中控屏→设置 →DiLink→检修设置界面开启或关闭前/后雨刮检修功能，开启相应的雨刮检修设置，则相应的雨刮旋转出来，便于检修和更换雨刮。\\n\\n更换前雨刮\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①。\\n\\n3. 握住刮片卡扣处，沿图示方向②取出来。\\n\\n4. 手握刮水器臂上喷水管一端，将其从刮片上拔出。\\n\\n5. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n[neighbor chunk_id=tang_p123_c146 page=123]\\n更换后雨刮\\n\\n1. 首先拉起后雨刮的刮水器臂。\\n\\n2. 用手握住刮臂位置①，沿图示方向拔出刮片。\\n\\n3. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n注意\\n\\n提起刮臂时，禁止打开前舱盖，否则会损坏前舱盖和刮水器臂。\\n\\n洗完车放下雨刮刮片时，禁止直接推雨刮刮臂让刮片直接撞击到风窗玻璃上。\\n\\n禁止折弯雨刮刮片、雨刮运行时禁止阻挡雨刮刮片。\\n\\n冬季雨雪天，建议进入多媒体检修界面开启前雨刮检修，将前雨刮手动抬起，以免雨刮被冻住。\\n\\n关于雨刮保养请参见“雨刮器刮片保养”。\", \"chunk_id\": \"tang_p122_c145\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"122\", \"context_chunk_ids\": [\"tang_p121_c144\", \"tang_p122_c145\", \"tang_p123_c146\"], \"page_number_start\": \"122\"}, {\"score\": 0.046448087431693985, \"content\": \"[neighbor chunk_id=tang_p334_c053 page=334-335]\\n防夹\\n\\n电动踏板在展开或收回过程中，遇到障碍物后，会立马停止当前动作，等待一段时间后，恢复到防夹前的状态。\\n\\n警告\\n\\n踏板在完全收回的瞬间，防夹功能将不能发挥作用。因此，请勿尝试利用身体任何部位来测试踏板防夹功能，以免造成人身伤害。\\n\\n电动踏板伸出或收回过程中，切勿踩踏，以免造成人身伤害。\\n\\n电动踏板不可承载车身重量，切勿将电动踏板作为支撑点举升车辆，以免造成车辆损坏甚至人身伤害。\\n\\n若车辆维修需要举升，请先收回电动踏板，以免举升期间与展开的电动踏板碰撞，从而导致踏板损坏。\\n\\n装有电动踏板的车辆维修时，只能用举升四轮的举升机进行举升。\\n\\n[seed chunk_id=tang_p335_c054 page=335-337]\\n注意\\n\\n使用电动踏板时，应避免踏板附着或夹杂过多的泥垢、树枝等杂物，以免杂物导致踏板功能异常。\\n\\n清理踏板时，可使用高压水枪冲洗踏板前后铰链位置，并在铰链处涂抹润滑脂。\\n\\n寒冷天气，若踏板由于结冰无法打开，需手动清除结冰。\\n\\n寒冷天气，踏板运行速度可能会延迟。\\n\\n车内装置\\n\\n5\\n\\n5-1 多媒体系统....339 中控屏....339 多媒体系统界面....340 场景模式*....341 手势及响应....345 蓝牙电话....346 OTA 升级*....347 智能语音....348 音响*....348 K 歌*....349 我的车*....350 手车互联*....350 其他应用....355 副驾屏*....357 车载影院系统*....359 投屏功能*....363 5-2 空调系统....365 空调面板视图....365 空调操作界面....367 功能定义....368 空调设置....373 香氛系统*....373 出风口....374 5-3 “比亚迪”App*....376 “比亚迪”App 介绍*....376 “比亚迪”App 使用*....376 比亚迪蓝牙遥控驾驶*....377\\n\\n[neighbor chunk_id=tang_p338_c055 page=338]\\n5\\n\\n车内装置\\n\\n5-4 冰箱*....380 冰箱*....380 5-5 储物装置....385 车门储物盒....385 票据盒*....385 置物盒*....386 杂物箱....386 中央扶手箱....387 杯托....387 文件袋....389 手机槽*....389 前舱储物装置....390 5-6 其他装置....392 遮阳板....392 安全拉手....392 挂钩*....393 车载电源....394 USB 接口....395 手机无线充电*....397 小桌板*....399 生态接口*....401 磁吸位置*....401\", \"chunk_id\": \"tang_p335_c054\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"注意\", \"page_number_end\": 337, \"context_chunk_ids\": [\"tang_p334_c053\", \"tang_p335_c054\", \"tang_p338_c055\"], \"page_number_start\": 335}, {\"score\": 0.03413537810682179, \"content\": \"[neighbor chunk_id=tang_p374_c110 page=374-376]\\n出风口\\n\\n前排出风口\\n\\n拨动出风口中央的调节片可以调节出风角度。\\n\\n向车内侧拨动前排中央出风口中央的调节片可以关闭出风口。\\n\\n向车外侧拨动前排侧出风口中央的调节片可以关闭出风口。\\n\\n顶棚出风口*\\n\\n拨动出风口中央的调节片可以调节出风角度和关闭出风口。\\n\\n“比亚迪”App 介绍*\\n\\n“比亚迪”App 是一款车联网移动应用产品，可以轻松实现远程控制、查看实时车况和使用车主服务，带您进入车联网的云时代。\\n\\n在应用市场或访问 https://profilesys.bydauto.com.cn/byd/home/index-mobile.html，下载并安装“比亚迪”App。\\n\\n[seed chunk_id=tang_p376_c111 page=376-377]\\n温馨提示\\n\\n通过App指引或购车时在服务店工作人员的指引下完成“比亚迪”App账号的注册、车主认证和云服务网联功能。\\n\\n“比亚迪”App 使用*\\n\\n“比亚迪”App 开通云服务网联功能后，即可查看车辆相关信息，如车辆位置、车辆状态等。设置完操作密码后，即可使用各项车辆控制功能。\\n\\n警告\\n\\n高温消毒杀菌持续时间较长且车内温度过高，可能会启动车辆。请确保燃油或电量充足，车身无遮盖物品且车内无人、宠物、生鲜食品、易燃易爆物品。\\n\\n温馨提示\\n\\nApp控制功能主要为远程使用场景，请注意手机和车辆周围信号情况。\\n\\n[neighbor chunk_id=tang_p377_c112 page=377-378]\\n比亚迪蓝牙遥控驾驶*\\n\\n蓝牙遥控驾驶介绍\\n\\n蓝牙遥控驾驶是通过近距离蓝牙连接车辆，遥控车辆低速行驶一段距离的功能。\\n\\n在应用市场下载并安装最新版“比亚迪”App，内部集成比亚迪汽车蓝牙遥控驾驶功能。\\n\\n应用端开启系统蓝牙后，靠近车辆会自动进行蓝牙连接，亦可手动选择蓝牙进行连接。\\n\\n选择“遥控驾驶”操作项，可开始蓝牙遥控驾驶。\\n\\n蓝牙遥控启动及熄火\\n\\n蓝牙连接成功后，向右滑动即可进入功能，进入功能将会自动启动车辆，启动成功后车辆转向灯闪烁 3次。若当前车辆已启动将自动跳过启动页。\\n\\n蓝牙遥控启动后，一段时间内未进行任何有效操作，车辆将自动退电并熄火，转向灯闪烁2次。\\n\\n5\\n\\n结束遥控驾驶时，可点击“结束”，选择“仅结束遥控驾驶”仅退出操作界面，选择“结束并熄火”，车辆将退电并熄火，转向灯闪烁 2次。\\n\\n蓝牙遥控驾驶操作\\n\\n车辆启动后，进入蓝牙遥控驾驶操作界面后，默认车头朝上，可点击右上方图标进入设置页进行车头朝向调整，便于驾驶员对应车辆位置。\\n\\n遥控转向\\n\\n长按界面下方左/右箭头（默认车头朝上)，将控制车辆左/右转，松开后，停上转向。\\n\\n遥控行进、停止\\n\\n拖拽车模上的按钮至上方/下方并保持长按(默认车头朝上)，车辆将缓慢前进/后退，转向灯双闪，后退时倒车灯将同时点亮；松开按钮后，车辆缓慢停止，转向灯及倒车灯熄灭。\\n\\n单次操作最多可控制车辆行驶1分钟。\", \"chunk_id\": \"tang_p376_c111\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"377\", \"context_chunk_ids\": [\"tang_p374_c110\", \"tang_p376_c111\", \"tang_p377_c112\"], \"page_number_start\": \"376\"}, {\"score\": 0.03331653225806452, \"content\": \"[neighbor chunk_id=tang_p427_c167 page=427-428]\\n注意\\n\\n如车辆进入高原环境前未排气，行驶中可能出现制动踏板变软、制动距离变长，严重时可能限制动力，请谨慎驾驶。\\n\\n洗涤器\\n\\n一正常使用时，应每月至少查看一次风窗玻璃洗涤器储液罐的液位。\\n\\n在天气恶劣的情况下，应适当的增加洗涤液的加注频率。\\n\\n应添加优质风窗玻璃洗涤液，这可提高除污能力，并能防止在寒冷天气中冻结。\\n\\n当您给储液罐再次添加洗涤液时，要用干净的布沾上风窗玻璃洗涤液，清洗风窗玻璃雨刮器的刮片，这将有助于使刮片刃口处于良好状态。\\n\\n[seed chunk_id=tang_p428_c168 page=428]\\n注意\\n\\n切勿向风窗玻璃洗涤器储液罐内注入醋水溶剂。\\n\\n建议使用合格的风窗玻璃洗涤液。\\n\\n空调系统\\n\\n车上的空调系统是一个密闭系统，任何重要保养工作建议由比亚迪汽车授权服务店的专业人员来进行。\\n\\n您自己可以进行如下操作，以确保空调系统有效地工作。\\n\\n定期检查散热器以及空调冷凝器。清除积塞在其前表面的树叶、昆虫及尘土。这些积物会阻碍气流，从而降低制冷效果。建议联系比亚迪汽车授权服务店处理。\\n\\n在天气寒冷的月份，应至少每周开启一次空调，每次至少 10min，这是为了让冷媒内所含的润滑油循环。\\n\\n如果空调系统的制冷效果不如以前，建议到比亚迪汽车授权服务店检修。\\n\\n[neighbor chunk_id=tang_p429_c169 page=429]\\n注意\\n\\n无论何时检修空调系统，都应要求检修站保证使用冷媒再循环系统。\\n\\n该系统可回收冷媒进行再利用，将冷媒释放于大气中会污染环境。\\n\\n雨刮器刮片\\n\\n雨刮器刮片保养\\n\\n刮片胶条材质为合成橡胶，属于易损件，各种车辆的使用环境和驾驶员使用习惯均可能会对刮片造成损坏，所以为了保证刮片的使用寿命和汽车行驶安全，请您注意以下事项：\\n\\n请勿用刮片去刮除挡风玻璃表面上结的冰，应该使用专用的刮冰器。\\n\\n请勿在脏污、有油污或有蜡的挡风玻璃表面刮刷。\\n\\n保持玻璃表面干净，请勿刮刷玻璃表面的灰尘、沙粒、昆虫和异物等。\\n\\n一洗车和车身油漆保养时，无需对挡风玻璃打蜡，蜡层在光线不好时会反光，影响视线和行车安全。洗车后应该用纯净水漂洗刮片，使用专用的玻璃蜡层清洗剂去除挡风玻璃上的蜡层。\\n\\n洗车时请勿直接用水枪冲洗刮片，防止水压过大损坏刮片。\", \"chunk_id\": \"tang_p428_c168\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"注意\", \"page_number_end\": \"428\", \"context_chunk_ids\": [\"tang_p427_c167\", \"tang_p428_c168\", \"tang_p429_c169\"], \"page_number_start\": \"428\"}, {\"score\": 0.032307692307692315, \"content\": \"[neighbor chunk_id=tang_p120_c142 page=120]\\n雨刮开关\\n\\n风窗玻璃刮水器与洗涤器\\n\\n前雨刮\\n\\n控制杆用来控制前风窗玻璃刮水器和洗涤器，此杆共分五个挡位：\\n\\n：前雨刮关闭\\n\\n：自动雨刮1挡/间歇挡位1挡\\n\\n：自动雨刮2挡/间歇挡位2挡\\n\\n：低速刮水模式\\n\\n：高速刮水模式\\n\\n如需选择挡位，向上或向下拨动挡位滚轮即可。\\n\\n在低速与高速挡位时，雨刮连续刮水。\\n\\n用户通过点击中控屏→设置 →驾驶→舒适用车打开自动雨刮开关时，雨刮刮刷一次，然后进入自动雨刮挡位，雨刮根据雨量自动工作。\\n\\n在自动雨刮挡位时，拨动雨刮滚轮可调节自动雨刮挡位。\\n\\n[seed chunk_id=tang_p120_c143 page=120-121]\\n警告\\n\\n电源挡位处于“ON/OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n注意\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压控制杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开位置。\\n\\n[neighbor chunk_id=tang_p121_c144 page=121-122]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压控制杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n■松开控制杆或者持续操作的时间超过 10s时，洗涤器将停止喷水，雨刮刮刷3~4个循环后停止工作。\\n\\n后雨刮\\n\\n将雨刮开关中段滚轮拨到“ ”位置，后雨刮进入间歇挡；\\n\\n将雨刮开关中段滚轮拨到“ ”位置或者后背门开启时，后雨刮停止工作；\\n\\n一将雨刮开关中段滚轮拨到“ ”位置并保持，后风窗刮水器和洗涤器同时启动；\\n\\n将雨刮开关中段滚轮拨到“ ”位置并释放，在喷射洗涤液之后，刮水器将工作2~3次后停止。\", \"chunk_id\": \"tang_p120_c143\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"121\", \"context_chunk_ids\": [\"tang_p120_c142\", \"tang_p120_c143\", \"tang_p121_c144\"], \"page_number_start\": \"120\"}, {\"score\": 0.03225806451612903, \"content\": \"[neighbor chunk_id=tang_p122_c145 page=122]\\n注意\\n\\n定期检查刮片，清除粘在刮片上的污物。\\n\\n尽量避免刚下雨时就开启雨刮，此时雨水混合着泥沙、灰尘，不但刮不干净风窗玻璃，反而在瞬间造成视野一片模糊，影响行车安全。\\n\\n请使用玻璃清洗剂。水或其他类型洗涤剂可能会导致洗涤电机损坏。\\n\\n请勿使洗涤器连续工作10s以上或者在洗涤液罐空置时操作，否则可能导致电机过热损坏。\\n\\n更换雨刮\\n\\n更换雨刮片\\n\\n至少每六个月检查一次前/后雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n一整车电源在“ON”挡或“OK”挡，用户可通过点击中控屏→设置 →DiLink→检修设置界面开启或关闭前/后雨刮检修功能，开启相应的雨刮检修设置，则相应的雨刮旋转出来，便于检修和更换雨刮。\\n\\n更换前雨刮\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①。\\n\\n3. 握住刮片卡扣处，沿图示方向②取出来。\\n\\n4. 手握刮水器臂上喷水管一端，将其从刮片上拔出。\\n\\n5. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n[seed chunk_id=tang_p123_c146 page=123]\\n更换后雨刮\\n\\n1. 首先拉起后雨刮的刮水器臂。\\n\\n2. 用手握住刮臂位置①，沿图示方向拔出刮片。\\n\\n3. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n注意\\n\\n提起刮臂时，禁止打开前舱盖，否则会损坏前舱盖和刮水器臂。\\n\\n洗完车放下雨刮刮片时，禁止直接推雨刮刮臂让刮片直接撞击到风窗玻璃上。\\n\\n禁止折弯雨刮刮片、雨刮运行时禁止阻挡雨刮刮片。\\n\\n冬季雨雪天，建议进入多媒体检修界面开启前雨刮检修，将前雨刮手动抬起，以免雨刮被冻住。\\n\\n关于雨刮保养请参见“雨刮器刮片保养”。\\n\\n[neighbor chunk_id=tang_p124_c147 page=124]\\n内后视镜\\n\\n上下、左右转动内后视镜，将内后视镜调至合适位置。\\n\\n警告\\n\\n请勿在内后视镜上悬挂重物，或用力摇晃、拖拽。\\n\\n手动调节内后视镜时，卡滞后切勿暴力调节，以免造成内后视镜脱落。\\n\\n请在车辆行驶前调节好内后视镜。应避免行驶过程中调节内后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n流媒体内后视镜*\\n\\n流媒体内后视镜有流媒体和传统内后视镜两种工作模式。\\n\\n流媒体模式\\n\\n通过实体开关按键(内后视镜背面后侧)或点击中控屏→设置→声音显示→流媒体后视镜按键，可选择开启或关闭流媒体内后视镜。\\n\\n●开启流媒体后视镜屏幕上可显示后方摄像头采集的实时画面，点击中控屏→设置 →声音显示→流媒体后视镜按键，打开屏幕调节选项后，可通过转向盘右侧左、右按键选择视角缩放、视野高度调节和屏幕亮度设置项，并通过滑动转向盘右侧滚轮进行挡位调节。\", \"chunk_id\": \"tang_p123_c146\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"更换后雨刮\", \"page_number_end\": \"123\", \"context_chunk_ids\": [\"tang_p122_c145\", \"tang_p123_c146\", \"tang_p124_c147\"], \"page_number_start\": \"123\"}, {\"score\": 0.03149801587301587, \"content\": \"[neighbor chunk_id=tang_p429_c169 page=429]\\n注意\\n\\n无论何时检修空调系统，都应要求检修站保证使用冷媒再循环系统。\\n\\n该系统可回收冷媒进行再利用，将冷媒释放于大气中会污染环境。\\n\\n雨刮器刮片\\n\\n雨刮器刮片保养\\n\\n刮片胶条材质为合成橡胶，属于易损件，各种车辆的使用环境和驾驶员使用习惯均可能会对刮片造成损坏，所以为了保证刮片的使用寿命和汽车行驶安全，请您注意以下事项：\\n\\n请勿用刮片去刮除挡风玻璃表面上结的冰，应该使用专用的刮冰器。\\n\\n请勿在脏污、有油污或有蜡的挡风玻璃表面刮刷。\\n\\n保持玻璃表面干净，请勿刮刷玻璃表面的灰尘、沙粒、昆虫和异物等。\\n\\n一洗车和车身油漆保养时，无需对挡风玻璃打蜡，蜡层在光线不好时会反光，影响视线和行车安全。洗车后应该用纯净水漂洗刮片，使用专用的玻璃蜡层清洗剂去除挡风玻璃上的蜡层。\\n\\n洗车时请勿直接用水枪冲洗刮片，防止水压过大损坏刮片。\\n\\n[seed chunk_id=tang_p429_c170 page=429-430]\\n保养细则\\n\\n定期清洗风窗玻璃和刮片(建议一至两周一次)。\\n\\n建议定期刮拭雨刮(建议一至二天一次)。使用刮片刮拭风窗玻璃时，必须保持玻璃充分湿润(未下雨时，必须预先开启洗涤液喷洒玻璃)。\\n\\n使用专用风窗玻璃清洗剂清洗风窗玻璃。\\n\\n风窗玻璃上粘附有泥土、昆虫的尸体时应及时用抹布擦拭干净。\\n\\n风窗玻璃上有碎石敲击的伤痕时，应及时进行保养(建议使用风窗玻璃修复树脂类产品，伤痕较多或过大建议更换风窗玻璃)。\\n\\n定期更换雨刮刮片，建议半年一次。\\n\\n清洗风窗玻璃时必须预先抬起雨刮刮臂，具体操作方法为：\\n\\n1. 点击中控屏→ →车辆→维护→检修，开启前/后雨刮检修，雨刮旋转出来。\\n\\n2. 抓住刮臂上端，小心地提起刮臂和刮片总成。\\n\\n[neighbor chunk_id=tang_p430_c171 page=430]\\n轮胎\\n\\n–为安全驾驶车辆，轮胎的型号和尺寸必须适合您的车型，并具有状态良好的胎纹和标准胎压。\\n\\n以下内容，将详细地介绍如何检查胎压、轮胎的损伤和磨耗及轮胎换位时的操作方法。\\n\\n警告\\n\\n使用过度磨损、胎压不足或胎压过高的轮胎将会引发事故，造成人身伤亡。\\n\\n须遵照本手册中关于轮胎充气及保养的所有说明。\\n\\n充气\\n\\n保持轮胎适当充气，可提供操纵性、胎面寿命和驾驶舒适性三者的最佳组合。\\n\\n使用充气不足的轮胎会导致轮胎磨损不均匀，并且影响操纵和能耗，更可能由于过热而漏气。\\n\\n一使用充气过度的轮胎会降低车辆的舒适性，也更容易因路面的不平而受损，严重时有爆胎风险，严重威胁整车安全；同时也会导致轮胎磨损不均匀，影响轮胎寿命。\\n\\n车辆配有胎压监测装置。冷胎时，您可以根据仪表上显示的各轮胎胎压值，决定是否需要补充胎压。\\n\\n–应该在轮胎处于冷态时测量胎压。这意味着至少要在停车三个小时之后再测量。如果您必须在测量胎压之前行驶，只要行驶距离不超过1.6km，仍可以认为轮胎是处于冷态。\\n\\n如果在轮胎处于热态时(行驶数千米后)检查胎压，压力读数将比冷态时的读数高 30~40kPa(0.3~0.4kgf/cm²)，此类现象属正常，请勿为了达到规定的冷态胎压读数而放气，否则将导致轮胎胎压不足。\", \"chunk_id\": \"tang_p429_c170\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"保养细则\", \"page_number_end\": \"430\", \"context_chunk_ids\": [\"tang_p429_c169\", \"tang_p429_c170\", \"tang_p430_c171\"], \"page_number_start\": \"429\"}, {\"score\": 0.03149801587301587, \"content\": \"[neighbor chunk_id=tang_p120_c143 page=120-121]\\n警告\\n\\n电源挡位处于“ON/OK”挡时，将雨刮开至自动挡位，此时若用手触碰或用布擦拭传感器上部的玻璃，均有可能引起雨刮运转，造成意外事故。\\n\\n注意\\n\\n在洗车、较干燥季节或无雨天气时要关闭自动雨刮，否则有可能会造成雨刮无意间运转。\\n\\n因积雪等原因，雨刮中途停止运转时，请关闭雨刮，将车辆停放在安全地点，然后清除积雪等杂物，以便雨刮能够正常工作。\\n\\n一下雪天由于雪花的形状不同，有时即使雪花碰触到雨量传感器，传感器也不能正常感知，致使雨刮不能正常工作。雪花融化后，有可能造成雨刮自动刮刷。\\n\\n如需让雨刮在点刮模式下运作，请按压控制杆端部按键至第一挡位置，雨刮将低速刮水，直至将按键松开位置。\\n\\n[seed chunk_id=tang_p121_c144 page=121-122]\\n前风窗玻璃洗涤器\\n\\n清洗前风窗玻璃时，可按压控制杆端部按键至第二挡位置，洗涤器持续喷水，之后雨刮开始工作。\\n\\n■松开控制杆或者持续操作的时间超过 10s时，洗涤器将停止喷水，雨刮刮刷3~4个循环后停止工作。\\n\\n后雨刮\\n\\n将雨刮开关中段滚轮拨到“ ”位置，后雨刮进入间歇挡；\\n\\n将雨刮开关中段滚轮拨到“ ”位置或者后背门开启时，后雨刮停止工作；\\n\\n一将雨刮开关中段滚轮拨到“ ”位置并保持，后风窗刮水器和洗涤器同时启动；\\n\\n将雨刮开关中段滚轮拨到“ ”位置并释放，在喷射洗涤液之后，刮水器将工作2~3次后停止。\\n\\n[neighbor chunk_id=tang_p122_c145 page=122]\\n注意\\n\\n定期检查刮片，清除粘在刮片上的污物。\\n\\n尽量避免刚下雨时就开启雨刮，此时雨水混合着泥沙、灰尘，不但刮不干净风窗玻璃，反而在瞬间造成视野一片模糊，影响行车安全。\\n\\n请使用玻璃清洗剂。水或其他类型洗涤剂可能会导致洗涤电机损坏。\\n\\n请勿使洗涤器连续工作10s以上或者在洗涤液罐空置时操作，否则可能导致电机过热损坏。\\n\\n更换雨刮\\n\\n更换雨刮片\\n\\n至少每六个月检查一次前/后雨刮器刮片状况，查看橡胶有无裂缝或者局部硬化。如发现这些现象，则应更换刮片，否则，使用时会留下条纹或刮不净的地方。\\n\\n一整车电源在“ON”挡或“OK”挡，用户可通过点击中控屏→设置 →DiLink→检修设置界面开启或关闭前/后雨刮检修功能，开启相应的雨刮检修设置，则相应的雨刮旋转出来，便于检修和更换雨刮。\\n\\n更换前雨刮\\n\\n1. 首先拉起驾驶员侧的刮水器臂，然后再拉起乘员侧的刮水器臂。\\n\\n2. 按下刮片锁止按钮①。\\n\\n3. 握住刮片卡扣处，沿图示方向②取出来。\\n\\n4. 手握刮水器臂上喷水管一端，将其从刮片上拔出。\\n\\n5. 新刮片装配时，按照取出刮片相反的步骤进行操作。\", \"chunk_id\": \"tang_p121_c144\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"前风窗玻璃洗涤器\", \"page_number_end\": \"122\", \"context_chunk_ids\": [\"tang_p120_c143\", \"tang_p121_c144\", \"tang_p122_c145\"], \"page_number_start\": \"121\"}, {\"score\": 0.021311475409836068, \"content\": \"[neighbor chunk_id=tang_p432_c174 page=432-433]\\n注意\\n\\n不适当的车轮平衡块将会卡装不牢固、脱落，行车时将会伤害到您的爱车或周边物体。\\n\\n不适当的车轮平衡块将会损坏您车辆的铝合金轮辋。因此，建议您使用原厂车轮平衡块，使其保持平衡。\\n\\n轮毂保养\\n\\n轮毂出现污垢后，请使用中性洗涤剂，尽快去除，之后用清水充分冲洗。\\n\\n注意\\n\\n为了防止涂装的损伤，请务必遵守以下事项：\\n\\n不使用酸性、碱性及含有研磨剂的洗涤剂；\\n\\n不使用硬刷；\\n\\n夏天行驶后或停车后车轮发热时，请勿用蒸汽清洗等方法直接将热水喷到车轮上。\\n\\n轮胎换位\\n\\n一为了使轮胎的磨损相同以及延长轮胎的使用寿命，我们建议您定期(不超过 10000km)检查轮胎内侧及外侧花纹的磨损情况，必要时进行轮胎换位，同时进行四轮定位检查调整。\\n\\n若车辆轮胎为临时备胎时，请勿进行换位。\\n\\n更换轮胎后，请前往比亚迪汽车授权服务店进行轮胎胎压匹配。\\n\\n购买更换轮胎时，有些轮胎是“有方向性的”，只能向一个方向换位。若使用有方向性轮胎，轮胎换位时只能前后轮对调。\\n\\n车辆轮胎换位如图所示：\\n\\n① 无方向性轮胎及车轮\\n\\n② 有方向性轮胎及车轮\\n\\n[seed chunk_id=tang_p433_c175 page=433]\\n警告\\n\\n前后轮使用相同规格的轮胎时可以进行轮胎换位，前后轮胎规格不相同时，不可以进行轮胎换位。\\n\\n更换轮胎与车轮\\n\\n本车的原装轮胎，是为了最大限度地发挥车辆性能而选择的，同时，可为您提供操纵性、乘坐舒适性以及使用寿命的最佳组合。\\n\\n建议到比亚迪汽车授权服务店更换原装轮胎。\\n\\n如使用尺寸、负荷范围、额定转速以及最大冷胎气压(标记在轮胎的侧面) 不相同的子午线轮胎进行更换，或混合使用子午线轮胎和斜纹轮胎，都会降低车辆的制动能力、驱动力(地面附着力)以及转向精确度。\\n\\n安装不适合的轮胎会影响车辆的操作灵活性和稳定性，并可能导致事故而造成伤亡。\\n\\n一最好同时更换四个轮胎，如果不可能或没有必要，则应成对更换两个前胎或后胎。只更换一个轮胎会严重地影响车辆的操纵性。\\n\\nABS(防抱死制动装置) 是通过比较车轮的转速而工作的。故更换轮胎时，必须使用与车辆原装轮胎尺寸一致的轮胎，轮胎的尺寸及结构会影响车轮转速，并可能导致系统的动作不协调。\\n\\n[neighbor chunk_id=tang_p434_c176 page=434]\\n434 6-3 自行保养\\n\\n一如需更换车轮，应确保新车轮的规格与原装车轮的规格相符。新车轮可在比亚迪汽车授权服务店购买到，在更换车轮之前，建议向比亚迪汽车授权服务店咨询。\\n\\n警告\\n\\n请遵守下列事项，否则会引起典型的操纵危险而导致车辆失去控制。\\n\\n车辆上请勿混用子午线轮胎、带束斜线轮胎或斜纹帘布层轮胎。\\n\\n请勿使用厂商推荐尺寸外的其它轮胎。\\n\\n保险丝\\n\\n车辆上所有电路均设有保险丝，以防止短路或超负荷。这些保险丝分别被安装在保险丝盒内，保险丝盒内附有保险丝标贴。通过标贴，可以确定保险丝与电气部件的对应关系。\\n\\n前舱正极保险盒位于前舱左翼子板旁。\\n\\n仪表板保险丝盒位于主驾仪表台下护板内部。\\n\\n后舱保险丝盒*位于左后侧围护板内部。\\n\\n注意\\n\\n请勿使用高于额定安培数的保险丝，或任何其它物体代替保险丝，否则将引起严重的损坏并可能造成火灾。\\n\\n保险丝烧断后，建议到比亚迪汽车授权服务店进行检查或更换。\", \"chunk_id\": \"tang_p433_c175\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"警告\", \"page_number_end\": \"433\", \"context_chunk_ids\": [\"tang_p432_c174\", \"tang_p433_c175\", \"tang_p434_c176\"], \"page_number_start\": \"433\"}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=tang_p226_c080 page=226]\\n功能设置\\n\\nNOA功能可在中控屏→ →辅助驾驶→行车辅助中开启“领航辅助”。\\n\\n在设置项中选择到“领航辅助”时也视为ACC、ICC功能开启。驾驶员主动激活功能时将优先激活NOA功能，若NOA功能无法激活，但满足ACC/ICC 功能条件时则可激活 ACC/ICC 功能。\\n\\n进入中控屏→ →辅助驾驶→行车辅助界面，可根据需要和个人偏好设置NOA的功能参数。\\n\\n–设置NOA的变道风格*。变道风格是驾驶员偏好的辅助驾驶员变道的风格，可设置的参数如下表所示。参数默认值分别为保守、标准。\\n\\n[seed chunk_id=tang_p226_c081 page=226]\\n第1条：\\n选项：保守\\n说明：超车变道风格温和,导航变道发起时机更早\\n\\n第2条：\\n选项：标准\\n说明：超车变道风格积极,导航变道发起时机更灵活\\n\\n[neighbor chunk_id=tang_p227_c082 page=227]\\n设置NOA的限速辅助参数，包括目标车速偏移方式和偏移量，目标车速偏移方式分为固定值和百分比两种：\\n\\n选择固定值时，偏移量与道路限速无关，所有道路使用相同的固定值。\\n\\n选择百分比时，偏移量为相对于道路限速的百分比值，道路限速不同则偏移量不同。\\n\\n目标车速偏移方式和偏移量用于计算限速辅助时的目标车速。参数默认值分别为数值、0km/h。\\n\\n设置NOA的通行效率优先参数。若开启通行效率优先开关，可以跟随周边车辆的速度调节自车车速。通行效率优先开关默认关闭。\", \"chunk_id\": \"tang_p226_c081\", \"chunk_type\": \"table\", \"source_file\": \"tang.pdf\", \"section_title\": \"功能设置\", \"page_number_end\": \"226\", \"context_chunk_ids\": [\"tang_p226_c080\", \"tang_p226_c081\", \"tang_p227_c082\"], \"page_number_start\": \"226\"}]',5,11127,1,NULL,'2026-06-23 12:24:29'),(32,1,NULL,NULL,NULL,'我的车怎么启动不了？怎么解决？','根据提供的《用户手册》资料，车辆无法启动主要与**低压蓄电池休眠/亏电**或**智能钥匙系统异常**有关。请按以下手册支持的步骤进行排查与处理：\n\n### 🔋 1. 低压蓄电池休眠或缺电\n长期停放后，低压蓄电池可能进入休眠状态，导致按键寻车及解锁失效。\n- **微动开关唤醒**：按下**左前门把手的微动开关**，即可唤醒低压蓄电池，车辆解锁后即可恢复正常使用。\n- **搭火启动**：若微动开关无效，请使用智能钥匙上的**机械钥匙**打开驾驶员侧车门。通过**前舱配电盒专用接口**，连接12V电源与搭火专用电缆线进行搭火启动车辆。启动后需保持车辆运行**15分钟以上**，以确保低压蓄电池充分充电。（仪表提示“蓄电池电量不足，车辆即将退电”属正常现象）\n- ⚠️ **安全提示**：严禁车辆未上“OK”挡即进行搭接对火；前舱搭火空间有限且存在电路风险，建议在专业人员指导下操作。\n\n### 🔑 2. 智能钥匙/启动系统异常\n- **钥匙没电或信号干扰**：受强电磁波、金属覆盖、长时间携带通讯设备或钥匙自身电池耗尽影响，可能导致启动功能失效。请改用**无线遥控功能**或**机械钥匙**开门，踩下制动踏板后按下“启动/停止”按键启动车辆。\n- **重复启动保护**：车辆在短时间内反复启动失败，属于系统保护机制。请等待约**10秒**后，再尝试启动。\n- **系统故障提示**：若组合仪表亮起智能钥匙系统警告灯，或提示系统故障，常规方法无法解决。\n\n### 🛠 3. 后续处理建议\n若上述唤醒、搭火及按键操作均无效，或故障频繁发生，请**立即停止自行操作**。为保障行车与电气安全，建议直接联系**比亚迪汽车授权服务店**进行专业检测与维修，具体请以车辆仪表盘实际提示及官方售后指导为准。','tang.pdf','[{\"score\": 0.051651954602774275, \"content\": \"[neighbor chunk_id=tang_p146_c177 page=146]\\n一般充电故障诊断\\n\\n[seed chunk_id=tang_p146_c178 page=146]\\n第1条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：充电卡欠费或充电桩故障\\n解决方法：充电卡费用查询或联系场站工作人员解决。\\n\\n第2条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：交流充电连接装置未正确连接\\n解决方法：确认充电枪开关已弹起,注意充电设备的插头长短不同和连接位置不同。\\n\\n第3条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：12V低压蓄电池过度放电220V 50Hz 10A 标准带接地插座无电\\n解决方法：从其他车辆上搭接12V电源,车辆启动后,会给低压蓄电池充电。确认电源是否已过载保护,请换至另外插座使用。\\n\\n第4条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：车辆或交流充电连接装置故障\\n解决方法：确定仪表盘上有动力系统故障灯点亮,或是有充电系统故障提示语,则停止充电,建议与比亚迪汽车授权服务店联系。\\n\\n第5条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：动力电池温度过低或过高时\\n解决方法：在充电前允许动力电池加热或冷却,将车辆置于适宜温度的环境内,待温度正常后再充电。\\n\\n第6条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：动力电池已充满\\n解决方法：动力电池已充满时,充电会自动停止。\\n\\n第7条：\\n故障状态：充电中途停止充电\\n可能原因：充电电缆没有连接完全\\n解决方法：确认充电连接装置电缆没有虚接。\\n\\n第8条：\\n故障状态：充电中途停止充电\\n可能原因：充电连接装置开关被按下\\n解决方法：充电连接装置开关被按下则停止充电,需重新连接充电连接装置,启动充电。\\n\\n第9条：\\n故障状态：充电中途停止充电\\n可能原因：电源断电\\n解决方法：在一定时间内,电源恢复后,需重新连接充电连接装置,启动充电。\\n\\n第10条：\\n故障状态：充电中途停止充电\\n可能原因：动力电池温度过高\\n解决方法：充电会自动停止,待电池冷却后再充电。\\n\\n[neighbor chunk_id=tang_p146_c179 page=146]\\n第11条：\\n故障状态：充电中途停止充电\\n可能原因：车辆或充电桩发生故障\\n解决方法：确认充电桩或车辆有故障提示,建议联系比亚迪汽车授权服务店。\", \"chunk_id\": \"tang_p146_c178\", \"chunk_type\": \"table\", \"source_file\": \"tang.pdf\", \"section_title\": \"一般充电故障诊断\", \"page_number_end\": 146, \"context_chunk_ids\": [\"tang_p146_c177\", \"tang_p146_c178\", \"tang_p146_c179\"], \"page_number_start\": 146}, {\"score\": 0.05024193548387097, \"content\": \"[neighbor chunk_id=tang_p93_c110 page=93-94]\\n智能进入和智能启动系统\\n\\n携带有效智能钥匙可为车门解/闭锁并启动车辆。\\n\\n进入功能\\n\\n携带有效智能钥匙，可为车门解锁或闭锁。(详细请参见“智能钥匙闭锁/解锁”和“微动开关闭锁/解锁”)\\n\\n启动功能\\n\\n携带有效智能钥匙，踩下制动踏板，按下“启动/停止”按键，启动车辆(详细请参见的“车内启动车辆”)。\\n\\n探测天线位置\\n\\n①位于车厢内的探测天线\\n\\n②位于车厢外的探测天线\\n\\n激活区域\\n\\n已登记的智能钥匙在激活区域内时，智能进入和启动功能方可生效。\\n\\n①进入功能激活区域——距前门把手和后背门外开关大约1m的范围内。\\n\\n②启动功能激活区域——车厢内。\\n\\n其他车辆的智能钥匙接近本车的智能钥匙时，车门解锁的时间可能要比平时长一些，属正常现象。\\n\\n温馨提示\\n\\n在下列情况下，智能进入和启动系统可能不会正常工作：\\n\\n当附近有释放强电磁波的设施，例如电视塔、发电站、广播站时。\\n\\n将智能钥匙与通讯装置一同携带时，比如双向无线电通讯设备或移动电话。\\n\\n当智能钥匙与金属物体接触或被其覆盖时。\\n\\n迅速操作车门把手时。\\n\\n智能钥匙接近车门把手时。\\n\\n当他人在附近的另一辆车上操作无线遥控功能时。\\n\\n当智能钥匙电池电量耗尽时。\\n\\n智能钥匙在高压设备或产生噪音的设备附近时。\\n\\n–当智能钥匙在同其他车辆智能进入和启动系统的钥匙或其他发射无线电波的装置一起携带时。\\n\\n[seed chunk_id=tang_p95_c111 page=95]\\n温馨提示(续)\\n\\n即使在激活区域内，在某些位置(如仪表板上、杂物箱内、地板上)智能钥匙也可能不会正常工作。\\n\\n■如果智能进入系统不正常工作，无法进入车内时，则可使用附在智能钥匙上的机械钥匙为驾驶员侧车门解锁和闭锁，或者用无线遥控功能为所有车门解锁和闭锁。\\n\\n按下“启动/停止”按键时，启动功能不能正常起作用，可能由下列原因引起：\\n\\n如果智能钥匙不起作用，组合仪表上的智能钥匙系统警告灯点亮，且组合仪表显示提示信息“钥匙电池电量低”，则钥匙的电池电量可能已耗尽。\\n\\n车辆在短时间内反复启动。需等10s，然后启动车辆。\\n\\n如果智能进入和智能启动系统因系统故障不能正常运行，建议携带所有智能钥匙到比亚迪汽车授权服务店进行维修。\\n\\n[neighbor chunk_id=tang_p95_c112 page=95-96]\\n节约电量\\n\\n■即使没有驾驶车辆，智能钥匙和车辆之间也能进行通信。因此，请勿将智能钥匙留在车内或距离车辆 2m的范围内。\\n\\n如果智能钥匙长期接收强电磁波，则电池电量会急速耗尽。请勿将其置于可产生磁场的电气设备附近，至少保持 1m的距离，例如：\\n\\n电视机\\n\\n个人电脑\\n\\n手机充电器\\n\\n电灯架\\n\\n荧光台灯\\n\\n机械儿童锁\\n\\n儿童锁是为防止坐在后排座椅上的儿童无意中打开后排车门而设计的，左后门、右后门的侧面均有儿童锁装置。\\n\\n开启儿童锁功能\\n\\n–按箭头①方向拨动锁栓，开启儿童锁功能，从车内不能打开该车门。欲打开此车门，需使用车外的车门把手。\\n\\n关闭儿童锁功能\\n\\n–按箭头②方向拨动锁栓，关闭儿童锁功能，从车内可以打开该车门。\", \"chunk_id\": \"tang_p95_c111\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"温馨提示(续)\", \"page_number_end\": 95, \"context_chunk_ids\": [\"tang_p93_c110\", \"tang_p95_c111\", \"tang_p95_c112\"], \"page_number_start\": 95}, {\"score\": 0.0378908188585608, \"content\": \"[neighbor chunk_id=tang_p65_c070 page=65]\\n温馨提示\\n\\n若用户长时间EV 行驶，会触发发动机保养需求启动发动机，仪表会提示：为了发动机保养需求已自动启动发动机。\\n\\n仪表其他故障说明\\n\\n仪表可能出现以下故障提示信息，请按照推荐的处理方法进行操作：\\n\\n[seed chunk_id=tang_p65_c071 page=65]\\n第1条：\\n故障提示：请检查车载充电系统\\n处理方法：车载充电系统有故障,请检查充电连接有无异常,重新连接充电设备。如不能解决,建议与比亚迪汽车授权服务店联系。\\n\\n第2条：\\n故障提示：为了您的安全,遥控驾驶暂停使用\\n处理方法：遥控驾驶出现异常,请暂停使用。\\n\\n第3条：\\n故障提示：请检查车辆网络\\n处理方法：表示当前车辆的数据网络可能存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n第4条：\\n故障提示：发动机附件功能受限\\n处理方法：表示发动机附件有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第5条：\\n故障提示：请检查记忆系统*\\n处理方法：表示记忆系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第6条：\\n故障提示：请检查前照灯系统\\n处理方法：表示前照灯系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第7条：\\n故障提示：请检查挡位系统\\n处理方法：表示挡位控制器存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n第8条：\\n故障提示：请检查 HDC 系统\\n处理方法：表示 HDC 系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n[neighbor chunk_id=tang_p67_c072 page=67-68]\\n3\\n\\n3-1 车门和钥匙....69 钥匙....69 闭锁/解锁车门....75 电动滑门....88 智能进入和智能启动系统....93 机械儿童锁....95 3-2 座椅....97 座椅....97 前排座椅....98 二排座椅....102 座椅加热通风*....106 三排座椅....107 头枕....111 3-3 转向盘....114 转向盘开关组....114 转向盘调节....118 3-4 雨刮....120 雨刮开关....120 更换雨刮....122 3-5 后视镜....124 内后视镜....124 外后视镜....125 3-6 开关....127 灯光开关....127 驾驶员侧车门开关组....129 乘员侧车窗控制开关....131\\n\\n自动关窗*....132 紧急告警灯开关....133 天窗开关....133 E-Call/云-Call 开关....136 二排控制面板*....137 室内灯开关....138\", \"chunk_id\": \"tang_p65_c071\", \"chunk_type\": \"table\", \"source_file\": \"tang.pdf\", \"section_title\": \"仪表其他故障说明\", \"page_number_end\": \"65\", \"context_chunk_ids\": [\"tang_p65_c070\", \"tang_p65_c071\", \"tang_p67_c072\"], \"page_number_start\": \"65\"}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=tang_p146_c178 page=146]\\n第1条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：充电卡欠费或充电桩故障\\n解决方法：充电卡费用查询或联系场站工作人员解决。\\n\\n第2条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：交流充电连接装置未正确连接\\n解决方法：确认充电枪开关已弹起,注意充电设备的插头长短不同和连接位置不同。\\n\\n第3条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：12V低压蓄电池过度放电220V 50Hz 10A 标准带接地插座无电\\n解决方法：从其他车辆上搭接12V电源,车辆启动后,会给低压蓄电池充电。确认电源是否已过载保护,请换至另外插座使用。\\n\\n第4条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：车辆或交流充电连接装置故障\\n解决方法：确定仪表盘上有动力系统故障灯点亮,或是有充电系统故障提示语,则停止充电,建议与比亚迪汽车授权服务店联系。\\n\\n第5条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：动力电池温度过低或过高时\\n解决方法：在充电前允许动力电池加热或冷却,将车辆置于适宜温度的环境内,待温度正常后再充电。\\n\\n第6条：\\n故障状态：不能充电:物理连接完成,已启动充电\\n可能原因：动力电池已充满\\n解决方法：动力电池已充满时,充电会自动停止。\\n\\n第7条：\\n故障状态：充电中途停止充电\\n可能原因：充电电缆没有连接完全\\n解决方法：确认充电连接装置电缆没有虚接。\\n\\n第8条：\\n故障状态：充电中途停止充电\\n可能原因：充电连接装置开关被按下\\n解决方法：充电连接装置开关被按下则停止充电,需重新连接充电连接装置,启动充电。\\n\\n第9条：\\n故障状态：充电中途停止充电\\n可能原因：电源断电\\n解决方法：在一定时间内,电源恢复后,需重新连接充电连接装置,启动充电。\\n\\n第10条：\\n故障状态：充电中途停止充电\\n可能原因：动力电池温度过高\\n解决方法：充电会自动停止,待电池冷却后再充电。\\n\\n[seed chunk_id=tang_p146_c179 page=146]\\n第11条：\\n故障状态：充电中途停止充电\\n可能原因：车辆或充电桩发生故障\\n解决方法：确认充电桩或车辆有故障提示,建议联系比亚迪汽车授权服务店。\\n\\n[neighbor chunk_id=tang_p147_c180 page=147]\\n整车交流充电/放电指示灯*\\n\\n充电/放电指示灯位于车身右侧充电口盖内。分别以绿色、黄色、红色、蓝色、白色颜色来说明充电状态。\\n\\n若不连接充/放电枪，白色常亮一段时间后会熄灭。使用过程中，若整车闭锁，指示灯点亮一段时候后熄灭。整车解锁时，指示灯再次点亮。\", \"chunk_id\": \"tang_p146_c179\", \"chunk_type\": \"table\", \"source_file\": \"tang.pdf\", \"section_title\": \"一般充电故障诊断\", \"page_number_end\": \"146\", \"context_chunk_ids\": [\"tang_p146_c178\", \"tang_p146_c179\", \"tang_p147_c180\"], \"page_number_start\": \"146\"}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=tang_p200_c034 page=200]\\n传感器标定触发条件\\n\\n一当相机出现换件，相机支架调整，或者中央计算平台更换等均需重新到比亚迪汽车授权服务店完成相机标定。\\n\\n一雷达类售后标定包含毫米波雷达（前雷达/角雷达）、激光雷达部分。当出现换件或拆装、支架调整等均需重新到比亚迪汽车授权服务店完成雷达标定。\\n\\n高精定位标定，当PBOX或中央计算平台换件或安装调整，均需到比亚迪汽车授权服务店重新完成高精定位标定。\\n\\n在使用泊车辅助功能时，当中控屏提示“请标定全景后使用”或者提示“传感器未标定，泊车暂不可用”时，请尽快驾驶车辆到比亚迪汽车授权服务店进行传感器标定，重新标定完成前泊车辅助功能暂不可用。\\n\\n[seed chunk_id=tang_p200_c035 page=200-201]\\n重启驾驶辅助系统\\n\\n如果系统出现异常或者无响应，驾驶员可以通过重启中控屏或者车辆重新上电来重启系统。\\n\\n重启方法\\n\\n1. 停车，挂入“P”挡。\\n\\n2. 同时长按转向盘右侧滚轮+向右按键 3s，待中控屏黑屏后松开即可重启系统。\\n\\n①多媒体触摸屏\\n\\n②转向盘右侧滚轮+向右按键\\n\\n温馨提示\\n\\n系统重启过程中，全景影像等驾驶辅助功能不可用。\\n\\n重启系统不影响车辆的电源状态，不会导致电源接通或断开。\\n\\n一重启系统后，车辆会重新定位自车位置，可能导致重启后首次使用驾驶辅助App时，地图界面的自车车标位置不准确。驾车在开阔路段行驶一段距离即可恢复车辆定位。\\n\\n如果中控屏在黑屏5分钟后仍无反应或出现其他异常，请尝试将车辆下电后，再上电重试。\\n\\n如果重启系统并将车辆下电后，再上电重试，中控屏仍无反应或出现其他系统异常，请联系比亚迪汽车授权服务店。\\n\\n[neighbor chunk_id=tang_p201_c036 page=201-202]\\n反馈驾驶辅助系统体验信息*\\n\\n–反馈系统体验问题信息：驾驶员可以通过实车操作来记录体验驾驶辅助的中发现的问题信息。\\n\\n使用方法\\n\\n用户可通过长按方向盘“时距-”按键超过0.5s或智能语音唤起上报驾驶辅助系统事件。\\n\\n待停车确认安全后或至比亚迪汽车授权服务店联系售后人员描述事件发生时间地点，必要时可提供行车记录仪佐证。\\n\\n上报事件时间建议\\n\\n202 4-5 驾驶辅助功能\\n\\n驾驶员及时、准确的反馈驾驶辅助体验有助于我们深入分析事件详情，持续优化改进。在确保安全的前提下，建议在发生以下情况的5秒内完成驾驶辅助事件上报操作。\\n\\n发生交通事故。\\n\\n车辆发生非预期行为，如非预期转向、加减速、功能退出或发出控制车辆提醒等。\\n\\n使用领航辅助时，车辆未按照导航路线行驶。\\n\\n显示屏上未显示自车周边部分车辆（目标漏检），或感知目标物显示异常（花屏、黑屏等）。\\n\\n其他驾驶辅助功能体验问题。\\n\\n我们将认真分析驾乘人员反馈的信息，持续提高驾驶辅助系统的使用体验。\", \"chunk_id\": \"tang_p200_c035\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"重启驾驶辅助系统\", \"page_number_end\": \"201\", \"context_chunk_ids\": [\"tang_p200_c034\", \"tang_p200_c035\", \"tang_p201_c036\"], \"page_number_start\": \"200\"}, {\"score\": 0.01746031746031746, \"content\": \"[neighbor chunk_id=tang_p167_c212 page=167-168]\\n警告\\n\\n■新能源汽车所有人有责任和义务将废旧动力电池移交回收服务网点。私自将废旧动力电池移交给其他单位或个人，私自拆卸、拆解动力电池，由此导致环境污染或安全事故的，应承担相应责任。\\n\\n低压蓄电池\\n\\n–本车低压蓄电池具备智能充电功能。当动力电池电量充足时，车辆可以自动开启动力电池对低压蓄电池充电，以延长低压蓄电池续航时长。\\n\\n温馨提示\\n\\n电源挡位处于“OFF”挡智能充电时，车辆会发出正常上“OK”挡时发出的声音，属正常现象。\\n\\n如果您离开车辆时，请确保已关闭所有用电设备，且车门已经关好。\\n\\n车辆亏电后唤醒功能\\n\\n[seed chunk_id=tang_p168_c213 page=168-169]\\n左前门微动开关唤醒\\n\\n低压蓄电池具有休眠唤醒功能。车辆长期存放后，若使用智能钥匙将无法实现寻车及车辆解锁功能，低压蓄电池可能已进入休眠状态。此时需按下左前门把手的微动开关(请参见“微动开关闭锁/解锁”)，即可唤醒低压蓄电池。对车辆解锁后，车辆即可正常使用。\\n\\n前舱搭火唤醒\\n\\n当车辆无法通过左前门微动开关唤醒和解锁时，可以使用机械钥匙打开车门。此时可以利用 12V 规格电源通过两根搭火专用电缆线搭火启动车辆。此时低压蓄电池电量较低，仪表可能提示“蓄电池电量不足，车辆即将退电”，车辆会再次休眠。需立即启动车辆发电并保持启动状态 15min 以上，以保证低压蓄电池充满电量。\\n\\n●搭火操作只能通过前舱配电盒专用接口进行。前舱配电盒搭火点如图所示。\\n\\n若上述操作均无法唤醒并启动车辆，建议请及时联系比亚迪汽车授权服务店处理。\\n\\n[neighbor chunk_id=tang_p169_c214 page=169]\\n警告\\n\\n严禁车辆未上“OK”挡即对其他车辆进行搭接对火，否则可能会损坏低压蓄电池。\\n\\n■当出现低压蓄电池亏电或无法正常使用等紧急需要临时搭火情况，请详细阅读用户手册该部分内容，并严格按照说明进行搭接或操作。\\n\\n低压蓄电池内部包含智能控制模块，非紧急情况下，请勿私自拆卸或破坏，避免低压蓄电池损坏。\\n\\n在更换零部件及整车维修检查前，请断开低压蓄电池负极。\\n\\n注意\\n\\n前舱配电盒搭火操作空间有限，同时存在一定的电路安全风险，搭火操作建议在专业人员指导下进行。\\n\\n低压蓄电池不能用液体清洗，避免让液体进入电池中。\", \"chunk_id\": \"tang_p168_c213\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"左前门微动开关唤醒\", \"page_number_end\": \"169\", \"context_chunk_ids\": [\"tang_p167_c212\", \"tang_p168_c213\", \"tang_p169_c214\"], \"page_number_start\": \"168\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=tang_p201_c036 page=201-202]\\n反馈驾驶辅助系统体验信息*\\n\\n–反馈系统体验问题信息：驾驶员可以通过实车操作来记录体验驾驶辅助的中发现的问题信息。\\n\\n使用方法\\n\\n用户可通过长按方向盘“时距-”按键超过0.5s或智能语音唤起上报驾驶辅助系统事件。\\n\\n待停车确认安全后或至比亚迪汽车授权服务店联系售后人员描述事件发生时间地点，必要时可提供行车记录仪佐证。\\n\\n上报事件时间建议\\n\\n202 4-5 驾驶辅助功能\\n\\n驾驶员及时、准确的反馈驾驶辅助体验有助于我们深入分析事件详情，持续优化改进。在确保安全的前提下，建议在发生以下情况的5秒内完成驾驶辅助事件上报操作。\\n\\n发生交通事故。\\n\\n车辆发生非预期行为，如非预期转向、加减速、功能退出或发出控制车辆提醒等。\\n\\n使用领航辅助时，车辆未按照导航路线行驶。\\n\\n显示屏上未显示自车周边部分车辆（目标漏检），或感知目标物显示异常（花屏、黑屏等）。\\n\\n其他驾驶辅助功能体验问题。\\n\\n我们将认真分析驾乘人员反馈的信息，持续提高驾驶辅助系统的使用体验。\\n\\n[seed chunk_id=tang_p202_c037 page=202-203]\\n驾驶辅助系统通用局限性\\n\\n驾驶辅助功能应用多传感器融合算法，许多因素都会影响辅助驾驶功能的性能，进而导致其无法实现预期的功能。常见的限制因素包括但不限于系统自身设备问题（含驾驶员误操作导致）、使用环境影响（天气、道路环境等）、周围车辆和其他交通参与者影响等，包括不限于以下因素：\\n\\n系统自身设备因素（包含人为使用原因）\\n\\n激光雷达*、毫米波雷达、超声波雷达、摄像头未校准、损坏、表面覆盖有异物（如冰雪、水、霜、泥浆、灰尘等物体覆盖）。\\n\\n有强烈反光物体的环境中（如高速公路上的交通标识牌、金属围栏，路面积水反光等）。\\n\\n发生如下情况请务必联系比亚迪汽车授权服务店对系统进行专业校准与确认，包括但不限于：\\n\\n拆卸前视摄像头、前风窗玻璃。\\n\\n因车轮跑偏，重新进行四轮定位后。\\n\\n车辆因发生剐蹭、碰撞等而导致车辆传感器异常或者车辆结构异常。特别是保险杠、前风窗玻璃、外后视镜、蒙皮（如翼子板、后尾门）、车架等因车辆碰撞或其他原因变形或损坏，导致传感器安装位置变化。\\n\\n如果装有挂车钩或装载的物体从车辆周围突出。\\n\\n自行安装在车辆后方的物体（如自行车架）造成干扰或阻碍。\\n\\n将过多车漆（车漆厚度发生变化）或胶粘制品（如胶带、贴纸，车衣等）涂抹或粘贴到车辆上造成的阻碍。\\n\\n对于配有电容传感器的车型，请勿安装方向盘套，可能会导致功能异常。\\n\\n车辆冷启动过程中，因驾驶辅助系统启动需要时间，行泊车功能暂不可用，请耐心等待。\\n\\n下列的情况下，本系统可能无法总是达到最优的性能水平，包括但不限于：\\n\\n刹车片过度磨损或者制动系统异常时。\\n\\n轮胎充气不当或轮胎过度磨损时。\\n\\n安装了不符合规定的轮胎时。\\n\\n安装了轮胎防滑链时。\\n\\n使用小型备胎或应急补胎工具时。\\n\\n车辆重载时。\\n\\n[neighbor chunk_id=tang_p203_c038 page=203-205]\\n使用环境影响因素\\n\\n若车辆长时间行驶在环形停车场、隧道等特殊道路条件下，雷达因探测特性局限性，可能会出现短暂的功能故障，当离开当前特殊道路后，功能恢复。\\n\\n–当进入和驶出弯道时，目标的选择有可能延迟或受到干扰。在这些情况下车辆将可能不按预期减速或延迟减速。\\n\\n在急转弯道路（如蛇行道路）上或道路弯道曲率过大时可能出现前车由于传感器视野限制在几秒钟内发生丢失，这可能导致车辆自动加速。\\n\\n对静止或缓慢移动的物体，例如车辆、车流尾端、收费站、摩托车、自行车或者行人，系统可能无法准确识别，存在发生碰撞的风险，需要驾驶员时刻注意车辆周边情况。\\n\\n如车辆处于拖车/雪地/泥地/沙地/山地等特殊驾驶模式*时，系统功能不能激活。\\n\\n在某些环境中探测有可能受到影响或者发生延迟，如目标的雷达反射截面积过小（可能是自行车、三轮车、四轮马车、行人、电动自行车、摩托车或异形车等）时，系统存在无法确认与前方目标距离的风险，可能出现对该类车辆反应延迟或无法反应的情况。\\n\\n雨、雪、雾、霾、浓雾等极端天气下，结冰及湿滑弯道上。\\n\\n周围环境视野差，例如浓烟，溅起的水花，扬尘，周围车辆排放的尾气等。\\n\\n车道线过度磨损或被遮挡、覆盖、消失，新旧标线重叠，因道路施工临时调整或变化迅速。\\n\\n系统易受地图实时性、车辆网络和道路环境的影响，途径边境线，军事基地等特殊区域时，系统功能不可用。\\n\\n车辆定位天线被金属遮挡物（含金属改色膜）覆盖。\\n\\n隧道、高大山体、多层高架、高压线密集区域等影响高精定位和信号传输。\\n\\n强光（由于迎面而来的前照灯灯光或直射的阳光等）、光线昏暗（如黎明、黄昏、夜晚）。\\n\\n极端的光线反差，例如隧道入口或出口。\\n\\n温度极高或极低。\\n\\n对于限重、限宽标识不规范，不满足国家规定尺寸要求的情况，可能会被误识别为限速标识，造成误识别。\\n\\n道路限速标志不清晰或者存在扭曲、倾斜、反光、部分遮挡或覆盖等，将导致摄像头识别能力下降或无法识别。\", \"chunk_id\": \"tang_p202_c037\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"驾驶辅助系统通用局限性\", \"page_number_end\": \"203\", \"context_chunk_ids\": [\"tang_p201_c036\", \"tang_p202_c037\", \"tang_p203_c038\"], \"page_number_start\": \"202\"}, {\"score\": 0.013114754098360656, \"content\": \"[neighbor chunk_id=tang_p6_c007 page=6-7]\\n6 保养及维护\\n\\n6-1 保养须知....404 保养周期及保养内容....404 6-2 定期保养....410 定期保养....410 车辆防腐蚀....411 漆面保养提示....412 车辆外部清洗....413 车辆内部清洁....415 滑门系统保养....417 6-3 自行保养....419 自行保养....419 天窗保养....422 车辆的存放....423 前舱盖....423\\n\\n发动机保养....425 冷却系统....426 制动系统....428 洗涤系统....428 空调系统....429 雨刮器刮片....429 轮胎....430 保险丝....434\\n\\n[seed chunk_id=tang_p7_c008 page=7]\\n发生故障时\\n\\n7-1 发生故障时....438 反光背心....438 如果智能钥匙电池电量耗尽....438 如果出现高压故障....439 如果车辆不能启动....439 如果在驾驶中发动机启动失败....440 如果发动机过热....440 如果车辆需要牵引....441 如果轮胎漏气....443\\n\\n8 车辆规格\\n\\n8-1 数据信息....450 整车参数....450 8-2 提示信息....454 车辆标识....454 警告标签....455 微波窗口....457\\n\\n[neighbor chunk_id=tang_p8_c009 page=8-9]\\n车外\\n\\n① 后背门.... P81 ② 充电前检查.... P148 便携式交流充电*.... P148 交流充电桩充电*.... P151 直流充电桩充电*.... P153 ③ 外后视镜.... P125 ④ 加注燃油.... P173 ⑤ 闭锁/解锁车.... P77\\n\\n⑥ 轮胎....P430 如果轮胎漏气....P443 ⑦ 车灯....P421 灯光开关....P127 ⑧ 前舱盖....P423 发动机机油....P425 冷却系统....P426 制动系统....P428 洗涤器....P428\", \"chunk_id\": \"tang_p7_c008\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"发生故障时\", \"page_number_end\": 7, \"context_chunk_ids\": [\"tang_p6_c007\", \"tang_p7_c008\", \"tang_p8_c009\"], \"page_number_start\": 7}, {\"score\": 0.012903225806451611, \"content\": \"[neighbor chunk_id=tang_p65_c069 page=65]\\n交通标志识别指示灯*\\n\\n此指示图标点亮时，代表系统识别到当前路段的限速值。\\n\\nGPF 需要再生指示灯*\\n\\n当颗粒捕集器(GPF)碳载量(排放颗粒物)达到一定量时，GPF会主动进入再生状态，GPF指示灯处于绿色常亮状态，此时在路况允许的情况下尽量多跑高速工况，待颗粒物处理完成，GPF指示灯会自动熄灭。\\n\\nGPF需要再生故障灯*\\n\\n当GPF碳载量(排放颗粒物)达到最大值时，导致油耗上升，动力性能下降，GPF指示灯处于黄色常亮状态，此时需要到比亚迪汽车授权服务店检查车辆。\\n\\n[seed chunk_id=tang_p65_c070 page=65]\\n温馨提示\\n\\n若用户长时间EV 行驶，会触发发动机保养需求启动发动机，仪表会提示：为了发动机保养需求已自动启动发动机。\\n\\n仪表其他故障说明\\n\\n仪表可能出现以下故障提示信息，请按照推荐的处理方法进行操作：\\n\\n[neighbor chunk_id=tang_p65_c071 page=65]\\n第1条：\\n故障提示：请检查车载充电系统\\n处理方法：车载充电系统有故障,请检查充电连接有无异常,重新连接充电设备。如不能解决,建议与比亚迪汽车授权服务店联系。\\n\\n第2条：\\n故障提示：为了您的安全,遥控驾驶暂停使用\\n处理方法：遥控驾驶出现异常,请暂停使用。\\n\\n第3条：\\n故障提示：请检查车辆网络\\n处理方法：表示当前车辆的数据网络可能存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n第4条：\\n故障提示：发动机附件功能受限\\n处理方法：表示发动机附件有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第5条：\\n故障提示：请检查记忆系统*\\n处理方法：表示记忆系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第6条：\\n故障提示：请检查前照灯系统\\n处理方法：表示前照灯系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第7条：\\n故障提示：请检查挡位系统\\n处理方法：表示挡位控制器存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n第8条：\\n故障提示：请检查 HDC 系统\\n处理方法：表示 HDC 系统有故障,建议与比亚迪汽车授权服务店联系。\", \"chunk_id\": \"tang_p65_c070\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": 65, \"context_chunk_ids\": [\"tang_p65_c069\", \"tang_p65_c070\", \"tang_p65_c071\"], \"page_number_start\": 65}, {\"score\": 0.012698412698412698, \"content\": \"[neighbor chunk_id=tang_p434_c176 page=434]\\n434 6-3 自行保养\\n\\n一如需更换车轮，应确保新车轮的规格与原装车轮的规格相符。新车轮可在比亚迪汽车授权服务店购买到，在更换车轮之前，建议向比亚迪汽车授权服务店咨询。\\n\\n警告\\n\\n请遵守下列事项，否则会引起典型的操纵危险而导致车辆失去控制。\\n\\n车辆上请勿混用子午线轮胎、带束斜线轮胎或斜纹帘布层轮胎。\\n\\n请勿使用厂商推荐尺寸外的其它轮胎。\\n\\n保险丝\\n\\n车辆上所有电路均设有保险丝，以防止短路或超负荷。这些保险丝分别被安装在保险丝盒内，保险丝盒内附有保险丝标贴。通过标贴，可以确定保险丝与电气部件的对应关系。\\n\\n前舱正极保险盒位于前舱左翼子板旁。\\n\\n仪表板保险丝盒位于主驾仪表台下护板内部。\\n\\n后舱保险丝盒*位于左后侧围护板内部。\\n\\n注意\\n\\n请勿使用高于额定安培数的保险丝，或任何其它物体代替保险丝，否则将引起严重的损坏并可能造成火灾。\\n\\n保险丝烧断后，建议到比亚迪汽车授权服务店进行检查或更换。\\n\\n[seed chunk_id=tang_p435_c177 page=435-436]\\n发生故障时\\n\\n7\\n\\n7-1 发生故障时....436 反光背心....436 如果智能钥匙电池电量耗尽...436 紧急关闭系统....437 高压切断装置....437 如果车辆发生碰撞....438 如果电池泄漏....438 如果车辆起火....439 如果车辆需要牵引....440 如果轮胎漏气或胎压不足....442\\n\\n反光背心\\n\\n反光背心放置在后备箱工具盒中。\\n\\n当您驾驶车辆遇到突发故障需要紧急下车检查或者处理车辆事故时，请及时正确穿戴反光背心再下车检查及处理故障，以保证自身的安全。\\n\\n如果智能钥匙电池电量耗尽\\n\\n如果电子智能钥匙指示灯不闪烁，且使用启动功能不能启动车辆时，则可能是电池电量耗尽。建议尽快联系比亚迪汽车授权服务店更换电池。此时可以使用无电模式启动车辆。\\n\\n[neighbor chunk_id=tang_p436_c178 page=436]\\n注意\\n\\n切勿将钥匙放在高温区域。\\n\\n请勿用硬物击打或摔钥匙。\\n\\n–无线电台、变电站或机场的无线电发射器等产生的磁场可能会干扰智能钥匙，影响无电钥匙启动车辆功能的正常使用。\\n\\n一当车门上锁并开启防盗功能后，如果不使用车辆，请将钥匙远离车辆放置，以免车辆自动寻卡功能通讯消耗车辆低压蓄电池和电子钥匙的电量。\\n\\n1. 使用机械钥匙解锁。\\n\\n2. 将智能钥匙靠近副仪表台无电标识。\\n\\n3. 踩下制动踏板并按下“启动/停止”按键，正常启动车辆。\", \"chunk_id\": \"tang_p435_c177\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"发生故障时\", \"page_number_end\": 436, \"context_chunk_ids\": [\"tang_p434_c176\", \"tang_p435_c177\", \"tang_p436_c178\"], \"page_number_start\": 435}]',5,15560,1,NULL,'2026-06-23 12:32:48'),(33,1,NULL,NULL,NULL,'你这车能做几个人，体积多大？','根据当前用户手册资料回答如下：\n- **核定载客人数**：该车乘员数为**7人**。\n- **车辆体积（外部尺寸/后备厢容积）**：根据当前用户手册资料，无法确定。资料中仅列出了车辆的质量参数（如整备质量2470kg、最大允许总质量3045kg等），并未提供外部长宽高尺寸及内部装载容积的具体数据。\n\n**安全提示**：在运载行李时，车辆本体、全体乘员与行李的总质量严禁超过最大允许总质量（3045kg）。超载或装载不当会严重影响车辆的操纵性、稳定性及安全性。请将行李均匀放置于后备箱，重物置底靠前，并使用绳索或锁链固定，防止行驶中滑动。如需准确的整车尺寸与空间参数，请以实车标识或比亚迪汽车授权服务店的官方数据为准。行车请遵守交通法规，确保安全驾驶。','xia.pdf','[{\"score\": 0.07079023549310436, \"content\": \"[neighbor chunk_id=xia_p450_c196 page=450]\\n第1条：\\n项目：产品型号\\n参数：BYD6510MT6HEV1\\n\\n第2条：\\n项目：整备质量(kg)\\n参数：2470\\n\\n第3条：\\n项目：整备前轴荷(kg)\\n参数：1372\\n\\n第4条：\\n项目：整备后轴荷(kg)\\n参数：1098\\n\\n第5条：\\n项目：最大允许总质量(kg)\\n参数：3045\\n\\n第6条：\\n项目：最大允许总质量前轴荷(kg)\\n参数：1468\\n\\n第7条：\\n项目：最大允许总质量后轴荷(kg)\\n参数：1577\\n\\n第8条：\\n项目：乘员数(人)\\n参数：7\\n\\n[seed chunk_id=xia_p450_c197 page=450]\\n发动机参数\\n\\n[neighbor chunk_id=xia_p450_c198 page=450]\\n第1条：\\n项目：发动机型号\\n参数：BYD472ZQB\\n\\n第2条：\\n项目：发动机型式\\n参数：缸内直喷、直列四缸、四冲程、点燃式、水冷、双顶置凸轮轴\\n\\n第3条：\\n项目：排量(L)\\n参数：1.498\\n\\n第4条：\\n项目：发动机额定功率(kW/rpm)\\n参数：115/5500\\n\\n第5条：\\n项目：发动机最大净功率(kW/rpm)\\n参数：110/5500\\n\\n第6条：\\n项目：最大扭矩(N•m/rpm)\\n参数：225/(2500-4500)\\n\\n第7条：\\n项目：排放标准\\n参数：国六\", \"chunk_id\": \"xia_p450_c197\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"发动机参数\", \"page_number_end\": \"450\", \"context_chunk_ids\": [\"xia_p450_c196\", \"xia_p450_c197\", \"xia_p450_c198\"], \"page_number_start\": \"450\"}, {\"score\": 0.06817590424147801, \"content\": \"[neighbor chunk_id=xia_p174_c223 page=174-175]\\n前轮应保持正确的定位。避免碰撞路边侧石，在崎岖路面上要缓慢驾驶。前轮定位不准，不仅会引起轮胎的过快磨损，还会使发动机增加负荷，也就是会增加油耗。\\n\\n车底盘应保持洁净、没有泥浆等物。这不但可以减轻车身的重量，也可防止腐蚀。\\n\\n调整车辆并保持在最佳的工作状态。空气滤清器过脏；火花塞过多积碳；机油和润滑油过脏、变质或粘稠；未调整好的制动器等，均会影响发动机的性能并浪费燃油。为了使所有的部件都保持较长的使用寿命，降低运行费用，则须进行定期保养。如果经常在恶劣的条件下行驶，则应缩短保养间隔时间。\\n\\n[seed chunk_id=xia_p176_c224 page=176]\\n温馨提示\\n\\n车辆行驶中，严禁空挡滑行。\\n\\n运载行李\\n\\n本车备有多个便利的储物空间，使您可以方便的放置物品。\\n\\n杂物箱、车门储物盒及座椅靠背文件袋是为存放小件及轻量物品而设计的，行李箱则用来放置较大、较重物品。\\n\\n运载太多的行李或者装载不当，可能会影响车辆的操纵性、稳定性及正常运转，并降低车辆的安全性。\\n\\n在装载行李时，车辆本体、全体乘员、行李的总质量不允许超过最大容许质量。\\n\\n所以在运载行李之前，请务必阅读以下内容。\\n\\n警告\\n\\n超载及不当的装载都会影响车辆的操纵性及稳定性，并可能导致撞车事故。\\n\\n请遵守本手册中有关总载荷极限及其他装载准则。\\n\\n请勿随车携带具有强磁性的物品，以免干扰车辆正常运行。\\n\\n在乘员区运载物品\\n\\n必须将碰撞时可能被抛向车内伤及乘员的所有物品收放好或固定好。\\n\\n一要保证放置在前排座椅后侧地板上的物品不会在座椅下滚动，从而避免影响驾驶员操纵踏板的能力或对座椅的正常调节。不可将货物堆至超过前排椅背。\\n\\n驾驶时，要保证杂物箱一直关闭。如果杂物箱处于打开状态，在碰撞或急停车时，可能会伤及乘员的膝部。\\n\\n[neighbor chunk_id=xia_p177_c225 page=177]\\n警告\\n\\n在车里堆满儿童玩具存在安全隐患，特别是在出现紧急制动或碰撞等情况时，这不仅会影响行车安全，还可能对孩子造成伤害。\\n\\n在后备箱内运载行李\\n\\n将行李均匀地放置在后备箱地板上，将最重的行李放在底部并尽可能往前放。\\n\\n用绳子或锁链将物品固定好，使其不会在驾驶过程中移动。请勿使堆积的物品高于前排座椅的椅背。\\n\\n氧化碳中毒的危险性\\n\\n发动机排气中含有一氧化碳气体。如果您正确保养车辆，在正常驾驶中，一氧化碳不会进入车内。\\n\\n在下列几种情况下，应检查排气系统是否泄漏：\\n\\n排气声音有异常。\\n\\n车辆经受过可能损坏车辆底部的事故。\\n\\n警告\\n\\n一氧化碳气体有毒。吸入该气体会导致丧失知觉甚至危及生命。应避开任何会导致一氧化碳中毒的封闭环境及活动。\\n\\n高浓度的一氧化碳气体会迅速集中在封闭的区域，例如在车库里，不要在车库门关闭时起动发动机。即使车库的门是开着的，发动机的运转时间亦应被控制在能将车辆开出车库的时间为限。\\n\\n当后背门打开时，气流会将排出的废气带入车内，造成危险的环境。如必须在后背门打开的情况下发动车辆，应将所有车窗打开，并按照下列提示，调节车内空气环境控制系统：\\n\\n选择“外循环”模式。\\n\\n选择“吹面吹脚”模式。\\n\\n风扇速度设定在“高转速”。\", \"chunk_id\": \"xia_p176_c224\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": 176, \"context_chunk_ids\": [\"xia_p174_c223\", \"xia_p176_c224\", \"xia_p177_c225\"], \"page_number_start\": 176}, {\"score\": 0.05387096774193549, \"content\": \"[neighbor chunk_id=xia_p452_c208 page=452]\\n第1条：\\n项目：产品型号\\n参数：BYD6510MT6HEV1\\n\\n第2条：\\n项目：动力电池类型\\n参数：磷酸铁锂蓄电池\\n\\n第3条：\\n项目：动力电池额定容量(Ah)\\n参数：54\\n\\n[seed chunk_id=xia_p452_c209 page=452]\\n座椅参数\\n\\n[neighbor chunk_id=xia_p452_c210 page=452]\\n第1条：\\n项目：(测量座垫深时)前排座椅前后位置\\n参数：滑轨行程最后位置向前 60mm\\n\\n第2条：\\n项目：(测量座垫深时)前排座椅靠背角度位置\\n参数：23°\\n\\n第3条：\\n项目：前排座椅靠背的正常使用状态\\n参数：设计位置向前 20°,向后 68°,滑轨向前 200mm,向后 60mm,滑轨角度 2.5°\\n\\n第4条：\\n项目：(测量座垫深时)二排座椅前后位置\\n参数：滑轨行程最后位置向前 180mm\\n\\n第5条：\\n项目：(测量座垫深时)二排座椅靠背角度位置\\n参数：25°\\n\\n第6条：\\n项目：二排座椅靠背的正常使用状态\\n参数：设计位置向前 26°,向后 43°,滑轨向前 200mm,向后 180mm,滑轨角度 3°\\n\\n第7条：\\n项目：(测量座垫深时)三排座椅前后位置\\n参数：滑轨行程最后位置(总行程向前 100mm)\\n\\n第8条：\\n项目：(测量座垫深时)三排座椅靠背角度位置\\n参数：30°\\n\\n第9条：\\n项目：三排座椅靠背的正常使用状态\\n参数：设计位置向前 100°,向后 8°,坐垫向后翻转 163°\", \"chunk_id\": \"xia_p452_c209\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"座椅参数\", \"page_number_end\": \"452\", \"context_chunk_ids\": [\"xia_p452_c208\", \"xia_p452_c209\", \"xia_p452_c210\"], \"page_number_start\": \"452\"}, {\"score\": 0.033060515873015874, \"content\": \"[neighbor chunk_id=xia_p170_c216 page=170]\\n磨合期\\n\\n如果动力总成难以启动或经常停止转动，须立刻检查车辆。\\n\\n如果动力总成有异常的响声，应停车检查。\\n\\n如果动力总成有严重的冷却液、润滑油泄露现象，应停车检查。\\n\\n动力总成需要进行磨合，建议 HEV-经济模式下的最初2000km 进行磨合，平稳驾驶，避免高速驾驶，遵守以下的简单要领，可有效延长车辆的使用寿命：\\n\\n在启动和驾驶时，避免将加速踏板踩到底。\\n\\n使用过程中避免车辆超速行驶。\\n\\n在最初的 300km之内，避免紧急制动。\\n\\n不要以单一的速度长时间地进行快速或慢速行驶。\\n\\n磨合期 HEV 模式驾驶里程数(发动机参与工作)不少于总里程数的50%。\\n\\n[seed chunk_id=xia_p170_c217 page=170-171]\\n挂车拖曳\\n\\n本车主要是为运载乘客而设计的，为了自己和他人的安全，请勿过载或拖车。\\n\\n拖曳挂车，将对车辆的操纵、性能、制动、耐久、经济驾驶以及能耗等各方面产生不良影响。\\n\\n驾驶的安全和舒适，完全依靠设备的正确使用和养成小心驾驶的习惯。\\n\\n因拖曳挂车造成的损坏或故障不在保修范围之内。\\n\\n安全驾驶注意事项\\n\\n严禁酒后驾车\\n\\n即使少量饮酒也会降低您对道路交通条件变化的应变能力，饮酒越多，反应越迟钝，因此，严禁酒后驾车。\\n\\n控制车速\\n\\n超速是发生撞车伤亡事故的主要原因，一般来说，速度越快危险性就越大，请您根据道路交通情况保持安全车速。\\n\\n[neighbor chunk_id=xia_p171_c218 page=171-172]\\n保持车辆处于安全驾驶状态\\n\\n轮胎爆裂或机械故障都是极端危险的，为减少这类故障发生的可能性，应经常检查车况，并定期完成规定的各个检查项目。\\n\\n警告\\n\\n驾驶员必须取得驾驶证后才能驾驶车辆。\\n\\n请勿疲劳驾驶。\\n\\n驾驶车辆时务必遵守交通法则。\\n\\n驾驶时请务必专注驾驶，不要进行与驾驶无关的操作(如接打电话、调节按钮等)。\\n\\n用车建议\\n\\n为了延长动力电池使用寿命，有以下建议：\\n\\n车辆长时间存放前，建议充满电后放电至 40%~60%，电量不宜太高或太低，车辆存放时请关好车门、窗。\\n\\n车辆长时间存放时，建议每 3个月满充和满放电一次，再充电至40%~60%存放。\\n\\n车辆使用时，若仪表SOC指示条进入红色警戒格时，电池电量已不足，请及时充电避免长时间低电量使用。\\n\\n车辆使用时，建议每1~2 周可以使用车载充电设备为车辆满充电一次。\\n\\n气温较高时，应避免车辆长期满电存放，建议车辆充满电后放电至95%以下。\\n\\n温度很低或很高时，建议车辆不要长时间室外停放。\\n\\n使用车辆时，应尽量避免反复急加速和急减速。\\n\\n使用车辆时，应尽量避免长时间连续使用，长时间工作可能会导致电池温度过高，影响车辆性能。\\n\\n使用车辆时，若仪表出现故障指示，建议及时前往比亚迪汽车授权服务店检查。\\n\\n电池温度较高时，车辆性能会有一定限制，请将车辆静置待电池温度下降后再使用。\", \"chunk_id\": \"xia_p170_c217\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"挂车拖曳\", \"page_number_end\": 171, \"context_chunk_ids\": [\"xia_p170_c216\", \"xia_p170_c217\", \"xia_p171_c218\"], \"page_number_start\": 170}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=xia_p333_c047 page=333]\\n恢复出厂设置\\n\\n用户通过点击中控屏→ →DiLink→版本管理→恢复出厂设置→恢复按钮操作，即可恢复出厂设置。\\n\\n如果您确定使用恢复出厂设置功能，多媒体设备中的所有数据都会恢复到出厂状态。\\n\\n请您在恢复出厂设置过程中不要碰触多媒体的任何键，更不要在此过程中断开汽车电源，以免恢复出厂设置过程中发生错误；\\n\\n多媒体恢复出厂设置需要2-5min，请您耐心等待。\\n\\n警告\\n\\n请勿在车上使用大功率的逆变器，否则会导致多媒体系统异常。\\n\\n严禁私自刷机或Root，否则会导致多媒体或者整车异常。\\n\\n为了您的行车安全，建议在行车过程中横屏使用多媒体系统。\\n\\n5\\n\\n[seed chunk_id=xia_p334_c048 page=334-335]\\n注意\\n\\n为防止损坏触摸屏\\n\\n用手轻轻触按屏幕，如果无响应，请从屏幕上移开手指然后再次触按。\\n\\n用柔软的布擦拭屏幕时，请勿使用洗涤剂。\\n\\n使用触摸屏\\n\\n当显示屏温度较低时，显示的图象可能较暗，或系统工作可能比正常时稍慢。\\n\\n戴太阳镜看屏幕可能较暗或难以看清楚。请改变看屏幕的角度或摘下太阳镜。\\n\\n呈灰色状态的触摸屏按键是不可操作的。\\n\\n触摸屏显示界面仅供参考，具体以实车为准。\\n\\n多媒体系统界面\\n\\n系统首次启动时，会弹出警告页面，点击“同意”后进入系统界面。\\n\\n多媒体系统启动后，自动进入桌面，该界面包含以下几个模块：状态栏、导航栏、桌面小组件等。\\n\\n顶部状态栏：\\n\\n顶部状态栏区域用于显示功能状态图标。\\n\\n状态栏图标分为两类显示：可点击操作图标*和仅状态显示图标。\\n\\n便捷菜单：\\n\\n用户可通过屏幕顶部向下拉调出便捷菜单。便捷菜单包括有便捷操作、亮度和音量调节、情景模式*等功能操作模块。\\n\\n导航栏：\\n\\n长按导航栏可调出控制菜单和应用，用户可以根据个人需要设置导航栏。\\n\\n：点击返回按钮，返回上一页或者退出程序；\\n\\n：点击主页按钮，可以返回到主页；\\n\\n：点击设置按钮，进入车辆设置页面；\\n\\n：点击应用列表按钮，进入应用列表界面；\\n\\n：点击分屏按钮，进入分屏状态，再次点击可以退出分屏；\\n\\n任务管理中心：\\n\\n屏幕底部上滑可打开任务管理中心。\\n\\n桌面小组件：\\n\\n桌面出厂默认显示定制组件，用户可以根据自己的喜好自行添加、删除或者改变小组件位置。\\n\\n[neighbor chunk_id=xia_p335_c049 page=335]\\n温馨提示\\n\\n桌面小组件内容以实车配置为准。\\n\\n应用中心\\n\\n应用中心界面展示应用列表、最近使用应用。同时支持语音打开应用。用户可以通过点击图标启动应用。\\n\\n温馨提示\\n\\n多媒体发生故障时，可通过【实用工具】相关功能上传故障信息。\\n\\n应用搭载情况以车辆实际配置为准。\\n\\n情景模式*\\n\\n小憩模式*\\n\\n模式进入：用户有短暂休息需求时，可在中控屏下拉便捷栏的情景模式选项中或使用语音进入小憩模式界面，设置小憩时长后点击“确认”开启小憩模式，点击“立即结束”退出小憩模式。\\n\\n闹钟设置：小憩结束后，会有闹钟提醒，点击“取消”结束闹铃。若用户无任何操作则闹钟默认延长一段小憩时间，时间到后闹钟会再次提醒。\\n\\n模式效果：用户进入小憩模式后，主驾座椅自动放倒至默认位置，空调自动打开，整车自动落锁，车窗、天窗等系统将自动关闭，中控屏幕显示小憩模式界面，副驾屏幕*、仪表屏幕等屏幕熄灭。\", \"chunk_id\": \"xia_p334_c048\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"注意\", \"page_number_end\": 335, \"context_chunk_ids\": [\"xia_p333_c047\", \"xia_p334_c048\", \"xia_p335_c049\"], \"page_number_start\": 334}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p260_c149 page=260-263]\\n车位内侧存在立柱、立柱靠近泊车路径。\\n\\n附近存在悬空类障碍物，如悬空箱式大车、消防箱、消防阀、消防栓、充电箱、外卖箱、车辆后方或者前方外凸拖车钩、车辆后备胎、空调外机、悬空广告牌、悬空（倾斜或笔直）的水管、悬空墙壁/横梁、墙面上有突出的墙块、悬空阳台、消防门上的悬空锁、消防类器材上的悬空开关旋钮尖角、打开的车门、半开的上卷式车门等。\\n\\n附近存在低矮和细小障碍物，如低矮的石头、灌木丛、花台、花坛、石墩、石板凳、石狮子、矮墙（40cm 以下）、窄墙、细杆、细小立柱、铁丝、铁丝网篱笆、卷闸门、牵引杆、纸箱、打开的地锁、限位块或其他无法正常反射雷达探测波的物体。\\n\\n附近有下行台阶、凸起路肩、凹坑、凹陷水槽或其他地面不平。\\n\\n附近存尖锐的障碍物，如直角柱子、多棱柱、墙尖角、悬挂及落地消防箱、落地充电箱等。\\n\\n附近及车位上方存在高度变化，易剐蹭碰撞顶部，如通风管道、倾斜顶棚等。\\n\\n附近存在具备特殊表面和结构的物品，如海绵、泡沫等，或者表面反光的物体，如玻璃、地面积水、反光的地坪漆车位等。\\n\\n●附近有近距离非机动车包括但不限于二轮车、三轮车、自行车、摩托车等，其他近距离的小推车、婴儿车、购物车，小动物及行人（尤其是儿童）。\\n\\n附近存在形状不规则的非典型目标物，如大型板车、公路养护车、与大片单一背景色颜色过于接近的车辆、透明凳子、桌椅、水马、雪糕筒以及其他各类难以被系统识别的障碍物等，均需要额外注意。\\n\\n[seed chunk_id=xia_p263_c150 page=263]\\n警告\\n\\n泊车辅助功能仅作为一种驾驶辅助功能，驾驶员应对驾驶安全负全部责任。\\n\\n上述注意事项并未尽述影响泊车辅助功能正常工作的全部情形，许多不可预见的情况都可能影响泊车能力。驾驶员必须时刻关注泊车状况和车辆周边环境，根据个人需求谨慎判断是否使用本功能并确保泊车安全。如遇突发状况，驾驶员需及时暂停并控制车辆，否则可能造成严重财产损坏或人员伤害。\\n\\n使用泊车辅助功能的过程中，请务必遵守当地的道路交通及其他相关法律法规。\\n\\n[neighbor chunk_id=xia_p264_c151 page=264]\\n遥控泊车辅助(RPA)*\\n\\n■遥控泊车辅助 RPA(Remote Parking Assist)支持驾驶员在车外通过比亚迪App 遥控车辆泊入或泊出车位，适用于空间狭窄车位场景，避免因停车空间紧凑导致的下车困难。\\n\\n遥控泊车辅助RPA 包括以下子功能：\\n\\n遥控泊入：当搜索到可泊车位后，驾驶员可下车通过比亚迪 App 应用的遥控泊车辅助功能将车辆泊入车位；\\n\\n遥控泊出：当车辆处于车位停泊状态，驾驶员无需上车启动车辆，驾驶员可直接通过比亚迪 App 应用的遥控泊车辅助功能将车辆泊出车位。\\n\\nRPA 支持的车位类型同泊车辅助(APA)支持的车位类型一致。\", \"chunk_id\": \"xia_p263_c150\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": 263, \"context_chunk_ids\": [\"xia_p260_c149\", \"xia_p263_c150\", \"xia_p264_c151\"], \"page_number_start\": 263}, {\"score\": 0.016923076923076926, \"content\": \"[neighbor chunk_id=xia_p422_c162 page=422]\\n全景天幕保养*\\n\\n用湿布擦拭天幕外侧密封条上的灰尘或者沙子，避免划伤密封条，导致天幕密封性能下降。\\n\\n用湿布擦拭前玻璃注塑边上的灰尘或者沙子，防止划伤密封条，导致天幕密封性能下降。\\n\\n经常清理两侧导轨及前水槽，避免灰尘、沙粒、树叶等杂物沉积，防止排水孔被这些杂物堵住，导致天幕排水不畅。\\n\\n洗车时，应确保高压水枪与车身保持足够距离，避免用高压水枪直接冲洗密封条，这样不仅容易使密封条在高压水枪的压力下变形甚至损坏，还容易引起车内进水。\\n\\n[seed chunk_id=xia_p423_c163 page=423]\\n车辆的存放\\n\\n如果需要长期(一个月以上)停放车辆，应做好下列准备。适当的准备有助于防止车况恶化，并易于重新使用车辆。如有可能，请将车辆停放在室内。\\n\\n彻底清洗、干燥车身外表。\\n\\n清扫车辆内部，确保地毯、地席等完全干燥。\\n\\n将换挡杆设置在驻车挡。\\n\\n如果车辆需长期存放，应使用千斤顶将车身撑起，以使轮胎离开地面。\\n\\n如果车辆需长期存放，车辆状态正常下可以不断开蓄电池，但需注意存放前做好满充，避免频繁唤醒车辆，否则可能导致电池SOC累计偏差过大，影响车辆启动。\\n\\n将前刮水器臂用折叠的毛巾或布片垫起，使其不与风窗玻璃接触。\\n\\n为减少粘黏，应在所有车门及后背门密封处喷上硅酮润滑剂，并且在车门及后背门密封条相接触的油漆表面涂上车身蜡。\\n\\n使用由棉布之类的“多孔材料”制成的透气覆盖物覆盖车身。塑料布之类的无孔材料会积聚水气，损坏车身表面漆。\\n\\n如有可能，应定期运转发动机片刻(最好每月一次)。如果车辆停放了一年或更长的时间，建议到比亚迪汽车授权服务店做一次全车保养。\\n\\n[neighbor chunk_id=xia_p423_c164 page=423-424]\\n前舱盖\\n\\n前舱盖的开启\\n\\n1. 将挡位置于“P”或“N”挡，且电子驻车已启动。连续 2 次拉起位于仪表台下本体左侧的前舱盖开启手柄，前舱盖将打开稍许，需手动拉起打开。\\n\\n2. 将前舱盖向上抬起超过前舱盖开启平衡位置后，松开手前舱盖即可自行开启至最大角度。\\n\\n前舱盖的关闭\\n\\n1. 关闭前舱盖时，下拉前舱盖超过平衡位置后，稍微用力向下按前舱盖并松手，即可关闭前舱盖。\\n\\n2. 关闭前舱盖后，应检查锁扣是否已被锁定牢固。\\n\\n警告\\n\\n确认前舱盖已关闭且被锁定牢固。否则，在驾驶中前舱盖可能突然打开而导致发生事故。\\n\\n锁止前舱盖时，请勿用力下放前舱盖。\\n\\n请勿单手关闭前舱盖，避免作用力集中在一个区域，造成前舱盖损坏。\\n\\n请勿用力按压前舱盖前部边缘，以免造成车辆损坏。\", \"chunk_id\": \"xia_p423_c163\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"车辆的存放\", \"page_number_end\": 423, \"context_chunk_ids\": [\"xia_p422_c162\", \"xia_p423_c163\", \"xia_p423_c164\"], \"page_number_start\": 423}, {\"score\": 0.016129032258064516, \"content\": \"[neighbor chunk_id=xia_p95_c111 page=95]\\n温馨提示(续)\\n\\n即使在激活区域内，在某些位置(如仪表板上、杂物箱内、地板上)智能钥匙也可能不会正常工作。\\n\\n■如果智能进入系统不正常工作，无法进入车内时，则可使用附在智能钥匙上的机械钥匙为驾驶员侧车门解锁和闭锁，或者用无线遥控功能为所有车门解锁和闭锁。\\n\\n按下“启动/停止”按键时，启动功能不能正常起作用，可能由下列原因引起：\\n\\n如果智能钥匙不起作用，组合仪表上的智能钥匙系统警告灯点亮，且组合仪表显示提示信息“钥匙电池电量低”，则钥匙的电池电量可能已耗尽。\\n\\n车辆在短时间内反复启动。需等10s，然后启动车辆。\\n\\n如果智能进入和智能启动系统因系统故障不能正常运行，建议携带所有智能钥匙到比亚迪汽车授权服务店进行维修。\\n\\n[seed chunk_id=xia_p95_c112 page=95-96]\\n节约电量\\n\\n■即使没有驾驶车辆，智能钥匙和车辆之间也能进行通信。因此，请勿将智能钥匙留在车内或距离车辆 2m的范围内。\\n\\n如果智能钥匙长期接收强电磁波，则电池电量会急速耗尽。请勿将其置于可产生磁场的电气设备附近，至少保持 1m的距离，例如：\\n\\n电视机\\n\\n个人电脑\\n\\n手机充电器\\n\\n电灯架\\n\\n荧光台灯\\n\\n机械儿童锁\\n\\n儿童锁是为防止坐在后排座椅上的儿童无意中打开后排车门而设计的，左后门、右后门的侧面均有儿童锁装置。\\n\\n开启儿童锁功能\\n\\n–按箭头①方向拨动锁栓，开启儿童锁功能，从车内不能打开该车门。欲打开此车门，需使用车外的车门把手。\\n\\n关闭儿童锁功能\\n\\n–按箭头②方向拨动锁栓，关闭儿童锁功能，从车内可以打开该车门。\\n\\n[neighbor chunk_id=xia_p96_c113 page=96-97]\\n警告\\n\\n驾驶之前，特别是有儿童在车中时，须确认车门关闭并开启儿童锁功能。\\n\\n正确使用安全带并开启儿童锁，有助于防止驾驶员和乘客在发生事故时被甩出车外。同时也能防止车门意外打开。\\n\\n座椅\\n\\n调节主驾座椅，使脚踏板、转向盘和仪表板控制器都位于驾驶员容易控制的范围之内。\\n\\n在车辆运行中最有效的防护措施是将座椅靠背保持直立，在座椅上始终将身体很好地靠在靠背上并将安全带调整在合适的位置。\\n\\n在车辆行驶过程中不能折叠后排座椅。\\n\\n适当地固定行李，防止其滑行或者移动。放置行李不要高过座椅靠背。\\n\\n头枕调整在有效位置来保护头部，如果头枕因为某些原因被移动，要经常及时地调整并放回原来的有效位置。\", \"chunk_id\": \"xia_p95_c112\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"节约电量\", \"page_number_end\": 96, \"context_chunk_ids\": [\"xia_p95_c111\", \"xia_p95_c112\", \"xia_p96_c113\"], \"page_number_start\": 95}]',5,18414,1,NULL,'2026-06-23 12:37:20'),(34,1,NULL,NULL,NULL,'后视镜章节在哪几页？','根据提供的用户手册资料，**“3-5 后视镜”章节从第124页开始**。手册目录及正文内容显示，内后视镜、外后视镜的调节、折叠及流媒体模式等相关设置说明，主要分布在第124页至第127页。您可直接翻页至该范围查阅具体操作步骤。','xia.pdf','[{\"score\": 0.05224748810153358, \"content\": \"[neighbor chunk_id=xia_p125_c148 page=125]\\n温馨提示\\n\\n请根据中控屏界面上的提示信息使用转向盘右侧按键进行调节，中控屏界面仅起提示作用，无法调节。\\n\\n因为内后视镜具备传统平面镜功能，所以在强光环境下镜面效果会和流媒体图像同时出现，造成重影现象，此时需要手动调节一下内后视镜角度，以规避重影，改善视野效果。\\n\\n传统内后视镜模式\\n\\n当关闭流媒体模式时，后视镜进入传统内后视镜模式，此模式下，内后视镜呈现镜面显示效果。\\n\\n手动防眩目内后视镜*\\n\\n手动防眩目内后视镜有普通和防眩两种工作模式：\\n\\n普通模式——将控制杆置于位置①，在此位置时，后视镜镜像最清晰。\\n\\n■防眩模式——将控制杆置于位置②，在此位置时，能有效降低夜晚后方来车大灯灯光干扰。需注意在降低眩光的同时，可能会令后方视野清晰度下降。\\n\\n外后视镜\\n\\n通过外后视镜开关，可将外后视镜调节至合适角度，使驾驶员刚好可以在后视镜中看到车辆两侧。\\n\\n[seed chunk_id=xia_p126_c149 page=126]\\n126 3-5 后视镜\\n\\n选择开关：用于选择需要调节的外后视镜。\\n\\n：左侧外后视镜按键\\n\\n：右侧外后视镜按键\\n\\n外后视镜方向调节按键 ：选择需调节的外后视镜后，再按下此按键，可将该外后视镜的镜片调节至合适位置。\\n\\n外后视镜折叠\\n\\n折叠开关 ：按下此按键，左右外后视镜同时折叠，再次按下此按键，外后视镜再次展开。\\n\\n进入防盗时外后视镜自动折叠，解除防盗时外后视镜自动展开。\\n\\n一用户可通过中控屏→设置 →驾驶→舒适用车→外后视镜设置界面开启或关闭外后视镜自动折叠功能。\\n\\n[neighbor chunk_id=xia_p126_c150 page=126-127]\\n警告\\n\\n请在车辆行驶前调节好外后视镜。应避免行驶过程中调节外后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n温馨提示\\n\\n如果后视镜被冰冻住，请勿操作控制器或刮后视镜的表面，须用喷雾式除冰器除去后视镜表面的冰。\\n\\n外后视镜具有倒车翻转功能*：执行车辆倒车时，电动外后视镜镜片会自动下翻到舒适的倒车角度。\\n\\n灯光开关\\n\\n自动灯、位置灯、近光灯、后雾灯和日间行车灯开关集成在多媒体系统上。\\n\\n■用户可通过点击中控屏→设置 →灯光→车外灯光进入“大灯控制 ” 界面，选择开启或关闭自动灯、位置灯、近光灯、后雾灯和日间行车灯，及关闭所有灯光。\\n\\n左右转向灯\\n\\n通过上下拨动组合开关手柄操纵左右转向灯的开启或关闭，向上拨动开启右转向灯，向下拨动开启左转向灯。\", \"chunk_id\": \"xia_p126_c149\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"126 3-5 后视镜\", \"page_number_end\": 126, \"context_chunk_ids\": [\"xia_p125_c148\", \"xia_p126_c149\", \"xia_p126_c150\"], \"page_number_start\": 126}, {\"score\": 0.05149161021715226, \"content\": \"[neighbor chunk_id=xia_p124_c147 page=124]\\n内后视镜\\n\\n上下、左右转动内后视镜，将内后视镜调至合适位置。\\n\\n警告\\n\\n请勿在内后视镜上悬挂重物，或用力摇晃、拖拽。\\n\\n手动调节内后视镜时，卡滞后切勿暴力调节，以免造成内后视镜脱落。\\n\\n请在车辆行驶前调节好内后视镜。应避免行驶过程中调节内后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n流媒体内后视镜*\\n\\n流媒体内后视镜有流媒体和传统内后视镜两种工作模式。\\n\\n流媒体模式\\n\\n通过实体开关按键(内后视镜背面后侧)或点击中控屏→设置→声音显示→流媒体后视镜按键，可选择开启或关闭流媒体内后视镜。\\n\\n●开启流媒体后视镜屏幕上可显示后方摄像头采集的实时画面，点击中控屏→设置 →声音显示→流媒体后视镜按键，打开屏幕调节选项后，可通过转向盘右侧左、右按键选择视角缩放、视野高度调节和屏幕亮度设置项，并通过滑动转向盘右侧滚轮进行挡位调节。\\n\\n[seed chunk_id=xia_p125_c148 page=125]\\n温馨提示\\n\\n请根据中控屏界面上的提示信息使用转向盘右侧按键进行调节，中控屏界面仅起提示作用，无法调节。\\n\\n因为内后视镜具备传统平面镜功能，所以在强光环境下镜面效果会和流媒体图像同时出现，造成重影现象，此时需要手动调节一下内后视镜角度，以规避重影，改善视野效果。\\n\\n传统内后视镜模式\\n\\n当关闭流媒体模式时，后视镜进入传统内后视镜模式，此模式下，内后视镜呈现镜面显示效果。\\n\\n手动防眩目内后视镜*\\n\\n手动防眩目内后视镜有普通和防眩两种工作模式：\\n\\n普通模式——将控制杆置于位置①，在此位置时，后视镜镜像最清晰。\\n\\n■防眩模式——将控制杆置于位置②，在此位置时，能有效降低夜晚后方来车大灯灯光干扰。需注意在降低眩光的同时，可能会令后方视野清晰度下降。\\n\\n外后视镜\\n\\n通过外后视镜开关，可将外后视镜调节至合适角度，使驾驶员刚好可以在后视镜中看到车辆两侧。\\n\\n[neighbor chunk_id=xia_p126_c149 page=126]\\n126 3-5 后视镜\\n\\n选择开关：用于选择需要调节的外后视镜。\\n\\n：左侧外后视镜按键\\n\\n：右侧外后视镜按键\\n\\n外后视镜方向调节按键 ：选择需调节的外后视镜后，再按下此按键，可将该外后视镜的镜片调节至合适位置。\\n\\n外后视镜折叠\\n\\n折叠开关 ：按下此按键，左右外后视镜同时折叠，再次按下此按键，外后视镜再次展开。\\n\\n进入防盗时外后视镜自动折叠，解除防盗时外后视镜自动展开。\\n\\n一用户可通过中控屏→设置 →驾驶→舒适用车→外后视镜设置界面开启或关闭外后视镜自动折叠功能。\", \"chunk_id\": \"xia_p125_c148\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": 125, \"context_chunk_ids\": [\"xia_p124_c147\", \"xia_p125_c148\", \"xia_p126_c149\"], \"page_number_start\": 125}, {\"score\": 0.03746031746031746, \"content\": \"[neighbor chunk_id=xia_p460_c217 page=460-461]\\nK\\n\\n开门安全提醒(DOW)*....300 空调控制板、汽车音响、仪表板、 控制面板和开关....416 空调设置....370\\n\\n蓝牙电话 …… 339 冷却液的选择 …… 426 邻车靠近避让(ELKA)* …… 295 领航辅助(NOA)* …… 224 流媒体内后视镜* …… 124 路面预瞄系统* …… 309 绿净操作界面 …… 371 绿净系统简介 …… 371\\n\\nM\\n\\n麦克风* …… 398 盲区监测(BSD)* …… 298 门板紧急扣手打开车门 …… 77 门窗 …… 416 磨合期 …… 170\\n\\n[seed chunk_id=xia_p461_c218 page=461]\\nN\\n\\n内部清洁 415 内后视镜 124 能量回馈强度设置 162\\n\\nP\\n\\n票据盒 .... 385 泊车辅助(APA)* .... 254 普通天窗保养方法* .... 422\\n\\nQ\\n\\n漆面保养提示 …… 412 其他应用 …… 351 启动车辆 …… 181 汽车事件数据记录系统 …… 48\\n\\n前舱盖的开启 ..... 423 前方横向碰撞提醒(FCTA)* ..... 283 前方横向碰撞制动(FCTB)* ..... 285 前排杯托 ..... 389 前排出风口 ..... 374 前排置物盒 ..... 386 前排座椅电动调节 ..... 98 前向碰撞提醒(FCW)* ..... 275 情景模式* ..... 335 全景天幕保养 ..... 422 全景影像系统 ..... 251 全液晶组合仪表 ..... 54\\n\\n[neighbor chunk_id=xia_p461_c219 page=461-462]\\nR\\n\\n燃油选用 172 如果轮胎漏气 443 如果在驾驶中发动机启动失败.440 如何节省燃油并延长车辆的使用寿命 174\\n\\nS\\n\\n三排杯托* …… 390 三排头枕调节 …… 112 三排座椅调节* …… 107 哨兵模式* …… 46 使用安全带 …… 17 室内灯开关 …… 138 手工洗车 …… 413 手机槽 …… 391 手机投屏* …… 359 手机无线充电* …… 398 手势及响应 …… 339 双模系统工作模式简介 …… 38 双模系统工作模式选择 …… 40\\n\\n双模系统工作模式注意事项 ……42\", \"chunk_id\": \"xia_p461_c218\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"N\", \"page_number_end\": \"461\", \"context_chunk_ids\": [\"xia_p460_c217\", \"xia_p461_c218\", \"xia_p461_c219\"], \"page_number_start\": \"461\"}, {\"score\": 0.03366615463389657, \"content\": \"[neighbor chunk_id=xia_p123_c146 page=123]\\n更换后雨刮\\n\\n1. 首先拉起后雨刮的刮水器臂。\\n\\n2. 用手握住刮臂位置①，沿图示方向拔出刮片。\\n\\n3. 新刮片装配时，按照取出刮片相反的步骤进行操作。\\n\\n注意\\n\\n提起刮臂时，禁止打开前舱盖，否则会损坏前舱盖和刮水器臂。\\n\\n洗完车放下雨刮刮片时，禁止直接推雨刮刮臂让刮片直接撞击到风窗玻璃上。\\n\\n禁止折弯雨刮刮片、雨刮运行时禁止阻挡雨刮刮片。\\n\\n冬季雨雪天，建议进入多媒体检修界面开启前雨刮检修，将前雨刮手动抬起，以免雨刮被冻住。\\n\\n关于雨刮保养请参见“雨刮器刮片保养”。\\n\\n[seed chunk_id=xia_p124_c147 page=124]\\n内后视镜\\n\\n上下、左右转动内后视镜，将内后视镜调至合适位置。\\n\\n警告\\n\\n请勿在内后视镜上悬挂重物，或用力摇晃、拖拽。\\n\\n手动调节内后视镜时，卡滞后切勿暴力调节，以免造成内后视镜脱落。\\n\\n请在车辆行驶前调节好内后视镜。应避免行驶过程中调节内后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n流媒体内后视镜*\\n\\n流媒体内后视镜有流媒体和传统内后视镜两种工作模式。\\n\\n流媒体模式\\n\\n通过实体开关按键(内后视镜背面后侧)或点击中控屏→设置→声音显示→流媒体后视镜按键，可选择开启或关闭流媒体内后视镜。\\n\\n●开启流媒体后视镜屏幕上可显示后方摄像头采集的实时画面，点击中控屏→设置 →声音显示→流媒体后视镜按键，打开屏幕调节选项后，可通过转向盘右侧左、右按键选择视角缩放、视野高度调节和屏幕亮度设置项，并通过滑动转向盘右侧滚轮进行挡位调节。\\n\\n[neighbor chunk_id=xia_p125_c148 page=125]\\n温馨提示\\n\\n请根据中控屏界面上的提示信息使用转向盘右侧按键进行调节，中控屏界面仅起提示作用，无法调节。\\n\\n因为内后视镜具备传统平面镜功能，所以在强光环境下镜面效果会和流媒体图像同时出现，造成重影现象，此时需要手动调节一下内后视镜角度，以规避重影，改善视野效果。\\n\\n传统内后视镜模式\\n\\n当关闭流媒体模式时，后视镜进入传统内后视镜模式，此模式下，内后视镜呈现镜面显示效果。\\n\\n手动防眩目内后视镜*\\n\\n手动防眩目内后视镜有普通和防眩两种工作模式：\\n\\n普通模式——将控制杆置于位置①，在此位置时，后视镜镜像最清晰。\\n\\n■防眩模式——将控制杆置于位置②，在此位置时，能有效降低夜晚后方来车大灯灯光干扰。需注意在降低眩光的同时，可能会令后方视野清晰度下降。\\n\\n外后视镜\\n\\n通过外后视镜开关，可将外后视镜调节至合适角度，使驾驶员刚好可以在后视镜中看到车辆两侧。\", \"chunk_id\": \"xia_p124_c147\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"内后视镜\", \"page_number_end\": 124, \"context_chunk_ids\": [\"xia_p123_c146\", \"xia_p124_c147\", \"xia_p125_c148\"], \"page_number_start\": 124}, {\"score\": 0.029423076923076927, \"content\": \"[neighbor chunk_id=xia_p126_c149 page=126]\\n126 3-5 后视镜\\n\\n选择开关：用于选择需要调节的外后视镜。\\n\\n：左侧外后视镜按键\\n\\n：右侧外后视镜按键\\n\\n外后视镜方向调节按键 ：选择需调节的外后视镜后，再按下此按键，可将该外后视镜的镜片调节至合适位置。\\n\\n外后视镜折叠\\n\\n折叠开关 ：按下此按键，左右外后视镜同时折叠，再次按下此按键，外后视镜再次展开。\\n\\n进入防盗时外后视镜自动折叠，解除防盗时外后视镜自动展开。\\n\\n一用户可通过中控屏→设置 →驾驶→舒适用车→外后视镜设置界面开启或关闭外后视镜自动折叠功能。\\n\\n[seed chunk_id=xia_p126_c150 page=126-127]\\n警告\\n\\n请在车辆行驶前调节好外后视镜。应避免行驶过程中调节外后视镜，以免分散驾驶员注意力，导致意外事故发生。\\n\\n温馨提示\\n\\n如果后视镜被冰冻住，请勿操作控制器或刮后视镜的表面，须用喷雾式除冰器除去后视镜表面的冰。\\n\\n外后视镜具有倒车翻转功能*：执行车辆倒车时，电动外后视镜镜片会自动下翻到舒适的倒车角度。\\n\\n灯光开关\\n\\n自动灯、位置灯、近光灯、后雾灯和日间行车灯开关集成在多媒体系统上。\\n\\n■用户可通过点击中控屏→设置 →灯光→车外灯光进入“大灯控制 ” 界面，选择开启或关闭自动灯、位置灯、近光灯、后雾灯和日间行车灯，及关闭所有灯光。\\n\\n左右转向灯\\n\\n通过上下拨动组合开关手柄操纵左右转向灯的开启或关闭，向上拨动开启右转向灯，向下拨动开启左转向灯。\\n\\n[neighbor chunk_id=xia_p127_c151 page=127-128]\\n超车灯与远光灯\\n\\n通过前后拨动组合开关手柄操纵超车灯与远光灯的开启或关闭，向前拨动开启远光灯，向后拨动开启超车灯。\\n\\n温馨提示\\n\\n四合一传感器位于风窗玻璃上端，请勿将传感器遮挡，或者溅上任何液体。\\n\\n自动熄灯功能\\n\\n自动熄灯功能开启条件：在灯光调节为“位置灯”或“近光灯”开启时，电源由“启动”状态切换至“停止”状态时，该功能启动。\\n\\n启动自动熄灯功能后，如果左前门处于关闭状态，10s 后，自动熄灯功能会自动将已打开的前大灯、位置灯、后雾灯、远光灯熄灭。\\n\\n启动自动熄灯功能后，如果左前门处于打开状态，10min后，自动熄灯功能会自动将已打开的前大灯、位置灯、后雾灯、远光灯熄灭。\\n\\n–自动熄灯后，若灯光挡状态改变，则按新状态点亮各灯，若此时仍满足自动熄灯开启条件，则再次进入自动熄灯功能。\\n\\n自动熄灯功能结束：整车电源启动后，自动熄灯功能结束，灯光正常操作。\\n\\n自动熄灯功能使灯熄灭，且进入防盗状态后，再解除防盗，解除防盗后，若未打开离家照明功能，则灯光不会点亮，若打开离家照明功能，灯光会先按照离家照明设置时间计时点亮，此时若打开车门且整车电源处于“停止”状态，自动熄灯功能会在10min 后将灯熄灭，开门触发灯光点亮后再关门，自动熄灯功能会在 10s后将灯熄灭。\", \"chunk_id\": \"xia_p126_c150\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"警告\", \"page_number_end\": 127, \"context_chunk_ids\": [\"xia_p126_c149\", \"xia_p126_c150\", \"xia_p127_c151\"], \"page_number_start\": 126}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p65_c071 page=65]\\n第1条：\\n故障提示：请检查车载充电系统\\n处理方法：车载充电系统有故障,请检查充电连接有无异常,重新连接充电设备。如不能解决,建议与比亚迪汽车授权服务店联系。\\n\\n第2条：\\n故障提示：为了您的安全,遥控驾驶暂停使用\\n处理方法：遥控驾驶出现异常,请暂停使用。\\n\\n第3条：\\n故障提示：请检查车辆网络\\n处理方法：表示当前车辆的数据网络可能存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n第4条：\\n故障提示：发动机附件功能受限\\n处理方法：表示发动机附件有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第5条：\\n故障提示：请检查记忆系统*\\n处理方法：表示记忆系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第6条：\\n故障提示：请检查前照灯系统\\n处理方法：表示前照灯系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n第7条：\\n故障提示：请检查挡位系统\\n处理方法：表示挡位控制器存在故障,应立即停车并建议与比亚迪汽车授权服务店联系。\\n\\n第8条：\\n故障提示：请检查 HDC 系统\\n处理方法：表示 HDC 系统有故障,建议与比亚迪汽车授权服务店联系。\\n\\n[seed chunk_id=xia_p67_c072 page=67-68]\\n3\\n\\n3-1 车门和钥匙....69 钥匙....69 闭锁/解锁车门....75 电动滑门....88 智能进入和智能启动系统....93 机械儿童锁....95 3-2 座椅....97 座椅....97 前排座椅....98 二排座椅....102 座椅加热通风*....106 三排座椅....107 头枕....111 3-3 转向盘....114 转向盘开关组....114 转向盘调节....118 3-4 雨刮....120 雨刮开关....120 更换雨刮....122 3-5 后视镜....124 内后视镜....124 外后视镜....125 3-6 开关....127 灯光开关....127 驾驶员侧车门开关组....129 乘员侧车窗控制开关....131\\n\\n自动关窗*....132 紧急告警灯开关....133 天窗开关....133 E-Call/云-Call 开关....136 二排控制面板*....137 室内灯开关....138\\n\\n[neighbor chunk_id=xia_p69_c073 page=69]\\n钥匙\\n\\n钥匙包括电子智能钥匙、机械钥匙(安装在电子智能钥匙内)、蓝牙钥匙*和NFC 钥匙*。\\n\\n电子智能钥匙\\n\\n电子智能钥匙——携带有效电子智能钥匙按左/右前门把手上的微动开关，可以解/闭锁所有车门；整车闭锁时，携带有效电子智能钥匙按左/右后门把手上的微动开关可以解锁整车，并开启对应侧的滑门；还可通过智能钥匙上按键进行车门解/闭锁、后背门开启/关闭以及滑门开启/关闭等功能。\\n\\n① 闭锁按键\\n\\n② 解锁按键\\n\\n③ 后背门开启/关闭按键\\n\\n④ 右侧滑门开启/关闭按键\\n\\n⑤ 左侧滑门开启/关闭按键\\n\\n⑥ 机械钥匙\", \"chunk_id\": \"xia_p67_c072\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"3\", \"page_number_end\": \"68\", \"context_chunk_ids\": [\"xia_p65_c071\", \"xia_p67_c072\", \"xia_p69_c073\"], \"page_number_start\": \"67\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=xia_p461_c219 page=461-462]\\nR\\n\\n燃油选用 172 如果轮胎漏气 443 如果在驾驶中发动机启动失败.440 如何节省燃油并延长车辆的使用寿命 174\\n\\nS\\n\\n三排杯托* …… 390 三排头枕调节 …… 112 三排座椅调节* …… 107 哨兵模式* …… 46 使用安全带 …… 17 室内灯开关 …… 138 手工洗车 …… 413 手机槽 …… 391 手机投屏* …… 359 手机无线充电* …… 398 手势及响应 …… 339 双模系统工作模式简介 …… 38 双模系统工作模式选择 …… 40\\n\\n双模系统工作模式注意事项 ……42\\n\\n[seed chunk_id=xia_p462_c220 page=462]\\nT\\n\\n头枕调节....111 投影感应开启后背门*....84 投影感应开启滑门*....91\\n\\nW\\n\\n外后视镜调节 …… 125 弯道超速提醒(CSW)* …… 290 微波窗口 …… 457 微动开关闭锁/解锁 …… 79 微动开关升/降窗 …… 80 文件袋 …… 391 我的车* …… 350\\n\\nX\\n\\n限速控制(ISLC)* 246 香氛系统* 373 小天窗开关 133 小天窗遮阳帘 134 小桌板* 400 行车记录仪* 327 行李箱座椅调节开关* 110\\n\\nY\\n\\n眼镜盒 …… 387 遥控泊车辅助(RPA)* …… 264 钥匙简介 …… 69 一般充电故障诊断 …… 146 一氧化碳中毒的危险性 …… 177 衣帽挂钩 …… 394\\n\\n仪表其他故障说明 …… 65 音响设置* …… 341 用车及存放建议 …… 171 雨刮器刮片 …… 429 预防火灾 …… 179 云辇-C* …… 186 运载行李 …… 176\\n\\n[neighbor chunk_id=xia_p462_c221 page=462-463]\\nZ\\n\\n杂物箱 …… 388 在后备箱内运载行李 …… 177 遮阳板 …… 393 整车参数 …… 450 整车紧急机械锁止 …… 87 整车铭牌 …… 455 直接胎压监测系统 …… 316 指示灯/警告灯标识 …… 55 制动系统 …… 428 智慧充电 …… 155 智能动力制动系统 …… 322 智能进入和智能启动系统 …… 93 智能上下电 …… 182 智能钥匙闭锁/解锁 …… 77 智能钥匙升/降窗 …… 78 智能语音 …… 341 中控屏 …… 333 中控置物盒 …… 386 驻车辅助系统 …… 247 转向盘开关组 …… 114 转向盘手动调节 …… 118 转向助力模式设置 …… 118 自动紧急制动(AEB)* …… 279 自动洗车 …… 415 自动驻车(AVH) …… 191 自适应前照灯(AFL)* …… 311\\n\\n自适应巡航(ACC)* 206 自行保养注意事项 419\", \"chunk_id\": \"xia_p462_c220\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"T\", \"page_number_end\": \"462\", \"context_chunk_ids\": [\"xia_p461_c219\", \"xia_p462_c220\", \"xia_p462_c221\"], \"page_number_start\": \"462\"}, {\"score\": 0.012307692307692308, \"content\": \"[neighbor chunk_id=xia_p80_c090 page=80]\\n温馨提示\\n\\n如果智能钥匙距离车门外把手或车窗太近，则可能不会激活进入功能。\\n\\n微动开关升/降窗\\n\\n■整车电源处于“OFF”挡时，携带有效智能钥匙，长按微动开关，可以实现四门玻璃自动上升、下降。\\n\\n用户可通过中控屏→设置 →门窗与锁→车窗，进入车窗设置界面开启或关闭长按微动开关闭锁关窗/长按微动开关解锁开窗功能。\\n\\nNFC钥匙闭锁/解锁*\\n\\n闭锁车门：\\n\\n车门关闭且未锁止，将有效 NFC钥匙靠近驾驶员侧外后视镜上指令区域，所有车门同时闭锁。如果车辆已熄火，此时，转向信号灯闪烁1 次。\\n\\n[seed chunk_id=xia_p80_c091 page=80-81]\\n解锁车门：\\n\\n在闭锁状态下，携带有效NFC钥匙靠近驾驶员侧外后视镜上指令区域，所有车门同时解锁。转向信号灯闪烁 2次。\\n\\n下列情况，有效NFC钥匙靠近驾驶员侧外后视镜上指令区域将不进行解/闭锁：\\n\\n打开或关闭车门的同时，有效 NFC 钥匙靠近驾驶员侧外后视镜上指令区域。\\n\\n手机NFC钥匙使用前需打开手机NFC功能开关，将手机背面顶部区域贴近驾驶员侧外后视镜NFC标示处。\\n\\n注意\\n\\n部分手机型号不支持关机使用。\\n\\n请尽量避免在手机无电关机情况下长时间、高频率的使用。\\n\\n[neighbor chunk_id=xia_p81_c092 page=81]\\n温馨提示\\n\\n防盗状态下，使用有效NFC钥匙解锁后，请在30s 内打开车门。否则所有车门将自动重新闭锁。\\n\\n使用有效NFC钥匙解锁后，在规定时间内提供用户启动权限，此权限在有效操作闭锁之后解除。\\n\\n有关手机NFC钥匙的设置操作请参见 NFC钥匙*。\\n\\n后背门闭锁/解锁\\n\\n智能钥匙打开/关闭后背门\\n\\n双击智能钥匙上的“后背门开启”按键，后背门打开，此时转向信号灯闪烁2次。再单击“后背门开启”按键，后背门打开动作停止，再双击，后背门反向运动。\\n\\n温馨提示\\n\\n后背门在打开或关闭的过程中，再次操作后背门开启按键，后背门停止当前动作。\", \"chunk_id\": \"xia_p80_c091\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"解锁车门：\", \"page_number_end\": 81, \"context_chunk_ids\": [\"xia_p80_c090\", \"xia_p80_c091\", \"xia_p81_c092\"], \"page_number_start\": 80}]',5,11361,1,NULL,'2026-06-23 12:39:29'),(35,1,NULL,NULL,NULL,'车怎么启动？','根据【用户手册资料】，车辆启动的具体操作步骤如下：\n\n**标准启动步骤：**\n1. **确认钥匙状态**：确保已携带有效的智能钥匙在车内（启动功能激活区域为车厢内）。\n2. **踩住刹车**：将脚踩在制动踏板上。\n3. **按按钮启动**：按下车辆上的**“启动/停止”按键**，车辆即可启动。\n\n**🔍 启动异常时的处理方法（资料提示）：**\n- 若按下按键无反应，且组合仪表提示**“钥匙电池电量低”**：表示智能钥匙电池可能已耗尽，请更换钥匙电池或使用随附的机械钥匙应急解锁后尝试启动。\n- 若车辆在短时间内**反复尝试启动**：请等待至少 `10秒` 后再重新踩刹车按启动键。\n- 若以上情况排除后仍无法正常启动：可能是智能进入/启动系统发生故障，建议携带所有智能钥匙前往比亚迪汽车授权服务店进行专业检测。\n\n⚠️ **安全提示**：车辆启动及后续驾驶涉及行车安全。操作请以车辆组合仪表的实际提示为准，如遇电气系统异常或无法启动，请勿强行驾驶，建议及时联系官方售后或道路救援。','tang.pdf','[{\"score\": 0.03905341089370704, \"content\": \"[neighbor chunk_id=tang_p93_c109 page=93]\\n温馨提示\\n\\n一充电口盖/燃油口盖开启时，对应侧滑门电动功能失效，可手动开启/关闭滑门，但手动开启对应侧滑门时受限制，会有机械挡块禁止滑门全开，以免与充电口盖/燃油口盖干涉。充电口盖/燃油口盖关闭后，对应侧滑门电动功能恢复。\\n\\n滑门处于闭锁状态时，滑门的电动开启和关闭功能将被关闭。\\n\\n滑门电动功能被关闭时，仍会保留对应的电动辅助吸合功能。当滑门半关时，仍会触发电动吸合功能，确保滑门完全关闭。\\n\\n在滑门开启时，若车辆已闭锁，滑门仅能电动关闭和吸合闭锁。\\n\\n滑门开启/关闭/触发防夹时，扬声器均会发出报警提示音。\\n\\n[seed chunk_id=tang_p93_c110 page=93-94]\\n智能进入和智能启动系统\\n\\n携带有效智能钥匙可为车门解/闭锁并启动车辆。\\n\\n进入功能\\n\\n携带有效智能钥匙，可为车门解锁或闭锁。(详细请参见“智能钥匙闭锁/解锁”和“微动开关闭锁/解锁”)\\n\\n启动功能\\n\\n携带有效智能钥匙，踩下制动踏板，按下“启动/停止”按键，启动车辆(详细请参见的“车内启动车辆”)。\\n\\n探测天线位置\\n\\n①位于车厢内的探测天线\\n\\n②位于车厢外的探测天线\\n\\n激活区域\\n\\n已登记的智能钥匙在激活区域内时，智能进入和启动功能方可生效。\\n\\n①进入功能激活区域——距前门把手和后背门外开关大约1m的范围内。\\n\\n②启动功能激活区域——车厢内。\\n\\n其他车辆的智能钥匙接近本车的智能钥匙时，车门解锁的时间可能要比平时长一些，属正常现象。\\n\\n温馨提示\\n\\n在下列情况下，智能进入和启动系统可能不会正常工作：\\n\\n当附近有释放强电磁波的设施，例如电视塔、发电站、广播站时。\\n\\n将智能钥匙与通讯装置一同携带时，比如双向无线电通讯设备或移动电话。\\n\\n当智能钥匙与金属物体接触或被其覆盖时。\\n\\n迅速操作车门把手时。\\n\\n智能钥匙接近车门把手时。\\n\\n当他人在附近的另一辆车上操作无线遥控功能时。\\n\\n当智能钥匙电池电量耗尽时。\\n\\n智能钥匙在高压设备或产生噪音的设备附近时。\\n\\n–当智能钥匙在同其他车辆智能进入和启动系统的钥匙或其他发射无线电波的装置一起携带时。\\n\\n[neighbor chunk_id=tang_p95_c111 page=95]\\n温馨提示(续)\\n\\n即使在激活区域内，在某些位置(如仪表板上、杂物箱内、地板上)智能钥匙也可能不会正常工作。\\n\\n■如果智能进入系统不正常工作，无法进入车内时，则可使用附在智能钥匙上的机械钥匙为驾驶员侧车门解锁和闭锁，或者用无线遥控功能为所有车门解锁和闭锁。\\n\\n按下“启动/停止”按键时，启动功能不能正常起作用，可能由下列原因引起：\\n\\n如果智能钥匙不起作用，组合仪表上的智能钥匙系统警告灯点亮，且组合仪表显示提示信息“钥匙电池电量低”，则钥匙的电池电量可能已耗尽。\\n\\n车辆在短时间内反复启动。需等10s，然后启动车辆。\\n\\n如果智能进入和智能启动系统因系统故障不能正常运行，建议携带所有智能钥匙到比亚迪汽车授权服务店进行维修。\", \"chunk_id\": \"tang_p93_c110\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"智能进入和智能启动系统\", \"page_number_end\": \"94\", \"context_chunk_ids\": [\"tang_p93_c109\", \"tang_p93_c110\", \"tang_p95_c111\"], \"page_number_start\": \"93\"}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=tang_p167_c212 page=167-168]\\n警告\\n\\n■新能源汽车所有人有责任和义务将废旧动力电池移交回收服务网点。私自将废旧动力电池移交给其他单位或个人，私自拆卸、拆解动力电池，由此导致环境污染或安全事故的，应承担相应责任。\\n\\n低压蓄电池\\n\\n–本车低压蓄电池具备智能充电功能。当动力电池电量充足时，车辆可以自动开启动力电池对低压蓄电池充电，以延长低压蓄电池续航时长。\\n\\n温馨提示\\n\\n电源挡位处于“OFF”挡智能充电时，车辆会发出正常上“OK”挡时发出的声音，属正常现象。\\n\\n如果您离开车辆时，请确保已关闭所有用电设备，且车门已经关好。\\n\\n车辆亏电后唤醒功能\\n\\n[seed chunk_id=tang_p168_c213 page=168-169]\\n左前门微动开关唤醒\\n\\n低压蓄电池具有休眠唤醒功能。车辆长期存放后，若使用智能钥匙将无法实现寻车及车辆解锁功能，低压蓄电池可能已进入休眠状态。此时需按下左前门把手的微动开关(请参见“微动开关闭锁/解锁”)，即可唤醒低压蓄电池。对车辆解锁后，车辆即可正常使用。\\n\\n前舱搭火唤醒\\n\\n当车辆无法通过左前门微动开关唤醒和解锁时，可以使用机械钥匙打开车门。此时可以利用 12V 规格电源通过两根搭火专用电缆线搭火启动车辆。此时低压蓄电池电量较低，仪表可能提示“蓄电池电量不足，车辆即将退电”，车辆会再次休眠。需立即启动车辆发电并保持启动状态 15min 以上，以保证低压蓄电池充满电量。\\n\\n●搭火操作只能通过前舱配电盒专用接口进行。前舱配电盒搭火点如图所示。\\n\\n若上述操作均无法唤醒并启动车辆，建议请及时联系比亚迪汽车授权服务店处理。\\n\\n[neighbor chunk_id=tang_p169_c214 page=169]\\n警告\\n\\n严禁车辆未上“OK”挡即对其他车辆进行搭接对火，否则可能会损坏低压蓄电池。\\n\\n■当出现低压蓄电池亏电或无法正常使用等紧急需要临时搭火情况，请详细阅读用户手册该部分内容，并严格按照说明进行搭接或操作。\\n\\n低压蓄电池内部包含智能控制模块，非紧急情况下，请勿私自拆卸或破坏，避免低压蓄电池损坏。\\n\\n在更换零部件及整车维修检查前，请断开低压蓄电池负极。\\n\\n注意\\n\\n前舱配电盒搭火操作空间有限，同时存在一定的电路安全风险，搭火操作建议在专业人员指导下进行。\\n\\n低压蓄电池不能用液体清洗，避免让液体进入电池中。\", \"chunk_id\": \"tang_p168_c213\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"左前门微动开关唤醒\", \"page_number_end\": \"169\", \"context_chunk_ids\": [\"tang_p167_c212\", \"tang_p168_c213\", \"tang_p169_c214\"], \"page_number_start\": \"168\"}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=tang_p99_c117 page=99-100]\\n注意\\n\\n松开开关会使座椅停在该位置，请勿在座椅下面放置任何物品，否则可能妨碍座椅的运行。\\n\\n调节前排座椅时，请勿过度前移，避免碰触到顶棚或遮阳板。\\n\\n二排可调节副驾座椅开关*\\n\\n① 副驾靠背角度调节开关\\n\\n前、后拨动副驾靠背角度调节开关，可调节副驾靠背角度。\\n\\n② 副驾座椅位置调节开关\\n\\n前、后移动座椅位置调节开关，可调节座椅前、后位置。\\n\\n前排座椅大床模式*\\n\\n如果您选择的车辆上配置有前排座椅大床模式，使用此功能前需确认前排座椅头枕是否已取下。\\n\\n用户可通过点击中控屏→我的车界面，点击“一键大床”按键。多媒体系统弹窗提醒用户取下主驾/副驾座椅头枕。确认后，“一键大床模式”功能开启，前排座椅和二排座椅自动调节滑轨位置和靠背角度。\\n\\n警告\\n\\n需确保前排座椅、二排座椅和第三排座椅均无人乘坐时，才可以使用前排座椅“一键大床模式”功能。\\n\\n若前排座椅头枕未取下，开启“一键大床模式”功能，则会触发防夹模式。\\n\\n[seed chunk_id=tang_p100_c118 page=100-101]\\n记忆系统*\\n\\n记忆开关位置\\n\\n用户可通过下拉中控屏的便捷菜单或点击中控屏→我的车→座椅调节界面设置记忆开关，共2个记忆挡位。\\n\\n记忆设定条件\\n\\n整车电源挡位处于启动状态、无车速。\\n\\n座椅、左右外后视镜已调至需求位置。\\n\\n座椅、左右外后视镜均无动作。\\n\\n记忆设置操作方法\\n\\n在中控屏座椅记忆设置项界面长按任一记忆开关，这时的座椅、外后视镜的位置将会被记住， 记忆设置完成。\\n\\n温馨提示\\n\\n如果记忆开关上位置按键已经被设置过，那么已经被设置的位置将被覆盖。\\n\\n记忆唤醒功能\\n\\n“OK”挡条件下记忆唤醒功能\\n\\n–换挡杆处于“P”挡，若符合下述条件，短按记忆系统开关中的任意一个，座椅、左右外后视镜等记忆系统将执行记忆唤醒操作：\\n\\n整车未进入防盗状态。\\n\\n无车速。\\n\\n记忆开关信号有效。\\n\\n座椅、左右外后视镜均无动作。\\n\\n通过下列方法，可中断当前记忆唤醒操作：\\n\\n按下或拨动主驾/副驾任一座椅调节开关。\\n\\n按下中控屏座椅记忆设置项界面任一记忆开关。\\n\\n警告\\n\\n座椅记忆功能唤醒前，请确保座椅周围无障碍物。\\n\\n座椅记忆功能唤醒过程中，请确保身体各部位未处于座椅的移动范围内。\\n\\n请勿让儿童操作记忆开关，以防在座椅移动过程中被夹伤。\\n\\n[neighbor chunk_id=tang_p101_c119 page=101-102]\\n座椅迎宾功能\\n\\n自动后退功能：\\n\\n●驾驶员取车时，遥控钥匙解锁整车，开启主驾车门，若座椅位置处于全行程前段，座椅将自动后退一段距离，方便驾驶员上车。\\n\\n电源由“启动”状态切换至“停止”状态时，若座椅位置处于全行程前段，驾驶员开启主驾车门时，座椅将自动后退一段距离，方便驾驶员下车。\\n\\n自动前进功能：\\n\\n●电源由“停止”状态切换至“启动”状态时，若上次退电执行过自动后退功能且退电开门后未对座椅水平方向进行过电动调节，则上电后，驾驶员关门时，座椅会自动前进至退电前的位置。\\n\\n电源由“启动”状态切换至“停止”状态时，若驾驶员开启主驾车门触发了自动后退功能后未对座椅水平方向进行过电动调节，则驾驶员下车关门时，座椅会自动前进至退电前的位置，为下一次迎宾做准备。\\n\\n用户设置：\\n\\n用户可通过点击中控屏→设置 →驾驶→舒适用车→前排座椅迎宾，可开启或关闭前排座椅迎宾功能。\\n\\n座椅自动后退过程中关闭主驾/副驾车门，或座椅自动前进过程中开启主驾/副驾车门，可中断对应座椅迎宾功能。\", \"chunk_id\": \"tang_p100_c118\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"记忆系统*\", \"page_number_end\": 101, \"context_chunk_ids\": [\"tang_p99_c117\", \"tang_p100_c118\", \"tang_p101_c119\"], \"page_number_start\": 100}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=tang_p283_c190 page=283-285]\\n探测还可能被噪声或电磁波影响，从而产生延迟或受到干扰。\\n\\n–前向碰撞提醒可能会对地面的水渍、路面阴影、井盖、铁板或道路指示牌等触发非必要的提醒。\\n\\n–若车辆长时间行驶在环形停车场、隧道等特殊道路条件下，前置毫米波雷达因探测特性可能会出现短暂的功能受限，当离开当前特殊道路后，功能将恢复。\\n\\n[seed chunk_id=tang_p285_c191 page=285]\\n警告\\n\\n请驾驶员务必安全驾驶，时刻注意观察周围交通状况，在任何情况下，均不得使用前向碰撞提醒代替正常的驾驶员判断和操作。\\n\\n如果前向碰撞提醒发出警报，则驾驶员必须根据交通状况施加制动来降低车速或通过转向避开障碍物。\\n\\n如果长时间近距离跟车行驶，那么安全距离报警会发出距离警告。如果在前方行驶的车辆紧急制动，那么碰撞无法避免。\\n\\n一行人保护场景因无法克服一些物理条件的限制，在系统规定的速度区间内，功能可能无法完全施展开。因此，采取及时有效的制动行为的责任始终依赖于驾驶员。行人保护场景是否发出警告，需要基于实际情况。\\n\\n行人保护场景无法依托系统自身，完全避免事故和严重伤害。\\n\\n行人保护场景在一些复杂工况下，可能会误触发不需要的提醒，例如，在弯曲的主路上。\\n\\n功能故障时，可能会有不需要的警报介入，例如，由于雷达/前视摄像头角度失准。\\n\\n请勿自行尝试使用纸箱、铁板、假人等物体测试前向碰撞提醒，系统可能不会正常工作，从而导致事故发生。\\n\\n发生如下情况请务必前往比亚迪汽车授权服务店对毫米波雷达进行专业校准：\\n\\n拆卸毫米波雷达或前视摄像头。\\n\\n在进行四轮定位的过程中已调节前束或后桥车轮外倾。\\n\\n车辆发生过碰撞后。\\n\\nACC 系统性能下降或异常。\\n\\n请根据个人需求结合交通状况及道路环境自行决定是否使用前向碰撞提醒功能。\\n\\n[neighbor chunk_id=tang_p286_c192 page=286]\\n温馨提示\\n\\n一前向碰撞提醒功能不能保证在任何情况下都发出提醒，在复杂的交通状况下，系统无法总是清楚地识别车辆、行人或骑行人。\\n\\n一雷达或前视摄像头表面出现污浊或异物覆盖时，组合仪表显示屏将显示相应信息，则应按要求清除传感器表面异物（表面污浊或被异物覆盖会导致传感器致盲）。在传感器污浊或被异物覆盖时，前向碰撞提醒功能关闭，清除之后，前向碰撞提醒功能正常。\\n\\n自动紧急制动(AEB)*\\n\\n■自动紧急制动(AEB)功能是利用前置毫米波雷达或摄像头等传感器检测自车前方的车辆、行人和骑行人，系统判定自车可能与前方车辆、行人或骑行人存在较严重碰撞风险时，则会自动施加必要的紧急制动，以辅助驾驶员避免碰撞或者减轻碰撞。\\n\\n当车辆以约 8km/h~150km/h的速度行驶时，自动紧急制动(AEB)系统实时检测车辆前方行驶环境，当识别到自车即将与前方的车辆、行人或骑行人碰撞时，自动实施制动以降低车辆速度。\\n\\n紧急制动时，仪表显示制动图标，显示提示弹窗动画，文言显示“紧急制动中”，同时伴有声音报警。\\n\\n紧急制动时，双闪灯将可能被激活点亮以提示后车注意追尾风险；若紧急制动结束后双闪灯未自动熄灭，则需要驾驶员手动关闭。\", \"chunk_id\": \"tang_p285_c191\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"警告\", \"page_number_end\": 285, \"context_chunk_ids\": [\"tang_p283_c190\", \"tang_p285_c191\", \"tang_p286_c192\"], \"page_number_start\": 285}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=tang_p200_c034 page=200]\\n传感器标定触发条件\\n\\n一当相机出现换件，相机支架调整，或者中央计算平台更换等均需重新到比亚迪汽车授权服务店完成相机标定。\\n\\n一雷达类售后标定包含毫米波雷达（前雷达/角雷达）、激光雷达部分。当出现换件或拆装、支架调整等均需重新到比亚迪汽车授权服务店完成雷达标定。\\n\\n高精定位标定，当PBOX或中央计算平台换件或安装调整，均需到比亚迪汽车授权服务店重新完成高精定位标定。\\n\\n在使用泊车辅助功能时，当中控屏提示“请标定全景后使用”或者提示“传感器未标定，泊车暂不可用”时，请尽快驾驶车辆到比亚迪汽车授权服务店进行传感器标定，重新标定完成前泊车辅助功能暂不可用。\\n\\n[seed chunk_id=tang_p200_c035 page=200-201]\\n重启驾驶辅助系统\\n\\n如果系统出现异常或者无响应，驾驶员可以通过重启中控屏或者车辆重新上电来重启系统。\\n\\n重启方法\\n\\n1. 停车，挂入“P”挡。\\n\\n2. 同时长按转向盘右侧滚轮+向右按键 3s，待中控屏黑屏后松开即可重启系统。\\n\\n①多媒体触摸屏\\n\\n②转向盘右侧滚轮+向右按键\\n\\n温馨提示\\n\\n系统重启过程中，全景影像等驾驶辅助功能不可用。\\n\\n重启系统不影响车辆的电源状态，不会导致电源接通或断开。\\n\\n一重启系统后，车辆会重新定位自车位置，可能导致重启后首次使用驾驶辅助App时，地图界面的自车车标位置不准确。驾车在开阔路段行驶一段距离即可恢复车辆定位。\\n\\n如果中控屏在黑屏5分钟后仍无反应或出现其他异常，请尝试将车辆下电后，再上电重试。\\n\\n如果重启系统并将车辆下电后，再上电重试，中控屏仍无反应或出现其他系统异常，请联系比亚迪汽车授权服务店。\\n\\n[neighbor chunk_id=tang_p201_c036 page=201-202]\\n反馈驾驶辅助系统体验信息*\\n\\n–反馈系统体验问题信息：驾驶员可以通过实车操作来记录体验驾驶辅助的中发现的问题信息。\\n\\n使用方法\\n\\n用户可通过长按方向盘“时距-”按键超过0.5s或智能语音唤起上报驾驶辅助系统事件。\\n\\n待停车确认安全后或至比亚迪汽车授权服务店联系售后人员描述事件发生时间地点，必要时可提供行车记录仪佐证。\\n\\n上报事件时间建议\\n\\n202 4-5 驾驶辅助功能\\n\\n驾驶员及时、准确的反馈驾驶辅助体验有助于我们深入分析事件详情，持续优化改进。在确保安全的前提下，建议在发生以下情况的5秒内完成驾驶辅助事件上报操作。\\n\\n发生交通事故。\\n\\n车辆发生非预期行为，如非预期转向、加减速、功能退出或发出控制车辆提醒等。\\n\\n使用领航辅助时，车辆未按照导航路线行驶。\\n\\n显示屏上未显示自车周边部分车辆（目标漏检），或感知目标物显示异常（花屏、黑屏等）。\\n\\n其他驾驶辅助功能体验问题。\\n\\n我们将认真分析驾乘人员反馈的信息，持续提高驾驶辅助系统的使用体验。\", \"chunk_id\": \"tang_p200_c035\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"重启驾驶辅助系统\", \"page_number_end\": \"201\", \"context_chunk_ids\": [\"tang_p200_c034\", \"tang_p200_c035\", \"tang_p201_c036\"], \"page_number_start\": \"200\"}, {\"score\": 0.018032786885245903, \"content\": \"[neighbor chunk_id=tang_p153_c189 page=153]\\n警告\\n\\n七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n\\n设备规格：请查看充电机相关说明。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=tang_p153_c190 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n–打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电：\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n[neighbor chunk_id=tang_p154_c191 page=154]\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n■直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备：\\n\\n■直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n\\n高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\", \"chunk_id\": \"tang_p153_c190\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": \"154\", \"context_chunk_ids\": [\"tang_p153_c189\", \"tang_p153_c190\", \"tang_p154_c191\"], \"page_number_start\": \"153\"}, {\"score\": 0.01746031746031746, \"content\": \"[neighbor chunk_id=tang_p151_c186 page=151]\\n温馨提示(续)\\n\\n若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n\\n电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n–为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n\\n使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=tang_p151_c187 page=151-152]\\n温馨提示\\n\\n使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n\\n也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n若使用充电盒为车辆充电，则无需此步操作。\\n\\n■若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n\\n■若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七*，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置：\\n\\n对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n\\n■对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n[neighbor chunk_id=tang_p152_c188 page=152-153]\\n温馨提示\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n\\n若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n若使用充电盒为车辆充电，则无需此步操作。\\n\\n4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n\\n5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"tang_p151_c187\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": 152, \"context_chunk_ids\": [\"tang_p151_c186\", \"tang_p151_c187\", \"tang_p152_c188\"], \"page_number_start\": 151}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=tang_p210_c051 page=210-211]\\n定速巡航\\n\\n当未检测到前方车辆阻碍自车行驶时，ACC会辅助驾驶员控制车辆以设定的速度巡航。\\n\\n跟车巡航\\n\\n当检测到前方车辆阻碍自车行驶时，ACC会辅助驾驶员控制车辆保持安全车距，跟随前车行驶，并支持跟随前车进行加减速、停车、起步等操作。\\n\\n跟车巡航时，仪表显示屏上会将跟随的前车蓝色高亮显示。跟车距离与车速、跟车时距挡位有关，非固定数值。（参考“设定跟车时距”）\\n\\n跟车巡航过程中，ACC会在跟车目标切出或有其他车辆切入时辅助驾驶员调整车速并更新跟车目标，如果没有新的跟车目标则进行定速巡航。\\n\\n使用ACC 过程中主动提速/减速（适用ICC、NOA功能）\\n\\nACC处于激活状态时，驾驶员可通过主动踩加速踏板加速，驾驶员加速干预期间，车辆将优先响应驾驶员操作，驾驶辅助系统不再辅助驾驶员控制车辆速度，也无法完成减速，此时驾驶员应对驾驶安全负责。\\n\\n可通过加速踏板快速提高当前车速，松开加速踏板时可提高巡航车速的设置值。\\n\\n如果踩加速踏板至实时车速大于目标巡航车速设置值，则松开加速踏板时，目标巡航车速设置值为松开加速踏板时的实时车速。\\n\\n若踩加速踏板的同时，向下拨动拨杆按键①，会将当前车速设置为目标巡航车速。\\n\\n向上拨动拨杆按键①，会增加目标巡航车速，短按按键可以单次加速5km/h，长按按键可以连续加速1km/h。若车速大于135km/h 或持续踩加速踏板时间超过5分钟，ACC功能退出。\\n\\n[seed chunk_id=tang_p211_c052 page=211]\\n车辆跟停/起步\\n\\nACC可以控制车辆在正常行驶工况下跟随前车停止：\\n\\n跟停前车短时间内(≤2.5分钟)，自车可主动跟随前车起步。\\n\\n若长时间跟停(2.5 分钟＜跟停时间≤3 分钟~10 分钟)，需要驾驶员根据提示踩下加速踏板来确认起步。\\n\\n若跟停时间过长(>3 分钟~10 分钟)，ACC 功能会主动退出并开启电子驻车制动。此时需驾驶员松开电子驻车制动并踩住制动踏板才可完成ACC 静止下激活。\\n\\n警告\\n\\n驾驶员应根据当地的交通法律法规和实际道路状况来设置目标车速和跟车时距，并在情况变化时及时调节，始终确保安全驾驶。\\n\\nACC 无法处理对向来车。\\n\\n自车距离前方车辆或行人过近时，ACC可能无法正确识别目标。\\n\\n在弯道上进行跟车巡航时，车辆可能会跟随错误的目标，导致车辆未按预期车速行驶或行驶方向偏移。驾驶员应专注驾驶，当发现跟车错误时及时正确控制车辆。\\n\\n切勿过度依赖跟车巡航功能的速度调节和跟车时距调节来保持准确、安全的跟车距离，以免发生碰撞。驾驶员有责任确定并始终保持安全的跟车距离。\\n\\n[neighbor chunk_id=tang_p212_c053 page=212]\\n警告(续)\\n\\n在车辆停车待行期间按下功能激活拨片/按键会导致车辆退出ACC，可能导致车辆因怠速突然向前行驶，进而引发事故。请时刻关注系统提示与注意行车环境，若发生怠速行驶的情形，请及时纠正并主动控制车辆，确保安全驾驶。\\n\\n一驾驶员应始终保持警惕，密切注意周围可能的各种危险情形，必要时及时人工干预或控制车辆（例如适当减速、制动、转向等），确保安全驾驶。违反上述操作会影响驾驶员的安全驾驶，可能会引发事故，甚至导致财产损毁、人身伤亡。\", \"chunk_id\": \"tang_p211_c052\", \"chunk_type\": \"text\", \"source_file\": \"tang.pdf\", \"section_title\": \"车辆跟停/起步\", \"page_number_end\": \"211\", \"context_chunk_ids\": [\"tang_p210_c051\", \"tang_p211_c052\", \"tang_p212_c053\"], \"page_number_start\": \"211\"}]',5,20302,1,NULL,'2026-06-26 17:26:28'),(36,1,NULL,NULL,NULL,'怎么充电？','⚠️ **安全提示**：充电涉及高压用电系统，请务必遵守本手册警告事项。若充电时出现异味、冒烟、异响或设备报警，请立即停止充电并联系授权服务店。具体操作请以您车辆当前系统提示及设备实际说明为准。\n\n根据用户手册资料，充电方式主要分为**家用便携式交流充电**、**公共交流充电桩/盒**和**直流快充**。通用检查与操作步骤如下：\n\n### 🔍 充电前必做检查（所有类型适用）\n1. **查设备**：确保充电枪、电缆无破损/磨损/进水，插头无锈蚀；接地良好。如有异常严禁充电。\n2. **查车端**：确保充电口内无积水或异物，金属端子完好。\n3. **选环境**：停放在通风干燥处，远离火源、易燃易爆物及雷电环境。**雷雨天气禁止充电**。充电时请勿遮挡进气格栅，充电线不可盘放。\n\n---\n\n### 🔌 充电操作步骤（按设备类型）\n\n#### 1️⃣ 家用便携式交流充电\n1. **插电源端**：将“三转七”供电插头插入符合国标的220V家用插座，电源指示灯常亮。（建议开启充电防盗功能）\n2. **开车侧**：整车解锁，电源挡位退至`OFF`，按下充电口盖自动开启，再掀开交流充电口保护盖。\n3. **插车侧**：按下充电枪黑色锁止按钮，将枪头对准车辆交流口推入到底，松开按钮。仪表充电连接指示灯点亮即可开始充电。\n\n#### 2️⃣ 公共交流充电桩 / 充电盒\n1. **开车侧**：同家用便携操作，解锁车辆并开启右侧充电口盖及保护盖。\n2. **插车侧**：将充电枪插入车辆接口，确认可靠锁止。\n3. **启动充电**：\n   - 公共场所有设置选项的桩/盒：按指引刷卡或扫码。\n   - 无设置选项的桩/盒：插好枪后即可自动启动充电。仪表指示灯点亮即正常。\n\n#### 3️⃣ 直流快充充电\n1. **开车侧**：整车解锁并退至`OFF`挡，按下车辆右侧充电口盖，打开直流充电口保护盖。\n2. **插车侧**：将直流充电枪插入车辆接口，确认枪锁止到位。\n3. **启动充电**：在充电桩屏幕上完成验证并按指导步骤点击“开始充电”。组合仪表显示充电参数与画面即开始工作。\n   > 💡 *注：高温环境下直流充电时，为保证效率建议充电过程中关闭空调。*\n\n---\n\n### 🛑 停止充电与拔枪操作\n1. **结束充电**：电量充满自动停止，或手动设置提前结束。\n2. **解锁拔枪**：\n   - 先通过钥匙解锁键或门把手微动开关解除整车电锁防盗。\n   - **按住**充电枪上的机械按钮，垂直平稳拔出充电枪。⛔ **切勿在锁止状态下强行拔枪**，以免损坏充电口。\n3. **收纳复原**：关紧充电口保护盖及充电口盖，将线缆/充电枪放回指定位置妥善存放。\n\n### 📖 附加注意事项\n- **预约充电**：可在多媒体设置，但**电量较低时无法使用**。\n- **温度影响**：极冷或极热环境下，电池热管理系统会自动加热/冷却，可能导致充电功率波动或时间延长，属正常现象。\n- **电池保养**：建议定期用交流电充满一次；长期停放建议保持电量在 `40%~60%`；SOC进入红色区域请及时补电。\n\n如需更详细的设备专属操作或遇到拔枪困难/故障报警，请参考随车充电设备说明书，或联系比亚迪汽车授权服务店处理。','han.pdf','[{\"score\": 0.05190375462718139, \"content\": \"[neighbor chunk_id=han_p123_c141 page=123-124]\\n充电方法\\n\\n充电前检查：\\n\\n确保充电装置没有壳体破裂、电缆磨损、插头生锈或有异物等异常情况。\\n\\n充电连接装置连接松动时，请勿充电。\\n\\n确保充电口内没有水或异物，金属端子没有生锈或者腐蚀。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n交流充电连接装置可以将车辆与家用标准 220V 50Hz 10A 单相两极带地插座相连，为车辆充电。\\n\\n–供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n\\n■该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n\\n设备规格：220V AC 50Hz 8A\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=han_p124_c142 page=124-126]\\n温馨提示\\n\\n建议联系比亚迪汽车授权服务店或当地电工，按充电设备要求选择合适的电源。\\n\\n使用三转七充电时，请开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡电，按下充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n–打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n将三转七的供电插头插入家用插座中，三转七电源指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n按下充电枪上的锁止按钮(黑色按钮)，将充电枪插入车辆插座中，然后松开锁止按钮。\\n\\n■插好充电枪，组合仪表充电连接指示灯 点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n此时可以通过多媒体设置预约充电，设置流程详见智慧充电(仅限交流充电）。\\n\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n车辆电量充满会自动结束充电。\\n\\n如需提前结束充电直接进入下一步。\\n\\n2. 断开充电口连接：\\n\\n若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n\\n若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n[neighbor chunk_id=han_p126_c143 page=126]\\n温馨提示\\n\\n整车解锁，按钥匙解锁按钮(“OFF”挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n\\n一启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n\\n电锁工作模式可通过多媒体设置，设置步骤详见充电口电锁防盗功能功能设置。\\n\\n若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照应急解锁。\\n\\n电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口盖。\\n\\n5. 妥善放置充电设备。\", \"chunk_id\": \"han_p124_c142\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": 126, \"context_chunk_ids\": [\"han_p123_c141\", \"han_p124_c142\", \"han_p126_c143\"], \"page_number_start\": 124}, {\"score\": 0.03723557692307693, \"content\": \"[neighbor chunk_id=han_p120_c135 page=120-121]\\n充电设备注意事项\\n\\n为了避免对充电设备及车辆造成损坏，注意以下避免事项：\\n\\n启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n\\n请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n\\n充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n\\n充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n\\n请勿在电锁锁止状态强行插入充电枪。\\n\\n应小心使用充放电设备：\\n\\n充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n\\n请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n\\n请勿在温度高于5 0 \\\\%的环境下存放或者使用充电设备。\\n\\n请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n不建议使用外加的电线或者适配器/转接器。如果一定要外加转接，请选择合适的线径(≥1.5mm²的电线)，且适配器/转接器参数需满足要求。\\n\\n[seed chunk_id=han_p121_c136 page=121-122]\\n充电前注意事项\\n\\n当充电口盖未解锁时，请勿强行开启充电口盖。\\n\\n先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n\\n当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n充电时建议人员不要停留在车辆内。\\n\\n充电时空调可正常使用，但会降低充电功率。\\n\\n建议将车辆停放在通风处，请勿遮挡进气格栅。\\n\\n当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n\\n电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n\\n充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n\\n充电时，充电连接线不能盘放，会影响散热。\\n\\n低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n\\n气温较低区域，建议用户在有供暖的室内进行充电。\\n\\n气温较高区域，建议用户在阴凉通风处充电。\\n\\n组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间可能有一定偏差，属于正常现象。\\n\\n在直流充电*时，建议充到80%~90%即可，若时间允许可充满。\\n\\n[neighbor chunk_id=han_p122_c137 page=122]\\n充电结束注意事项：\\n\\n先停止充电，并确保充电口已经解锁。\\n\\n手握充电枪，并按住充电枪上的按钮*，拔出充电枪。\\n\\n充电结束后，请先解锁后，再拔出充电插头。\\n\\n请勿在充电口锁止状态下强行拔出充电枪，否则会损坏充电口。\\n\\n拔下充电枪后，请确保充电口保护盖及充电口盖处于闭合状态，避免水或异物进入充电端口，影响正常使用。\\n\\n为提升用车体验建议如下：\\n\\n当组合仪表动力电池剩余电量(SOC)指示条颜色到达红色区域时，表明动力电池电量即将耗尽，请及时充电，否则会影响动力电池的使用寿命。\\n\\n建议用车结束后立即充电，充电性能更佳。\", \"chunk_id\": \"han_p121_c136\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"122\", \"context_chunk_ids\": [\"han_p120_c135\", \"han_p121_c136\", \"han_p122_c137\"], \"page_number_start\": \"121\"}, {\"score\": 0.034009888108248766, \"content\": \"[neighbor chunk_id=han_p128_c146 page=128]\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 关闭交流充电口盖(参照家用便携式交流充电）。\\n\\n4. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n直流充电桩充电\\n\\n使用直流充电桩充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守充电说明中的充电安全注意事项。\\n\\n[seed chunk_id=han_p128_c147 page=128-129]\\n设备说明\\n\\n使用公共场所的直流充电桩为车辆充电，充电桩一般安装在特定的充电站。\\n\\n设备规格：请查看充电桩相关说明。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开直流充电口保护盖：\\n\\n打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n将充电桩的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 启动充电：\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n[neighbor chunk_id=han_p129_c148 page=129-130]\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n充电桩设置提前结束或充电已完成充电桩会自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n■按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备：\\n\\n充电桩直流充电结束，整理充电设备，并妥善放置，将充电枪放到充电桩的指定位置。\\n\\n注意\\n\\n充完电后，若充电枪不能拔出，请及时联系充电桩客服人员。\\n\\n注意(续)\\n\\n一高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n整车交流充电/放电指示灯\\n\\n充电/放电指示灯位于车身右侧充电口盖内。分别以绿色、黄色、红色、蓝色、白色颜色来说明充电状态。\\n\\n–若不连接充/放电枪，白色常亮一段时间后会熄灭。使用过程中，若整车闭锁，指示灯点亮一段时候后熄灭。整车解锁时，指示灯再次点亮。\", \"chunk_id\": \"han_p128_c147\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"设备说明\", \"page_number_end\": 129, \"context_chunk_ids\": [\"han_p128_c146\", \"han_p128_c147\", \"han_p129_c148\"], \"page_number_start\": 128}, {\"score\": 0.0325, \"content\": \"[neighbor chunk_id=han_p126_c143 page=126]\\n温馨提示\\n\\n整车解锁，按钥匙解锁按钮(“OFF”挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n\\n一启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n\\n电锁工作模式可通过多媒体设置，设置步骤详见充电口电锁防盗功能功能设置。\\n\\n若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照应急解锁。\\n\\n电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n[seed chunk_id=han_p126_c144 page=126-127]\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守充电说明中的充电安全警告事项。\\n\\n–为避免造成充电设备及车辆损坏，请仔细阅读并遵守充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒 *\\n\\n单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息参见充电盒说明书。\\n\\n使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩*\\n\\n使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n三相交流充电桩 *\\n\\n使用公共场所的交流充电桩为车辆充电。\\n\\n也可使用三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n[neighbor chunk_id=han_p127_c145 page=127-128]\\n2. 连接供电口端：\\n\\n若使用充电盒为车辆充电，则无需此步操作。\\n\\n若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n\\n3. 连接车辆接口：\\n\\n将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置：\\n\\n对于交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n\\n■对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n温馨提示\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n此时可以通过多媒体设置预约充电，设置流程详见智慧充电(仅限交流充电）功能设置。\", \"chunk_id\": \"han_p126_c144\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"交流充电桩充电\", \"page_number_end\": 127, \"context_chunk_ids\": [\"han_p126_c143\", \"han_p126_c144\", \"han_p127_c145\"], \"page_number_start\": 126}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=han_p121_c136 page=121-122]\\n充电前注意事项\\n\\n当充电口盖未解锁时，请勿强行开启充电口盖。\\n\\n先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n\\n当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n充电时建议人员不要停留在车辆内。\\n\\n充电时空调可正常使用，但会降低充电功率。\\n\\n建议将车辆停放在通风处，请勿遮挡进气格栅。\\n\\n当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n\\n电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n\\n充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n\\n充电时，充电连接线不能盘放，会影响散热。\\n\\n低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n\\n气温较低区域，建议用户在有供暖的室内进行充电。\\n\\n气温较高区域，建议用户在阴凉通风处充电。\\n\\n组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间可能有一定偏差，属于正常现象。\\n\\n在直流充电*时，建议充到80%~90%即可，若时间允许可充满。\\n\\n[seed chunk_id=han_p122_c137 page=122]\\n充电结束注意事项：\\n\\n先停止充电，并确保充电口已经解锁。\\n\\n手握充电枪，并按住充电枪上的按钮*，拔出充电枪。\\n\\n充电结束后，请先解锁后，再拔出充电插头。\\n\\n请勿在充电口锁止状态下强行拔出充电枪，否则会损坏充电口。\\n\\n拔下充电枪后，请确保充电口保护盖及充电口盖处于闭合状态，避免水或异物进入充电端口，影响正常使用。\\n\\n为提升用车体验建议如下：\\n\\n当组合仪表动力电池剩余电量(SOC)指示条颜色到达红色区域时，表明动力电池电量即将耗尽，请及时充电，否则会影响动力电池的使用寿命。\\n\\n建议用车结束后立即充电，充电性能更佳。\\n\\n[neighbor chunk_id=han_p122_c138 page=122]\\n一般充电故障诊断\", \"chunk_id\": \"han_p122_c137\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"充电结束注意事项：\", \"page_number_end\": \"122\", \"context_chunk_ids\": [\"han_p121_c136\", \"han_p122_c137\", \"han_p122_c138\"], \"page_number_start\": \"122\"}, {\"score\": 0.017741935483870968, \"content\": \"[neighbor chunk_id=han_p140_c165 page=140-141]\\n动力电池保养\\n\\n为了使电池处于最佳状态，请定期使用交流充电连接装置为电池充满电，建议每周至少充满一次。\\n\\n当车辆不使用超过7天时，为延长其使用寿命，建议电池电量保持在40%~60%SOC 区间内。超过3个月不使用时，须先充电至100%再放电至 40%~60%SOC，以避免电池性能降低，甚至损坏。\\n\\n动力电池低温加热功能\\n\\n当外界温度较低时，动力电池加热系统将启动并加热电池，提升低温充电速度和保证整车动力性及续航里程。\\n\\n[seed chunk_id=han_p141_c166 page=141]\\n警告\\n\\n非专业人员请勿打开动力电池包。私自拆卸、拆解电池导致的环境污染或安全事故，单位或个人将承担相应责任。\\n\\n注意\\n\\n动力电池出现故障时，建议您联系比亚迪汽车授权服务店。\\n\\n温馨提示\\n\\n动力电池正常工作温度区间为-35℃~60℃。\\n\\n动力电池工作温度较高或者较低时，充电时间可能会延长。\\n\\n动力电池回收\\n\\n当新能源汽车达到报废要求时，建议您按以下流程操作：\\n\\n1. 将车辆送至比亚迪回收服务网点，比亚迪将对动力电池进行残值评估。\\n\\n2. 将评估后的车辆送至报废汽车回收拆解企业拆卸动力电池。\\n\\n3. 将汽车回收拆卸机构拆卸的废旧动力电池移交至回收服务网点，回收服务网点将对动力电池进行回购。\\n\\n[neighbor chunk_id=han_p141_c167 page=141-142]\\n警告\\n\\n■新能源汽车所有人有责任和义务将废旧动力电池移交回收服务网点。私自将废旧动力电池移交给其他单位或个人，私自拆卸、拆解动力电池，由此导致环境污染或安全事故的，应承担相应责任。\\n\\n低压蓄电池\\n\\n本车使用的低压蓄电池为比亚迪自研磷酸铁锂电池。低压蓄电池具备智能充电功能。当动力电池电量充足时，车辆可以自动开启动力电池或起发动机对低压蓄电池充电，以延长低压蓄电池续航时长。\\n\\n温馨提示\\n\\n电源挡位处于“OFF”挡智能充电时，车辆会发出正常上“OK”挡时发出的声音，属正常现象。\\n\\n如果您离开车辆时，请确保已关闭所有用电设备，且车门已经关好。\\n\\n车辆亏电后唤醒功能\", \"chunk_id\": \"han_p141_c166\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"警告\", \"page_number_end\": 141, \"context_chunk_ids\": [\"han_p140_c165\", \"han_p141_c166\", \"han_p141_c167\"], \"page_number_start\": 141}, {\"score\": 0.01746031746031746, \"content\": \"[neighbor chunk_id=han_p119_c131 page=119]\\n充电说明\\n\\n充电安全警告\\n\\n禁止未成年人进行充电作业或触摸使用充电设备，充电枪为高压用电器件，在充电时请勿让未成年人靠近。\\n\\n请选择在相对较安全的环境下充电，如避免有危化液体、火源、热源、雷电、易燃易爆等环境。\\n\\n严禁湿手操作，触摸充电口或充电座的裸露金属，否则可能引起触电、电击，造成人身伤害。\\n\\n由于充电可能影响医疗电子设备，甚至造成严重的人身伤害或者死亡，如果您使用任何医疗电子设备（如可移植心脏起搏器或者可移植心脏血管去纤颤器），在启动充电操作之前与医疗电子设备的制造商确认充电是否影响设备的正常工作。\\n\\n[seed chunk_id=han_p119_c132 page=119]\\n充电设备警告事项\\n\\n使用满足国家相关标准的电动汽车专用充电设备：\\n\\n请勿私自对充电设备及相关端口进行改装、拆卸或擅自维修，若有故障请联系比亚迪汽车授权服务店进行处理，避免导致充电故障，引起火灾。\\n\\n严禁使用不合格产品。\\n\\n严禁在家用供电插排线变软、充电枪电缆磨损、绝缘层破裂或者其他任何损坏的情况下，使用该充电设备。\\n\\n严禁充电枪、供电插头或供电插排断开、破裂或者表面露出有任何损坏的情况下，使用该设备。\\n\\n充电设备接地说明：\\n\\n设备必须接地良好，如果充电设备出现故障或者损坏时，接地线可提供最小阻抗电路放电，从而减少触电的危险。\\n\\n设备装有设备接地点与供电插头接地点相连的接地线，供电插头必须与符合安装正确且接地良好的供电插座互配。\\n\\n充电时，禁止将设备放置于后备箱、车头下以及轮胎附近。\\n\\n[neighbor chunk_id=han_p119_c133 page=119-120]\\n充电前警告事项\\n\\n请确保车辆、供电设备和充电设备的充电端口内没有水等异物，并确保金属端子没有因生锈或腐蚀而造成的破坏、影响等情况，若出现上述情况，请勿充电。\\n\\n充电中警告事项\\n\\n为了避免造成严重的人身伤害，车辆正在充电时，注意以下预防事项：\\n\\n禁止接触充电端口、充电连接器或者插头的金属连接处。\\n\\n当有雷雨天气时，禁止给车辆充电或触摸车辆，闪电击中可能导致充电设备损坏、引起人身伤害。\\n\\n在直流充电*时，请保持交流充电口保护盖处于关闭状态；在交流充电时，请保持直流充电口*保护盖处于关闭状态。\\n\\n充电时，如果发现车辆或充电设备异常，如产生异味、冒烟等现象，请立即停止充电，并建议与比亚迪汽车授权服务店联系。\\n\\n充电时，禁止对车辆进行维修。\", \"chunk_id\": \"han_p119_c132\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"充电设备警告事项\", \"page_number_end\": \"119\", \"context_chunk_ids\": [\"han_p119_c131\", \"han_p119_c132\", \"han_p119_c133\"], \"page_number_start\": \"119\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=han_p141_c166 page=141]\\n警告\\n\\n非专业人员请勿打开动力电池包。私自拆卸、拆解电池导致的环境污染或安全事故，单位或个人将承担相应责任。\\n\\n注意\\n\\n动力电池出现故障时，建议您联系比亚迪汽车授权服务店。\\n\\n温馨提示\\n\\n动力电池正常工作温度区间为-35℃~60℃。\\n\\n动力电池工作温度较高或者较低时，充电时间可能会延长。\\n\\n动力电池回收\\n\\n当新能源汽车达到报废要求时，建议您按以下流程操作：\\n\\n1. 将车辆送至比亚迪回收服务网点，比亚迪将对动力电池进行残值评估。\\n\\n2. 将评估后的车辆送至报废汽车回收拆解企业拆卸动力电池。\\n\\n3. 将汽车回收拆卸机构拆卸的废旧动力电池移交至回收服务网点，回收服务网点将对动力电池进行回购。\\n\\n[seed chunk_id=han_p141_c167 page=141-142]\\n警告\\n\\n■新能源汽车所有人有责任和义务将废旧动力电池移交回收服务网点。私自将废旧动力电池移交给其他单位或个人，私自拆卸、拆解动力电池，由此导致环境污染或安全事故的，应承担相应责任。\\n\\n低压蓄电池\\n\\n本车使用的低压蓄电池为比亚迪自研磷酸铁锂电池。低压蓄电池具备智能充电功能。当动力电池电量充足时，车辆可以自动开启动力电池或起发动机对低压蓄电池充电，以延长低压蓄电池续航时长。\\n\\n温馨提示\\n\\n电源挡位处于“OFF”挡智能充电时，车辆会发出正常上“OK”挡时发出的声音，属正常现象。\\n\\n如果您离开车辆时，请确保已关闭所有用电设备，且车门已经关好。\\n\\n车辆亏电后唤醒功能\\n\\n[neighbor chunk_id=han_p142_c168 page=142-143]\\n左前门微动开关唤醒：\\n\\n●低压蓄电池具有休眠唤醒功能，车辆长期存放后，若使用智能钥匙将无法实现寻车及车辆解锁功能，低压蓄电池可能已进入休眠状态。此时需按下左前门把手的微动开关(如下图所示），即可唤醒低压蓄电池。对车辆解锁后，车辆即可正常使用。\\n\\n当车辆无法通过左前门微动开关唤醒和解锁时，可以使用机械钥匙打开车门。此时可以利用12V规格电源通过两根搭火专用电缆线搭火启动车辆。此时低压蓄电池电量较低，仪表可能提示“蓄电池电量不足，车辆即将退电”，车辆会再次休眠。需立即启动车辆发电并保持启动状态15分钟以上，以保证低压蓄电池充满电量。搭火操作只能通过前舱配电盒专用接口进行。\\n\\n① 前舱配电盒搭火正极\\n\\n② 电控壳体搭火负极\\n\\n若上述操作均无法唤醒并启动车辆，建议及时联系比亚迪汽车授权服务店处理。\", \"chunk_id\": \"han_p141_c167\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"警告\", \"page_number_end\": 142, \"context_chunk_ids\": [\"han_p141_c166\", \"han_p141_c167\", \"han_p142_c168\"], \"page_number_start\": 141}]',5,30170,1,NULL,'2026-06-26 17:39:10'),(37,1,NULL,NULL,NULL,'你好','您好！欢迎选购比亚迪汽车。\n\n根据您提供的《用户手册》前言及索引部分资料，为您整理现有文档中的**目录/索引概览**如下：\n\n**📖 图片索引（按核心模块检索）**\n1. **安全**：确保通读本部分内容\n2. **仪表组**：如何读取仪表、各种警告灯和指示灯等\n3. **控制器操作**：打开和关闭车门与车窗、驾驶前的调节等\n4. **使用和驾驶**：驾驶时的必要操作和建议\n5. **车内装置**：使用车内装置等\n6. **保养及维护**：车辆维护和保养步骤\n7. **发生故障时**：发生故障时或紧急情况下的应对措施\n8. **车辆规格**：车辆规格参数和提示信息\n\n**🔤 字母索引**\n手册末尾附有完整的字母索引，您可查阅对应页码获取详细功能说明、操作步骤或故障排查指南。\n\n💡 **温馨提示**：\n* 本资料仅提取了当前片段中的索引框架。如需查看具体功能的详细操作步骤、参数或最新系统逻辑，请以您的实车中控屏菜单、完整纸质/电子手册为准。\n* 如遇操作疑问或需要进一步协助，可拨打比亚迪汽车官方客服电话：**400-830-3666**。\n* 涉及驾驶安全、充电或故障处理时，请务必以车辆实际仪表提示及官方售后指导为准。\n\n请问您需要了解手册中哪个具体功能或操作步骤？我将为您精准解答。','han.pdf','[{\"score\": 0.03866770752016654, \"content\": \"[neighbor chunk_id=han_p1_c001 page=1]\\n精于勤诚于心比亚迪精诚服务Superior and Sincere Services\\n\\n比亚迪精诚服务品牌建立于2006年，秉承了比亚迪汽车所有售后人“精于勤，诚于心”的服务理念。\\n\\n《庄子》有云：“真者，精诚之至也。不精不诚，不能动人。\\n\\n比亚迪汽车售后人把精诚的理念引入汽车售后行业，将比亚迪精诚服务品牌定位为专业、真诚、贴心。\\n\\n比亚迪精诚服务始终致力于为比亚迪汽车客户及其爱车提供高水准的售后服务，坚信精湛的服务技术源于专业和勤奋，真诚的服务态度来自责任与用心。\\n\\n[seed chunk_id=han_p2_c002 page=2-6]\\n前言\\n\\n欢迎您选用比亚迪汽车。为帮助您正确使用和保养车辆，请您在使用前务必仔细阅读本手册全部内容，阅读后并妥善保存。\\n\\n特别说明：比亚迪汽车工业有限公司建议您选用纯正备件，并按照使用手册要求正确使用、维护、修理车辆。使用非纯正备件更换、改装车辆将影响整车的性能，特别是安全性和耐久性，对此产生的车辆损坏及性能问题，均不在保修范围之内，除此之外对车辆的改装还有可能触犯国家法律法规和当地政府条例。\\n\\n感谢您选用比亚迪汽车，欢迎您提出宝贵意见和建议。为了确保更好的为您服务，请务必提供准确的联系方式，如有变更，请及时联系比亚迪汽车授权服务店在系统上更新。同时，请您及时关注国家相关法律和法规及当地政策规定，尽快为车辆上牌，否则可能存在无法上牌风险。\\n\\n网络安全事件及漏洞收集：如果您发现与网络安全相关的事件或者漏洞，请及时通过电子邮件方式发送到 cve.auto@byd.com，我们会对反馈的内容进行核查，并会根据国家相关规定及要求进行通报。若反馈的漏洞信息涉及到其他组织单位，我们会及时告知对方。感谢您的关注与支持！\\n\\n本手册中带有“*”标号的描述仅适用于部分车型，使用图片仅采样于其中一个配置，如与您所购车辆有差异，请以实车为准。\\n\\n本手册中，注有“警告”、“注意”和“温馨提示”的地方，必须小心根据提示的内容来避免受伤或损坏的可能性。提示类型的表示和使用方法如下所示：\\n\\n警告\\n\\n为保护人身安全而必须遵守的事项。\\n\\n注意\\n\\n为避免损坏车辆而必须遵守的事项。\\n\\n温馨提示\\n\\n为使检修方便等而必须遵守的事项。\\n\\n左图所示的安全标记表示“不可以如此做”或“不可以让此发生”。\\n\\n本手册的用途在于帮助您正确地使用产品，并不代表对本产品配置及软件版本的任何说明。有关产品配置和软件版本情况，请查阅与本产品相关合约 (若有)，或咨询向您出售产品的销售商。\\n\\n比亚迪汽车官网：https://www.bydauto.com.cn\\n\\n[neighbor chunk_id=han_p2_c003 page=2-6]\\n比亚迪汽车官方客服电话：400-830-3666\\n\\n动力电池回收网点查询请登录比亚迪汽车官网：\\n\\nhttps://www.byd.com/cn/socialresponsibility/batteryrecycle.html\\n\\n详细的产品使用说明请扫描以下小程序二维码查询：\\n\\n比亚迪汽车工业有限公司版权所有\\n\\n未经比亚迪汽车工业有限公司书面许可授权，不得转载或复制、存储或翻译本手册的部分或全部内容，也不得以电子或其他任何形式进行传播\\n\\n翻版必究\\n\\n图片索引 按照插图检索 1 安全 确保通读本部分内容 2 仪表组 如何读取仪表、各种警告灯和指示灯等 3 控制器操作 打开和关闭车门与车窗、驾驶前的调节等 4 使用和驾驶 驾驶时的必要操作和建议 5 车内装置 使用车内装置等 6 保养及维护 车辆维护和保养步骤 7 发生故障时 发生故障时或紧急情况下的应对措施 8 车辆规格 车辆规格参数和提示信息 字母索引 字母索引\\n\\n精诚服务.... 1 前言.... 2\", \"chunk_id\": \"han_p2_c002\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"前言\", \"page_number_end\": \"6\", \"context_chunk_ids\": [\"han_p1_c001\", \"han_p2_c002\", \"han_p2_c003\"], \"page_number_start\": \"2\"}, {\"score\": 0.030575071558678116, \"content\": \"[neighbor chunk_id=han_p2_c002 page=2-6]\\n前言\\n\\n欢迎您选用比亚迪汽车。为帮助您正确使用和保养车辆，请您在使用前务必仔细阅读本手册全部内容，阅读后并妥善保存。\\n\\n特别说明：比亚迪汽车工业有限公司建议您选用纯正备件，并按照使用手册要求正确使用、维护、修理车辆。使用非纯正备件更换、改装车辆将影响整车的性能，特别是安全性和耐久性，对此产生的车辆损坏及性能问题，均不在保修范围之内，除此之外对车辆的改装还有可能触犯国家法律法规和当地政府条例。\\n\\n感谢您选用比亚迪汽车，欢迎您提出宝贵意见和建议。为了确保更好的为您服务，请务必提供准确的联系方式，如有变更，请及时联系比亚迪汽车授权服务店在系统上更新。同时，请您及时关注国家相关法律和法规及当地政策规定，尽快为车辆上牌，否则可能存在无法上牌风险。\\n\\n网络安全事件及漏洞收集：如果您发现与网络安全相关的事件或者漏洞，请及时通过电子邮件方式发送到 cve.auto@byd.com，我们会对反馈的内容进行核查，并会根据国家相关规定及要求进行通报。若反馈的漏洞信息涉及到其他组织单位，我们会及时告知对方。感谢您的关注与支持！\\n\\n本手册中带有“*”标号的描述仅适用于部分车型，使用图片仅采样于其中一个配置，如与您所购车辆有差异，请以实车为准。\\n\\n本手册中，注有“警告”、“注意”和“温馨提示”的地方，必须小心根据提示的内容来避免受伤或损坏的可能性。提示类型的表示和使用方法如下所示：\\n\\n警告\\n\\n为保护人身安全而必须遵守的事项。\\n\\n注意\\n\\n为避免损坏车辆而必须遵守的事项。\\n\\n温馨提示\\n\\n为使检修方便等而必须遵守的事项。\\n\\n左图所示的安全标记表示“不可以如此做”或“不可以让此发生”。\\n\\n本手册的用途在于帮助您正确地使用产品，并不代表对本产品配置及软件版本的任何说明。有关产品配置和软件版本情况，请查阅与本产品相关合约 (若有)，或咨询向您出售产品的销售商。\\n\\n比亚迪汽车官网：https://www.bydauto.com.cn\\n\\n[seed chunk_id=han_p2_c003 page=2-6]\\n比亚迪汽车官方客服电话：400-830-3666\\n\\n动力电池回收网点查询请登录比亚迪汽车官网：\\n\\nhttps://www.byd.com/cn/socialresponsibility/batteryrecycle.html\\n\\n详细的产品使用说明请扫描以下小程序二维码查询：\\n\\n比亚迪汽车工业有限公司版权所有\\n\\n未经比亚迪汽车工业有限公司书面许可授权，不得转载或复制、存储或翻译本手册的部分或全部内容，也不得以电子或其他任何形式进行传播\\n\\n翻版必究\\n\\n图片索引 按照插图检索 1 安全 确保通读本部分内容 2 仪表组 如何读取仪表、各种警告灯和指示灯等 3 控制器操作 打开和关闭车门与车窗、驾驶前的调节等 4 使用和驾驶 驾驶时的必要操作和建议 5 车内装置 使用车内装置等 6 保养及维护 车辆维护和保养步骤 7 发生故障时 发生故障时或紧急情况下的应对措施 8 车辆规格 车辆规格参数和提示信息 字母索引 字母索引\\n\\n精诚服务.... 1 前言.... 2\\n\\n[neighbor chunk_id=han_p6_c004 page=6]\\n1 安全\\n\\n1-1 座椅安全带....18 安全带简介....18 使用安全带....19 1-2 安全气囊....23 安全气囊简介....23 安全气囊类型....24 安全气囊触发条件及注意事项....27 1-3 儿童保护装置....32 儿童保护装置....32 安装儿童保护装置....32 1-4 双模系统工作模式....37 双模系统工作模式简介....37 双模系统工作模式选择....39 1-5 防盗系统....44 防盗系统....44 1-6 汽车事件数据记录系统..46 汽车事件数据记录系统(EDR)....46 1-7 哨兵模式*....49 哨兵模式*....49 2 仪表组 2-1 组合仪表....52\\n\\n组合仪表....52 仪表指示灯....53\", \"chunk_id\": \"han_p2_c003\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"前言\", \"page_number_end\": 6, \"context_chunk_ids\": [\"han_p2_c002\", \"han_p2_c003\", \"han_p6_c004\"], \"page_number_start\": 2}, {\"score\": 0.030049627791563276, \"content\": \"[neighbor chunk_id=han_p174_c006 page=174]\\n驾驶辅助系统简介\\n\\n驾驶辅助系统功能分为行车辅助、泊车辅助、安全辅助和驾驶辅助拓展功能四大类，（具体功能以实车配置为准）。\\n\\n行车辅助：提供自适应巡航(ACC)、车道巡航辅助(ICC)、领航辅助(NOA)和拨杆变道(ILCA)四种驾驶辅助功能，辅助驾驶员驾驶。\\n\\n(泊车辅助：提供驻车辅助系统(PDC&SDW)、泊车辅助(APA)、遥控泊车辅助(RPA)、下车泊入等多种泊车辅助功能，辅助驾驶员完成泊车。\\n\\n安全辅助：提供前、侧、后向的安全辅助功能，辅助驾驶员安全驾驶。\\n\\n驾驶辅助拓展功能：提供路面预瞄、驾驶辅助节能功能。\\n\\n[seed chunk_id=han_p174_c007 page=174]\\n警告\\n\\n驾驶员应在使用系统功能前认真阅读、理解相关协议和配套文件，详细了解、掌握使用系统的相关知识（包括但不限于驾驶辅助系统使用向导、驾驶辅助系统通用局限性、各驾驶辅助功能的具体含义、适用范围和使用方法、注意事项等），并在使用过程中严格遵守相关操作说明，否则可能会引发事故，甚至导致财产损毁、人身伤亡。因驾驶员未遵守本手册、相关协议和配套文件而导致的财产损毁、人身伤亡等，除法律法规另有强制性规定外，比亚迪汽车不承担责任。\\n\\n系统不能取代驾驶员的专注驾驶和准确判断。使用系统功能时，驾驶员应确保遵守当地法律法规使用车辆，并应始终手握转向盘，并保持警惕，密切注意周围各种危险情形，必要时及时人工干预或控制车辆，确保安全驾驶，否则可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n本手册中所使用的控制车辆及相关表述，意在通过简练的语言传达驾驶员使用系统过程中的相关事项。但在系统运行过程中，驾驶员始终是车辆的唯一驾驶主体，应全程对车辆和系统运行情况、车辆外部环境和相关目标进行持续监测和必要响应，并在必要时立即通过本手册中规定的操作方式人工干预和控制车辆行驶，确保行车安全，否则可能会引发事故，甚至导致财产损毁、人身伤亡。\\n\\n驾驶员应以自己的名义注册、登录使用车主账号或车主授权账号以及使用驾驶辅助系统软件服务。系统将以注册人为账号所有人。驾驶员应妥善保管账号信息，因未按要求使用账号、被他人登录驾驶员本人\\n\\n[neighbor chunk_id=han_p175_c008 page=175]\\n警告(续)\\n\\n账号，可能造成驾驶员的个人信息泄露、财产损失，也可能影响车辆安全，造成严重的人身损伤乃至伤亡。因不当使用账号、被他人登录账号所引起的全部责任由驾驶员承担。\\n\\n将车辆交给他人使用时，驾驶员务必退出自己的账号，并督促对方登录其个人账号使用车辆，否则可能会造成驾驶员的个人信息泄露、财产损失，也可能影响车辆安全，造成严重的人身损伤乃至伤亡。因驾驶员外借账号而导致的伤害和损失，由驾驶员自行承担，比亚迪汽车不承担责任。\\n\\n驾驶员应遵守当地的法律法规要求合法使用驾驶辅助系统功能，不得在系统上添加功能、App、工具等进行任何不当或违反法律的行为，也不得违法收集和使用个人信息与地理信息数据。比亚迪汽车对用户的任何滥用、错误使用或未经授权修改系统功能服务导致的违法行为不承担任何责任，并有权临时关停系统功能，乃至终止向用户提供服务，并有权对用户的违法行为所涉及到的数据进行留存，以便作为证据提供给具有依法调取程序的机构。\", \"chunk_id\": \"han_p174_c007\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"警告\", \"page_number_end\": 174, \"context_chunk_ids\": [\"han_p174_c006\", \"han_p174_c007\", \"han_p175_c008\"], \"page_number_start\": 174}, {\"score\": 0.021311475409836068, \"content\": \"[neighbor chunk_id=han_p326_c040 page=326]\\n注意\\n\\nOTA 升级过程中请勿移动车辆。\\n\\nOTA升级需确保车辆停靠在安全区域，挡位处于\\\"P\\\"挡，且移动通信网络处于连接正常状态下方可进行。\\n\\nOTA升级过程中车辆不能进行充电与放电，请确保车辆电量充足再进行升级。\\n\\nOTA升级前或升级过程中，请勿在车载诊断接口处安装任何第三方设备。\\n\\nOTA升级过程中车辆将无法行驶，除车辆解闭锁/室内灯开关/紧急告警灯/车窗开关功能外，其他车辆功能将被暂时禁用。\\n\\n一如果OTA升级失败，请重试升级，若重试升级仍失败，请您拨打比亚迪汽车官方客服电话或联系比亚迪汽车授权服务店处理。\\n\\n一如果OTA升级失败，仪表上故障警告灯（如驻车制动故障警告灯、ABS故障警告灯、动力系统故障警告灯等）异常点亮，请勿驾驶车辆，并尽快联系比亚迪汽车授权服务店检查车辆状态。\\n\\n[seed chunk_id=han_p326_c041 page=326-327]\\n温馨提示\\n\\n升级操作路径可能与车机系统、手机 App实际路径略有出入，具体请以实际路径为准。\\n\\nOTA升级完成后，车辆部分功能可能会发生变更，您可以通过点击新版本号查看升级说明，再次了解更新的功能。\\n\\n智能语音\\n\\n■智能语音助手支持车主语音控制导航、音乐、空调、电话等操作。只需轻声一唤：“你好小迪”，即可启动智能语音助手，识别并执行您的指令。支持连续对话，无需重复唤醒；随时打断，即刻响应。\\n\\n车主可通过点击方向盘上的按键 或点击桌面语音图标 或语音唤醒词“你好小迪”唤醒语音助手。\\n\\n用户唤醒智能语音系统后，智能语音助手开始识别用户的语音指令。\\n\\n车辆控制功能：支持语音控制空调、车窗、天窗、遮阳帘、氛围灯、座椅通风、座椅加热、无线充电等功能。只需一声令下，“打开天窗”、“空调调到27 度”，即可轻松实现控制。\\n\\n音视频类功能：支持播放音乐、视频、儿童故事、动画片、有声小说、新闻、广播等。通过语音控制多媒体应用的播放、暂停、上一首、下一首、快进、快退、放一首歌、循环播放、查看歌词等即可轻松实现控制。\\n\\n[neighbor chunk_id=han_p327_c042 page=327]\\n其他应用\\n\\n地图\\n\\n地图支持定位、搜索、路径规划、导航、手车互联等功能。\\n\\n地图整体界面的交互控件主要设计在左半屏，更符合驾车使用场景；您可以方便快捷的查找附近的充电站、停车场等兴趣点。\\n\\n外部应用\\n\\n本多媒体系统为安卓开发系统，可进行外部应用程序的安装和使用。\\n\\n安装和使用：\\n\\n1. 下载好您所需要的应用程序；\\n\\n2. 点击应用程序文件，选择“允许安装外部来源应用”，进行应用安装；\\n\\n3. 安装完成后，您可在应用列表界面找到您安装好的应用，点击使用。\\n\\n注意\\n\\n推荐优先安装“应用市场”内的应用；\\n\\n外部应用未与本车机系统适配，使用过程中可能存在卡顿、不兼容等情况，请谨慎安装和使用；\\n\\n一建议安装发行方官方认证的应用程序，未经应用发行方官方认证的应用程序，可能侵犯发行方相关权利或损害您个人相关利益，或无法正常使用，请谨慎安装和使用；\\n\\n系统内存有限，如安装大量应用程序，可能导致系统卡顿，请谨慎安装和使用；\", \"chunk_id\": \"han_p326_c041\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"327\", \"context_chunk_ids\": [\"han_p326_c040\", \"han_p326_c041\", \"han_p327_c042\"], \"page_number_start\": \"326\"}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=han_p130_c149 page=130]\\n第1条：\\n功能：照明\\n状态：充电口打开(无电枪连接)\\n点亮状态：白色常亮\\n\\n第2条：\\n功能：充电\\n状态：充放电初始化过程\\n点亮状态：黄色闪烁\\n\\n第3条：\\n功能：充电\\n状态：充电预约中/充电暂停\\n点亮状态：黄色常亮\\n\\n第4条：\\n功能：充电\\n状态：充电中\\n点亮状态：绿色闪烁\\n\\n第5条：\\n功能：充电\\n状态：充电完成\\n点亮状态：绿色常亮\\n\\n第6条：\\n功能：放电\\n状态：放电中\\n点亮状态：蓝色闪烁\\n\\n第7条：\\n功能：故障\\n状态：充放电故障\\n点亮状态：红色常亮\\n\\n[seed chunk_id=han_p130_c150 page=130-131]\\n智慧充电(仅限交流充电）\\n\\n本车支持桌面应用图标、车辆设置、智能语音打开充电设置界面：\\n\\n通过多媒体应用列表的“智慧充电”App 进入设置界面；\\n\\n通过中控屏→设置 →能量→充电与放电设置进入“智慧充电”设置界面；\\n\\n通过呼唤“你好小迪，打开智慧/预约充电”、“你好小迪，我要智慧/预约充电”、“你好小迪，请帮我打开智慧/预约充电”快速进入。\\n\\n本车可通过点击返回键 /home 键 或智能语音退出智慧充电页面：\\n\\n通过呼唤“你好小迪，关闭智慧/预约充电”、“你好小迪，退出智慧/预约充电”快速退出。\\n\\n[neighbor chunk_id=han_p131_c151 page=131-132]\\n预约充电操作指南\\n\\n①预约充电开关\\n\\n②充电开始、结束时间*\\n\\n③重复周期\\n\\n④切换到预约用车模式*\\n\\n⑤设置\\n\\n出厂时车辆默认设置为立即充电，即预约充电开关关闭。\\n\\n如需进行预约充电，点击预约充电开启按钮①，设置充电开始、结束时间②和重复周期③，点击“确定”保存设置。\\n\\n–预约设置成功后，若您连接充电枪或按下电源按键使车辆下电，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n预约用车设置页面 *\\n\\n①预约用车开关\\n\\n②预约用车时间\\n\\n③重复周期\\n\\n④电价优惠时段\\n\\n⑤切换到预约充电模式\\n\\n如需进行预约用车，点击预约用车开启按钮①，设置用车时间②，重复周期③和电价优惠时段④，点击“确定”保存设置。\\n\\n预约设置成功后，若您连接充电枪，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n用户可点击智慧充电“ ”图标，在“预约充电提醒”中关闭连接充电枪提醒及下电提醒弹框。\", \"chunk_id\": \"han_p130_c150\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"智慧充电(仅限交流充电）\", \"page_number_end\": 131, \"context_chunk_ids\": [\"han_p130_c149\", \"han_p130_c150\", \"han_p131_c151\"], \"page_number_start\": 130}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=han_p409_c150 page=409-410]\\nE\\n\\n儿童锁 84\\n\\nF\\n\\n发动机机油 …… 379 防盗系统 …… 44 防滑链 …… 172 放电装置* …… 136\\n\\nG\\n\\n功能定义 331\\n\\nH\\n\\n后排头枕调节*....93 换挡操纵机构....164\\n\\nJ\\n\\n机械钥匙闭锁/解锁 ..... 72 驾驶安全系统 ..... 308 驾驶车辆 ..... 158 驾驶要领 ..... 170 驾驶员监测辅助系统* ..... 302 交通灯路口通行 (TLC) ..... 227 紧急告警灯开关 ..... 111 警告标签 ..... 405\\n\\nK\\n\\n空调操作界面 …… 329 空调控制板、汽车音响、仪表板、控制面板和开关 …… 370 空调面板 …… 329 空调设置项 …… 338 空调系统 …… 380\\n\\nL\\n\\n冷却液的选择 …… 377 里程切换开关 …… 110 绿净系统简介 …… 335 轮胎 …… 382\\n\\nM\\n\\n盲区监测(BSD)....287 门窗....369 磨合期....145\\n\\n[seed chunk_id=han_p410_c151 page=410]\\nN\\n\\n内部清洁 368\\n\\nP\\n\\n票据盒 .... 347 泊车辅助(APA)* .... 239\\n\\nQ\\n\\n漆面保养提示 …… 366 启动车辆 …… 156 前舱盖的开启 …… 376 前风窗玻璃刮水器与洗涤器 …… 101 前排杯托 …… 345 前排头枕调节* …… 92 前室内灯开关 …… 115 全景影像系统 …… 236\\n\\nR\\n\\n燃油选用 .... 146 如果车辆需要牵引 .... 394 如果轮胎漏气 .... 396 如果在驾驶中发动机启动失败 .390 如果智能钥匙电池电量耗尽 .... 388 如何节省燃油并延长车辆的使用寿命 .... 149\\n\\n[neighbor chunk_id=han_p411_c152 page=411]\\nS\\n\\n哨兵模式* 49 使用安全带 19 手动调节内后视镜 104 手工洗车 367 手机无线充电* 351 双模系统工作模式简介 37\\n\\nT\\n\\n胎压监测 …… 306 抬头显示* …… 305 天窗 …… 111 天窗保养* …… 375\\n\\nW\\n\\n微波窗口 407 文件袋 347\\n\\nX\\n\\n洗涤器 378 下车泊入* 257\\n\\nY\\n\\n眼镜盒* 346 遥控泊车辅助(RPA) 249 一般充电故障诊断 122 一氧化碳中毒的危险性 153 用车建议 145 雨刮 102 雨刮器刮片 381 雨季洪涝防止车辆进水 153 预防火灾 151\\n\\n运载行李 150\\n\\nZ\\n\\n杂物箱 …… 344 遮阳板 …… 348 整车拖曳 …… 146 整车应急机械锁止 …… 81 指示灯/警告灯 …… 53 制动系统 …… 378 智慧充电(仅限交流充电) …… 130 智能进入和智能启动系统 …… 82 中央扶手置物盒 …… 344 驻车辅助系统(PDC&SDW) …… 232 转向盘开关组 …… 95 转向助力模式设置 …… 99 自动防眩目内后视镜* …… 105 自动洗车 …… 368 自动驻车 …… 169 自行保养注意事项 …… 372 组合灯 …… 374\", \"chunk_id\": \"han_p410_c151\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"N\", \"page_number_end\": \"410\", \"context_chunk_ids\": [\"han_p409_c150\", \"han_p410_c151\", \"han_p411_c152\"], \"page_number_start\": \"410\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=han_p365_c087 page=365-366]\\n警告\\n\\n请勿继续驾驶未经检查的车辆，否则将造成严重的车辆损坏和人身伤害。\\n\\n车辆防腐蚀\\n\\n引起车辆腐蚀最常见的原因是：\\n\\n在车辆下面积满盐碱、灰尘和湿气。\\n\\n高湿度环境或者车辆的某些部位长期处于潮湿高温环境。\\n\\n因轻微碰撞或由于石块和砂砾而划破油漆层或底层。\\n\\n为防止车辆腐蚀，应遵守以下准则：\\n\\n勤于洗车。\\n\\n如果冬季在含有盐碱的道路上行驶，或住在海边，将车辆的着陆部分至少每月冲洗一次，用高压水枪或者蒸汽清洗底盘和轮罩，以减少腐蚀，冬季过后，将车辆底盘彻底清洗。\\n\\n检查车身的油漆和装饰件。\\n\\n如果发现油漆层有任何碎片或裂纹，应立刻修补，以防止腐蚀。如果碎片或裂纹从金属面上剥落，建议到比亚迪汽车授权服务店修复。\\n\\n检查车厢内部。\\n\\n水分和灰尘长时间堆积在地毯的下面会导致腐蚀，应经常检查地毯的下面，确保这些部位干燥。\\n\\n运输化学物品、清洁剂、化肥、盐等物品时，应特别小心，须采用适当的容器进行运输。如果发现有溅出或渗漏，请立刻清洗干净并保持干燥。\\n\\n使用挡泥板。\\n\\n如在盐碱地区或砾石路面行驶，挡泥板能保护车辆。挡泥板尺寸越大、越接近地面越好。\\n\\n将车辆停在充分通风且干燥的地方。\\n\\n[seed chunk_id=han_p366_c088 page=366-367]\\n漆面保养提示\\n\\n及时清洗车辆。\\n\\n漆面若无明显划痕，不要轻易进行二次喷漆，以防止漆色不合或结合不好。\\n\\n车辆长期停放，应停在车库或通风良好的地方，冬天应用专用车身罩覆盖。临时停放时，要选择阴凉的地方。\\n\\n防止对车身漆膜进行强烈冲击、磕碰或划痕。如发现漆面有伤痕、凹陷或脱落应及时进行修补，最好是到专业的汽车美容店修补。\\n\\n请勿用带有油污的脏手触摸车身漆面或用油抹布随意擦洗漆面，请勿将粘有油污的工具或含有有机溶剂的擦布置于车身上，以免产生化学反应。\\n\\n–每月一次或者当车身表面不能很好地抗水时，须对漆面进行上蜡保护并定期(每季度一次)到汽车专业美容店进行养护，及时恢复车身漆面的亮丽光泽。\\n\\n采用优质的抛光剂和车蜡。如果车身的抛光已严重风化，使用和车蜡分开的汽车清洁抛光剂。仔细遵守制造厂商的说明以及预防措施，镀铬面和油漆面一样要抛光和打蜡。\\n\\n[neighbor chunk_id=han_p367_c089 page=367-368]\\n注意\\n\\n如果车辆被重新喷油漆，并且停放在高温的油漆上蜡工作间中，须取下车辆的塑料保险杠，高温将损坏保险杠。\\n\\n车辆清洗\\n\\n以下情况将引起油漆层的剥落或导致车身和零件腐蚀，须及时清洗车辆：\\n\\n在沿海一带行驶时。\\n\\n在撒有防冻剂的路面上行驶时。\\n\\n在粘有煤焦油道路上行驶时。\\n\\n树脂、鸟粪和昆虫尸体粘在车辆上时。\\n\\n在含有大量烟尘、煤灰、灰尘、铁屑或化学物质的地区行驶时。\\n\\n车辆被尘埃和泥浆明显弄脏时。\\n\\n雨后。\\n\\n手工洗车\\n\\n在阴凉处，等待车辆充分降温后，再清洗车辆。\\n\\n1. 用水管将松动的脏污冲掉，将车辆底部和车轮凹陷部的所有泥浆或道路盐碱全部冲掉。\\n\\n2. 用中性洗车剂清洗车辆，洗车剂的混合应根据制造厂的说明进行。用软布浸上清洁液，应顺着水流的方向自上而下轻轻地擦拭，请勿画圈和横向擦拭。\\n\\n3. 充分冲洗——洗车剂风干后会形成斑纹。在高温天气洗车后，必须正确地用清水将各部分冲洗干净。\\n\\n4. 为了防止留有水迹，须用干净的软毛巾将车身抹干，避免用力擦或按压，否则会擦伤油漆面。\", \"chunk_id\": \"han_p366_c088\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"漆面保养提示\", \"page_number_end\": 367, \"context_chunk_ids\": [\"han_p365_c087\", \"han_p366_c088\", \"han_p367_c089\"], \"page_number_start\": 366}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=han_p412_c153 page=412]\\n缩略语\\n\\n[seed chunk_id=han_p412_c154 page=412]\\n第1条：\\n术语：EDR\\n全称：汽车事件数据记录系统\\n\\n第2条：\\n术语：NFC\\n全称：近场通信\\n\\n第3条：\\n术语：EPB\\n全称：电子驻车\\n\\n第4条：\\n术语：ACC\\n全称：自适应巡航\\n\\n第5条：\\n术语：HNOA\\n全称：高快领航\\n\\n第6条：\\n术语：FCW\\n全称：前向碰撞提醒\\n\\n第7条：\\n术语：BSD\\n全称：盲区监测\\n\\n第8条：\\n术语：RCTB\\n全称：后方横向碰撞制动\\n\\n第9条：\\n术语：AVAS\\n全称：低速提示音系统\\n\\n第10条：\\n术语：TCS\\n全称：牵引力控制系统\\n\\n第11条：\\n术语：HBA\\n全称：液压制动辅助系统\\n\\n第12条：\\n术语：PM2.5\\n全称：绿净系统\\n\\n第13条：\\n术语：MIN\\n全称：最小值\", \"chunk_id\": \"han_p412_c154\", \"chunk_type\": \"table\", \"source_file\": \"han.pdf\", \"section_title\": \"缩略语\", \"page_number_end\": \"412\", \"context_chunk_ids\": [\"han_p412_c153\", \"han_p412_c154\"], \"page_number_start\": \"412\"}]',5,14173,1,NULL,'2026-06-26 17:41:21'),(38,1,NULL,NULL,NULL,'我的车辆怎么充电？','根据《用户手册》资料，您的车辆支持**交流充电**与**直流充电**两种模式。具体操作步骤及安全注意事项如下：\n\n### 🔌 一、交流充电（家用便携式/公共交流桩）\n1. **开盖**：打开车辆右侧充电口盖及充电口保护盖。\n2. **连接供电端**：使用充电盒可跳过此步；若使用未配备充电枪的单相交流桩，需使用七转七将供电插头连接至充电桩插座。\n3. **连接车辆**：将充电枪插入车辆充电口，确认可靠锁止。\n4. **启动充电**：公开放置有设置选项的充电桩需刷卡或扫码（家用便携/无选项桩可跳过）。\n5. **充电中**：组合仪表充电连接指示灯点亮，显示充电参数与画面。\n**🔚 停止操作**：充电结束或手动提前结束 → （若电锁防盗模式为“启用”，需先按钥匙解锁或门把手微动开关）→ 按下充电枪机械按钮拔出 → 断开供电插头（若有）→ 关闭充电口保护盖与车辆充电口盖 → 妥善收纳设备。\n\n### ⚡ 二、直流充电（公共直流快充桩）\n1. **开盖**：整车解锁，电源挡位建议退至“OFF”，按压车辆右侧充电口盖使其自动弹开。\n2. **开保护盖**：打开直流充电口保护盖，确保枪头与插座端部无异物。\n3. **连接车辆**：将充电桩充电枪插入直流充电口并可靠锁止。\n4. **启动充电**：按充电桩设备指导步骤操作启动。\n5. **充电中**：组合仪表充电连接指示灯点亮，显示充电画面与参数。\n**🔚 停止操作**：充电结束或手动提前结束 → 按下直流充电枪上的机械锁止按钮拔出枪 → 关闭充电口保护盖与车辆充电口盖 → 将充电枪放回充电桩指定位置。\n\n### ⚠️ 核心注意事项与安全提示\n- **挡位与启动安全**：充电前建议将电源挡位退至`OFF`，充电期间车辆无法进入`OK`挡。启动车辆前，必须确认充电设备已完全拔开。\n- **插拔规范**：严禁在电锁锁止状态强行插枪；充电过程中请勿晃动充电枪；若枪体或车口因天气冻住，请充分解冻后再操作，**切勿强行拔枪或开盖**。\n- **环境与效能**：建议停放在通风处，车头半米内勿遮挡；充电时空调可降低充电功率，高温直流充电时建议关闭空调以保证充电效率。\n- **电池管理**：电量较低时不可使用预约充电；直流充电日常建议充至80%~90%即可；车辆长期停放需定期充放电维护。\n- **异常拔枪处理**：若充电结束后无法拔枪，可尝试多次整车解锁；仍无法拔出时，可参考后备箱右侧的交流充电应急解锁拉绳进行操作。\n> 📢 **安全提醒**：充电涉及高压 electrical 系统，请务必严格遵守上述操作步骤。若遇设备报警、充电中断、枪体卡滞或任何不确定情况，请**立即停止操作，以车辆仪表盘实际提示为准，并及时联系充电站客服或比亚迪官方授权服务店**，切勿自行拆解或带载断电。','xia.pdf','[{\"score\": 0.05224748810153358, \"content\": \"[neighbor chunk_id=xia_p151_c186 page=151]\\n温馨提示(续)\\n\\n若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n\\n电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n–为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n\\n使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[seed chunk_id=xia_p151_c187 page=151-152]\\n温馨提示\\n\\n使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n\\n也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n若使用充电盒为车辆充电，则无需此步操作。\\n\\n■若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n\\n■若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七*，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置：\\n\\n对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n\\n■对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n[neighbor chunk_id=xia_p152_c188 page=152-153]\\n温馨提示\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n此时可以通过多媒体设置预约充电，设置流程详见“智慧充电”功能设置。\\n\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 断开供电插头：\\n\\n若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n\\n若使用七转七，建议先拔出充电枪，后拔出供电插头。\\n\\n若使用充电盒为车辆充电，则无需此步操作。\\n\\n4. 关闭交流充电口保护盖和车辆充电口盖(参照家用便携式交流充电)。\\n\\n5. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n若使用七转七，将其整理好，并妥善放置。\", \"chunk_id\": \"xia_p151_c187\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": 152, \"context_chunk_ids\": [\"xia_p151_c186\", \"xia_p151_c187\", \"xia_p152_c188\"], \"page_number_start\": 151}, {\"score\": 0.0509371747332813, \"content\": \"[neighbor chunk_id=xia_p153_c189 page=153]\\n警告\\n\\n七转七禁止跌落，严禁直接拉扯线缆移动此设备，移动时需轻拿轻放，使用后请将设备存放在阴凉处。\\n\\n充电桩直流充电*\\n\\n使用充电桩直流充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n使用公共场所的直流充电桩为车辆充电，直流充电桩一般安装在特定的充电站。\\n\\n设备规格：请查看充电机相关说明。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=xia_p153_c190 page=153-154]\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动弹开。\\n\\n2. 打开直流充电口保护盖：\\n\\n–打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n将充电桩的充电枪连接至车辆直流充电口，并可靠锁止。\\n\\n4. 启动充电：\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n[neighbor chunk_id=xia_p154_c191 page=154]\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n■直流充电桩设置提前结束或充满后自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备：\\n\\n■直流充电桩充电结束后，整理充电设备，并妥善放置，将充电枪放到直流充电桩的指定位置。\\n\\n注意\\n\\n充完电后，若充电枪不能拔出，请及时联系充电站客服人员。\\n\\n高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\", \"chunk_id\": \"xia_p153_c190\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电操作指南\", \"page_number_end\": 154, \"context_chunk_ids\": [\"xia_p153_c189\", \"xia_p153_c190\", \"xia_p154_c191\"], \"page_number_start\": 153}, {\"score\": 0.029621489621489624, \"content\": \"[neighbor chunk_id=xia_p150_c185 page=150]\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n车辆电量充满会自动结束充电。\\n\\n如需提前结束充电直接进入下一步。\\n\\n2. 断开充电口连接：\\n\\n■若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n\\n■若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n温馨提示\\n\\n整车解锁，按钥匙解锁按钮(OFF 挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n\\n启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n\\n电锁工作模式可通过多媒体设置，设置步骤详见“充电口电锁控制功能”设置。\\n\\n[seed chunk_id=xia_p151_c186 page=151]\\n温馨提示(续)\\n\\n若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照充电口电锁控制中充电口应急解锁。\\n\\n电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口保护盖和车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n–为避免造成严重人身伤害，请仔细阅读并遵守本章节充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守本章节充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒*\\n\\n单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息请参见充电盒说明书。\\n\\n使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩\\n\\n使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n[neighbor chunk_id=xia_p151_c187 page=151-152]\\n温馨提示\\n\\n使用公共场所的交流充电桩为车辆充电。交流充电桩通常安装在大型超市、购物广场及停车场等公共场所。\\n\\n也可使用比亚迪三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n2. 连接供电口端：\\n\\n若使用充电盒为车辆充电，则无需此步操作。\\n\\n■若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n\\n■若使用单相交流充电桩且充电桩未配备充电枪，则需使用七转七*，使用时需将供电插头连接至充电桩上供电插座。\\n\\n3. 连接车辆接口：\\n\\n将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置：\\n\\n对于单相交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n\\n■对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯 点亮。\", \"chunk_id\": \"xia_p151_c186\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"温馨提示(续)\", \"page_number_end\": 151, \"context_chunk_ids\": [\"xia_p150_c185\", \"xia_p151_c186\", \"xia_p151_c187\"], \"page_number_start\": 151}, {\"score\": 0.020967741935483872, \"content\": \"[neighbor chunk_id=xia_p350_c075 page=350]\\nK 歌*\\n\\n用户按下麦克风开机键，待点亮“K歌小程序”，即可开始体验K歌功能。（麦克风信息请参见“麦克风*”）\\n\\n打开 K歌App，开始体验K歌，在K歌系统界面可以进行麦克风音量调节、混响调节和音效选择。\\n\\n进入 K 歌 App 后，点击悬浮麦克风图标或麦克风按键(功能键)，在比亚迪 K 歌系统弹窗上调节音量大小及混响大小。如果想要体验更好的K歌效果，建议将整车的系统音量调节至25以上；\\n\\n在比亚迪 K 歌系统弹窗上选择音效，支持录音棚、KTV、音乐厅、原声四种音效，点击您想体验的音效场景按键，麦克风自动完成切换。\\n\\n[seed chunk_id=xia_p350_c076 page=350-351]\\n我的车*\\n\\n我的车分为车辆控制、驾驶行为和健康服务模块。\\n\\n车辆控制包括快捷控制和 3D 车模控制*。\\n\\n快捷控制：用户可以通过左边快捷栏及底部卡片入口快捷功能一键控制。\\n\\n3D 车模控制：用户可点击车模热点区域操作车辆控制功能。包含遮阳帘、车窗、后尾门等功能控制。\\n\\n车身换色功能：用户点击换肤功能图标，可切换车身颜色。\\n\\n车辆控制自定义功能：用户可点击更多查看全部快捷功能，长按快捷功能拖动可互换快捷功能位置。\\n\\n温馨提示\\n\\n一应用搭载情况以车辆实际配置为准。\\n\\n[neighbor chunk_id=xia_p351_c077 page=351]\\n其他应用\\n\\n定制应用——地图\\n\\n地图支持定位、搜索、路径规划、导航、手车互联、组队等功能。\\n\\n地图整体界面的交互控件主要设计在左半屏，更符合驾车使用场景。您可以方便快捷的查找附近的充电站、停车场等兴趣点。\\n\\n外部应用\\n\\n本多媒体系统为安卓开发系统，可进行外部应用程序的安装和使用。\\n\\n外部应用安装和使用：\\n\\n1. 下载好您所需要的应用程序；\\n\\n5\\n\\n2. 点击应用程序文件，选择允许安装外部来源的应用后进行安装；\\n\\n3. 当安装完成后，您在应用列表找到已安装好的应用，点击即可使用。\\n\\n注意\\n\\n推荐优先按照“应用市场”内的应用；\\n\\n外部应用未与本车机系统适配，使用过程中可能存在卡顿、不兼容等情况，请谨慎安装和使用；\\n\\n建议安装发行方官方认证的应用程序，未经应用发行方官方认证的应用程序，可能侵犯发行方相关权利或损害您个人相关利益，或无法正常使用，请谨慎安装和使用；\\n\\n安装大量不必要的软件，可能会导致系统卡顿或不能使用。请谨慎安装和使用。\", \"chunk_id\": \"xia_p350_c076\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"我的车*\", \"page_number_end\": 351, \"context_chunk_ids\": [\"xia_p350_c075\", \"xia_p350_c076\", \"xia_p351_c077\"], \"page_number_start\": 350}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=xia_p72_c078 page=72]\\nNFC 钥匙*\\n\\nNFC 钥匙简介\\n\\nNFC钥匙是“比亚迪”App为用户提供的一种可以将手机或可穿戴设备注册为车钥匙，可实现解闭锁车门及启动车辆的功能。\\n\\n■您可以使用支持车钥匙功能的手机或可穿戴设备，通过比亚迪NFC钥匙添加流程将手机或可穿戴设备注册为车钥匙，手机或可穿戴设备即可当车钥匙使用。\\n\\n■添加手机NFC钥匙前请确认以下条件是否满足：\\n\\n该手机在支持的机型列表中；\\n\\n该手机系统 NFC 功能开启；\\n\\nAndroid 手机 NFC设置的默认应用为“钱包”；\\n\\n该 Android 手机钱包账号或 iPhone Apple ID 账号已登录；\\n\\n比亚迪App账号已登录，且已完成比亚迪车主认证；\\n\\n手机与车辆网络状态良好。\\n\\n[seed chunk_id=xia_p72_c079 page=72-73]\\n手机 NFC 钥匙添加入口\\n\\n配置NFC钥匙的车辆，开通并登录App账号后，可进入\\\\mathsf { \\\\Omega } ^ { \\\\mathsf { \\\\tiny { u } } } { \\\\mathsf { N } } { \\\\mathsf { F } } { \\\\mathsf { C } } ^ { \\\\mathsf { \\\\tiny { v } } }钥匙管理页，按照App指引操作，完成添加。\\n\\n–\\\\mathsf { \\\\Omega } ^ { \\\\mathrm { * } } \\\\mathsf { N F C } ^ { \\\\mathrm { * } }钥匙管理页进入路径如下：\\n\\n在首页点击车辆\\\\mathsf { \\\\Omega } ^ { \\\\ast } \\\\mathsf { N F C } ^ { \\\\prime \\\\prime }图标，进入\\\\mathsf { \\\\Omega } ^ { \\\\ast } { \\\\mathsf { N F C } } ^ { \\\\prime \\\\prime }钥匙管理页。\\n\\n选择“我的”页点击“我的车”，点击“NFC 数字钥匙 ”进入钥匙管理页。\\n\\n[neighbor chunk_id=xia_p73_c080 page=73]\\n开通手机NFC 钥匙*\\n\\nAndroid 手机用户按照App指引操作将手机添加为车钥匙。每辆车最多支持开通9 个Android NFC 钥匙(包括车主/可穿戴设备钥匙和授权钥匙)。\\n\\niPhone 用户需按照App指引操作将手机添加为车钥匙。最多支持开通1把车主钥匙。\\n\\n手机 NFC 钥匙使用*\\n\\n使用手机NFC钥匙前请确认以下条件是否满足：\\n\\n该手机已成功添加NFC钥匙；\\n\\n该手机系统 NFC功能开启；\\n\\n该手机默认刷卡设置为车钥匙；\\n\\n部分车型仅熄火状态下可用，具体功能以实际车型配置为准。\\n\\n具有解锁权限*的手机车钥匙，将手机背面顶部贴近车辆外后视镜读卡器感应区，可以解闭锁车门。\\n\\n具有解锁与驾驶权限*的手机车钥匙，将手机放置在车辆NFC标识处，可以启动车辆。标识位置具体以仪表提示为准，如需帮助可咨询服务店或拨打客服热线。\", \"chunk_id\": \"xia_p72_c079\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"手机 NFC 钥匙添加入口\", \"page_number_end\": 73, \"context_chunk_ids\": [\"xia_p72_c078\", \"xia_p72_c079\", \"xia_p73_c080\"], \"page_number_start\": 72}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=xia_p165_c208 page=165]\\n如上面表格，车辆若处于2/3/4/6状态下，用户除上述解锁操作外，可通过按充电枪按钮进行解锁拔枪，但此操作有可能影响充电口或充电枪的使用寿命，为应急操作，不建议频繁进行此操作。\\n\\n温馨提示\\n\\n解锁充电枪后，2min 内可拔枪，2min后电锁会重新闭合。\\n\\n锁车后充满电，在“停用”模式下电锁会自动解开，在“启用/智能”模式下电锁须按上述方法手动解开。\\n\\n为保证充电完成后正常行车，拔枪后请关闭充电口盖。\\n\\n交流充电口应急解锁\\n\\n当电锁出现故障，导致交流充电枪不能拔出时，可通过使用应急解锁拔出交流充电枪。\\n\\n电锁位于后备箱右侧。轻拉应急解锁拉绳即可解锁充电枪。\\n\\n解锁完成后复位拉索卡扣。\\n\\n温馨提示\\n\\n若上述功能异常或失效，建议联系比亚迪汽车授权服务店。\\n\\n[seed chunk_id=xia_p166_c209 page=166]\\n动力电池\\n\\n车辆主要动力源之一是动力电池，位于车辆地板下，可进行多次反复充电。通过外接电源给动力电池进行充电的主要方式为：家用便携式充电、交流充电桩充电、直流充电桩充电*，车辆在制动、滑行或发动机开启时，亦可通过电机为动力电池充电。\\n\\n注意\\n\\n动力电池位于车身底部，如遇崎岖路面，请谨慎驾驶。\\n\\n温馨提示\\n\\n车辆上“ON”挡或“OK”挡时高压线路都将处于连通状态。\\n\\n对于新车在动力电池状态正常的情况下，由于驾驶习惯、路况、气温和用电设备开启与否等不同，纯电里程会有所增减。\\n\\n为了延长电池使用寿命以及保证电池安全，电池系统在充电至高电量时会切换至涓流充电模式，充电时间可能会加长。\\n\\n一由于电池本身化学特性所致，已使用一段时间的车辆，电池容量存在自然衰减现象，其纯电里程会有所减少。当您发现爱车纯电里程有所减少时，可以到比亚迪汽车授权服务店进行检查。店端检查可以确认纯电里程的减少是否属于正常衰减。\\n\\n[neighbor chunk_id=xia_p166_c210 page=166-167]\\n动力电池保养\\n\\n为了使电池处于最佳状态，请定期使用交流充电连接装置为电池充满电，建议每周至少充满一次。\\n\\n当车辆不使用超过7天时，为延长其使用寿命，建议电池电量保持在40%~60% SOC 区间内。超过 3个月不使用时，须先充电至100%再放电至 40%~60% SOC，以避免电池性能降低，甚至损坏。\\n\\n动力电池低温加热功能\\n\\n当外界温度较低时，动力电池加热系统将启动并加热电池，提升低温充电速度和保证整车动力性及续航里程。\", \"chunk_id\": \"xia_p166_c209\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"动力电池\", \"page_number_end\": \"166\", \"context_chunk_ids\": [\"xia_p165_c208\", \"xia_p166_c209\", \"xia_p166_c210\"], \"page_number_start\": \"166\"}, {\"score\": 0.017741935483870968, \"content\": \"[neighbor chunk_id=xia_p144_c172 page=144]\\n充电结束后警告事项\\n\\n车辆行驶前，请确保拔出充放电设备，并关闭充电口盖。\\n\\n充电注意事项\\n\\n任何电源挡位下都可以进行交流充电、直流充电*，为保证安全，充电前，建议退电至“OFF”挡，充电时车辆无法进入“OK”挡。\\n\\n当外部电网短时间断电并再次供电时，原装充电设备会自动重新启动充电，无需重新连接充电设备。\\n\\n在未充满电的情况下，需要提前结束充电，请通过充电设备设置提前结束充电，尽量不要带载断电。\\n\\n如果车辆长时间不使用，建议至少 1个月充电一次。\\n\\n[seed chunk_id=xia_p144_c173 page=144-145]\\n充电设备注意事项\\n\\n为了避免对充电设备及车辆造成损坏，注意以下预防事项：\\n\\n启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n\\n请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n\\n充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n\\n充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n\\n请勿在电锁锁止状态强行插入充电枪。\\n\\n应小心使用充放电设备：\\n\\n充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n\\n请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n\\n请勿在温度高于50℃的环境下存放或者使用充电设备。\\n\\n请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n不建议使用外加的电线或者适配器/转接器。\\n\\n[neighbor chunk_id=xia_p145_c174 page=145]\\n充电前注意事项\\n\\n当充电口盖未解锁时，请勿强行开启充电口盖。\\n\\n先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n\\n当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n充电时建议人员不要停留在车辆内。\\n\\n充电时空调可正常使用，但会降低充电功率。\\n\\n建议将车辆停放在通风处，车头半米内请勿遮挡。\\n\\n当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n\\n电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n\\n充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n\\n在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\", \"chunk_id\": \"xia_p144_c173\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电设备注意事项\", \"page_number_end\": \"145\", \"context_chunk_ids\": [\"xia_p144_c172\", \"xia_p144_c173\", \"xia_p145_c174\"], \"page_number_start\": \"144\"}, {\"score\": 0.01746031746031746, \"content\": \"[neighbor chunk_id=xia_p144_c173 page=144-145]\\n充电设备注意事项\\n\\n为了避免对充电设备及车辆造成损坏，注意以下预防事项：\\n\\n启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n\\n请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n\\n充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n\\n充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n\\n请勿在电锁锁止状态强行插入充电枪。\\n\\n应小心使用充放电设备：\\n\\n充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n\\n请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n\\n请勿在温度高于50℃的环境下存放或者使用充电设备。\\n\\n请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n不建议使用外加的电线或者适配器/转接器。\\n\\n[seed chunk_id=xia_p145_c174 page=145]\\n充电前注意事项\\n\\n当充电口盖未解锁时，请勿强行开启充电口盖。\\n\\n先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n\\n当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n充电时建议人员不要停留在车辆内。\\n\\n充电时空调可正常使用，但会降低充电功率。\\n\\n建议将车辆停放在通风处，车头半米内请勿遮挡。\\n\\n当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n\\n电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n\\n充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n\\n在直流充电*时，建议充到 80%~90%即可，若时间允许可充满。\\n\\n[neighbor chunk_id=xia_p146_c175 page=146]\\n146 4-1 充/放电说明\\n\\n充电时，充电连接线不能盘放，会影响散热。\\n\\n电池温度过低或过高时，车辆的充电性能会受到影响：\\n\\n低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n\\n北方气温较低区域，建议用户在有供暖的室内进行充电。\\n\\n南方气温较高区域，建议用户在阴凉通风处充电。\\n\\n一组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间存在一定偏差，属于正常现象。\", \"chunk_id\": \"xia_p145_c174\", \"chunk_type\": \"text\", \"source_file\": \"xia.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"145\", \"context_chunk_ids\": [\"xia_p144_c173\", \"xia_p145_c174\", \"xia_p146_c175\"], \"page_number_start\": \"145\"}]',5,27183,1,NULL,'2026-07-04 10:06:19'),(39,1,NULL,NULL,NULL,'汉车型怎么充电？','根据《汉》用户手册，不同充电设备的操作流程有所区别。以下为您梳理标准操作步骤及安全提示：\n\n### ⚠️ 充电安全与通用注意事项\n- **端口检查**：充电前务必确保车辆及充电设备端口内无积水、异物，金属端子无锈蚀。如有异常，**禁止充电**，以免短路或电击。\n- **挡位要求**：为保障安全，充电前建议将车辆电源挡位退至**“OFF”**挡。充电时车辆无法进入“OK”挡。\n- **环境与人员**：建议车辆停放在通风处，勿遮挡进气格栅；充电连接线不可盘放，以免影响散热。充电时建议人员不要停留在车内。\n- **极端情况**：雷雨天气禁止充电或触摸车辆；如发现设备/车辆有异味、冒烟等异常，请**立即停止充电**并联系授权服务店。充电结束后，**严禁用湿手或站在水中拔枪**，以防触电。\n- **实操提示**：充电枪被冻住或电锁锁止时，请勿强行插拔，应先解冻或通过正规解锁流程操作。\n\n---\n\n### 一、家用便携式交流充电\n1. **开充电口盖**：整车解锁，电源挡退至“OFF”，按下充电口盖，其自动弹开。\n2. **开保护盖**：掀开充电枪与车辆交流充电口的保护盖，确保内部无杂物。\n3. **接市电**：将“三转七”设备的供电插头插入符合国标的家用220V 50Hz插座，设备电源指示灯应常亮。\n4. **插车辆端**：按下充电枪黑色锁止按钮，将充电枪对准车辆充电口推入到位后松开按钮。组合仪表充电连接指示灯点亮即开始充电。\n\n### 二、交流充电桩/盒充电\n1. **开盖**：同家用便携方式，解锁车辆并退至“OFF”挡后打开充电口盖及保护盖。\n2. **接电源**：使用充电盒时无需此步；使用配有充电枪的公共桩也无须此步；若需自行连接线缆请按设备指引操作。\n3. **插车辆端**：将充电枪插入车辆充电口并确认可靠锁止。\n4. **启动/设置**：公共桩需按说明刷卡或扫码操作启动。仪表指示灯点亮后，可通过多媒体设置**预约充电**（仅支持交流充电）。\n\n### 三、直流快充充电\n1. **开充电口盖**：整车解锁，电源挡退至“OFF”，按下车辆**右侧**充电口盖，其自动开启。\n2. **开保护盖**：打开直流充电口保护盖，确保端部无障碍物。\n3. **插车辆端**：将充电桩直流充电枪插入车辆充电口，并确认可靠锁止。\n4. **启动**：严格按充电桩屏幕或操作指引启动。仪表指示灯点亮并显示参数即进入快充状态。\n> 💡 *直流充电建议充至80%~90%即可（对电池寿命更友好）；高温环境下快充时，建议关闭座舱空调以保证充电效率。*\n\n---\n\n### 四、停止充电操作\n1. **结束充电**：电量充满将自动停止；如需提前结束，请通过充电设备端设置或中控屏取消。\n2. **断开连接**：\n   - 先确保充电口已解锁。若启用了**电锁防盗功能**，需先按钥匙解锁键或触摸门把手微动开关解除电锁，并在**2分钟内**拔出充电枪，否则电锁会重新锁止。\n   - 按下充电枪上的机械按钮，平稳拔出充电枪。\n3. **收尾工作**：依次关闭直流/交流充电口保护盖及车辆充电口盖，将充电线缆及设备妥善保管。\n\n### 📱 附加功能说明\n- **预约充电**：出厂默认“立即充电”。连接直流枪、电量极低或非比亚迪认证慢充设备时，预约功能可能无效。可在中控屏 `设置 → 能量 → 智慧充电` 中配置。\n- **充电口防盗**：默认处于“停用”状态。需开启时，请前往中控屏 `设置 → 能量 → 充电与放电 → 充电口电锁防盗` 选择“启用”。\n\n> 🔔 **安全提醒**：本回复严格基于您提供的《汉》用户手册资料整理。实际充电过程中，请始终以车辆组合仪表提示、充电设备操作规范为准；如遇拔枪困难、设备报警或故障，请勿强行操作，建议第一时间联系比亚迪汽车授权服务店获取专业支持。','han.pdf','[{\"score\": 0.03870967741935484, \"content\": \"[neighbor chunk_id=han_p123_c141 page=123-124]\\n充电方法\\n\\n充电前检查：\\n\\n确保充电装置没有壳体破裂、电缆磨损、插头生锈或有异物等异常情况。\\n\\n充电连接装置连接松动时，请勿充电。\\n\\n确保充电口内没有水或异物，金属端子没有生锈或者腐蚀。\\n\\n若出现以上情况，禁止充电，否则可能导致短路或电击，引起人身伤害。\\n\\n家用便携式交流充电\\n\\n使用家用便携式交流充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n交流充电连接装置可以将车辆与家用标准 220V 50Hz 10A 单相两极带地插座相连，为车辆充电。\\n\\n–供电插座应选用符合国家标准的家用插座，避免因大功率充电导致线路损坏和保护跳闸，影响其他设备的正常使用。\\n\\n■该装置由符合国家标准的供电插头、充电枪、充电枪保护盖、充电线缆组成，简称三转七。供电插头连接家用标准供电插座，充电枪连接车辆充电口。\\n\\n设备规格：220V AC 50Hz 8A\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n[seed chunk_id=han_p124_c142 page=124-126]\\n温馨提示\\n\\n建议联系比亚迪汽车授权服务店或当地电工，按充电设备要求选择合适的电源。\\n\\n使用三转七充电时，请开启充电防盗。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡电，按下充电口盖，充电口盖自动开启。\\n\\n2. 打开交流充电口保护盖：\\n\\n–打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接供电口端：\\n\\n将三转七的供电插头插入家用插座中，三转七电源指示灯常亮。\\n\\n4. 连接车辆接口：\\n\\n按下充电枪上的锁止按钮(黑色按钮)，将充电枪插入车辆插座中，然后松开锁止按钮。\\n\\n■插好充电枪，组合仪表充电连接指示灯 点亮。三转七充电指示灯会闪烁。\\n\\n充电过程中，仪表显示相关充电参数，同时显示充电画面。\\n\\n此时可以通过多媒体设置预约充电，设置流程详见智慧充电(仅限交流充电）。\\n\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n车辆电量充满会自动结束充电。\\n\\n如需提前结束充电直接进入下一步。\\n\\n2. 断开充电口连接：\\n\\n若电锁工作模式为停用防盗，则直接按下充电枪的机械按钮，拔出充电枪。\\n\\n若电锁工作模式为启用防盗，需要按钥匙解锁按钮或按下门把手上微动开关(钥匙在附近时)，再按下充电枪的机械按钮，拔出充电枪。\\n\\n[neighbor chunk_id=han_p126_c143 page=126]\\n温馨提示\\n\\n整车解锁，按钥匙解锁按钮(“OFF”挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n\\n一启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n\\n电锁工作模式可通过多媒体设置，设置步骤详见充电口电锁防盗功能功能设置。\\n\\n若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照应急解锁。\\n\\n电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口盖。\\n\\n5. 妥善放置充电设备。\", \"chunk_id\": \"han_p124_c142\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"126\", \"context_chunk_ids\": [\"han_p123_c141\", \"han_p124_c142\", \"han_p126_c143\"], \"page_number_start\": \"124\"}, {\"score\": 0.03381147540983607, \"content\": \"[neighbor chunk_id=han_p128_c146 page=128]\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n充电设备设置提前结束或电量充满车辆自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n参照家用便携式交流充电断开充电口连接。\\n\\n3. 关闭交流充电口盖(参照家用便携式交流充电）。\\n\\n4. 整理充电设备，并妥善放置。\\n\\n若使用交流充电桩/盒，将充电枪放到充电桩/盒的指定位置。\\n\\n直流充电桩充电\\n\\n使用直流充电桩充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守充电说明中的充电安全警告事项。\\n\\n为避免造成充电设备及车辆损坏，请仔细阅读并遵守充电说明中的充电安全注意事项。\\n\\n[seed chunk_id=han_p128_c147 page=128-129]\\n设备说明\\n\\n使用公共场所的直流充电桩为车辆充电，充电桩一般安装在特定的充电站。\\n\\n设备规格：请查看充电桩相关说明。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖：\\n\\n整车解锁，电源挡位建议退至“OFF”挡，按下车辆右侧的充电口盖，充电口盖自动开启。\\n\\n2. 打开直流充电口保护盖：\\n\\n打开充电枪和车辆插座的保护盖，确保充电枪头和充电插座的端部没有障碍物。\\n\\n3. 连接车辆接口：\\n\\n将充电桩的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 启动充电：\\n\\n按充电设备指导步骤操作，启动充电。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n[neighbor chunk_id=han_p129_c148 page=129-130]\\n停止充电操作指南\\n\\n1. 结束充电：\\n\\n充电桩设置提前结束或充电已完成充电桩会自动结束充电。\\n\\n2. 断开充电口连接：\\n\\n■按下直流充电枪上的机械锁止按钮，拔出充电枪。\\n\\n3. 关闭充电口保护盖与车辆充电口盖。\\n\\n4. 整理充电设备：\\n\\n充电桩直流充电结束，整理充电设备，并妥善放置，将充电枪放到充电桩的指定位置。\\n\\n注意\\n\\n充完电后，若充电枪不能拔出，请及时联系充电桩客服人员。\\n\\n注意(续)\\n\\n一高温直流充电，电池热管理性能可能会受乘员舱空调影响，出现充电性能下降，充电时间延长现象。为保证充电效率，建议充电过程中关闭空调。\\n\\n整车交流充电/放电指示灯\\n\\n充电/放电指示灯位于车身右侧充电口盖内。分别以绿色、黄色、红色、蓝色、白色颜色来说明充电状态。\\n\\n–若不连接充/放电枪，白色常亮一段时间后会熄灭。使用过程中，若整车闭锁，指示灯点亮一段时候后熄灭。整车解锁时，指示灯再次点亮。\", \"chunk_id\": \"han_p128_c147\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"设备说明\", \"page_number_end\": 129, \"context_chunk_ids\": [\"han_p128_c146\", \"han_p128_c147\", \"han_p129_c148\"], \"page_number_start\": 128}, {\"score\": 0.030575071558678116, \"content\": \"[neighbor chunk_id=han_p126_c143 page=126]\\n温馨提示\\n\\n整车解锁，按钥匙解锁按钮(“OFF”挡充电时)或按下门把手上微动开关(钥匙在附近时)。\\n\\n一启用防盗时，拔出充电枪前，请操作整车解锁以解除充电口的电锁，并在2min 内拔出充电枪头，否则充电口的电锁会重新锁止。\\n\\n电锁工作模式可通过多媒体设置，设置步骤详见充电口电锁防盗功能功能设置。\\n\\n若解锁操作后无法拔下充电枪，可多次尝试解锁，仍无法拔枪时，可尝试应急解锁，操作步骤参照应急解锁。\\n\\n电量较低时，不能使用预约充电。\\n\\n3. 断开供电插头。\\n\\n4. 关闭车辆充电口盖。\\n\\n5. 妥善放置充电设备。\\n\\n[seed chunk_id=han_p126_c144 page=126-127]\\n交流充电桩充电\\n\\n使用交流充电桩充电前：\\n\\n为避免造成严重人身伤害，请仔细阅读并遵守充电说明中的充电安全警告事项。\\n\\n–为避免造成充电设备及车辆损坏，请仔细阅读并遵守充电说明中的充电安全注意事项。\\n\\n设备说明\\n\\n单相交流充电盒 *\\n\\n单相交流充电盒：该装置由充电盒、充电枪和连接线缆组成，断路器、急停开关等信息参见充电盒说明书。\\n\\n使用充电盒为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n单相交流充电桩*\\n\\n使用公共场所的单相交流充电桩为车辆充电。部分充电桩未配备充电枪，需准备交流充电连接器。\\n\\n三相交流充电桩 *\\n\\n使用公共场所的交流充电桩为车辆充电。\\n\\n也可使用三相交流充电桩为车辆充电，充电设备的使用请参考其使用手册或按其指导步骤操作。\\n\\n充电时间：请参考组合仪表上的充电时间提醒。\\n\\n充电操作指南\\n\\n1. 打开充电口盖和充电口保护盖：\\n\\n参照家用便携式交流充电的解锁充电口盖，打开车辆右侧的充电口盖、充电口保护盖。\\n\\n[neighbor chunk_id=han_p127_c145 page=127-128]\\n2. 连接供电口端：\\n\\n若使用充电盒为车辆充电，则无需此步操作。\\n\\n若使用交流充电桩且充电桩配备充电枪，则无需此步操作。\\n\\n3. 连接车辆接口：\\n\\n将充电装置的充电枪连接至车辆充电口，并可靠锁止。\\n\\n4. 充电设置：\\n\\n对于交流充电盒或公共场所没有设置选项的交流充电桩，可跳过此步骤。\\n\\n■对于公共场所有设置选项的交流充电桩/盒，需要刷卡或扫二维码等操作，具体操作见充电桩/盒使用说明。\\n\\n5. 组合仪表充电连接指示灯 点亮。\\n\\n温馨提示\\n\\n充电过程中，组合仪表显示相关充电参数，同时显示充电画面。\\n\\n此时可以通过多媒体设置预约充电，设置流程详见智慧充电(仅限交流充电）功能设置。\", \"chunk_id\": \"han_p126_c144\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"交流充电桩充电\", \"page_number_end\": 127, \"context_chunk_ids\": [\"han_p126_c143\", \"han_p126_c144\", \"han_p127_c145\"], \"page_number_start\": 126}, {\"score\": 0.02063492063492063, \"content\": \"[neighbor chunk_id=han_p403_c146 page=403]\\n表格：推荐的油液和加注量\\n\\n第1条：\\n项目：产品型号\\n参数：BYD7150YT6HEV15\\n\\n第2条：\\n项目：BYD472ZQB 发动机机油型号\\n参数：SP 0W-16\\n\\n第3条：\\n项目：BYD472ZQB 发动机机油加注量(L)\\n参数：4.0(售后保养更换机滤)3.7(售后保养不更换机滤)\\n\\n第4条：\\n项目：EHS 专用变速器齿轮油型号\\n参数：EHSF-2LV\\n\\n第5条：\\n项目：EHS 专用变速器齿轮油加注量(L)\\n参数：3.2±0.1\\n\\n第6条：\\n项目：制动液型号\\n参数：HZY6/DOT4\\n\\n第7条：\\n项目：制动液加注量(L)\\n参数：1.11±0.2\\n\\n第8条：\\n项目：电机电控冷却液型号\\n参数：乙二醇型长效防锈防冻液\\n\\n第9条：\\n项目：电机电控冷却液加注量(L)\\n参数：6.51±0.5\\n\\n第10条：\\n项目：发动机冷却液型号\\n参数：乙二醇型长效防锈防冻\\n\\n第11条：\\n项目：发动机冷却液加注量(L)\\n参数：7.1±0.5\\n\\n[seed chunk_id=han_p403_c147 page=403-405]\\n注意\\n\\n推荐的油液型号经比亚迪测试和认可，使用其他油液型号可能影响车辆性能，甚至导致车辆故障或部件损坏。\\n\\n车辆标识\\n\\n车辆识别代码\\n\\nVIN码粘贴位置：\\n\\n① 前防撞梁上\\n\\n② 变速器总成壳体后侧\\n\\n③ 前舱盖内板\\n\\n④ 前风窗下横梁\\n\\n⑤ 左前门内钣金面\\n\\n⑥ 左后门槛上\\n\\n⑦ 左后轮罩连接钣金处\\n\\n⑧ 行李箱盖右侧\\n\\nVIN 码刻印位置：\\n\\nVIN码刻印于副驾驶座椅下方。可通过连接车辆VDS，选择车型后在右上角读取车辆识别代码（VIN），具体可参考VDS使用说明书。\\n\\n整车铭牌\\n\\n整车铭牌位于右侧B 柱下方。整车铭牌包含：公司名称、品牌、制造国、整车型号、乘坐人数、制造年月、驱动电机型号、驱动电机峰值功率、发动机型号、动力电池系统额定电压、发动机最大净功率、动力电池系统额定容量、车辆识别代号、发动机排量、最大允许总质量等信息。\\n\\n[neighbor chunk_id=han_p405_c148 page=405-407]\\n发动机、驱动电机型号及编号\\n\\n①发动机型号及编号粘贴在发动机顶部中冷器上方\\n\\n②发动机型号及编号刻印在缸体合箱面侧面\\n\\n③前驱动电机型号及编号刻印在前驱动电机壳体上\\n\\n④前驱动电机型号及编号粘贴在前舱机盖内板左上方\\n\\n警告标签\\n\\n空调系统、冷却风扇标贴粘贴在前舱盖内板右上方。\\n\\n安全气囊警告标签烫印在右侧遮阳板上。\\n\\n轮胎气压标签粘贴在左侧B 柱下方。\\n\\n油标指示牌粘贴在加油口盖内侧。\\n\\n充电警示标签粘贴在充电口盖内侧。\\n\\n微波窗口\\n\\n微波窗口位于前风窗玻璃右侧上部位置。\\n\\n注意\\n\\n粘贴电子标识时请勿与玻璃边框或其他物体重叠。\", \"chunk_id\": \"han_p403_c147\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"注意\", \"page_number_end\": 405, \"context_chunk_ids\": [\"han_p403_c146\", \"han_p403_c147\", \"han_p405_c148\"], \"page_number_start\": 403}, {\"score\": 0.0203125, \"content\": \"[neighbor chunk_id=han_p120_c135 page=120-121]\\n充电设备注意事项\\n\\n为了避免对充电设备及车辆造成损坏，注意以下避免事项：\\n\\n启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n\\n请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n\\n充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n\\n充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n\\n请勿在电锁锁止状态强行插入充电枪。\\n\\n应小心使用充放电设备：\\n\\n充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n\\n请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n\\n请勿在温度高于5 0 \\\\%的环境下存放或者使用充电设备。\\n\\n请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n不建议使用外加的电线或者适配器/转接器。如果一定要外加转接，请选择合适的线径(≥1.5mm²的电线)，且适配器/转接器参数需满足要求。\\n\\n[seed chunk_id=han_p121_c136 page=121-122]\\n充电前注意事项\\n\\n当充电口盖未解锁时，请勿强行开启充电口盖。\\n\\n先确保充电枪和充电口无异物，且充电枪端子的防触帽没有松动或变形。\\n\\n当充电口盖解锁后，开启充电口盖，手握充电枪，将充电枪对准充电口并推入，确保充电枪插入到位。\\n\\n充电中注意事项\\n\\n充电时建议人员不要停留在车辆内。\\n\\n充电时空调可正常使用，但会降低充电功率。\\n\\n建议将车辆停放在通风处，请勿遮挡进气格栅。\\n\\n当电池加热工作后，仪表显示充电功率可能有短时波动，属于正常现象。\\n\\n电池冷却可能会启动，压缩机、风扇等零部件按需工作，前舱会有一定的声音，属于正常现象。\\n\\n充电完成前，为提高电池使用寿命，会开启电池均衡，可能会存在充电时间较长的现象。\\n\\n充电时，充电连接线不能盘放，会影响散热。\\n\\n低温充电时，电池热管理可改善电池低温充电能力，但充电时间会延长，加热耗电量会增加，属于正常现象。\\n\\n气温较低区域，建议用户在有供暖的室内进行充电。\\n\\n气温较高区域，建议用户在阴凉通风处充电。\\n\\n组合仪表上会提示预计剩余充满电时间。不同温度、电量、充电设施等情况下，剩余充满电时间可能有一定偏差，属于正常现象。\\n\\n在直流充电*时，建议充到80%~90%即可，若时间允许可充满。\\n\\n[neighbor chunk_id=han_p122_c137 page=122]\\n充电结束注意事项：\\n\\n先停止充电，并确保充电口已经解锁。\\n\\n手握充电枪，并按住充电枪上的按钮*，拔出充电枪。\\n\\n充电结束后，请先解锁后，再拔出充电插头。\\n\\n请勿在充电口锁止状态下强行拔出充电枪，否则会损坏充电口。\\n\\n拔下充电枪后，请确保充电口保护盖及充电口盖处于闭合状态，避免水或异物进入充电端口，影响正常使用。\\n\\n为提升用车体验建议如下：\\n\\n当组合仪表动力电池剩余电量(SOC)指示条颜色到达红色区域时，表明动力电池电量即将耗尽，请及时充电，否则会影响动力电池的使用寿命。\\n\\n建议用车结束后立即充电，充电性能更佳。\", \"chunk_id\": \"han_p121_c136\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"充电前注意事项\", \"page_number_end\": \"122\", \"context_chunk_ids\": [\"han_p120_c135\", \"han_p121_c136\", \"han_p122_c137\"], \"page_number_start\": \"121\"}, {\"score\": 0.02, \"content\": \"[neighbor chunk_id=han_p403_c147 page=403-405]\\n注意\\n\\n推荐的油液型号经比亚迪测试和认可，使用其他油液型号可能影响车辆性能，甚至导致车辆故障或部件损坏。\\n\\n车辆标识\\n\\n车辆识别代码\\n\\nVIN码粘贴位置：\\n\\n① 前防撞梁上\\n\\n② 变速器总成壳体后侧\\n\\n③ 前舱盖内板\\n\\n④ 前风窗下横梁\\n\\n⑤ 左前门内钣金面\\n\\n⑥ 左后门槛上\\n\\n⑦ 左后轮罩连接钣金处\\n\\n⑧ 行李箱盖右侧\\n\\nVIN 码刻印位置：\\n\\nVIN码刻印于副驾驶座椅下方。可通过连接车辆VDS，选择车型后在右上角读取车辆识别代码（VIN），具体可参考VDS使用说明书。\\n\\n整车铭牌\\n\\n整车铭牌位于右侧B 柱下方。整车铭牌包含：公司名称、品牌、制造国、整车型号、乘坐人数、制造年月、驱动电机型号、驱动电机峰值功率、发动机型号、动力电池系统额定电压、发动机最大净功率、动力电池系统额定容量、车辆识别代号、发动机排量、最大允许总质量等信息。\\n\\n[seed chunk_id=han_p405_c148 page=405-407]\\n发动机、驱动电机型号及编号\\n\\n①发动机型号及编号粘贴在发动机顶部中冷器上方\\n\\n②发动机型号及编号刻印在缸体合箱面侧面\\n\\n③前驱动电机型号及编号刻印在前驱动电机壳体上\\n\\n④前驱动电机型号及编号粘贴在前舱机盖内板左上方\\n\\n警告标签\\n\\n空调系统、冷却风扇标贴粘贴在前舱盖内板右上方。\\n\\n安全气囊警告标签烫印在右侧遮阳板上。\\n\\n轮胎气压标签粘贴在左侧B 柱下方。\\n\\n油标指示牌粘贴在加油口盖内侧。\\n\\n充电警示标签粘贴在充电口盖内侧。\\n\\n微波窗口\\n\\n微波窗口位于前风窗玻璃右侧上部位置。\\n\\n注意\\n\\n粘贴电子标识时请勿与玻璃边框或其他物体重叠。\\n\\n[neighbor chunk_id=han_p409_c149 page=409]\\n1,2,3...\\n\\n12V 备用电源 349\\n\\n字母\\n\\nABS(防抱死制动系统)....311 ETC*....317 USB/充电接口....350 VTOL 车外放电方法....137\\n\\nA\\n\\n安全带 …… 369 安全驾驶注意事项 …… 155 安全拉手 …… 348 安全气囊简介 …… 23\\n\\nB\\n\\n保险丝 …… 385 保养周期及保养内容 …… 358\\n\\nC\\n\\n车辆保养计划 …… 358 车辆的存放 …… 375 车辆防腐蚀 …… 365 车辆检修 …… 364 车辆碰撞救援 …… 391 车辆起火救援 …… 393 车辆清洗 …… 367 车辆识别号(VIN 码) …… 404 车门储物盒 …… 346 车身内部的皮革饰件 …… 370\\n\\n充电安全警告 …… 119 充电口防盗 …… 132 充电注意事项 …… 120 出风口 …… 335\\n\\nD\\n\\n地毯 …… 369 灯光开关 …… 107 低速提示音系统 …… 307 低压蓄电池 …… 142 电池泄漏救援 …… 392 电动车窗开关 …… 108 电动外后视镜 …… 105 电量平衡功能 …… 134 电子智能钥匙 …… 66 电子驻车(EPB) …… 165 定期保养 …… 364 冬季驾驶要领 …… 171 动力电池 …… 140 动力电池回收 …… 141\", \"chunk_id\": \"han_p405_c148\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"发动机、驱动电机型号及编号\", \"page_number_end\": 407, \"context_chunk_ids\": [\"han_p403_c147\", \"han_p405_c148\", \"han_p409_c149\"], \"page_number_start\": 405}, {\"score\": 0.018032786885245903, \"content\": \"[neighbor chunk_id=han_p119_c133 page=119-120]\\n充电前警告事项\\n\\n请确保车辆、供电设备和充电设备的充电端口内没有水等异物，并确保金属端子没有因生锈或腐蚀而造成的破坏、影响等情况，若出现上述情况，请勿充电。\\n\\n充电中警告事项\\n\\n为了避免造成严重的人身伤害，车辆正在充电时，注意以下预防事项：\\n\\n禁止接触充电端口、充电连接器或者插头的金属连接处。\\n\\n当有雷雨天气时，禁止给车辆充电或触摸车辆，闪电击中可能导致充电设备损坏、引起人身伤害。\\n\\n在直流充电*时，请保持交流充电口保护盖处于关闭状态；在交流充电时，请保持直流充电口*保护盖处于关闭状态。\\n\\n充电时，如果发现车辆或充电设备异常，如产生异味、冒烟等现象，请立即停止充电，并建议与比亚迪汽车授权服务店联系。\\n\\n充电时，禁止对车辆进行维修。\\n\\n[seed chunk_id=han_p120_c134 page=120]\\n充电结束后警告事项\\n\\n充电结束后，请勿以湿手或站在水里断开充电设备，否则可能引起电击，造成人身伤害。\\n\\n车辆行驶前，请确保拔出充放电设备，并关闭充电口盖。\\n\\n充电注意事项\\n\\n任何电源挡位下都可以进行交流充电、直流充电*，为保证安全，充电前，建议退电至“OFF”挡，充电时车辆无法进入“OK”挡。\\n\\n当外部电网短时间断电并再次供电时，比亚迪充电设备会自动重新启动充电，不用重新连接充电设备。\\n\\n–在未充满电的情况下，需要提前结束充电，请通过充电设备设置提前结束充电，尽量不要带载断电。\\n\\n如果车辆长时间不使用，建议至少 1个月充电一次。\\n\\n[neighbor chunk_id=han_p120_c135 page=120-121]\\n充电设备注意事项\\n\\n为了避免对充电设备及车辆造成损坏，注意以下避免事项：\\n\\n启动车辆前，请确保充电设备已拔开，避免充电枪未插到位状态下，车辆可能会上“OK”挡，并能够挂挡行驶，会导致充电设备及车辆损坏。\\n\\n请勿在充电口保护盖打开的状态下关闭充电口盖。\\n\\n为防止充电口盖失灵，切勿反复开闭充电口盖，建议两次开闭充电口盖的时间间隔>1s。\\n\\n充电口盖、充电枪因天气等原因导致被冻住时，请解冻后再操作，切勿强行开启充电口盖或强行拔枪。\\n\\n充电时，为避免损坏车辆，请勿晃动充电枪，可能会损坏车辆充电口。\\n\\n请勿在电锁锁止状态强行插入充电枪。\\n\\n应小心使用充放电设备：\\n\\n充电连接线长度有限，不可强行拉扯充电连接线，请勿用力拉或者扭转充电电缆。\\n\\n请勿撞击充放电设备，移动时需轻拿轻放，以防止跌落、外力冲撞等机械损伤。\\n\\n请勿在温度高于5 0 \\\\%的环境下存放或者使用充电设备。\\n\\n请勿把充电设备放在靠近加热器或其它热源的地方。\\n\\n不建议使用外加的电线或者适配器/转接器。如果一定要外加转接，请选择合适的线径(≥1.5mm²的电线)，且适配器/转接器参数需满足要求。\", \"chunk_id\": \"han_p120_c134\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"充电结束后警告事项\", \"page_number_end\": \"120\", \"context_chunk_ids\": [\"han_p119_c133\", \"han_p120_c134\", \"han_p120_c135\"], \"page_number_start\": \"120\"}, {\"score\": 0.0171875, \"content\": \"[neighbor chunk_id=han_p131_c151 page=131-132]\\n预约充电操作指南\\n\\n①预约充电开关\\n\\n②充电开始、结束时间*\\n\\n③重复周期\\n\\n④切换到预约用车模式*\\n\\n⑤设置\\n\\n出厂时车辆默认设置为立即充电，即预约充电开关关闭。\\n\\n如需进行预约充电，点击预约充电开启按钮①，设置充电开始、结束时间②和重复周期③，点击“确定”保存设置。\\n\\n–预约设置成功后，若您连接充电枪或按下电源按键使车辆下电，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n预约用车设置页面 *\\n\\n①预约用车开关\\n\\n②预约用车时间\\n\\n③重复周期\\n\\n④电价优惠时段\\n\\n⑤切换到预约充电模式\\n\\n如需进行预约用车，点击预约用车开启按钮①，设置用车时间②，重复周期③和电价优惠时段④，点击“确定”保存设置。\\n\\n预约设置成功后，若您连接充电枪，多媒体将提醒您充电开始时间，您可根据需要改为立即充电。\\n\\n用户可点击智慧充电“ ”图标，在“预约充电提醒”中关闭连接充电枪提醒及下电提醒弹框。\\n\\n[seed chunk_id=han_p132_c152 page=132]\\n温馨提示\\n\\n一智慧充电功能只针对比亚迪配送的交流慢充设备研发，车主使用非比亚迪认证的交流慢充设备时，应关闭此功能，否则可能因充电设备不响应导致无法充电，造成车辆亏电、电池电量不足。如需要在公共充电设备上应用，请确认设备可支持桩端预约。\\n\\n一电池电量过低时，车辆在进入预约前将进行保底充电，保底充电时多媒体仍会进行熄火下电提醒和充电枪连接提醒，仪表下方将出现相应的温馨提示。\\n\\n一若车辆处于寒冷环境中，预约用车将智能开启电池预加热，电池加热功能不连接充电枪也可以使用，这将消耗部分电量。\\n\\n提醒弹框“改为立即充电”只针对本次预约，如需取消全部预约，请在设置界面关闭预约开关。\\n\\n连接直流充电枪*，预约设置无效，车辆将进入立即充电。\\n\\n[neighbor chunk_id=han_p132_c153 page=132-133]\\n充电口电锁防盗功能\\n\\n为防止充放电时电枪被盗，本车充放电过程中充电口具备防盗功能，该功能为默认“停用”状态，用户可通过中控屏→设置 →能量→充电与放电进入“充电口电锁防盗”设置界面，选择“启用”开启防盗功能。\\n\\n在“启用/智能”模式下，充电过程中用户可以通过以下几种方式进行解锁拔下充电枪：\\n\\n●“OFF”挡下按智能钥匙解锁按键进行解锁。\\n\\n按主驾门外门把手旁边的微动开关进行解锁。\\n\\n按主驾门内车窗下的中控锁进行解锁。\\n\\n若车辆已充满电，充电枪会自动解锁(仅“智能”模式)。\", \"chunk_id\": \"han_p132_c152\", \"chunk_type\": \"text\", \"source_file\": \"han.pdf\", \"section_title\": \"温馨提示\", \"page_number_end\": \"132\", \"context_chunk_ids\": [\"han_p131_c151\", \"han_p132_c152\", \"han_p132_c153\"], \"page_number_start\": \"132\"}]',5,35746,1,NULL,'2026-07-04 10:07:39');
